_AUTO_MODE_ACTIVE = False  # pylint: disable=invalid-name


def _should_disable_interactive_prompts(shell: object | None = None) -> bool:
    """Return True if the current run must not block on interactive prompts.

    We support three non-interactive signals:
    - Auto mode: enabled by `adscan ci` to force defaults and skip all prompts.
    - Session env: set to "ci" by CLI plumbing for CI runs.
    - Classic CI / non-TTY: CI environment variables or missing TTY.

    Args:
        shell: Optional shell instance (used to read session_command_type defensively).

    Returns:
        True if prompts must not be shown / waited on; False otherwise.
    """
    try:
        if _AUTO_MODE_ACTIVE:
            return True
    except Exception:
        # Best-effort only; never block on a broken prompt flag.
        return True

    # Delegate to the central predicate for everything else.
    from adscan_internal.interaction import is_non_interactive

    return is_non_interactive(shell=shell)


_PIP_BREAK_SYSTEM_PACKAGES_FLAG = "--break-system-packages"
_PIP_BREAK_SYSTEM_PACKAGES_SUPPORT_CACHE: dict[str, bool] = {}

raw_SYSTEM_REQUIREMENTS_URL = (
    "https://www.adscanpro.com/docs/getting-started/system-requirements"
)
_SYSTEM_REQUIREMENTS_URL = mark_passthrough(raw_SYSTEM_REQUIREMENTS_URL)
_DOCKER_USE_SUDO: bool | None = None


def _pip_supports_break_system_packages(
    python_executable: str, env: dict[str, str] | None
) -> bool:
    """Return True if `pip install` supports --break-system-packages.

    Some environments (non-Debian/Ubuntu, older pip) don't support this flag.
    """
    cached = _PIP_BREAK_SYSTEM_PACKAGES_SUPPORT_CACHE.get(python_executable)
    if cached is not None:
        return cached

    supported = False
    try:
        result = run_command(
            [python_executable, "-m", "pip", "install", "--help"],
            check=False,
            capture_output=True,
            env=env,
            timeout=8,
        )
        combined = f"{result.stdout or ''}\n{result.stderr or ''}"
        supported = _PIP_BREAK_SYSTEM_PACKAGES_FLAG in combined
    except Exception:
        supported = False

    _PIP_BREAK_SYSTEM_PACKAGES_SUPPORT_CACHE[python_executable] = supported
    return supported


def _is_pip_break_system_packages_unknown_option(error_output: str) -> bool:
    """Return True if pip output indicates --break-system-packages is unsupported."""
    normalized = (error_output or "").lower()
    return (
        "no such option" in normalized or "unknown option" in normalized
    ) and _PIP_BREAK_SYSTEM_PACKAGES_FLAG in normalized


def _run_pip_install_with_optional_break_system_packages(
    python_executable: str,
    args: list[str],
    env: dict[str, str] | None,
    prefer_break_system_packages: bool,
) -> None:
    """Run `python -m pip install ...`, adding --break-system-packages only when supported.

    Retries without the flag if pip rejects it at runtime.
    """
    base_cmd = [python_executable, "-m", "pip", "install"] + args
    cmd = base_cmd

    if prefer_break_system_packages and _pip_supports_break_system_packages(
        python_executable, env
    ):
        cmd = base_cmd[:4] + [_PIP_BREAK_SYSTEM_PACKAGES_FLAG] + base_cmd[4:]

    try:
        run_command(cmd, env=env)
    except subprocess.CalledProcessError as e:
        combined = f"{getattr(e, 'stdout', '')}\n{getattr(e, 'stderr', '')}"
        if _is_pip_break_system_packages_unknown_option(combined):
            fallback_cmd = [c for c in cmd if c != _PIP_BREAK_SYSTEM_PACKAGES_FLAG]
            run_command(fallback_cmd, env=env)
            return
        raise


def _is_transient_pip_network_error(error_output: str) -> bool:
    """Return True if pip output suggests a transient network/download issue."""
    normalized = (error_output or "").lower()
    return any(
        needle in normalized
        for needle in (
            "read timed out",
            "the read operation timed out",
            "readtimeouterror",
            "connection reset by peer",
            "connection aborted",
            "temporary failure",
            "tlsv1",
            "sslerror",
            "chunkedencodingerror",
            "incompleteread",
            "remote end closed connection",
        )
    )


def _run_pip_install_with_retries(
    cmd: list[str],
    *,
    env: dict[str, str] | None,
    attempts: int = 3,
    backoff_seconds: int = 10,
    label: str = "pip install",
) -> None:
    """Run a pip command with retries for transient network errors.

    This targets sporadic failures where large wheels (e.g. numpy) time out on
    slow/unreliable networks or through corporate proxies.
    """
    if attempts < 1:
        attempts = 1

    last_exc: Exception | None = None
    for attempt in range(1, attempts + 1):
        try:
            run_command(cmd, env=env, check=True)
            return
        except subprocess.CalledProcessError as exc:
            last_exc = exc
            combined = f"{getattr(exc, 'stdout', '')}\n{getattr(exc, 'stderr', '')}"
            if is_dns_resolution_error(combined) and attempt < attempts:
                wait_s = backoff_seconds * attempt
                print_warning(
                    f"{label} failed due to a DNS resolution error; retrying ({attempt}/{attempts}) in {wait_s}s..."
                )
                time.sleep(wait_s)
                continue
            if _is_transient_pip_network_error(combined) and attempt < attempts:
                wait_s = backoff_seconds * attempt
                print_warning(
                    f"{label} failed due to a transient network error; retrying ({attempt}/{attempts}) in {wait_s}s..."
                )
                time.sleep(wait_s)
                continue
            raise
        except Exception as exc:  # pragma: no cover - unexpected execution errors
            last_exc = exc
            if attempt < attempts:
                wait_s = backoff_seconds * attempt
                print_warning(
                    f"{label} failed unexpectedly; retrying ({attempt}/{attempts}) in {wait_s}s..."
                )
                time.sleep(wait_s)
                continue
            raise

    if last_exc is not None:
        raise last_exc


def _is_netexec_like_command(command: str, netexec_path: str | None = None) -> bool:
    """Return True if the command should be treated as a NetExec/NXC invocation.

    We consider a command NetExec-like when:
    - It contains the resolved NetExec path (normal case), or
    - The first executable token is `nxc` or `netexec` (including absolute paths).

    This keeps retry/clock-skew handling consistent even when callers use the
    `nxc` binary directly instead of the `netexec` wrapper.
    """
    if not command:
        return False
    if netexec_path and netexec_path in command:
        # Avoid treating helper wrappers (e.g. enum-trusts --nxc-path <path>) as NXC.
        if (
            f"--nxc-path {netexec_path}" in command
            or f"--nxc-path={netexec_path}" in command
        ):
            return False
        escaped = re.escape(netexec_path)
        pattern = rf"(^|\s)(sudo\s+)?{escaped}(\s|$)"
        if re.search(pattern, command):
            return True

    try:
        first_token = re.split(r"\s+", command.strip(), maxsplit=1)[0]
    except Exception:
        first_token = command.strip().split(" ")[0] if command.strip() else ""

    first_token = first_token.strip().strip("'\"")
    basename = os.path.basename(first_token)
    return basename in {"nxc", "netexec"}


def _is_arch_like_distro(distro_info: dict[str, Any]) -> bool:
    """Return True if the detected distro looks Arch-based (unsupported)."""
    distro_id = (distro_info.get("id") or "").lower()
    id_like = (distro_info.get("id_like") or "").lower()
    pretty = (distro_info.get("pretty_name") or "").lower()

    arch_markers = {
        "arch",
        "garuda",
        "manjaro",
        "endeavouros",
        "arcolinux",
        "blackarch",
    }
    return (
        any(marker in distro_id for marker in arch_markers)
        or "arch" in id_like
        or "arch" in pretty
    )


def _is_rpm_like_distro(distro_info: dict[str, Any]) -> bool:
    """Return True if the detected distro looks RPM-based (unsupported)."""
    distro_id = (distro_info.get("id") or "").lower()
    id_like = (distro_info.get("id_like") or "").lower()
    pretty = (distro_info.get("pretty_name") or "").lower()

    def _tokens(value: str) -> set[str]:
        return {t for t in re.split(r"[^a-z0-9]+", value) if t}

    rpm_ids = {
        "fedora",
        "rhel",
        "centos",
        "rocky",
        "almalinux",
        "amzn",
        "ol",
    }

    tokens = _tokens(distro_id) | _tokens(id_like) | _tokens(pretty)
    if distro_id in rpm_ids:
        return True

    # ID_LIKE often includes "rhel fedora" style tokens.
    if tokens.intersection(rpm_ids):
        return True

    # Pretty names can spell out vendors without exposing ID=rhel/ol.
    if {"red", "hat"}.issubset(tokens):
        return True
    if {"oracle", "linux"}.issubset(tokens):
        return True
    if {"amazon", "linux"}.issubset(tokens):
        return True

    return False


def _is_unsupported_kali_version(distro_info: dict[str, Any]) -> bool:
    """Return True if the detected Kali version is known to be unsupported."""
    distro_id = (distro_info.get("id") or "").lower()
    version_id = (distro_info.get("version_id") or "").strip()

    if distro_id != "kali":
        return False

    # Known incompatible baselines (CI-verified).
    return version_id.startswith(("2024.1", "2024.2"))


def _guard_unsupported_distribution(command: str | None) -> None:
    """Abort early on unsupported distributions."""
    if platform.system().lower() != "linux":
        return

    distro_info = _detect_distribution()

    is_arch = _is_arch_like_distro(distro_info)
    is_rpm = _is_rpm_like_distro(distro_info)
    is_kali_unsupported = _is_unsupported_kali_version(distro_info)

    if not (is_arch or is_rpm or is_kali_unsupported):
        return

    distro_id = distro_info.get("id") or "unknown"
    distro_like = distro_info.get("id_like") or "unknown"
    version_id = distro_info.get("version_id") or "unknown"
    print_info_debug(
        "[platform] Unsupported distro detected: "
        f"id={distro_id}, like={distro_like}, version_id={version_id}, command={command}"
    )

    if is_arch:
        print_error(
            "ADscan is not compatible with Arch-based distributions (e.g., Arch, Garuda, Manjaro)."
        )
        print_instruction(f"See supported systems: {_SYSTEM_REQUIREMENTS_URL}")
    elif is_rpm:
        print_error(
            "ADscan is not compatible with RPM-based distributions (e.g., Fedora/RHEL/CentOS) yet."
        )
        print_instruction(f"See supported systems: {_SYSTEM_REQUIREMENTS_URL}")
    elif is_kali_unsupported:
        print_warning(
            "This Kali Linux version is known to cause issues with ADscan (Kali 2024.1 / 2024.2 or earlier baseline)."
        )
        print_instruction(
            f"Recommended: upgrade Kali. See supported systems: {_SYSTEM_REQUIREMENTS_URL}"
        )

        if os.getenv("CI") or not sys.stdin.isatty():
            print_error(
                "Refusing to continue on an unsupported Kali baseline in non-interactive mode."
            )
            raise SystemExit(1)

        proceed = Confirm.ask(
            "Continue anyway (not recommended)?",
            default=False,
        )
        if proceed:
            return

        print_warning("Aborted by user.")
        raise SystemExit(1)

    # Arch/RPM are not supported at all: abort (except informational commands).
    if command in (None, "version"):
        return
    raise SystemExit(1)


def _sudo_validate() -> bool:
    """Ensure sudo credentials are cached for the current user/session.

    Delegates to ``adscan_internal.sudo_utils.sudo_validate()`` for the core
    logic and adds Rich error output and telemetry capture on failure.
    """
    from adscan_internal.sudo_utils import (
        sudo_validate as _core_validate,
        _is_non_interactive,
    )

    try:
        result = _core_validate()
        if not result and _is_non_interactive():
            print_error("Sudo is required but not available without a password prompt.")
            print_instruction(
                "Configure sudoers (NOPASSWD) for CI, or run this in an interactive terminal."
            )
        return result
    except Exception as exc:  # pragma: no cover - environment dependent
        telemetry.capture_exception(exc)
        print_error(
            "Sudo authentication failed; cannot proceed with privileged operations."
        )
        print_exception(show_locals=False, exception=exc)
        return False


# Docker access denied check is now in adscan_internal.docker_runtime
_docker_access_denied = docker_access_denied


def _detect_docker_use_sudo() -> bool:
    """Return True if Docker commands require sudo in this environment.

    This is a wrapper around docker_needs_sudo() from docker_runtime module.
    """
    return docker_needs_sudo(timeout=10)


def _run_docker_command(
    command: str | list[str],
    *,
    shell: bool,
    check: bool,
    capture_output: bool | None = None,
    text: bool = True,
    timeout: int | None = None,
) -> subprocess.CompletedProcess:
    """Run a docker command, automatically using sudo when needed.

    If sudo is required and credentials are not cached, this will prompt the user.
    """
    global _DOCKER_USE_SUDO  # pylint: disable=global-statement
    if _DOCKER_USE_SUDO is None:
        _DOCKER_USE_SUDO = _detect_docker_use_sudo()

    # Use the modularized run_docker_command with dependencies
    return run_docker_command(
        command,
        shell=shell,
        check=check,
        capture_output=capture_output,
        text=text,
        timeout=timeout,
        run_command_func=run_command,
        sudo_validate_func=_sudo_validate,
        build_effective_user_env_func=_build_effective_user_env_for_command,
        sudo_preserve_env_keys=_DEFAULT_SUDO_PRESERVE_ENV_KEYS,
        sudo_prefix_args_func=_sudo_prefix_args,
    )


def _run_systemctl_command(
    args: list[str],
    *,
    check: bool = False,
    timeout: int = 30,
) -> subprocess.CompletedProcess | None:
    """Run systemctl, prompting for sudo password if needed."""
    if not shutil.which("systemctl"):
        return None

    cmd: list[str] = ["systemctl"] + args
    cmd_env: dict[str, str] | None = None
    if os.geteuid() != 0:
        if not _sudo_validate():
            raise RuntimeError("sudo validation failed for systemctl")
        cmd_env = _build_effective_user_env_for_command(cmd, shell=False)
        cmd = _sudo_prefix_args() + cmd

    return run_command(
        cmd,
        check=check,
        capture_output=False,
        timeout=timeout,
        env=cmd_env,
    )


def _build_command_metadata(shell=None, command_type: str | None = None, extra=None):
    """Compose telemetry metadata including command type and optional extras."""
    metadata = {}
    base_metadata = _build_session_metadata(shell) if shell is not None else None
    if base_metadata:
        metadata.update(base_metadata)

    resolved_command = (
        command_type
        or (getattr(shell, "session_command_type", None) if shell is not None else None)
        or SESSION_COMMAND_TYPE
    )
    if resolved_command:
        metadata["command_type"] = resolved_command

    if extra:
        for key, value in extra.items():
            if value is not None:
                metadata[key] = value

    return metadata or None


_ALLOWED_SESSION_COMMANDS = telemetry.SESSION_CAPTURE_ALLOWED_COMMANDS

_LAST_CHECK_SESSION_EXTRA: dict[str, object] | None = None

_SESSION_CAPTURE_FINALIZED: bool = False


def _resolve_command_type(shell=None, override: Optional[str] = None) -> Optional[str]:
    """Resolve current command type from override, shell, or global state."""
    if override:
        return override
    if shell is not None:
        shell_type = getattr(shell, "session_command_type", None)
        if shell_type:
            return shell_type
    return SESSION_COMMAND_TYPE


def _is_session_capture_allowed(command_type: Optional[str]) -> bool:
    """Return True if the command should upload Rich session recordings."""
    return telemetry.is_session_capture_command(
        command_type, allowed_commands=set(_ALLOWED_SESSION_COMMANDS)
    )


def _capture_command_session(
    command_type: str, *, success: bool | None = None, extra=None
):
    """Upload the Rich recording for non-interactive commands."""
    global _SESSION_CAPTURE_FINALIZED
    if _SESSION_CAPTURE_FINALIZED:
        return
    if not _is_session_capture_allowed(command_type):
        _SESSION_CAPTURE_FINALIZED = True
        return
    metadata = _build_command_metadata(command_type=command_type, extra=extra)
    if success is not None:
        metadata = metadata or {}
        metadata["command_success"] = bool(success)

    env = None
    if metadata and "environment" in metadata:
        env = metadata["environment"]
    else:
        env = _determine_session_environment()
        if metadata is not None:
            metadata.setdefault("environment", env)

    if command_type in {"check", "install"} and (VERBOSE_MODE or DEBUG_MODE):
        status = (
            "success"
            if success is True
            else "failure"
            if success is False
            else "unknown"
        )
        detail = f"metadata={metadata}" if DEBUG_MODE and metadata is not None else ""
        message = (
            f"Uploading session recording for command '{command_type}' "
            f"(environment: {env}, status: {status})"
        )
        if detail:
            message = f"{message} {detail}"
        print_info_debug(message)

    telemetry.capture_command_session(
        console=TELEMETRY_CONSOLE,
        command_type=command_type,
        base_metadata=metadata,
        allowed_commands=set(_ALLOWED_SESSION_COMMANDS),
    )
    _SESSION_CAPTURE_FINALIZED = True


def _log_free_disk_space_debug(context: str) -> None:
    """Log current free disk space to aid debugging heavy install flows."""
    try:
        usage = shutil.disk_usage("/")  # type: ignore[attr-defined]
        free_gb = usage.free / (1024**3)
        print_info_debug(
            f"[Disk] {context}: {free_gb:.2f} GB free ({usage.free} bytes)"
        )
    except Exception as exc:  # Best-effort logging; never raise
        try:
            telemetry.capture_exception(exc)
        except Exception:
            pass
        print_info_debug(f"[Disk] Failed to determine free space for {context}: {exc}")


def _get_free_disk_space_bytes(path: str = "/") -> int | None:
    """Return free disk space in bytes for the filesystem containing `path`.

    Args:
        path: Path to check (defaults to root filesystem).

    Returns:
        Free bytes, or None if the check fails.
    """
    try:
        usage = shutil.disk_usage(path)  # type: ignore[attr-defined]
        return int(usage.free)
    except Exception as exc:  # pragma: no cover - depends on runtime environment
        telemetry.capture_exception(exc)
        print_info_debug(f"[Disk] Failed to determine free space for {path}: {exc}")
        return None


def _process_exit_cleanup():
    """Ensure workspace save and session upload even on abrupt exits."""
    global _SESSION_CAPTURE_FINALIZED
    if _SESSION_CAPTURE_FINALIZED:
        return
    shell = globals().get("ACTIVE_SHELL")
    command_type = _resolve_command_type(shell)
    if not _is_session_capture_allowed(command_type):
        _SESSION_CAPTURE_FINALIZED = True
        return
    try:
        if shell and not getattr(shell, "_shutdown_in_progress", False):
            print_info_debug("[atexit] Cleanup handler invoking do_exit")
            shell.do_exit(exit=False)
            return
    except Exception as exc:  # pragma: no cover - best-effort shutdown
        telemetry.capture_exception(exc)
        print_info_debug(f"[atexit] Cleanup handler failed to run do_exit: {exc}")
    metadata = _build_command_metadata(shell=shell)
    print_info_debug("[atexit] Uploading session recording from cleanup handler")
    telemetry.capture_session_end(console=TELEMETRY_CONSOLE, metadata=metadata)
    _SESSION_CAPTURE_FINALIZED = True


atexit.register(_process_exit_cleanup)


def _normalize_interactive_text(value: str) -> str:
    """Normalize user-provided input coming from interactive prompts.

    Some terminals/recorders can introduce invisible Unicode formatting marks
    (e.g., directional or zero-width characters). These can break comparisons
    like `value.lower() == "all"` and can also leak into filenames/commands.

    Args:
        value: Raw user input as returned by Rich Prompt/Questionary wrappers.

    Returns:
        A sanitized string with control/format characters removed and
        surrounding whitespace trimmed.
    """
    # A cancelled/absent prompt returns Python ``None``; ``str(None)`` would
    # yield the truthy string ``"None"`` and defeat downstream ``if not value``
    # abort guards (this ran DCSync against a bogus "None" account). Normalise
    # None/empty to "" so cancellation aborts cleanly.
    if value is None:
        return ""
    sanitized_chars: list[str] = []
    for ch in str(value):
        codepoint = ord(ch)
        if codepoint < 32 or codepoint == 127:
            continue
        if unicodedata.category(ch) == "Cf":
            continue
        sanitized_chars.append(ch)
    return "".join(sanitized_chars).strip()


def _resolve_domain_key(domains_data: dict[str, Any], domain: str) -> str | None:
    """Resolve a domain string to a canonical key in domains_data.

    Users can paste values that include invisible Unicode formatting characters
    (e.g., zero-width joiners) or mixed case. This helper normalizes the input
    and finds the matching key in the domains_data mapping.

    Args:
        domains_data: Mapping keyed by domain name.
        domain: Domain string provided by user or extracted from tool output.

    Returns:
        The canonical domain key present in domains_data, or None if no match.
    """
    if not domain:
        return None
    if domain in domains_data:
        return domain

    normalized = _normalize_interactive_text(domain).casefold()
    if not normalized:
        return None

    for key in domains_data.keys():
        if _normalize_interactive_text(str(key)).casefold() == normalized:
            return str(key)

    return None


def _log_interrupt_debug(*, kind: str, source: str) -> None:
    """Emit a standardized debug line when an interactive interrupt is detected."""
    try:
        print_info_debug(f"[interrupt] kind={kind} source={source}")
    except Exception:
        # Best-effort only; interrupt logging must never alter control flow.
        pass


def _configure_prompt_runtime_behavior() -> None:
    """Configure centralized prompt wrappers for runtime-specific behavior."""

    def _interrupt_logger(kind: str, source: str) -> None:
        _log_interrupt_debug(kind=kind, source=source)

    configure_prompt_behavior(
        should_disable_interactive_prompts=_should_disable_interactive_prompts,
        interrupt_logger=_interrupt_logger,
        use_questionary_in_container=lambda: (
            os.getenv("ADSCAN_CONTAINER_RUNTIME") == "1"
        ),
    )
    install_prompt_logging_wrappers()


# Configure centralized prompt wrappers once at import time.
_configure_prompt_runtime_behavior()


def _logged_prompt_ask(*prompt_args, **kwargs):
    """Compatibility wrapper delegating to centralized Prompt.ask behavior."""
    return Prompt.ask(*prompt_args, **kwargs)


def _logged_confirm_ask(*confirm_args, **kwargs):
    """Compatibility wrapper delegating to centralized Confirm.ask behavior."""
    return Confirm.ask(*confirm_args, **kwargs)


def enable_auto_mode():
    """Enable auto mode: all prompts return defaults without user interaction."""
    global _AUTO_MODE_ACTIVE  # pylint: disable=global-statement
    _AUTO_MODE_ACTIVE = True
    set_prompt_auto_mode(True)
    install_prompt_logging_wrappers()


def disable_auto_mode():
    """Disable auto mode: restore original prompt functions."""
    global _AUTO_MODE_ACTIVE  # pylint: disable=global-statement
    _AUTO_MODE_ACTIVE = False
    set_prompt_auto_mode(False)
    install_prompt_logging_wrappers()


