# Collected information to present at installation summary
INSTALL_SUMMARY = {}


# Determine if running inside Docker/container environment
def _is_full_adscan_container_runtime() -> bool:
    """Return True when running inside the ADscan FULL runtime container.

    This is distinct from "Docker is installed on the host". In this mode, ADscan
    is already bundled with its dependencies under `/opt/adscan`, and we must
    avoid recursive Docker-mode execution (Docker-in-Docker is not supported).
    """
    if os.getenv("ADSCAN_CONTAINER_RUNTIME") == "1":
        return True
    if not is_docker_env():
        return False
    adscan_home = str(os.getenv("ADSCAN_HOME") or "").strip()
    if adscan_home and adscan_home != "/opt/adscan":
        return False
    return (
        os.path.isdir("/opt/adscan/tool_venvs")
        and os.path.isdir("/opt/adscan/tools")
        and os.path.isdir("/opt/adscan/wordlists")
    )


def _has_gui_session() -> bool:
    """Return True if a GUI session appears available for launching desktop apps.

    This is a best-effort check used to avoid spawning GUI clients (e.g., xfreerdp)
    in headless/container contexts where they will immediately fail with display
    errors.
    """
    display = os.environ.get("DISPLAY", "").strip()
    wayland = os.environ.get("WAYLAND_DISPLAY", "").strip()
    if display:
        try:
            # Most X11 clients require the Unix socket directory to be mounted.
            if os.path.isdir("/tmp/.X11-unix"):
                return True
        except OSError:
            return False
        return True
    if wayland:
        # Wayland clients typically rely on XDG_RUNTIME_DIR; we don't try to
        # validate the socket path exhaustively here.
        return True
    return False


def _normalize_dns_like(value: str) -> str:
    """Normalize domain/FQDN-like tokens for comparison."""
    return (value or "").strip().lower().rstrip(".")


def _is_direct_child_fqdn(fqdn: str, domain: str) -> bool:
    """Return True if fqdn is exactly one label below domain.

    Examples:
        - kingslanding.sevenkingdoms.local is a direct child of sevenkingdoms.local
        - winterfell.north.sevenkingdoms.local is NOT a direct child of sevenkingdoms.local
    """
    fqdn_norm = _normalize_dns_like(fqdn)
    domain_norm = _normalize_dns_like(domain)
    if not fqdn_norm or not domain_norm:
        return False
    if fqdn_norm == domain_norm:
        return False
    if not fqdn_norm.endswith("." + domain_norm):
        return False
    fqdn_labels = [p for p in fqdn_norm.split(".") if p]
    domain_labels = [p for p in domain_norm.split(".") if p]
    return len(fqdn_labels) == len(domain_labels) + 1


def _is_adscan_hosts_line_for_domain(stripped_line: str, domain: str) -> bool:
    """Return True if a /etc/hosts line looks like an ADscan-managed mapping for the domain.

    ADscan writes entries as:
        <IP> <HOST>.<DOMAIN> <HOST> <DOMAIN>
    This helper is used to avoid substring bugs when domains are nested (e.g. north.sevenkingdoms.local
    contains sevenkingdoms.local).
    """
    stripped = (stripped_line or "").strip()
    if not stripped or stripped.startswith("#"):
        return False
    domain_norm = _normalize_dns_like(domain)
    if not domain_norm:
        return False
    parts = stripped.split()
    if len(parts) < 4:
        return False

    normalized_tokens = [_normalize_dns_like(p) for p in parts[1:]]
    if domain_norm not in normalized_tokens:
        return False

    fqdn_token = next(
        (tok for tok in normalized_tokens if _is_direct_child_fqdn(tok, domain_norm)),
        None,
    )
    if not fqdn_token:
        return False
    host_label = fqdn_token.split(".", 1)[0]
    return host_label in normalized_tokens


