def _is_systemd_available() -> bool:
    """Return True when systemd is available as a service manager.

    In many container images, `systemctl` may exist but systemd is not PID 1, so
    service management commands will fail. We treat systemd as available only when
    the runtime looks like a real systemd environment.
    """
    # ADscan container runtime never runs systemd as PID 1; avoid noisy probes.
    if _is_full_adscan_container_runtime():
        return False
    if not shutil.which("systemctl"):
        return False
    if os.path.isdir("/run/systemd/system"):
        return True
    try:
        proc = subprocess.run(
            ["ps", "-p", "1", "-o", "comm="],
            capture_output=True,
            text=True,
            timeout=3,
            check=False,
        )
        return proc.returncode == 0 and proc.stdout.strip() == "systemd"
    except Exception:
        return False


def _is_loopback_ip(value: str) -> bool:
    """Return True if *value* is a loopback IP address."""
    try:
        return ipaddress.ip_address(value).is_loopback
    except Exception:
        return False


def _get_adscan_local_resolver_ip() -> str:
    """Return the loopback IP that ADscan should use as its local resolver.

    In Docker host-network mode, the container must avoid binding to 127.0.0.1:53
    when the host already has a DNS service listening there. The entrypoint can
    select an available loopback (e.g. 127.0.0.2) and exports it via
    ``ADSCAN_LOCAL_RESOLVER_IP``.

    On host (legacy) installs, Unbound is expected to listen on 127.0.0.1.
    """
    env_ip = (os.getenv("ADSCAN_LOCAL_RESOLVER_IP") or "").strip()
    if env_ip and _is_loopback_ip(env_ip):
        return env_ip

    if _is_full_adscan_container_runtime():
        try:
            with open("/etc/resolv.conf", encoding="utf-8") as rf:
                for line in rf:
                    line = line.strip()
                    if not line or line.startswith("#"):
                        continue
                    if line.startswith("nameserver"):
                        parts = line.split()
                        if len(parts) >= 2 and _is_loopback_ip(parts[1].strip()):
                            return parts[1].strip()
        except OSError:
            pass

    return "127.0.0.1"


def _is_unbound_listening_local(*, resolver_ip: str | None = None) -> bool:
    """Return True if Unbound appears to be listening on the local resolver."""
    local_ip = resolver_ip or _get_adscan_local_resolver_ip()
    try:
        ss_tcp = run_command(
            ["ss", "-H", "-ltnp"], check=False, capture_output=True, text=True
        )
        ss_udp = run_command(
            ["ss", "-H", "-lunp"], check=False, capture_output=True, text=True
        )
        listeners = "\n".join(
            [
                (ss_tcp.stdout or "") if ss_tcp else "",
                (ss_udp.stdout or "") if ss_udp else "",
            ]
        )
        return f"{local_ip}:53" in listeners and "unbound" in listeners
    except Exception:
        return False


def _get_port_53_listeners_text(*, use_sudo: bool) -> str:
    """Return best-effort `ss` output for TCP/UDP listeners on port 53.

    Args:
        use_sudo: When True, prefix `ss` commands with `sudo -n` to reveal process
            names even when running unprivileged.

    Returns:
        A combined string of TCP+UDP `ss` output (may be empty).
    """
    try:
        prefix: list[str] = []
        if use_sudo and os.geteuid() != 0:
            prefix = _sudo_prefix_args(non_interactive=True)
        ss_tcp = run_command(
            prefix + ["ss", "-H", "-ltnup"], check=False, capture_output=True, text=True
        )
        ss_udp = run_command(
            prefix + ["ss", "-H", "-lunp"], check=False, capture_output=True, text=True
        )
        return "\n".join(
            [
                (ss_tcp.stdout or "") if ss_tcp else "",
                (ss_udp.stdout or "") if ss_udp else "",
            ]
        ).strip()
    except Exception:
        return ""


def _extract_process_names_from_ss(text: str) -> set[str]:
    """Extract process names from `ss` output."""
    try:
        if not text:
            return set()
        # Typical fragment: users:(("dnsmasq",pid=123,fd=3))
        return {m.group(1) for m in re.finditer(r'users:\(\("([^"]+)"', text)}
    except Exception:
        return set()


def _stop_dns_resolver_service_for_unbound(
    service_name: str,
    *,
    systemd_available: bool,
    context: str,
) -> None:
    """Best-effort stop/disable a conflicting DNS resolver so Unbound can bind 53.

    This is only intended to be used in explicit repair flows (e.g. `check --fix`).
    """
    try:
        print_info_verbose(
            f"[dns] Stopping conflicting resolver '{service_name}' ({context})..."
        )
        if os.geteuid() != 0 and not _sudo_validate():
            print_warning(
                "Cannot stop conflicting DNS resolver automatically without sudo privileges."
            )
            return

        sudo_prefix = _sudo_prefix_args() if os.geteuid() != 0 else []

        if systemd_available:
            run_command(
                sudo_prefix + ["systemctl", "disable", "--now", service_name],
                check=False,
                capture_output=True,
                text=True,
                timeout=30,
            )
        # Fallback for non-systemd or as an extra stop attempt.
        run_command(
            sudo_prefix + ["service", service_name, "stop"],
            check=False,
            capture_output=True,
            text=True,
            timeout=30,
        )
        # Best-effort: ensure the process is not still running/holding port 53.
        run_command(
            sudo_prefix + ["pkill", "-x", service_name],
            check=False,
            capture_output=True,
            text=True,
            timeout=15,
        )
    except Exception as exc:  # pragma: no cover - env dependent
        telemetry.capture_exception(exc)


def _start_unbound_without_systemd() -> bool:
    """Start Unbound without relying on systemd/service managers.

    This is mainly for container images where systemd is not PID 1. We launch
    Unbound as a detached background process and verify it binds to the local
    resolver IP (:53).
    """
    try:
        local_ip = _get_adscan_local_resolver_ip()
        if os.geteuid() != 0:
            return False
        if _is_unbound_listening_local(resolver_ip=local_ip):
            return True
        if not shutil.which("unbound"):
            return False

        checkconf = run_command(
            ["unbound-checkconf", "/etc/unbound/unbound.conf"],
            check=False,
            capture_output=True,
            text=True,
        )
        if checkconf and checkconf.returncode != 0:
            return False

        log_dir = os.path.join(ADSCAN_BASE_DIR, "logs")
        try:
            os.makedirs(log_dir, exist_ok=True)
        except Exception:
            log_dir = "/tmp"
        log_path = os.path.join(log_dir, "unbound-standalone.log")

        with open(log_path, "a", encoding="utf-8") as logf:
            subprocess.Popen(
                ["unbound", "-d", "-p", "-c", "/etc/unbound/unbound.conf"],
                stdin=subprocess.DEVNULL,
                stdout=logf,
                stderr=logf,
                start_new_session=True,
            )

        for _ in range(10):
            if _is_unbound_listening_local(resolver_ip=local_ip):
                return True
            time.sleep(0.2)

        return False
    except Exception:
        return False


def _start_unbound_without_systemd_via_sudo() -> bool:
    """Best-effort: start Unbound without systemd using sudo -n (non-interactive).

    This is primarily for CI containers where ADscan runs as a non-root user but
    passwordless sudo is available. If sudo requires a password, this will fail
    cleanly without blocking on a prompt.
    """
    try:
        local_ip = _get_adscan_local_resolver_ip()
        if os.geteuid() == 0:
            return _start_unbound_without_systemd()
        if not shutil.which("sudo"):
            return False
        if not shutil.which("unbound"):
            return False
        if _is_unbound_listening_local(resolver_ip=local_ip):
            return True

        # Validate config first (non-fatal if this fails; the daemon start will fail anyway).
        run_command(
            _sudo_prefix_args(non_interactive=True)
            + ["unbound-checkconf", "/etc/unbound/unbound.conf"],
            check=False,
            capture_output=True,
            text=True,
            env=_build_effective_user_env_for_command(
                ["unbound-checkconf", "/etc/unbound/unbound.conf"],
                shell=False,
            ),
        )

        log_dir = os.path.join(ADSCAN_BASE_DIR, "logs")
        log_path = os.path.join(log_dir, "unbound-standalone.log")
        start_cmd = (
            "mkdir -p "
            + shlex.quote(log_dir)
            + " && nohup unbound -d -p -c /etc/unbound/unbound.conf >> "
            + shlex.quote(log_path)
            + " 2>&1 &"
        )
        # Use sudo -n so we never block. If it fails, return False and caller can show guidance.
        run_command(
            _sudo_prefix_args(non_interactive=True) + ["sh", "-c", start_cmd],
            check=False,
            capture_output=True,
            text=True,
            env=_build_effective_user_env_for_command(
                ["sh", "-c", start_cmd], shell=False
            ),
        )

        for _ in range(10):
            if _is_unbound_listening_local():
                return True
            time.sleep(0.2)
        return False
    except Exception:
        return False


def _get_adscan_base_dir() -> str:
    """Return the ADscan base directory for the current session.

    Priority:
      1) Explicit override via env var ``ADSCAN_HOME``.
      2) If running under sudo, prefer the invoking user's home (``SUDO_USER``),
         so running `sudo adscan ...` doesn't move state into `/root`.
      3) Fallback to the current user's home.
    """
    override = os.getenv("ADSCAN_HOME")
    if override:
        return _expand_effective_user_path(override)

    sudo_user = os.environ.get("SUDO_USER")
    if sudo_user:
        try:
            import pwd

            sudo_home = pwd.getpwnam(sudo_user).pw_dir
            return os.path.join(sudo_home, ".adscan")
        except Exception:
            pass

    return os.path.join(_get_effective_user_home(), ".adscan")


def _get_effective_user_home() -> str:
    """Return the home directory that should own ADscan state/config.

    If running under sudo, prefer the invoking user's home so we don't write to /root.
    """
    sudo_user = os.environ.get("SUDO_USER")
    if sudo_user:
        try:
            import pwd

            return pwd.getpwnam(sudo_user).pw_dir
        except Exception:
            pass
    # Fallback to the real user's home directory, even if HOME is polluted
    # (e.g., from sudo -E or legacy shell aliases).
    try:
        import pwd

        return pwd.getpwuid(os.getuid()).pw_dir
    except Exception:
        return os.path.expanduser("~")


def _get_effective_user_name_and_group() -> tuple[str, str]:
    """Return the username and group name that should own ADscan state.

    Preference order:
      1) SUDO_USER (invoking user)
      2) current uid name

    Returns:
        (username, groupname)
    """
    import pwd

    sudo_user = os.environ.get("SUDO_USER")
    if sudo_user:
        try:
            pw = pwd.getpwnam(sudo_user)
            return pw.pw_name, pw.pw_name
        except Exception:
            return sudo_user, sudo_user

    pw = pwd.getpwuid(os.getuid())
    return pw.pw_name, pw.pw_name


def _dir_is_writable(path: str) -> bool:
    """Return True if directory exists and current user can create entries in it."""
    try:
        return os.path.isdir(path) and os.access(path, os.W_OK | os.X_OK)
    except Exception:
        return False


def _ensure_dir_writable(
    path: str,
    *,
    description: str,
    fix: bool,
    recursive: bool = True,
) -> bool:
    """Ensure a directory exists and is writable for the effective user.

    This is primarily used by `adscan check --fix` to repair legacy root-owned
    paths (e.g. when older versions were run as root / via sudo -E alias).

    Args:
        path: Target directory path.
        description: Human-friendly label for messages.
        fix: Whether to attempt repairs (sudo/chown/chmod).
        recursive: Whether to apply repairs recursively.

    Returns:
        True if the directory is writable (or was made writable), False otherwise.
    """
    try:
        os.makedirs(path, exist_ok=True)
    except PermissionError as exc:
        telemetry.capture_exception(exc)
        print_warning(
            f"{description} directory exists but cannot be created/accessed: {path}"
        )

        # Legacy root-owned directories (created by older sudo-based installs) are
        # a common cause. If `--fix` is enabled, attempt to repair via sudo even
        # if we cannot traverse the directory as the current user.
        if fix and os.geteuid() != 0:
            if not _sudo_validate():
                return False
            user, group = _get_effective_user_name_and_group()
            try:
                run_command(
                    ["sudo", "-n", "mkdir", "-p", path],
                    check=False,
                    capture_output=True,
                    timeout=30,
                )
                if recursive:
                    run_command(
                        ["sudo", "-n", "chown", "-R", f"{user}:{group}", path],
                        check=False,
                        capture_output=True,
                        timeout=60,
                    )
                    run_command(
                        ["sudo", "-n", "chmod", "-R", "u+rwX", path],
                        check=False,
                        capture_output=True,
                        timeout=60,
                    )
                else:
                    run_command(
                        ["sudo", "-n", "chown", f"{user}:{group}", path],
                        check=False,
                        capture_output=True,
                        timeout=30,
                    )
                    run_command(
                        ["sudo", "-n", "chmod", "u+rwX", path],
                        check=False,
                        capture_output=True,
                        timeout=30,
                    )
            except Exception as inner_exc:  # pragma: no cover - env dependent
                telemetry.capture_exception(inner_exc)
                print_info_debug(
                    f"[check] Failed to repair {description} dir via sudo after PermissionError: {inner_exc}"
                )
                return False

            # Retry creation/check after sudo repair.
            try:
                os.makedirs(path, exist_ok=True)
            except Exception:
                return _dir_is_writable(path)
            return _dir_is_writable(path)

        return False
    except Exception as exc:
        telemetry.capture_exception(exc)
        print_warning(f"Failed to ensure {description} directory exists: {path}")
        print_info_debug(f"[check] {description} mkdir error: {exc}")
        return False

    if _dir_is_writable(path):
        return True

    print_warning(f"{description} directory is not writable: {path}")
    if not fix:
        return False

    user, group = _get_effective_user_name_and_group()
    chown_args = ["chown"]
    chmod_args = ["chmod"]
    if recursive:
        chown_args.append("-R")
        chmod_args.append("-R")
    chown_args.append(f"{user}:{group}")
    chown_args.append(path)
    chmod_args.extend(["u+rwX", path])

    try:
        if os.geteuid() == 0:
            run_command(chown_args, check=False, capture_output=True, timeout=60)
            run_command(chmod_args, check=False, capture_output=True, timeout=60)
        else:
            if not _sudo_validate():
                return False
            run_command(
                ["sudo", "-n"] + chown_args,
                check=False,
                capture_output=True,
                timeout=60,
            )
            run_command(
                ["sudo", "-n"] + chmod_args,
                check=False,
                capture_output=True,
                timeout=60,
            )
    except Exception as exc:  # pragma: no cover - environment dependent
        telemetry.capture_exception(exc)
        print_info_debug(
            f"[check] Failed to repair permissions for {description} dir {path}: {exc}"
        )
        return False

    if _dir_is_writable(path):
        print_success_verbose(
            f"{description} directory permissions repaired successfully (--fix)."
        )
        return True

    print_warning(
        f"{description} directory is still not writable after repair attempt: {path}"
    )
    return False


def _apply_effective_user_home_to_env(env: dict[str, str]) -> dict[str, str]:
    """Apply effective-user HOME defaults to an env dict for subprocess execution.

    When ADscan runs under sudo, many tools (rustup/go/pyenv/pip caches) default to
    writing into the current process HOME (often ``/root``). For workflows where we
    want to keep tool state under the invoking user, force ``HOME`` to the effective
    user's home directory.

    Args:
        env: Environment dict to mutate.

    Returns:
        The same dict instance for convenience.
    """
    effective_home = _get_effective_user_home()
    env["HOME"] = effective_home

    sudo_user = os.environ.get("SUDO_USER")
    if sudo_user:
        env.setdefault("USER", sudo_user)
        env.setdefault("LOGNAME", sudo_user)

    return env


def _build_effective_user_env_for_command(
    command: str | list[str],
    *,
    shell: bool,
) -> dict[str, str]:
    """Build a subprocess env that avoids /root HOME leakage when using sudo.

    Many third-party tools (docker-compose stacks, rustup, pyenv, etc.) derive
    their config/cache directories from HOME/XDG_* variables. When ADscan runs as
    a non-root user but executes a specific command with sudo, the default sudo
    env reset often switches HOME to /root, causing tools to read/write the wrong
    config paths.

    This helper builds an env that:
      - Uses clean_env when the command would normally need it
      - Forces HOME to the effective user's home
      - Ensures XDG_CONFIG_HOME points to $HOME/.config
      - Ensures ADSCAN_HOME is set for any child processes that rely on it

    Args:
        command: Command string (shell=True) or argv list (shell=False).
        shell: Whether the command will be executed in shell mode.

    Returns:
        Env dict suitable to pass to run_command/subprocess.run.
    """
    needs_clean_env = (
        _command_string_needs_clean_env(command)
        if shell
        else _command_needs_clean_env(
            command if isinstance(command, list) else shlex.split(command)
        )
    )
    env = _get_clean_env_for_compilation() if needs_clean_env else os.environ.copy()
    _apply_effective_user_home_to_env(env)
    env.setdefault("XDG_CONFIG_HOME", os.path.join(env["HOME"], ".config"))
    env.setdefault("ADSCAN_HOME", _get_adscan_base_dir())
    return env


