def _get_nxc_base_dir() -> str:
    """Return the NetExec (nxc) state directory (~/.nxc) for the effective user."""
    return os.path.join(_get_effective_user_home(), ".nxc")


def _get_nxc_modules_dir() -> str:
    """Return the NetExec modules directory (~/.nxc/modules) for the effective user."""
    return os.path.join(_get_nxc_base_dir(), "modules")


def _expand_effective_user_path(path: str) -> str:
    """Expand ~ paths using the effective user's home directory.

    We cannot rely on os.path.expanduser() when running under sudo/root because it
    may resolve ~ to /root. For paths that are meant to live in the invoking user's
    home (like ~/.nxc), resolve ~ manually using `_get_effective_user_home()`.
    """
    expanded = os.path.expandvars(path)
    if expanded.startswith("~/"):
        return os.path.join(_get_effective_user_home(), expanded[2:])
    if expanded == "~":
        return _get_effective_user_home()
    return expanded


ADSCAN_SUDO_ALIAS_MARKER = "# ADscan auto-sudo alias"


def _remove_legacy_adscan_sudo_alias(rcfile: str) -> bool:
    """Remove the legacy ADscan auto-sudo alias from a shell rc file.

    Older versions of ADscan (and its PyPI wrapper) injected:

        # ADscan auto-sudo alias
        alias adscan='sudo -E ...'

    This is now harmful because it forces ADscan to run as root (and preserve
    environment), which can lead to permission issues and state divergence.

    The cleanup is intentionally conservative: it only removes the exact marker
    line plus the following alias line when it matches the previous pattern.

    Args:
        rcfile: Path to the rc file to edit in-place.

    Returns:
        True if the file was modified.
    """
    try:
        if not os.path.exists(rcfile):
            return False

        with open(rcfile, "r", encoding="utf-8") as f:
            lines = f.readlines()

        changed = False
        new_lines: list[str] = []
        idx = 0
        while idx < len(lines):
            line = lines[idx]
            if line.strip() == ADSCAN_SUDO_ALIAS_MARKER.strip():
                next_idx = idx + 1
                if next_idx < len(lines):
                    candidate = lines[next_idx].lstrip()
                    if candidate.startswith(
                        "alias adscan='sudo -E "
                    ) or candidate.startswith('alias adscan="sudo -E '):
                        changed = True
                        idx += 2
                        continue
            new_lines.append(line)
            idx += 1

        if not changed:
            return False

        with open(rcfile, "w", encoding="utf-8") as f:
            f.writelines(new_lines)

        return True
    except Exception as exc:
        telemetry.capture_exception(exc)
        return False


def _cleanup_legacy_adscan_sudo_alias() -> None:
    """Best-effort removal of the legacy auto-sudo alias from user shell configs."""
    try:
        target_user: str | None
        if os.geteuid() == 0 and os.environ.get("SUDO_USER"):
            target_user = os.environ.get("SUDO_USER")
        else:
            target_user = os.environ.get("USER")

        if target_user:
            home = os.path.expanduser(f"~{target_user}")
        else:
            home = os.path.expanduser("~")

        shell = os.environ.get("SHELL", "")
        if "zsh" in shell:
            rcfiles = [os.path.join(home, ".zshrc")]
        else:
            rcfiles = [
                os.path.join(home, ".bash_aliases"),
                os.path.join(home, ".bashrc"),
            ]

        for rcfile in rcfiles:
            if _remove_legacy_adscan_sudo_alias(rcfile):
                marked_rcfile = mark_sensitive(rcfile, "path")
                print_info_debug(
                    f"[DEBUG] Removed legacy ADscan auto-sudo alias from {marked_rcfile}"
                )
    except Exception as exc:
        telemetry.capture_exception(exc)
        print_info_debug("[DEBUG] Failed to cleanup legacy ADscan auto-sudo alias")


def _guard_root_shell_without_user_context(command: str) -> None:
    """Prevent accidental split state between /root and the real user.

    Running ADscan inside a root shell created by `sudo su` / `su -` often loses
    the `SUDO_USER` context, which means ADscan cannot know the real user's home
    directory. In that case it will use `/root/.adscan` by default, which can
    cause confusing permission issues when the user later runs ADscan normally.

    For safety, we warn and require an explicit confirmation before continuing
    for commands that create/modify state.

    Args:
        command: The CLI subcommand (start/install/check/etc.)
    """
    try:
        if os.geteuid() != 0:
            return
        if os.getenv("CI"):
            return
        if os.getenv("SUDO_USER"):
            return
        if os.getenv("ADSCAN_HOME"):
            return
        if command not in ("install", "start", "check"):
            return

        marked_base_dir = mark_sensitive(ADSCAN_BASE_DIR, "path")
        title = "[bold yellow]Root shell detected[/bold yellow]"
        message = (
            "[yellow]ADscan is running as root, but without SUDO_USER/ADSCAN_HOME context.[/yellow]\n\n"
            "This commonly happens when using [bold]sudo su[/bold] or [bold]su -[/bold].\n"
            "In this mode, ADscan will store state under:\n"
            f"  • {marked_base_dir}\n\n"
            "[bold]Recommended:[/bold]\n"
            "  1) Exit the root shell\n"
            "  2) Run ADscan as your normal user\n\n"
            "[bold]Alternative (advanced):[/bold]\n"
            "  Set ADSCAN_HOME explicitly before running ADscan as root, for example:\n"
            "    ADSCAN_HOME=/home/<user>/.adscan adscan install\n"
        )
        print_panel(message, title=title, border_style="yellow")

        proceed = Confirm.ask(
            "Continue anyway (not recommended)?",
            default=False,
        )
        if not proceed:
            print_warning("Aborted to avoid creating state under /root.")
            sys.exit(1)
    except SystemExit:
        raise
    except Exception as exc:
        telemetry.capture_exception(exc)


def _container_runtime_launcher_contract_issues() -> list[str]:
    """Return missing launcher-managed runtime requirements for FULL container mode."""
    issues: list[str] = []
    if not _is_full_adscan_container_runtime():
        return issues

    if str(os.getenv("ADSCAN_OFFICIAL_LAUNCHER") or "").strip() != "1":
        issues.append("official_launcher_marker")

    helper_sock = str(os.getenv("ADSCAN_HOST_HELPER_SOCK") or "").strip()
    if not helper_sock:
        issues.append("host_helper_socket_env")
    elif not os.path.exists(helper_sock):
        issues.append("host_helper_socket_path")

    if not str(os.getenv("ADSCAN_LOCAL_RESOLVER_IP") or "").strip():
        issues.append("local_resolver_ip")

    return issues


def _guard_container_runtime_launcher_contract(command: str | None) -> None:
    """Abort when the FULL runtime was not started through the official launcher."""
    if not _is_full_adscan_container_runtime():
        return
    if command in (None, "version", "host-helper"):
        return

    # Build-time bake escape hatch. ``scripts/bake_cheatsheet.sh`` invokes the
    # cheatsheet renderer inside the PRO image to produce the LITE static
    # asset; that one-shot pipeline has no host helper / resolver / launcher
    # marker — and doesn't need any of them, since it renders to a bind-
    # mounted file and exits. The env var is set ONLY by the bake script,
    # never by users, and the bypass is limited to safe pure-render verbs.
    if str(os.getenv("ADSCAN_BAKE_MODE") or "").strip() == "1" and command in (
        "cheatsheet",
        "demo",
    ):
        return

    issues = _container_runtime_launcher_contract_issues()
    if not issues:
        return

    helper_sock = str(os.getenv("ADSCAN_HOST_HELPER_SOCK") or "").strip()
    runtime_image = str(os.getenv("ADSCAN_RUNTIME_IMAGE") or "adscan runtime").strip()
    marked_helper_sock = mark_sensitive(helper_sock or "<unset>", "path")
    marked_runtime_image = mark_sensitive(runtime_image, "path")

    print_info_debug(
        "[container_guard] Refusing direct in-container launch without official launcher "
        f"(command={command}, issues={issues}, helper_sock={marked_helper_sock})"
    )
    telemetry.capture(
        "container_runtime_launcher_contract_missing",
        {
            "command": str(command or ""),
            "issues": list(issues),
            "has_official_launcher_marker": str(
                str(os.getenv("ADSCAN_OFFICIAL_LAUNCHER") or "").strip() == "1"
            ).lower(),
            "has_host_helper_sock_env": str(bool(helper_sock)).lower(),
            "host_helper_sock_exists": str(
                bool(helper_sock and os.path.exists(helper_sock))
            ).lower(),
            "has_local_resolver_ip": str(
                bool(str(os.getenv("ADSCAN_LOCAL_RESOLVER_IP") or "").strip())
            ).lower(),
        },
    )

    issue_map = {
        "official_launcher_marker": "- Missing official launcher marker inside the runtime.",
        "host_helper_socket_env": "- Missing host-helper socket environment (`ADSCAN_HOST_HELPER_SOCK`).",
        "host_helper_socket_path": "- Host-helper socket path is not mounted or is unavailable.",
        "local_resolver_ip": "- Missing launcher-provided local resolver IP (`ADSCAN_LOCAL_RESOLVER_IP`).",
    }
    detail_lines = [issue_map[issue] for issue in issues if issue in issue_map]

    print_panel(
        "[bold]This ADscan FULL runtime must be launched from the official host launcher.[/bold]\n\n"
        "The current container session is missing launcher-managed runtime wiring, so "
        "ADscan will not run from this shell.\n\n"
        f"Runtime image: {marked_runtime_image}\n"
        f"Host-helper socket: {marked_helper_sock}\n\n"
        "Missing runtime requirements:\n" + "\n".join(detail_lines) + "\n\n"
        "The official launcher sets up the host-helper, loopback DNS context, "
        "workspace/state mounts, and container runtime environment before ADscan starts.",
        title="[bold]🧭 Official Launcher Required[/bold]",
        border_style="yellow",
        padding=(1, 2),
    )
    print_instruction(
        "Install the official launcher on the host with `pipx install adscan`."
    )
    print_instruction("Alternative: `pip install adscan`.")
    print_instruction("Exit the container shell and run `adscan start` from the host.")
    print_instruction(
        "Do not launch ADscan manually from inside the FULL runtime container."
    )
    raise SystemExit(1)


