def _ensure_state_dir_exists() -> Path:
    """Return the persisted ADscan state directory, creating it if needed (best effort)."""
    state_dir = Path(ADSCAN_STATE_DIR)
    try:
        state_dir.mkdir(parents=True, exist_ok=True)
        return state_dir
    except Exception:
        return Path(ADSCAN_BASE_DIR)


def _migrate_state_file(*, legacy_path: Path, new_path: Path) -> None:
    """Move legacy state file to its new location (best effort)."""
    try:
        if new_path.exists() or not legacy_path.exists():
            return
        new_path.parent.mkdir(parents=True, exist_ok=True)
        try:
            legacy_path.replace(new_path)
        except OSError:
            shutil.copy2(legacy_path, new_path)
    except Exception:
        # Non-critical: state is best-effort.
        return


def _migrate_adscan_state_files() -> None:
    """Migrate legacy ADscan state files into the persisted state directory (best effort)."""
    state_dir = _ensure_state_dir_exists()
    _migrate_state_file(
        legacy_path=_BH_CE_CONFIG_LEGACY_PATH, new_path=state_dir / "bh_ce.json"
    )
    _migrate_state_file(
        legacy_path=_BH_MODE_LEGACY_PATH, new_path=state_dir / "bh_mode"
    )
    _migrate_state_file(
        legacy_path=Path(ADSCAN_BASE_DIR) / ".victory_hints_state.json",
        new_path=state_dir / ".victory_hints_state.json",
    )
    _migrate_state_file(
        legacy_path=Path.home() / ".adscan" / "non_whitelisted_labs.json",
        new_path=state_dir / "non_whitelisted_labs.json",
    )
    # First-run marker may have been written under either base dir or workspaces.
    _migrate_state_file(
        legacy_path=Path(ADSCAN_BASE_DIR) / ".first_run_complete",
        new_path=state_dir / ".first_run_complete",
    )
    workspaces_dir = os.getenv("ADSCAN_WORKSPACES_DIR")
    if workspaces_dir:
        _migrate_state_file(
            legacy_path=Path(workspaces_dir) / ".first_run_complete",
            new_path=state_dir / ".first_run_complete",
        )


_migrate_adscan_state_files()

# License defaults
#
# Public releases built from this repository must keep this as "LITE".
# Private customer builds may override this constant at build time to "PRO".
DEFAULT_LICENSE_MODE = "LITE"
ADSCAN_RUNTIME_LICENSE_MODE_ENV = "ADSCAN_RUNTIME_LICENSE_MODE"

# DNS tooling compatibility
#
# Legacy DNS compatibility flags kept in the runtime config for backward-compatible
# service construction. DNS queries now use dnspython directly with EDNS disabled.
_DIG_COMPAT_FLAGS = "+noedns +nocookie"


def _resolve_license_mode(*, requested_pro: bool) -> str:
    """Resolve license mode at runtime (no persistence).

    Args:
        requested_pro: Ignored in public/LITE builds. Kept for compatibility.

    Returns:
        Default runtime license mode for this build.
    """
    _ = requested_pro
    env_license_mode = str(
        os.getenv(ADSCAN_RUNTIME_LICENSE_MODE_ENV, DEFAULT_LICENSE_MODE)
    ).strip()
    normalized_license_mode = env_license_mode.upper() or DEFAULT_LICENSE_MODE
    if normalized_license_mode in {"LITE", "PRO"}:
        return normalized_license_mode
    return DEFAULT_LICENSE_MODE


def _format_runtime_version_tag(license_mode: str) -> str:
    """Return a runtime version tag including the license mode suffix.

    Args:
        license_mode: "LITE" or "PRO".

    Returns:
        Version tag like "3.1.2-lite" or "3.1.2-pro".
    """
    return get_version_tag(license_mode)


# --- Helper functions for report generation and bundled resources ---
def _get_template_path():
    """Get the path to the Word template file.

    Handles both PyInstaller bundle (sys._MEIPASS) and development mode.
    The template is bundled with PyInstaller using --add-data.

    Search order:
    1. PyInstaller bundle (_MEIPASS)
    2. templates/ directory (development mode)
    3. Project root (legacy location)

    Returns:
        str: Path to template.docx, or None if not found
    """
    template_name = "template.docx"

    # Check if running in PyInstaller bundle
    if getattr(sys, "frozen", False) and hasattr(sys, "_MEIPASS"):
        # Template is bundled in _MEIPASS directory
        meipass = getattr(sys, "_MEIPASS", None)  # pylint: disable=no-member
        if meipass:
            template_path = os.path.join(meipass, template_name)
            if os.path.exists(template_path):
                return template_path

    # Development mode: check in templates/ directory first
    current_dir = os.path.dirname(os.path.abspath(__file__))
    template_path = os.path.join(current_dir, "templates", template_name)
    if os.path.exists(template_path):
        return template_path

    # Fallback: check in project root (legacy location)
    template_path = os.path.join(current_dir, template_name)
    if os.path.exists(template_path):
        return template_path

    # If not found, return None (will use default styles)
    return None


