def _setup_external_tool(
    tool_name: str,
    config: Dict[str, Any],
    *,
    github_dns_ok: bool,
    force_reinstall: bool = False,
) -> bool:
    """Install/update an external non-Python tool (git/curl) under `TOOLS_INSTALL_DIR`.

    Some tools also ship a `requirements.txt` and are installed into an isolated venv
    under `TOOL_VENVS_BASE_DIR/<tool>/venv`.

    Args:
        tool_name: Tool key (must exist in `EXTERNAL_TOOLS_CONFIG`).
        config: Tool configuration entry.
        github_dns_ok: Whether github.com resolves (used to skip GitHub-dependent tools).
        force_reinstall: When True, remove any existing tool directory before installing.

    Returns:
        True on success, False otherwise.
    """
    tool_path = os.path.join(TOOLS_INSTALL_DIR, tool_name)
    tool_type = config.get("type")
    python_version_for_tool_venvs = "3.12.3"
    primary_url = (config.get("url") or "").lower()
    if not github_dns_ok and any(
        host in primary_url for host in ("github.com/", "raw.githubusercontent.com/")
    ):
        print_warning(
            f"Skipping {tool_name}: GitHub is not resolvable from this host right now."
        )
        return False

    try:
        if force_reinstall and os.path.exists(tool_path):
            if os.path.isdir(tool_path):
                shutil.rmtree(tool_path)
            else:
                os.remove(tool_path)

        if tool_type == "git":
            if not os.path.exists(tool_path):
                if VERBOSE_MODE or DEBUG_MODE:
                    print_command(
                        f"git clone {config['url']} {tool_path}",
                        show_copy_hint=False,
                    )
                run_command(["git", "clone", config["url"], tool_path])
            else:
                print_info(f"{tool_name} already cloned. Attempting to update...")
                if VERBOSE_MODE or DEBUG_MODE:
                    print_command(f"cd {tool_path} && git pull", show_copy_hint=False)
                run_command(["git", "pull"], cwd=tool_path, check=False)

        elif tool_type == "curl_script":
            os.makedirs(tool_path, exist_ok=True)
            script_dest = os.path.join(tool_path, config["script_name"])
            run_command(["curl", "-L", "-o", script_dest, config["url"]])
            run_command(["chmod", "+x", script_dest])
            if config.get("req_url"):
                req_dest = os.path.join(tool_path, config["req_file"])
                run_command(["curl", "-L", "-o", req_dest, config["req_url"]])

        elif tool_type == "curl_binary":
            os.makedirs(tool_path, exist_ok=True)
            bin_dest = os.path.join(tool_path, config["name"])
            run_command(["curl", "-L", "-o", bin_dest, config["url"]])
            run_command(["chmod", "+x", bin_dest])
            os.makedirs(os.path.join(VENV_PATH, "bin"), exist_ok=True)
            venv_bin_link = os.path.join(VENV_PATH, "bin", config["name"])
            if os.path.exists(venv_bin_link):
                os.remove(venv_bin_link)
            os.symlink(bin_dest, venv_bin_link)
            print_info(f"Symlinked {config['name']} to venv/bin")

        elif tool_type == "multi_curl":
            os.makedirs(tool_path, exist_ok=True)
            for file_info in config["files"]:
                file_dest = os.path.join(tool_path, file_info["name"])
                run_command(["curl", "-L", "-o", file_dest, file_info["url"]])
                run_command(["chmod", "+x", file_dest])

        elif tool_type == "curl_nxc_module":
            nxc_modules_path = _get_nxc_modules_dir()
            os.makedirs(nxc_modules_path, exist_ok=True)
            dest_file_path = os.path.join(nxc_modules_path, config["script_name"])
            if not os.path.exists(dest_file_path) or force_reinstall:
                print_info(
                    f"Downloading {config['script_name']} to {nxc_modules_path}..."
                )
                run_command(["curl", "-L", config["url"], "-o", dest_file_path])
                print_success(f"{config['script_name']} downloaded successfully.")
            else:
                print_info(
                    f"{config['script_name']} already exists in {nxc_modules_path}, skipping."
                )

        elif tool_type == "curl_zip_extract_linux_app":
            os.makedirs(tool_path, exist_ok=True)
            zip_download_path = os.path.join(tool_path, config["zip_filename"])
            print_info(f"Downloading {config['zip_filename']} for {tool_name}...")
            run_command(["curl", "-L", "-o", zip_download_path, config["url"]])
            print_info(f"Extracting {config['zip_filename']} into {tool_path}...")
            run_command(["unzip", "-o", zip_download_path, "-d", tool_path])
            print_info(f"Removing downloaded zip file {zip_download_path}...")
            run_command(["rm", zip_download_path])
            absolute_executable_path = os.path.join(
                tool_path, config["executable_path_in_zip"]
            )
            if os.path.exists(absolute_executable_path):
                print_info(f"Making {absolute_executable_path} executable...")
                run_command(["chmod", "+x", absolute_executable_path])
                if config.get("symlink_name"):
                    os.makedirs(os.path.join(VENV_PATH, "bin"), exist_ok=True)
                    venv_bin_link = os.path.join(
                        VENV_PATH, "bin", config["symlink_name"]
                    )
                    if os.path.exists(venv_bin_link):
                        print_info(f"Removing existing symlink at {venv_bin_link}...")
                        os.remove(venv_bin_link)
                    print_info(
                        f"Creating symlink from {absolute_executable_path} to {venv_bin_link}..."
                    )
                    os.symlink(absolute_executable_path, venv_bin_link)
                    print_info(
                        f"Symlinked {tool_name} as {config['symlink_name']} to venv/bin"
                    )
            else:
                print_warning(
                    f"Expected executable not found after extraction: {absolute_executable_path}"
                )

        elif tool_type == "git_make":
            if not os.path.exists(tool_path):
                if VERBOSE_MODE or DEBUG_MODE:
                    print_command(
                        f"git clone {config['url']} {tool_path}",
                        show_copy_hint=False,
                    )
                run_command(["git", "clone", config["url"], tool_path])
            else:
                print_info(f"{tool_name} already cloned. Attempting to update...")
                if VERBOSE_MODE or DEBUG_MODE:
                    print_command(f"cd {tool_path} && git pull", show_copy_hint=False)
                run_command(["git", "pull"], cwd=tool_path, check=False)

            build_command = config.get("build_command") or ["make"]
            if isinstance(build_command, str):
                build_command = build_command.split()
            run_command(build_command, cwd=tool_path)

            binary_rel_path = config.get("binary_rel_path") or config.get("name")
            binary_path = os.path.join(tool_path, binary_rel_path)
            if not os.path.exists(binary_path):
                print_warning(
                    f"Expected binary for {tool_name} not found at {binary_path}."
                )
                return False
            run_command(["chmod", "+x", binary_path])

            symlink_name = config.get("symlink_name") or config.get("name") or tool_name
            if symlink_name:
                os.makedirs(os.path.join(ADSCAN_BASE_DIR, "bin"), exist_ok=True)
                bin_link = os.path.join(ADSCAN_BASE_DIR, "bin", symlink_name)
                if os.path.exists(bin_link):
                    os.remove(bin_link)
                os.symlink(binary_path, bin_link)
                print_info(f"Symlinked {symlink_name} to {bin_link}")

                if config.get("check_venv_link", False):
                    os.makedirs(os.path.join(VENV_PATH, "bin"), exist_ok=True)
                    venv_bin_link = os.path.join(VENV_PATH, "bin", symlink_name)
                    if os.path.exists(venv_bin_link):
                        os.remove(venv_bin_link)
                    os.symlink(binary_path, venv_bin_link)
                    print_info(f"Symlinked {symlink_name} to venv/bin")

        else:
            print_warning(f"Unknown external tool type '{tool_type}' for {tool_name}.")
            return False

        req_file_path = config.get("req_file")
        if req_file_path and os.path.exists(os.path.join(tool_path, req_file_path)):
            print_info(
                f"Setting up isolated venv for {tool_name} and installing requirements..."
            )
            tool_specific_venv_base = os.path.join(TOOL_VENVS_BASE_DIR, tool_name)
            tool_specific_venv_path = os.path.join(tool_specific_venv_base, "venv")
            tool_specific_python = os.path.join(
                tool_specific_venv_path, "bin", "python"
            )

            if force_reinstall and os.path.exists(tool_specific_venv_base):
                shutil.rmtree(tool_specific_venv_base, ignore_errors=True)

            if not os.path.exists(
                os.path.join(tool_specific_venv_path, "bin", "activate")
            ):
                print_info(
                    f"Creating isolated virtual environment for {tool_name} at: {tool_specific_venv_path}"
                )
                pyenv_available, _, pyenv_cmd_list = _is_pyenv_available(os.environ)
                if not pyenv_available or not pyenv_cmd_list:
                    print_error(f"pyenv is not available for {tool_name} venv creation")
                    return False

                pyenv_root_result = run_command(
                    pyenv_cmd_list + ["root"], capture_output=True, check=True
                )
                pyenv_root = pyenv_root_result.stdout.strip()
                pyenv_python = os.path.join(
                    pyenv_root,
                    "versions",
                    python_version_for_tool_venvs,
                    "bin",
                    "python",
                )
                if not os.path.exists(pyenv_python):
                    print_error(f"Python executable not found at: {pyenv_python}")
                    return False

                clean_env = _get_clean_env_for_compilation()
                venv_args = [pyenv_python, "-m", "venv"]
                if tool_name == "LSA-Reaper":
                    # LSA-Reaper imports python-apt and also shells out to
                    # ``sudo python3 -m pypykatz`` internally. A normal isolated
                    # venv cannot see distro-provided python3-apt, so it must be
                    # created with system site-packages enabled.
                    venv_args.append("--system-site-packages")
                venv_args.append(tool_specific_venv_path)
                result = run_command(
                    venv_args,
                    check=False,
                    env=clean_env,
                )
                if result.returncode != 0:
                    print_warning(
                        f"Venv creation failed for {tool_name}, trying fallback method..."
                    )
                    try:
                        if os.path.exists(tool_specific_venv_path):
                            shutil.rmtree(tool_specific_venv_path)
                        run_command(
                            [
                                pyenv_python,
                                "-m",
                                "venv",
                                "--without-pip",
                                tool_specific_venv_path,
                            ],
                            check=True,
                            env=clean_env,
                        )
                        venv_python = os.path.join(
                            tool_specific_venv_path, "bin", "python"
                        )
                        ensurepip_ok = False
                        try:
                            run_command(
                                [venv_python, "-m", "ensurepip", "--upgrade"],
                                check=True,
                                capture_output=True,
                                timeout=60,
                            )
                            ensurepip_ok = True
                        except Exception:
                            ensurepip_ok = False

                        if not ensurepip_ok:
                            # Final fallback: install pip manually via get-pip.py (network-dependent).
                            get_pip_url = "https://bootstrap.pypa.io/get-pip.py"
                            get_pip_path = os.path.join(ADSCAN_BASE_DIR, "get-pip.py")
                            try:
                                _download_file_with_fallbacks(
                                    get_pip_url, get_pip_path, timeout=30
                                )
                                pip_clean_env = _get_clean_env_for_compilation()
                                venv_bin = os.path.dirname(venv_python)
                                venv_dir = os.path.dirname(venv_bin)
                                pip_clean_env["VIRTUAL_ENV"] = venv_dir
                                pip_clean_env["PATH"] = (
                                    f"{venv_bin}:{pip_clean_env.get('PATH', '')}"
                                )
                                pip_clean_env.pop("PYTHONHOME", None)
                                pip_clean_env.pop("PYTHONPATH", None)
                                run_command(
                                    [venv_python, get_pip_path],
                                    check=True,
                                    env=pip_clean_env,
                                )
                            finally:
                                try:
                                    if os.path.exists(get_pip_path):
                                        os.remove(get_pip_path)
                                except Exception:
                                    pass
                    except Exception as venv_fallback_e:
                        telemetry.capture_exception(venv_fallback_e)
                        print_error(
                            f"Failed to create venv for {tool_name} even with fallback: {venv_fallback_e}"
                        )
                        return False
            else:
                print_info(
                    f"Isolated virtual environment for {tool_name} already exists."
                )

            print_info(
                f"Installing requirements for {tool_name} from {req_file_path}..."
            )
            pip_env = os.environ.copy()
            pip_env["VIRTUAL_ENV"] = tool_specific_venv_path
            tool_venv_bin = os.path.dirname(tool_specific_python)
            pip_env["PATH"] = f"{tool_venv_bin}:{pip_env.get('PATH', '')}"
            pip_env.pop("LD_LIBRARY_PATH", None)
            pip_env.pop("PYTHONHOME", None)
            pip_env.pop("PYTHONPATH", None)
            _configure_ssl_certificates(pip_env)
            pip_install_command = [
                tool_specific_python,
                "-m",
                "pip",
                "install",
                "-r",
                os.path.join(tool_path, req_file_path),
            ]
            if tool_name == "LSA-Reaper":
                # LSA-Reaper depends on Impacket explicitly at runtime even
                # though its upstream requirements.txt omits it.
                pip_install_command.append("impacket")
            run_command(
                pip_install_command,
                env=pip_env,
                use_clean_env=False,
            )
            print_success(f"Requirements installed for {tool_name} in isolated venv.")

        print_success(f"{tool_name} setup complete.")
        return True
    except Exception as exc:  # pragma: no cover - best-effort install
        telemetry.capture_exception(exc)
        print_error(f"Failed to set up {tool_name}.")
        print_exception(show_locals=False, exception=exc)
        return False


def _ensure_wordlist_installed(
    wl_name: str, config: Dict[str, Any], *, fix: bool
) -> bool:
    """Ensure a configured wordlist exists under `WORDLISTS_INSTALL_DIR`."""
    final_wl_name = config["dest"].replace(".xz", "").replace(".7z", "")
    final_wl_path = os.path.join(WORDLISTS_INSTALL_DIR, final_wl_name)
    if os.path.exists(final_wl_path):
        return True

    if wl_name == "rockyou.txt":
        system_txt = "/usr/share/wordlists/rockyou.txt"
        system_gz = "/usr/share/wordlists/rockyou.txt.gz"
        try:
            if os.path.exists(system_txt):
                os.makedirs(WORDLISTS_INSTALL_DIR, exist_ok=True)
                shutil.copy2(system_txt, final_wl_path)
                return os.path.exists(final_wl_path)
            if os.path.exists(system_gz) and fix:
                import gzip

                os.makedirs(WORDLISTS_INSTALL_DIR, exist_ok=True)
                with (
                    gzip.open(system_gz, "rb") as src,
                    open(final_wl_path, "wb") as dst,
                ):
                    shutil.copyfileobj(src, dst)
                return os.path.exists(final_wl_path)
        except Exception:
            return False
        return False

    if not fix:
        return False

    try:
        os.makedirs(WORDLISTS_INSTALL_DIR, exist_ok=True)
        dl_wl_path = os.path.join(WORDLISTS_INSTALL_DIR, config["dest"])
        clean_env = _get_clean_env_for_compilation()
        run_command(["curl", "-L", "-o", dl_wl_path, config["url"]], env=clean_env)
        if config.get("extract_xz"):
            run_command(["xz", "-d", dl_wl_path], env=clean_env)
        if config.get("extract_7z"):
            run_command(
                ["7z", "x", "-y", f"-o{WORDLISTS_INSTALL_DIR}", dl_wl_path],
                env=clean_env,
            )
            run_command(["rm", "-f", dl_wl_path], check=False, env=clean_env)
        return os.path.exists(final_wl_path)
    except Exception as exc:  # pragma: no cover - network/environment dependent
        telemetry.capture_exception(exc)
        return False


# Global core requirements configuration - for Python packages
CORE_REQUIREMENTS = [
    # Kept intentionally minimal: all other dependencies are embedded in the
    # PyInstaller binary or installed in isolated tool environments.
]

VersionCheckStatus = Literal["ok", "warning", "error"]


def _extract_name_from_vcs_spec(spec: str) -> str:
    """Derive a distribution-like name from a VCS requirement spec."""
    egg_match = re.search(r"#egg=([A-Za-z0-9_.-]+)", spec)
    if egg_match:
        return egg_match.group(1)

    tail = spec.rsplit("/", maxsplit=1)[-1]
    if "@" in tail:
        tail = tail.split("@", 1)[0]
    if tail.endswith(".git"):
        tail = tail[:-4]
    return tail or spec


def _parse_requirement_spec(spec: str) -> Dict[str, Any]:
    """Parse a pip-style requirement specification string into metadata."""
    info: Dict[str, Any] = {
        "original": spec,
        "package_name": spec,
        "specifier": None,
        "is_vcs": False,
        "vcs_reference": None,
        "vcs_backend": None,
        "vcs_url": None,
    }
    if spec.startswith(("git+", "hg+", "svn+", "bzr+")):
        info["is_vcs"] = True
        info["package_name"] = _extract_name_from_vcs_spec(spec)
        info["vcs_url"] = spec
        backend_end = spec.split("+", 1)[0]
        info["vcs_backend"] = backend_end
        if "@" in spec:
            _, remainder = spec.split("@", 1)
            reference_part = remainder.split("#", 1)[0]
            info["vcs_reference"] = reference_part or None
        return info
    try:
        parsed_req = Requirement(spec)
        info["package_name"] = parsed_req.name
        info["specifier"] = parsed_req.specifier if parsed_req.specifier else None
    except InvalidRequirement:
        pass
    return info


def _get_python_package_version(
    python_executable: str,
    package_name: str,
    env: Optional[Dict[str, str]] = None,
) -> Optional[str]:
    """Return the installed version of a package via the given Python executable."""
    package_literal = json.dumps(package_name)
    script = (
        "import sys\n"
        "try:\n"
        "    from importlib import metadata as importlib_metadata\n"
        "except ImportError:\n"
        "    import importlib_metadata\n"
        "try:\n"
        f"    print(importlib_metadata.version({package_literal}))\n"
        "except Exception:\n"
        "    sys.exit(1)\n"
    )
    try:
        result = run_command(
            [python_executable, "-c", script],
            capture_output=True,
            check=False,
            env=env,
        )
    except FileNotFoundError as exc:
        telemetry.capture_exception(exc)
        print_warning(
            f"Python executable '{python_executable}' not found when checking version for {package_name}."
        )
        return None

    if result and result.returncode == 0:
        output = (result.stdout or "").strip()
        if output:
            return output.splitlines()[-1].strip()
    return None


def _get_latest_pypi_version(package_name: str, timeout: int = 5) -> Optional[str]:
    """Return the latest published PyPI version for the provided package."""
    url = f"https://pypi.org/pypi/{package_name}/json"
    try:
        response = requests.get(url, timeout=timeout)
    except requests.RequestException as exc:
        telemetry.capture_exception(exc)
        print_warning(f"Failed to query PyPI for {package_name}: {exc}")
        return None

    if response.status_code != 200:
        print_warning(
            f"PyPI responded with HTTP {response.status_code} when checking {package_name}"
        )
        return None

    try:
        payload = response.json()
    except ValueError as exc:
        telemetry.capture_exception(exc)
        print_warning(f"PyPI response for {package_name} is not valid JSON: {exc}")
        return None

    return payload.get("info", {}).get("version")


def _get_noninteractive_apt_env(
    base_env: Optional[Dict[str, str]] = None,
) -> Dict[str, str]:
    """Return an environment suitable for non-interactive apt/dpkg runs.

    This prevents CI hangs caused by package postinst prompts and tools like
    apt-listchanges/needrestart (common when libc/locales get upgraded).

    Args:
        base_env: Base environment (typically `_get_clean_env_for_compilation()`).

    Returns:
        A copy of the environment with safe defaults for non-interactive apt.
    """
    env = dict(base_env or {})
    env.setdefault("DEBIAN_FRONTEND", "noninteractive")
    env.setdefault("DEBIAN_PRIORITY", "critical")
    env.setdefault("APT_LISTCHANGES_FRONTEND", "none")
    # needrestart can prompt in postinst; force automatic behavior.
    env.setdefault("NEEDRESTART_MODE", "a")
    return env


def _get_installed_vcs_reference(
    python_executable: str,
    package_name: str,
    env: Optional[Dict[str, str]] = None,
) -> Optional[Dict[str, Optional[str]]]:
    """Return VCS metadata (url, commit) for a package installed via pip."""
    script = (
        "import json\n"
        "import sys\n"
        "from importlib import metadata as importlib_metadata\n"
        "try:\n"
        "    dist = importlib_metadata.distribution(sys.argv[1])\n"
        "except importlib_metadata.PackageNotFoundError:\n"
        "    sys.exit(3)\n"
        "try:\n"
        "    text = dist.read_text('direct_url.json')\n"
        "except FileNotFoundError:\n"
        "    text = None\n"
        "if not text:\n"
        "    sys.exit(4)\n"
        "try:\n"
        "    data = json.loads(text)\n"
        "except Exception:\n"
        "    sys.exit(5)\n"
        "vcs_info = data.get('vcs_info') or {}\n"
        "out = {\n"
        "    'url': data.get('url'),\n"
        "    'commit_id': vcs_info.get('commit_id'),\n"
        "    'requested_revision': vcs_info.get('requested_revision'),\n"
        "    'vcs': vcs_info.get('vcs'),\n"
        "}\n"
        "print(json.dumps(out))\n"
    )
    result = run_command(
        [python_executable, "-c", script, package_name],
        capture_output=True,
        check=False,
        env=env,
    )
    if result.returncode != 0:
        return None
    try:
        metadata_obj = json.loads(result.stdout.strip())
    except json.JSONDecodeError:
        return None
    return metadata_obj


def _normalize_vcs_repo_url(vcs_spec: str) -> Optional[str]:
    """Return the repository URL portion of a pip VCS spec.

    Example:
        git+https://github.com/ADScanPro/MANSPIDER@cedb138 -> https://github.com/ADScanPro/MANSPIDER

    Args:
        vcs_spec: VCS requirement string from PipToolsConfig.

    Returns:
        Normalized repo URL without git+ prefix, revision, or fragments.
    """
    if not vcs_spec:
        return None
    if not vcs_spec.startswith(("git+", "hg+", "svn+", "bzr+")):
        return None
    _, remainder = vcs_spec.split("+", 1)
    if "@" in remainder:
        remainder = remainder.split("@", 1)[0]
    if "#" in remainder:
        remainder = remainder.split("#", 1)[0]
    return remainder.strip() or None


def _get_installed_vcs_reference_by_url(
    python_executable: str,
    repo_url: str,
    env: Optional[Dict[str, str]] = None,
) -> Optional[Dict[str, Optional[str]]]:
    """Locate a VCS-installed distribution by matching its PEP 610 URL.

    Some projects (e.g., MANSPIDER) install with a distribution name that does
    not match the GitHub repo folder name, so looking up the distribution by
    package name can fail. This helper scans installed distributions and finds
    the one whose ``direct_url.json`` matches the expected repo URL.
    """
    script = (
        "import json\n"
        "import sys\n"
        "from importlib import metadata as importlib_metadata\n"
        "expected = sys.argv[1].strip().strip('\"').strip(\"'\").rstrip('/')\n"
        "def norm(url: str | None) -> str:\n"
        "    if not url:\n"
        "        return ''\n"
        "    url = url.rstrip('/')\n"
        "    if url.endswith('.git'):\n"
        "        url = url[:-4]\n"
        "    return url\n"
        "expected_norm = norm(expected)\n"
        "for dist in importlib_metadata.distributions():\n"
        "    try:\n"
        "        text = dist.read_text('direct_url.json')\n"
        "    except FileNotFoundError:\n"
        "        continue\n"
        "    if not text:\n"
        "        continue\n"
        "    try:\n"
        "        data = json.loads(text)\n"
        "    except Exception:\n"
        "        continue\n"
        "    url = data.get('url')\n"
        "    if norm(url) != expected_norm:\n"
        "        continue\n"
        "    vcs_info = data.get('vcs_info') or {}\n"
        "    out = {\n"
        "        'name': dist.metadata.get('Name'),\n"
        "        'url': url,\n"
        "        'commit_id': vcs_info.get('commit_id'),\n"
        "        'requested_revision': vcs_info.get('requested_revision'),\n"
        "        'vcs': vcs_info.get('vcs'),\n"
        "    }\n"
        "    print(json.dumps(out))\n"
        "    sys.exit(0)\n"
        "sys.exit(4)\n"
    )
    result = run_command(
        [python_executable, "-c", script, repo_url],
        capture_output=True,
        check=False,
        env=env,
    )
    if result.returncode != 0:
        return None
    try:
        metadata_obj = json.loads(result.stdout.strip())
    except json.JSONDecodeError:
        return None
    return metadata_obj


def _vcs_reference_matches(installed: Optional[str], expected: Optional[str]) -> bool:
    """Return True if installed/expected VCS references refer to same commit."""
    if not installed or not expected:
        return False
    installed = installed.strip()
    expected = expected.strip()
    return installed.startswith(expected) or expected.startswith(installed)


def _assess_version_compliance(
    package_name: str,
    installed_version: Optional[str],
    *,
    specifier: Optional[SpecifierSet],
    enforce_latest: bool,
) -> Tuple[VersionCheckStatus, str]:
    """Compare installed package version against requirement spec."""
    if not installed_version:
        return "error", f"Could not determine installed version for {package_name}."

    if specifier:
        if specifier.contains(installed_version, prereleases=True):
            return (
                "ok",
                f"{package_name} {installed_version} satisfies requirement '{specifier}'.",
            )
        return (
            "error",
            f"{package_name} {installed_version} does not satisfy required specifier '{specifier}'.",
        )

    if enforce_latest:
        latest_version = _get_latest_pypi_version(package_name)
        if not latest_version:
            return (
                "warning",
                f"Could not determine latest PyPI version for {package_name}; skipping freshness check.",
            )
        try:
            installed_parsed = version.parse(installed_version)
            latest_parsed = version.parse(latest_version)
        except Exception as exc:
            telemetry.capture_exception(exc)
            return (
                "warning",
                f"Failed to compare versions for {package_name}: {exc}",
            )

        if installed_parsed > latest_parsed:
            return (
                "ok",
                f"{package_name} {installed_version} is newer than the current PyPI release ({latest_version}).",
            )
        if installed_parsed == latest_parsed:
            return ("ok", f"{package_name} is up-to-date ({installed_version}).")
        return (
            "error",
            f"{package_name} {installed_version} is outdated (latest {latest_version}).",
        )

    return ("ok", f"{package_name} {installed_version} is installed.")


