# --- Rich Console Initialization ---
# Primary console for user-facing output (no recording needed here).
console = _build_rich_console(theme=ADSCAN_THEME, strip_markers=True)

# Dedicated telemetry console that records everything rendered via the Rich
# helpers and logging. This console is never shown directly to the user; we
# direct its output to an in-memory buffer so nothing appears in the user's
# terminal or on disk. The recording is later sanitized and uploaded.
# CRITICAL: Preserve existing TELEMETRY_CONSOLE buffer when module re-executes (e.g., PyInstaller).
# When the module re-executes, we need to preserve the buffer with all previous messages.
# We check if rich_output already has a telemetry console set, and if so, reuse it.
# Otherwise, create a new one.
try:
    from adscan_internal.rich_output import _telemetry_console

    if _telemetry_console is not None and hasattr(_telemetry_console, "file"):
        # Module re-executed - reuse existing console to preserve buffer
        TELEMETRY_CONSOLE = _telemetry_console
        _telemetry_buffer = _telemetry_console.file
    else:
        # First execution or console not set yet - create new console
        _telemetry_buffer = StringIO()
        TELEMETRY_CONSOLE = _build_rich_console(
            theme=ADSCAN_THEME, record=True, file=_telemetry_buffer
        )
except (ImportError, AttributeError):
    # rich_output not available or _telemetry_console not accessible - create new
    _telemetry_buffer = StringIO()
    TELEMETRY_CONSOLE = _build_rich_console(
        theme=ADSCAN_THEME, record=True, file=_telemetry_buffer
    )

