# --- Custom Lexer and Completers for prompt-toolkit ---


class DomainCompleter(Completer):
    def __init__(self, shell_instance):
        self.shell_instance = shell_instance

    def get_completions(self, document, complete_event):
        word_before_cursor = document.get_word_before_cursor(WORD=True)

        available_domains = []
        # Safely access self.domains, ensuring it exists and is a list
        if hasattr(self.shell_instance, "domains") and isinstance(
            self.shell_instance.domains, list
        ):
            available_domains = self.shell_instance.domains
        else:
            # Optionally, log or handle the case where self.domains is not as expected
            # For now, just proceed with an empty list
            pass

        for domain_name in available_domains:
            if isinstance(domain_name, str) and domain_name.startswith(
                word_before_cursor
            ):
                yield Completion(domain_name, start_position=-len(word_before_cursor))


class SimpleCommandLexer(Lexer):
    def __init__(self, known_commands):
        self.known_commands = set(known_commands)

    def lex_document(self, document):
        lines = document.lines

        # This lexer is simple and works on a line-by-line basis.
        # For a single-line input typical in CLIs, line_number will be 0.
        def get_line(line_number):
            line_text = lines[line_number]
            if not line_text.strip():  # Empty line
                return []

            parts = line_text.split(" ", 1)
            command_candidate = parts[0]

            if command_candidate in self.known_commands:
                if len(parts) > 1:
                    # Command and arguments
                    return [
                        ("class:command", command_candidate),
                        ("class:default", " "),  # The space separator
                        ("class:argument", parts[1]),  # Rest of the line as arguments
                    ]
                # Command only
                return [("class:command", command_candidate)]
            # Not a known command, or just part of typing
            # Could be an unknown command, or the start of a command
            return [("class:default", line_text)]

        return get_line


# --- Custom Completers for prompt-toolkit ---
class InterfaceCompleter(Completer):
    def __init__(self, shell_instance):
        self.shell_instance = shell_instance

    def get_completions(self, document, complete_event):
        interfaces = self.shell_instance._get_available_interfaces()
        word_before_cursor = document.get_word_before_cursor(WORD=True)
        for iface_name in interfaces:
            if iface_name.startswith(word_before_cursor):
                yield Completion(
                    iface_name,
                    start_position=-len(word_before_cursor),
                    display=iface_name,
                    display_meta="Network Interface",
                )


class CredentialCompleter(Completer):
    """Intelligent credential autocomplete for compromised users.

    Provides context-aware suggestions for usernames from compromised credentials,
    showing credential type (password/hash) and making CTF-style workflows faster.
    """

    def __init__(self, shell_instance):
        self.shell_instance = shell_instance

    def _extract_domain_from_command(self, command_text: str) -> str | None:
        """Extract domain from command line.

        Supports patterns:
        - spray example.local ...
        - secretsdump example.local -u ...
        - dcsync example.local -u ...
        """
        parts = command_text.strip().split()
        if len(parts) < 2:
            return None

        # Domain is typically the first argument after command
        potential_domain = parts[1]

        # Check if it looks like a domain (contains dot or is in known domains)
        if "." in potential_domain or potential_domain in self.shell_instance.domains:
            return potential_domain

        # Fallback: check if current domain is set
        if hasattr(self.shell_instance, "domain") and self.shell_instance.domain:
            return self.shell_instance.domain

        return None

    def _is_hash(self, credential: str) -> bool:
        """Check if credential is a hash (NTLM format)."""
        from adscan_internal.cli.creds import is_hash

        if not credential:
            return False
        return is_hash(credential)

    def _should_suggest_credentials(self, command_text: str) -> bool:
        """Check if cursor position suggests credential completion.

        Returns True if:
        - After -u or --username flag
        - In commands that typically use credentials
        """
        # Check if we're after a username flag
        username_flags = ["-u ", "--username ", "-U ", "--user ", "-p ", "--password "]
        for flag in username_flags:
            if flag in command_text:
                # Check if cursor is after the flag
                text_before_cursor = (
                    command_text[: command_text.rfind(" ") + 1]
                    if " " in command_text
                    else command_text
                )
                if any(flag in text_before_cursor for flag in username_flags):
                    return True

        # Commands that implicitly use credentials in interactive menus
        # For these, suggest credentials as subsequent arguments (rare, most use flags)
        # Spraying is handled by interactive menu, so autocompletion is less relevant
        # But we keep common ones that might accept username directly
        cred_commands = ["kerberoast", "asreproast"]
        parts = command_text.strip().split()
        if parts and parts[0] in cred_commands:
            # If domain is already specified, suggest usernames
            if len(parts) >= 2:
                return True

        return False

    def get_completions(self, document, complete_event):
        """Generate completions for compromised usernames."""
        word_before_cursor = document.get_word_before_cursor(WORD=True)
        command_text = document.text

        # Only suggest if context is appropriate
        if not self._should_suggest_credentials(command_text):
            return

        # Extract domain from command
        domain = self._extract_domain_from_command(command_text)
        if not domain:
            return

        # Get credentials for this domain
        domain_data = self.shell_instance.domains_data.get(domain, {})
        credentials = domain_data.get("credentials", {})

        if not credentials:
            return

        # Generate completions for each user
        for username, cred_value in credentials.items():
            if not isinstance(username, str):
                continue

            # Filter by what user is typing
            if word_before_cursor and not username.startswith(
                word_before_cursor.lower()
            ):
                continue

            # Determine credential type
            is_hash = self._is_hash(cred_value)
            cred_type = "🔑 Hash" if is_hash else "🔐 Password"

            # Create preview of credential (truncated for security)
            if is_hash:
                cred_preview = f"{cred_value[:8]}...{cred_value[-4:]}"
            else:
                cred_preview = f"{cred_value[:3]}{'*' * min(len(cred_value) - 3, 8)}"

            yield Completion(
                text=username,
                start_position=-len(word_before_cursor),
                display=username,
                display_meta=f"{cred_type} | {cred_preview}",
            )


class SmartCommandCompleter(Completer):
    """Smart completer that combines domain and credential suggestions.

    Intelligently switches between suggesting domains (first argument) and
    credentials (after -u flag or in credential-expecting positions).
    """

    def __init__(self, shell_instance):
        self.shell_instance = shell_instance
        self.domain_completer = DomainCompleter(shell_instance)
        self.credential_completer = CredentialCompleter(shell_instance)

    def get_completions(self, document, complete_event):
        """Delegate to appropriate completer based on context."""
        command_text = document.text

        # Try credential completer first (more specific)
        if self.credential_completer._should_suggest_credentials(command_text):
            yield from self.credential_completer.get_completions(
                document, complete_event
            )
        else:
            # Fall back to domain completer
            yield from self.domain_completer.get_completions(document, complete_event)


# --- Helper functions for colored output using Rich ---
# All print functions are now imported from adscan_internal.rich_output
# The functions are initialized with console and mode flags above


def run_command(
    command_list,
    check=True,
    capture_output=None,  # None = auto-detect (True if check=True, False otherwise)
    text=True,
    cwd=None,
    env=None,
    shell_instance=None,  # pylint: disable=unused-argument
    use_clean_env=None,
    timeout=None,
    shell=False,
):
    """Helper to run shell commands.

    Args:
        command_list: List of command arguments, or string if shell=True
        check: If True, raise exception on non-zero exit code
        capture_output: If True, capture stdout and stderr. If None (default),
                       automatically captures output when check=True to show errors.
        text: If True, return strings instead of bytes
        cwd: Working directory for command
        env: Environment variables (if None and use_clean_env is True/None, auto-detect)
        shell_instance: Optional shell instance (unused, kept for compatibility)
        use_clean_env: If True, always use clean_env. If False, never use it.
                      If None (default), auto-detect based on command type.
        timeout: Optional timeout in seconds for command execution
        shell: If True, command_list can be a string and will be executed through shell

    Returns:
        subprocess.CompletedProcess: Result of command execution
    """
    # Auto-capture output when check=True (unless explicitly disabled)
    # This allows us to show error output when commands fail
    if capture_output is None:
        capture_output = check
    # Handle shell mode: if shell=True, command_list can be a string
    if shell:
        if isinstance(command_list, str):
            command_str = strip_sensitive_markers(command_list)
            # For shell mode with string, use _command_string_needs_clean_env
            if use_clean_env is None:
                use_clean_env = _command_string_needs_clean_env(command_str)
            command_arg = command_str
        else:
            # Convert list to string for shell mode
            command_str = " ".join(
                strip_sensitive_markers(str(arg)) for arg in command_list
            )
            if use_clean_env is None:
                use_clean_env = _command_string_needs_clean_env(command_str)
            command_arg = command_str
    else:
        # Non-shell mode: command_list must be a list
        if isinstance(command_list, str):
            # If string provided without shell=True, convert to list
            command_list = shlex.split(command_list)
        # Strip any invisible markers from individual arguments
        command_list = [strip_sensitive_markers(str(arg)) for arg in command_list]
        # Auto-detect if clean_env is needed (unless explicitly set)
        if use_clean_env is None:
            use_clean_env = _command_needs_clean_env(command_list)
        command_arg = command_list

    # Apply clean_env if needed and env not explicitly provided
    if use_clean_env and env is None:
        env = _get_clean_env_for_compilation()

    try:
        if shell:
            # For shell mode, pass the command as string
            process = subprocess.run(
                command_arg,
                shell=True,
                check=check,
                capture_output=capture_output,
                text=text,
                cwd=cwd,
                env=env,
                timeout=timeout,
            )
        else:
            # For non-shell mode, pass as list
            process = subprocess.run(
                command_arg,
                check=check,
                capture_output=capture_output,
                text=text,
                cwd=cwd,
                env=env,
                timeout=timeout,
            )
        return process
    except subprocess.CalledProcessError as e:
        telemetry.capture_exception(e)
        print_error("Command failed.")
        print_exception(show_locals=False, exception=e)

        # Prepare content for the panel
        content = Text()
        if e.stdout:
            content.append("Stdout:\n", style="bold cyan")
            content.append(e.stdout.strip())
            if e.stderr:  # Add a newline if both stdout and stderr are present
                content.append("\n\n")
        if e.stderr:
            content.append("Stderr:\n", style="bold magenta")
            content.append(e.stderr.strip())

        if e.stdout or e.stderr:  # Only print panel if there's output
            from adscan_internal.rich_output import print_panel

            print_panel(
                content,
                title="[bold red]Process Output[/bold red]",
                border_style="red",
                expand=False,
            )
        raise
    except subprocess.TimeoutExpired as e:
        telemetry.capture_exception(e)
        cmd_display = (
            command_arg
            if isinstance(command_arg, str)
            else " ".join(str(arg) for arg in command_arg)
            if command_arg
            else "unknown"
        )
        print_error(f"Command timed out after {timeout} seconds: {cmd_display}")
        raise
    except FileNotFoundError as e:
        # Don't capture telemetry for FileNotFoundError when check=False
        # This is expected behavior when checking if a command exists
        if check:
            telemetry.capture_exception(e)
        cmd_name = (
            command_arg
            if isinstance(command_arg, str)
            else (command_arg[0] if command_arg and len(command_arg) > 0 else "unknown")
        )
        print_warning(f"Command not found: {cmd_name}. Is it installed and in PATH?")
        raise


def run_command_stream(
    command_list,
    *,
    check: bool = True,
    text: bool = True,
    cwd: str | None = None,
    env: dict[str, str] | None = None,
    use_clean_env: bool | None = None,
    timeout: int | None = None,
    shell: bool = False,
    telemetry_stream: bool = False,
    heartbeat_seconds: int | None = 30,
) -> subprocess.CompletedProcess[str]:
    """Run a command and stream its output to the console while capturing it.

    This is intended for long-running install flows where users benefit from
    real-time progress, but we still want a captured output buffer for
    structured error reporting when the command fails.
    """
    start_time = time.time()

    if shell:
        if isinstance(command_list, str):
            command_str = strip_sensitive_markers(command_list)
        else:
            command_str = " ".join(
                strip_sensitive_markers(str(arg)) for arg in command_list
            )
        command_arg = command_str
    else:
        if isinstance(command_list, str):
            command_list = shlex.split(command_list)
        command_arg = [strip_sensitive_markers(str(arg)) for arg in command_list]

    if use_clean_env and env is None:
        env = _get_clean_env_for_compilation()

    proc = subprocess.Popen(  # nosec B603
        command_arg,
        shell=shell,
        stdout=subprocess.PIPE,
        stderr=subprocess.STDOUT,
        text=False,
        cwd=cwd,
        env=env,
    )

    output_lines: list[str] = []
    max_lines = 4000
    try:
        # Stream output in real-time (handles both newline and carriage-return updates).
        assert proc.stdout is not None
        import selectors

        selector = selectors.DefaultSelector()
        selector.register(proc.stdout, selectors.EVENT_READ)
        pending = ""
        last_output_ts = time.time()
        last_heartbeat_ts = last_output_ts
        last_progress_line = ""
        last_progress_print_ts = 0.0

        while True:
            if timeout is not None and (time.time() - start_time) > timeout:
                proc.kill()
                raise subprocess.TimeoutExpired(command_arg, timeout)

            if proc.poll() is not None:
                # Drain any remaining output after process exit
                events = selector.select(timeout=0)
                if not events:
                    break
            events = selector.select(timeout=0.2)
            if not events:
                if heartbeat_seconds is not None:
                    now = time.time()
                    if (now - last_output_ts) >= heartbeat_seconds and (
                        now - last_heartbeat_ts
                    ) >= heartbeat_seconds:
                        message = "[install] Still running (no output yet)..."
                        console.print(message, style="dim")
                        if telemetry_stream:
                            try:
                                TELEMETRY_CONSOLE.print(message)
                            except Exception:
                                pass
                        last_heartbeat_ts = now
                continue

            try:
                chunk = proc.stdout.read1(4096)  # type: ignore[attr-defined]
            except Exception:
                chunk = proc.stdout.read(4096)

            if not chunk:
                break

            decoded = chunk.decode("utf-8", errors="replace")
            pending += decoded

            # Process output chunks and handle both newline lines and carriage-return
            # progress updates. We treat '\r' as an in-place update delimiter and
            # print it in a throttled way to avoid flooding the console.
            while True:
                next_nl = pending.find("\n")
                next_cr = pending.find("\r")
                if next_nl == -1 and next_cr == -1:
                    break

                # Choose the earliest delimiter
                if next_nl == -1:
                    idx = next_cr
                    delim = "\r"
                elif next_cr == -1:
                    idx = next_nl
                    delim = "\n"
                else:
                    idx = min(next_nl, next_cr)
                    delim = "\n" if idx == next_nl else "\r"

                segment, pending = pending[:idx], pending[idx + 1 :]
                line_clean = strip_ansi_codes(segment).strip()
                if not line_clean:
                    continue

                if delim == "\r":
                    # Carriage-return progress update: only print occasionally and
                    # only if it changed.
                    prev_progress_line = last_progress_line
                    last_progress_line = line_clean
                    now = time.time()
                    if (
                        line_clean != prev_progress_line
                        and (now - last_progress_print_ts) >= 1.5
                    ):
                        console.print(line_clean, style="dim")
                        if telemetry_stream:
                            try:
                                TELEMETRY_CONSOLE.print(line_clean)
                            except Exception:
                                pass
                        output_lines.append(line_clean)
                        last_output_ts = now
                        last_progress_print_ts = now
                        if len(output_lines) > max_lines:
                            output_lines = output_lines[-max_lines:]
                    continue

                # Normal newline-terminated line
                console.print(line_clean)
                if telemetry_stream:
                    try:
                        TELEMETRY_CONSOLE.print(line_clean)
                    except Exception:
                        pass
                output_lines.append(line_clean)
                last_output_ts = time.time()
                if len(output_lines) > max_lines:
                    output_lines = output_lines[-max_lines:]

        if pending.strip():
            line_clean = strip_ansi_codes(pending).strip()
            if line_clean:
                console.print(line_clean)
            if telemetry_stream:
                try:
                    TELEMETRY_CONSOLE.print(line_clean)
                except Exception:
                    pass
            if line_clean:
                output_lines.append(line_clean)
    finally:
        try:
            if proc.stdout:
                proc.stdout.close()
        except Exception:
            pass

    returncode = proc.wait()
    stdout = "\n".join(output_lines)

    if check and returncode != 0:
        from adscan_internal.rich_output import print_panel

        print_error("Command failed during installation.")
        if stdout.strip():
            print_panel(
                stdout,
                title="[bold red]Process Output[/bold red]",
                border_style="red",
                expand=False,
            )
        raise subprocess.CalledProcessError(returncode, command_arg, output=stdout)

    # Keep API compatible: respect requested text mode, but we already decoded into str.
    return subprocess.CompletedProcess(command_arg, returncode, stdout, None)


def is_tool_installed(tool_name):
    """Checks if a tool is available in PATH."""
    return shutil.which(tool_name) is not None


def is_venv():
    """Check if the script is running inside the ADscan virtual environment."""
    # A simple check based on sys.prefix. More robust checks might be needed
    # if you allow the venv to be located elsewhere or named differently.
    return os.path.abspath(sys.prefix) == os.path.abspath(VENV_PATH)


