# ============================================================================
# Victory-Based CTA System (CLI_CTA_STRATEGY.md)
# ============================================================================
# Following Hormozi's Give:Ask ratio (98% Give / 2% Ask)
# Show subtle CTAs only after victory moments with proper rate limiting


def _get_victory_state_file():
    """Get path to victory hints state file."""
    _migrate_adscan_state_files()
    return Path(ADSCAN_STATE_DIR) / ".victory_hints_state.json"


def _load_victory_state():
    """Load victory hints state from file."""
    state_file = _get_victory_state_file()
    if not state_file.exists():
        return {}
    try:
        with open(state_file, "r", encoding="utf-8") as f:
            return json.load(f)
    except Exception:
        return {}


def _save_victory_state(state):
    """Save victory hints state to file."""
    state_file = _get_victory_state_file()
    try:
        with open(state_file, "w", encoding="utf-8") as f:
            json.dump(state, f, indent=2)
    except Exception:
        pass


def should_show_victory_hint(victory_type: str, tier: str = "subtle") -> bool:
    """Check if a victory hint should be shown based on cooldown period.

    Args:
        victory_type: Type of victory (domain_compromised, scan_completed, da_compromise)
        tier: "subtle" (7-day cooldown) or "explicit" (30-day cooldown)

    Returns:
        True if hint should be shown, False otherwise
    """
    state = _load_victory_state()

    # Get last shown timestamp for this victory type
    last_shown = state.get(victory_type, {}).get("last_shown")
    if not last_shown:
        return True  # Never shown before

    # Check cooldown period
    # scan_complete_report fires at peak goodwill (attack paths found) — shorter cooldown
    cooldown_days = 1 if victory_type == "scan_complete_report" else (7 if tier == "subtle" else 30)
    try:
        last_shown_dt = datetime.fromisoformat(last_shown)
        now = datetime.now()
        days_since = (now - last_shown_dt).days

        return days_since >= cooldown_days
    except (ValueError, TypeError):
        return True  # Invalid timestamp, allow showing


def mark_victory_hint_shown(victory_type: str):
    """Mark that a victory hint has been shown."""
    state = _load_victory_state()

    if victory_type not in state:
        state[victory_type] = {}

    state[victory_type]["last_shown"] = datetime.now().isoformat()
    state[victory_type]["count"] = state[victory_type].get("count", 0) + 1

    _save_victory_state(state)


def show_victory_hint_subtle(victory_type: str, message: str, docs_link: str):
    """Show subtle victory hint (Tier 2: 4% of victories).

    Args:
        victory_type: Type of victory for rate limiting
        message: Victory message to show
        docs_link: Documentation link with UTM parameters
    """
    hint_text = Text.from_markup(
        f"[green]✓ {message}[/green]\n\n"
        f"[dim]💡 Tip: Share this with your team?[/dim]\n"
        f"   [link={docs_link}]Quick share link[/link]\n"
    )

    print_info(hint_text, icon="")
    mark_victory_hint_shown(victory_type)

    # Track telemetry
    try:
        from adscan_internal.telemetry import capture

        capture(
            "victory_hint_shown",
            {
                "victory_type": victory_type,
                "tier": "subtle",
                "docs_link": docs_link,
            },
        )
    except Exception:
        pass


def show_victory_hint_explicit(victory_type: str, title: str, message: str):
    """Show explicit victory panel (Tier 3: 1% of victories - major wins only).

    Args:
        victory_type: Type of victory for rate limiting
        title: Panel title
        message: Detailed victory message with share CTA
    """
    panel_text = Text.from_markup(message)

    print_panel(
        panel_text,
        title=f"[bold green]{title}[/bold green]",
        border_style="green",
        padding=(1, 2),
    )

    mark_victory_hint_shown(victory_type)

    # Track telemetry
    try:
        from adscan_internal.telemetry import capture

        capture(
            "victory_hint_shown",
            {
                "victory_type": victory_type,
                "tier": "explicit",
            },
        )
    except Exception:
        pass


def _is_attribution_asked() -> bool:
    """Return True if attribution question has already been asked (once-ever flag)."""
    flag_file = Path(ADSCAN_STATE_DIR) / ".attribution_asked"
    return flag_file.exists()


def _mark_attribution_asked() -> None:
    """Persist the once-ever attribution flag."""
    flag_file = Path(ADSCAN_STATE_DIR) / ".attribution_asked"
    try:
        flag_file.parent.mkdir(parents=True, exist_ok=True)
        flag_file.touch()
    except Exception:
        pass


def _maybe_ask_attribution(shell) -> None:
    """Ask once-ever how the user found ADscan. Captured to PostHog as attribution_source.

    Shown on the first exit only, before the session summary, so the user
    still has the session context in mind.  Non-blocking: Ctrl-C or any
    cancel returns None and is silently ignored.
    """
    if _is_attribution_asked():
        return
    if _should_disable_interactive_prompts():
        return

    options = [
        "LinkedIn",
        "GitHub",
        "A colleague or friend recommended it",
        "Discord community",
        "Web (adscanpro.com)",
        "Conference or talk (RootedCON, Hackén...)",
        "Other / Prefer not to say",
    ]

    _ATTR_KEYS = [
        "linkedin",
        "github_organic",
        "word_of_mouth",
        "discord_community",
        "landing_web",
        "conference",
        "other",
    ]

    try:
        shell.console.print()
        print_info(
            "[dim]Quick question (optional) — helps us show up where pentesters actually look:[/dim]"
        )
        idx = questionary_select_index(
            title="How did you first hear about ADscan?",
            options=options,
            default_idx=6,  # default → "Other / Prefer not to say"
            shell=shell,
        )
    except Exception:
        idx = None
    finally:
        _mark_attribution_asked()

    if idx is None:
        return

    source = _ATTR_KEYS[idx] if 0 <= idx < len(_ATTR_KEYS) else "other"
    try:
        telemetry.capture(
            "attribution_source", {"source": source, "source_label": options[idx]}
        )
    except Exception:
        pass


def _show_exit_summary(shell) -> str | None:
    """Show a context-aware session summary panel at exit.

    Returns the victory level shown ("domain_compromise", "findings") or None.
    Only shown when the session produced meaningful results.
    """
    victories = getattr(shell, "_session_victories", [])
    session_attack_paths = getattr(shell, "_session_attack_paths_count", 0)
    attack_paths = resolve_session_attack_paths_for_summary(
        shell, fallback_count=session_attack_paths
    )
    creds = getattr(shell, "_session_credentials_count", 0)
    hashes = getattr(shell, "_session_hashes_count", 0)
    workspace_creds = count_workspace_credentials(shell)
    path_breakdown = get_attack_path_summary_breakdown(shell)

    start_time = getattr(shell, "_session_start_time", None)
    duration_str = ""
    if start_time is not None:
        minutes = max(0.0, (time.monotonic() - start_time) / 60.0)
        if minutes >= 60:
            duration_str = f"{int(minutes // 60)}h {int(minutes % 60)}m"
        elif minutes >= 1:
            duration_str = f"{int(minutes)}m"

    nothing_found = (
        not victories and session_attack_paths == 0 and creds == 0 and hashes == 0
    )
    if nothing_found:
        return None

    lines = []
    border = "green" if "domain_compromise" in victories else "cyan"

    if "domain_compromise" in victories:
        lines.append("[bold green]Domain compromised[/bold green] ✓")
    if attack_paths:
        s = "s" if attack_paths != 1 else ""
        lines.append(f"[cyan]{attack_paths}[/cyan] attack path{s} identified")
    theoretical_paths = int(path_breakdown.get("total") or 0)
    blocked_paths = int(path_breakdown.get("blocked") or 0)
    unsupported_paths = int(path_breakdown.get("unsupported") or 0)
    if theoretical_paths and theoretical_paths != attack_paths:
        suffix_parts = []
        if blocked_paths:
            suffix_parts.append(f"{blocked_paths} blocked")
        if unsupported_paths:
            suffix_parts.append(f"{unsupported_paths} unsupported")
        suffix = f" ({', '.join(suffix_parts)})" if suffix_parts else ""
        lines.append(
            f"[dim]{theoretical_paths} theoretical graph path(s) persisted{suffix}[/dim]"
        )
    if creds:
        s = "s" if creds != 1 else ""
        lines.append(f"[cyan]{creds}[/cyan] new credential{s} obtained")
    if workspace_creds and workspace_creds != creds:
        s = "s" if workspace_creds != 1 else ""
        lines.append(
            f"[cyan]{workspace_creds}[/cyan] credential{s} currently stored in workspace"
        )
    if hashes:
        s = "es" if hashes != 1 else ""
        lines.append(f"[cyan]{hashes}[/cyan] hash{s} captured")
    if duration_str:
        lines.append(f"[dim]Duration: {duration_str}[/dim]")

    if not lines:
        return None

    from rich.text import Text as _Text

    panel_text = _Text.from_markup("\n".join(lines))
    print_panel(
        panel_text,
        title="[bold]Session Summary[/bold]",
        title_align="center",
        border_style=border,
        padding=(0, 2),
        fit=True,
    )

    return "domain_compromise" if "domain_compromise" in victories else "findings"


def _maybe_show_report_cta(shell) -> None:
    """Show a contextual report CTA when the session produced actionable findings."""
    session_attack_paths = getattr(shell, "_session_attack_paths_count", 0)
    attack_paths = resolve_session_attack_paths_for_summary(
        shell, fallback_count=session_attack_paths
    )
    creds = getattr(shell, "_session_credentials_count", 0)
    victories = getattr(shell, "_session_victories", [])
    if not (bool(victories) or attack_paths > 0 or creds > 0):
        return
    workspace_type = str(getattr(shell, "type", "") or "").strip().lower()
    if workspace_type != "audit":
        return
    shell.console.print()
    _pro_url = mark_passthrough("https://adscanpro.com/pro")
    if "domain_compromise" in victories:
        print_info(
            f"Domain Admin achieved — document it before the engagement closes. "
            f"PRO generates a client-ready PDF in 90 seconds: exec summary, attack chains, "
            f"MITRE mapping, remediation roadmap → {_pro_url}"
        )
    elif attack_paths > 0:
        print_info(
            f"[bold]{attack_paths} attack path(s) found[/bold] — turn them into a client deliverable "
            f"before session data is gone. PRO: exec summary + remediation roadmap in 90 seconds "
            f"→ {_pro_url}"
        )
    else:
        print_info(
            f"Credentials collected this session — document the evidence. "
            f"PRO generates a PDF report with findings and remediation steps "
            f"→ {_pro_url}"
        )


