def track_docs_link_shown(context: str, url: str):
    """Track when a documentation link is shown to the user.

    Args:
        context: Context where link was shown (install_error, bloodhound_error, help_command, etc)
        url: Full documentation URL with UTM parameters
    """
    try:
        from adscan_internal.telemetry import capture
        from urllib.parse import urlparse, parse_qs

        # Extract UTM parameters from URL for better tracking
        parsed = urlparse(url)
        query_params = parse_qs(parsed.query)

        capture(
            "docs_link_shown",
            {
                "context": context,
                "url": url,
                "utm_source": query_params.get("utm_source", [None])[0],
                "utm_medium": query_params.get("utm_medium", [None])[0],
                "path": parsed.path,
            },
        )
    except Exception:
        pass


def _detect_distribution():
    """Detect Linux distribution and version for Docker repository setup.

    Returns:
        dict: Distribution info with 'id', 'version_codename', 'base_distro', plus
        best-effort metadata ('version_id', 'id_like', 'pretty_name').
    """
    distro_info = {
        "id": None,
        "id_like": None,
        "pretty_name": None,
        "version_id": None,
        "version_codename": None,
        "base_distro": None,  # 'ubuntu', 'debian', or None
    }

    try:
        # Read /etc/os-release
        with open("/etc/os-release", "r", encoding="utf-8") as f:
            os_release = {}
            for line in f:
                line = line.strip()
                if "=" in line:
                    key, value = line.split("=", 1)
                    # Remove quotes if present
                    value = value.strip('"').strip("'")
                    os_release[key] = value

        distro_id = os_release.get("ID", "").lower()
        version_codename = os_release.get("VERSION_CODENAME") or os_release.get(
            "UBUNTU_CODENAME"
        )
        id_like = os_release.get("ID_LIKE", "").lower()
        pretty_name = os_release.get("PRETTY_NAME", "").lower()
        version_id = os_release.get("VERSION_ID", "") or ""

        distro_info["id_like"] = id_like
        distro_info["pretty_name"] = pretty_name
        distro_info["version_id"] = version_id

        # Enhanced detection for Parrot/Kali even if ID=debian
        # Check ID_LIKE and PRETTY_NAME for better detection
        if "parrot" in distro_id or "parrot" in id_like or "parrot" in pretty_name:
            distro_info["id"] = "parrot"
            distro_info["base_distro"] = "debian"
        elif "kali" in distro_id or "kali" in id_like or "kali" in pretty_name:
            distro_info["id"] = "kali"
            distro_info["base_distro"] = "debian"
        elif distro_id in ["ubuntu", "kubuntu", "lubuntu", "xubuntu"]:
            distro_info["id"] = distro_id
            distro_info["base_distro"] = "ubuntu"
        elif distro_id == "debian":
            distro_info["id"] = "debian"
            distro_info["base_distro"] = "debian"
        else:
            # Fallback: use original ID
            distro_info["id"] = distro_id
            distro_info["base_distro"] = "debian"  # Default assumption

        distro_info["version_codename"] = version_codename

        return distro_info

    except (OSError, IOError, FileNotFoundError, KeyError, ValueError) as e:
        telemetry.capture_exception(e)
        # Default to Debian if detection fails
        return {
            "id": "debian",
            "id_like": "debian",
            "pretty_name": "debian",
            "version_id": None,
            "version_codename": None,
            "base_distro": "debian",
        }


def _configure_ssl_certificates(env):
    """Configure SSL certificate environment variables for Python/pip operations.

    This is a wrapper around the shared configure_ssl_certificates function from
    adscan_internal.ssl_certificates module. It maintains backward compatibility
    with existing code that calls _configure_ssl_certificates.

    Args:
        env (dict): Environment dictionary to modify in-place

    Returns:
        dict: Modified environment dictionary with SSL certificates configured
    """
    return configure_ssl_certificates(env)


def _cleanup_disk_space(aggressive=False):
    """Clean up disk space by removing cache files and temporary data.

    This function helps free up disk space during installation, especially
    important in containerized environments where disk space is limited.

    Args:
        aggressive (bool): If True, performs more aggressive cleanup including
                          removing package lists and more cache directories.

    Returns:
        tuple: (bool, int) - (success, freed_mb_estimate)
    """
    try:
        freed_mb = 0
        clean_env = _get_clean_env_for_compilation()

        # Clean apt cache (always)
        print_info_verbose("Cleaning apt cache...")
        try:
            run_command(["apt-get", "clean"], check=False, env=clean_env)
            freed_mb += 50  # Estimate: apt cache can be 50-200MB
        except Exception:
            pass

        # Clean apt lists if aggressive
        if aggressive:
            print_info_verbose("Cleaning apt package lists...")
            try:
                run_command(
                    ["rm", "-rf", "/var/lib/apt/lists/*"], check=False, env=clean_env
                )
                freed_mb += 20  # Estimate: package lists can be 20-50MB
            except Exception:
                pass

        # Note: We don't clean /tmp or /var/tmp to avoid:
        # - Deleting user temporary files
        # - Interfering with running processes
        # - Removing PyInstaller directories (which contain SSL certificates)
        # - Causing issues with file locks or sockets

        # Clean pip cache
        print_info_verbose("Cleaning pip cache...")
        try:
            pip_cache_dirs = [
                _expand_effective_user_path("~/.cache/pip"),
                _expand_effective_user_path("~/.pip/cache"),
            ]
            for cache_dir in pip_cache_dirs:
                if os.path.exists(cache_dir):
                    shutil.rmtree(cache_dir)
                    freed_mb += 30  # Estimate: pip cache can be 30-100MB
        except Exception:
            pass

        # Clean Rust cache if aggressive
        if aggressive:
            print_info_verbose("Cleaning Rust cache...")
            try:
                cargo_cache = _expand_effective_user_path("~/.cargo/registry/cache")
                if os.path.exists(cargo_cache):
                    shutil.rmtree(cargo_cache)
                    freed_mb += 50  # Estimate: Rust cache can be 50-200MB
            except Exception:
                pass

        return True, freed_mb

    except Exception as e:
        telemetry.capture_exception(e)

        print_warning_verbose(f"Disk cleanup encountered errors: {e}")
        print_exception(exception=e)
        return False, 0


def _download_file_with_fallbacks(url, dest_path, timeout=30):
    """Download a file from URL with multiple fallback methods to handle SSL issues.

    In PyInstaller environments, SSL certificate verification can fail. This function
    tries multiple download methods in order of preference:
    1. requests library (with SSL verification)
    2. requests library (with SSL verification disabled)
    3. curl command (uses system SSL libraries via clean_env)
    4. wget command (uses system SSL libraries via clean_env)
    5. urllib.request with SSL verification disabled (last resort)

    Args:
        url (str): URL to download from
        dest_path (str): Destination file path
        timeout (int): Timeout in seconds (default: 30)

    Returns:
        bool: True if download succeeded, False otherwise

    Raises:
        Exception: If all download methods fail
    """
    last_error = None

    # Try requests first with SSL verification (most reliable when it works)
    try:
        response = requests.get(url, timeout=timeout, verify=True)
        response.raise_for_status()
        with open(dest_path, "wb") as f:
            f.write(response.content)
        print_info_verbose("Download succeeded using requests (SSL verified)")
        return True
    except (requests.RequestException, OSError, IOError) as e:
        last_error = e
        print_info_verbose(f"requests (SSL verified) failed: {e}")

    # Try requests with SSL verification disabled
    try:
        response = requests.get(url, timeout=timeout, verify=False)
        response.raise_for_status()
        with open(dest_path, "wb") as f:
            f.write(response.content)
        print_info_verbose("Download succeeded using requests (SSL unverified)")
        return True
    except (requests.RequestException, OSError, IOError) as e:
        last_error = e
        print_info_verbose(f"requests (SSL unverified) failed: {e}")

    # Try curl (uses system SSL libraries via clean_env)
    try:
        clean_env = _get_clean_env_for_compilation()
        subprocess.run(
            ["curl", "-fsSL", url, "-o", dest_path],
            check=True,
            timeout=timeout,
            capture_output=True,
            text=True,
            env=clean_env,
        )
        print_info_verbose("Download succeeded using curl")
        return True
    except subprocess.CalledProcessError as e:
        last_error = e
        error_msg = e.stderr if e.stderr else e.stdout if e.stdout else str(e)
        print_info_verbose(f"curl failed: {error_msg}")
    except (OSError, TimeoutError) as e:
        last_error = e
        print_info_verbose(f"curl failed: {e}")

    # Try wget (uses system SSL libraries via clean_env)
    try:
        clean_env = _get_clean_env_for_compilation()
        subprocess.run(
            ["wget", "-q", "-O", dest_path, url],
            check=True,
            timeout=timeout,
            capture_output=True,
            text=True,
            env=clean_env,
        )
        print_info_verbose("Download succeeded using wget")
        return True
    except subprocess.CalledProcessError as e:
        last_error = e
        error_msg = e.stderr if e.stderr else e.stdout if e.stdout else str(e)
        print_info_verbose(f"wget failed: {error_msg}")
    except (OSError, TimeoutError) as e:
        last_error = e
        print_info_verbose(f"wget failed: {e}")

    # Last resort: urllib with SSL verification disabled
    try:
        import ssl
        import urllib.request

        ssl_context = ssl.create_default_context()
        ssl_context.check_hostname = False
        ssl_context.verify_mode = ssl.CERT_NONE
        with urllib.request.urlopen(
            url, timeout=timeout, context=ssl_context
        ) as response:
            with open(dest_path, "wb") as f:
                f.write(response.read())
        print_info_verbose("Download succeeded using urllib (SSL unverified)")
        return True
    except (urllib.error.URLError, urllib.error.HTTPError, OSError, TimeoutError) as e:
        last_error = e
        print_info_verbose(f"urllib failed: {e}")
        raise RuntimeError(
            f"All download methods failed. Last error: {last_error}"
        ) from e


def _get_debian_base_version(distro_id, version_codename):
    """Get Debian base version codename for Debian-based distributions.

    Implements robust mapping following Docker's official guidelines:
    - Priority 1: Use DEBIAN_CODENAME from /etc/os-release if available
    - Priority 2: Minimal mapping for known derivatives (Parrot lory → bookworm)
    - Priority 3: Parse /etc/debian_version (handles numeric and codename formats)
    - Priority 3.5: For Kali rolling, verify Docker repository availability (trixie → bookworm → bullseye)
    - Priority 4: Fallback to bookworm (conservative default)

    Following Docker's guidance: In Debian derivatives, use the Debian codename,
    not the derivative's own codename.

    Args:
        distro_id (str): Distribution ID (kali, parrot, etc.)
        version_codename (str): Distribution version codename

    Returns:
        str: Debian codename (bookworm, trixie, bullseye, etc.)
    """
    try:
        # Read /etc/os-release for additional info
        with open("/etc/os-release", "r", encoding="utf-8") as f:
            os_release = {}
            for line in f:
                line = line.strip()
                if "=" in line:
                    key, value = line.split("=", 1)
                    value = value.strip('"').strip("'")
                    os_release[key] = value

        # Priority 1: DEBIAN_CODENAME directly from /etc/os-release
        # This is the most reliable source if available
        debian_codename = os_release.get("DEBIAN_CODENAME", "")
        if debian_codename:
            if VERBOSE_MODE or DEBUG_MODE:
                print_info(
                    f"Found DEBIAN_CODENAME in /etc/os-release: {debian_codename}"
                )
            return debian_codename

        if VERBOSE_MODE or DEBUG_MODE:
            print_info(
                "[bold]Distribution detection[/bold]",
                items=[
                    f"[cyan]ID:[/cyan] {distro_id}",
                    f"[cyan]Version codename:[/cyan] {version_codename}",
                    f"[cyan]Version ID:[/cyan] {os_release.get('VERSION_ID', 'N/A')}",
                ],
                panel=True,
            )

        # Priority 2: Minimal mapping for known derivatives with specific codenames
        # Only map when the derivative's codename would confuse Docker's repo selection
        # Parrot: lory is Parrot's codename, but Docker needs Debian's codename
        if distro_id == "parrot" and version_codename == "lory":
            if VERBOSE_MODE or DEBUG_MODE:
                print_info(
                    "Mapped Parrot 'lory' → Debian 'bookworm' (Parrot 6.x → Debian 12)"
                )
            return "bookworm"

        # Note: For Kali, we don't hardcode mappings. kali-rolling tracks Debian testing,
        # which can be bookworm or trixie depending on when Kali was synced. We let
        # /etc/debian_version determine the actual base version.

        # Priority 3: Parse /etc/debian_version
        # This file is reliable for Debian and its derivatives
        # Examples: "13.0", "trixie/sid", "12.6", "bookworm/sid"
        if VERBOSE_MODE or DEBUG_MODE:
            print_info("No DEBIAN_CODENAME found, parsing /etc/debian_version...")

        try:
            with open("/etc/debian_version", "r", encoding="utf-8") as f:
                debian_version = f.read().strip()

            if VERBOSE_MODE or DEBUG_MODE:
                print_info(f"Read /etc/debian_version: '{debian_version}'")

            # Extract the first token (before "/" or space)
            # Examples: "trixie/sid" → "trixie", "13.0" → "13.0", "bookworm/sid" → "bookworm"
            token = debian_version.split("/")[0].split()[0]

            # Try numeric version first (e.g., "13.0", "12.6")
            if token and token.split(".")[0].isdigit():
                major_version = int(token.split(".")[0])
                version_to_codename = {
                    13: "trixie",
                    12: "bookworm",
                    11: "bullseye",
                    10: "buster",
                }
                debian_codename = version_to_codename.get(major_version, "bookworm")
                if VERBOSE_MODE or DEBUG_MODE:
                    print_info(
                        f"Detected Debian {major_version} from /etc/debian_version → {debian_codename}"
                    )
                return debian_codename

            # Try codename directly (e.g., "trixie", "bookworm", "bullseye")
            # Validate it's a known Debian codename
            known_codenames = [
                "trixie",
                "bookworm",
                "bullseye",
                "buster",
                "stretch",
                "jessie",
            ]
            if token.lower() in known_codenames:
                debian_codename = token.lower()
                if VERBOSE_MODE or DEBUG_MODE:
                    print_info(
                        f"Detected Debian codename '{debian_codename}' from /etc/debian_version"
                    )
                return debian_codename

            if VERBOSE_MODE or DEBUG_MODE:
                print_warning(
                    f"Unknown format in /etc/debian_version: '{debian_version}' (token: '{token}')"
                )

        except FileNotFoundError:
            if VERBOSE_MODE or DEBUG_MODE:
                print_warning("/etc/debian_version not found")
        except (ValueError, Exception) as e:
            if VERBOSE_MODE or DEBUG_MODE:
                print_warning(f"Error parsing /etc/debian_version: {e}")

        # Priority 3.5: For Kali rolling, try Docker repository verification
        # This handles cases where /etc/debian_version doesn't contain Debian info
        if distro_id == "kali" and version_codename == "kali-rolling":
            if VERBOSE_MODE or DEBUG_MODE:
                print_info(
                    "Kali rolling detected, trying Docker repository verification..."
                )

            # Get architecture for repository URL construction
            arch_result = run_command(
                ["dpkg", "--print-architecture"],
                check=False,
                capture_output=True,
                text=True,
            )
            architecture = (
                arch_result.stdout.strip()
                if arch_result and arch_result.returncode == 0
                else "amd64"
            )

            # Try candidates in order of likelihood for current Kali rolling
            # 2025.x Kali typically tracks Debian testing (trixie), but can fall back
            candidates = ["trixie", "bookworm", "bullseye"]

            for candidate in candidates:
                if VERBOSE_MODE or DEBUG_MODE:
                    print_info(f"Testing Docker repository for Debian '{candidate}'...")

                # Test if the repository URL exists by checking if we can reach it
                repo_url = f"https://download.docker.com/linux/debian/dists/{candidate}/stable/binary-{architecture}/"

                try:
                    # Use curl to test if the repository exists (HEAD request)
                    test_result = run_command(
                        ["curl", "-fsSL", "--head", "--max-time", "10", repo_url],
                        check=False,
                        capture_output=True,
                        text=True,
                    )

                    if test_result and test_result.returncode == 0:
                        # Repository exists, this is our candidate
                        if VERBOSE_MODE or DEBUG_MODE:
                            print_info(
                                f"✓ Docker repository for Debian '{candidate}' is available"
                            )
                        return candidate
                    if VERBOSE_MODE or DEBUG_MODE:
                        print_info(
                            f"✗ Docker repository for Debian '{candidate}' not available"
                        )

                except (subprocess.TimeoutExpired, FileNotFoundError, Exception) as e:
                    if VERBOSE_MODE or DEBUG_MODE:
                        print_warning(
                            f"Error testing repository for '{candidate}': {e}"
                        )
                    continue

            if VERBOSE_MODE or DEBUG_MODE:
                print_warning(
                    "No working Docker repository found for Kali rolling, will use fallback"
                )

        # Priority 4: Fallback to bookworm (conservative default)
        # Docker supports Debian 13/12/11, and bookworm (12) is a safe middle ground
        if VERBOSE_MODE or DEBUG_MODE:
            print_warning(
                f"Could not determine Debian version for {distro_id} '{version_codename}'"
            )
            print_info("Using conservative default: 'bookworm' (Debian 12)")
        return "bookworm"

    except Exception as e:
        telemetry.capture_exception(e)
        if VERBOSE_MODE or DEBUG_MODE:
            print_warning(f"Error detecting Debian base version: {e}")
        return "bookworm"  # Safe default


def _ensure_docker_daemon_running() -> bool:
    """Ensure the Docker daemon is running; try to start it when possible.

    Returns:
        bool: True if the daemon is running or was started successfully.
    """
    global _DOCKER_USE_SUDO  # pylint: disable=global-statement

    def set_docker_use_sudo(value: bool) -> None:
        """Set the global _DOCKER_USE_SUDO flag."""
        global _DOCKER_USE_SUDO  # pylint: disable=global-statement
        _DOCKER_USE_SUDO = value

    return _ensure_docker_daemon_running_internal(
        docker_access_denied_func=_docker_access_denied,
        run_docker_command_func=_run_docker_command,
        sudo_validate_func=_sudo_validate,
        run_systemctl_command_func=_run_systemctl_command,
        print_warning_func=print_warning,
        print_info_func=print_info,
        print_info_debug_func=print_info_debug,
        print_info_verbose_func=print_info_verbose,
        print_success_verbose_func=print_success_verbose,
        print_error_func=print_error,
        print_exception_func=print_exception,
        set_docker_use_sudo_func=set_docker_use_sudo,
    )


def _install_docker_prerequisites_legacy():
    """Legacy implementation to install Docker engine and Docker Compose.

    Follows official Docker installation guide: https://docs.docker.com/engine/install/

    This implementation has been migrated to
    :func:`adscan_internal.docker_host_install.install_docker_prerequisites`.
    It is kept here only as a reference and is not used by the CLI anymore.

    Returns:
        bool: True if Docker and Compose are available, False otherwise
    """
    try:
        # Skip Docker installation if running inside a container
        in_container = is_docker_env()
        if in_container:
            print_info_verbose(
                "Skipping Docker installation: running inside container (Docker-in-Docker not supported)"
            )
            # Check if Docker is available (might be available via host Docker socket)
            docker_installed, docker_version = _is_docker_official_installed()
            compose_available, compose_version = _is_docker_compose_plugin_available()
            if docker_installed and compose_available:
                print_info_verbose(
                    f"Docker and Compose available via host: Docker {docker_version}, Compose {compose_version}"
                )
                return True
            # Return True anyway to avoid blocking installation in containers
            # Docker is not needed in containers for BloodHound CE
            return True

        # Check if official Docker Engine and Docker Compose plugin are already installed
        docker_installed, docker_version = _is_docker_official_installed()
        compose_available, compose_version = _is_docker_compose_plugin_available()

        if docker_installed and compose_available:
            print_success(
                "[bold]Docker and Docker Compose[/bold] already present",
                items=[
                    f"[cyan]Docker:[/cyan] {docker_version}",
                    f"[cyan]Docker Compose:[/cyan] {compose_version}",
                ],
                panel=True,
            )
            return True
        if docker_installed and not compose_available:
            print_warning(
                f"Official Docker found ({docker_version}) but Docker Compose plugin missing."
            )
            print_info("Will install Docker Compose plugin...")
        elif not docker_installed and compose_available:
            print_warning(
                f"Docker Compose plugin found ({compose_version}) but official Docker missing."
            )
            print_info("Will install official Docker Engine...")
        else:
            print_info("Neither official Docker nor Docker Compose plugin found.")
            print_info("Will install both from official repositories...")

        print_info(
            "Installing Docker engine and Docker Compose from official repositories..."
        )

        # Legacy note:
        # The detailed host Docker installation steps (removing old packages,
        # adding the Docker GPG key and repository) have been migrated to the
        # modular helper:
        #   adscan_internal.docker_host_install.install_docker_prerequisites
        #
        # This legacy function is kept only as historical reference and is not
        # used by the current CLI flows. The original calls to
        # `_remove_old_docker_packages`, `_add_docker_gpg_key`, and
        # `_add_docker_repository` have been removed to avoid NameErrors while
        # keeping the rest of the function body intact for future reference.

        # Step 4: Update package list
        print_info(
            "[bold]Updating package list[/bold] after adding Docker repository..."
        )
        # Use clean environment to avoid PyInstaller library conflicts with dpkg/apt
        clean_env = _get_clean_env_for_compilation()
        run_command(["apt-get", "update"], check=True, env=clean_env)
        print_success("[bold]Package list[/bold] updated successfully", panel=True)

        # Step 5: Install Docker packages
        print_info("[bold]Installing Docker Engine and Docker Compose plugin[/bold]...")
        docker_packages = [
            "docker-ce",
            "docker-ce-cli",
            "containerd.io",
            "docker-buildx-plugin",
            "docker-compose-plugin",
        ]

        docker_install_result = run_command(
            ["apt-get", "install", "-y"] + docker_packages,
            check=False,
            capture_output=True,
            env=clean_env,
        )
        if docker_install_result is None:
            print_error("Failed to install Docker Engine and Docker Compose plugin.")
            return False

        if docker_install_result.returncode != 0:
            combined_output = "\n".join(
                s
                for s in [
                    (docker_install_result.stdout or "").strip(),
                    (docker_install_result.stderr or "").strip(),
                ]
                if s
            ).lower()
            buildx_conflict = (
                "trying to overwrite" in combined_output
                and "/usr/libexec/docker/cli-plugins/docker-buildx" in combined_output
            )
            if buildx_conflict:
                telemetry._capture_user_property_event(
                    "docker_install_buildx_conflict",
                    "installation_status",
                    "docker_buildx_conflict",
                )
                print_warning(
                    "Docker Buildx conflict detected (docker-buildx vs docker-buildx-plugin). "
                    "Attempting automatic remediation..."
                )
                run_command(
                    ["apt-get", "remove", "-y", "docker-buildx"],
                    check=False,
                    capture_output=True,
                    env=clean_env,
                )
                run_command(
                    ["apt-get", "install", "--fix-broken", "-y"],
                    check=False,
                    capture_output=True,
                    env=clean_env,
                )
                docker_install_result = run_command(
                    ["apt-get", "install", "-y"] + docker_packages,
                    check=False,
                    capture_output=True,
                    env=clean_env,
                )
                if docker_install_result is None:
                    print_error(
                        "Failed to install Docker Engine and Docker Compose plugin."
                    )
                    return False

        if docker_install_result.returncode != 0:
            from rich.text import Text

            from adscan_internal.rich_output import print_panel

            print_error("Failed to install Docker Engine and Docker Compose plugin.")

            content = Text()
            if docker_install_result.stdout:
                content.append("Stdout:\n", style="bold cyan")
                content.append(docker_install_result.stdout.strip())
                if docker_install_result.stderr:
                    content.append("\n\n")
            if docker_install_result.stderr:
                content.append("Stderr:\n", style="bold magenta")
                content.append(docker_install_result.stderr.strip())
            if str(content).strip():
                print_panel(
                    content,
                    title="[bold red]Process Output[/bold red]",
                    border_style="red",
                    expand=False,
                )
            return False
        print_success(
            "[bold]Docker Engine and Docker Compose[/bold] installed successfully",
            items=[f"[green]✓[/green] {pkg}" for pkg in docker_packages],
            panel=True,
        )

        # Step 6: Verify installation
        print_info("[bold]Verifying Docker installation[/bold]...")
        docker_status = run_command(
            ["systemctl", "status", "docker", "--no-pager"],
            check=False,
            capture_output=True,
            text=True,
        )

        if docker_status and docker_status.returncode == 0:
            print_success("[bold]Docker service[/bold] is running", panel=True)
        else:
            print_warning(
                "Docker service status check failed, but installation may have succeeded."
            )
            # Try to start Docker service
            print_info("Attempting to start Docker service...")
            run_command(["systemctl", "start", "docker"], check=False)
            run_command(["systemctl", "enable", "docker"], check=False)

        # Final verification using official Docker detection
        docker_installed, docker_version = _is_docker_official_installed()
        compose_available, compose_version = _is_docker_compose_plugin_available()

        if docker_installed and compose_available:
            print_success("Docker and Docker Compose installation verified.")
            print_info(f"Docker: {docker_version}")
            print_info(f"Docker Compose: {compose_version}")
            return True
        print_warning("Docker installation verification failed.")
        if not docker_installed:
            print_warning(f"Docker verification failed: {docker_version}")
        if not compose_available:
            print_warning(f"Docker Compose verification failed: {compose_version}")
        return False

    except Exception as e:
        telemetry.capture_exception(e)
        print_warning("Failed to install Docker prerequisites.")
        print_exception(show_locals=False, exception=e)
        return False


def _is_rustup_available(env=None):
    """Check if rustup is available in the system.

    Args:
        env (dict, optional): Environment variables for subprocess

    Returns:
        tuple: (bool, str) - (is_available, version_output)
    """
    try:
        effective_home = _get_effective_user_home()
        cargo_bin_path = os.path.join(effective_home, ".cargo", "bin")

        if env is None:
            env = os.environ.copy()
        env = dict(env)
        _apply_effective_user_home_to_env(env)
        env["CARGO_HOME"] = os.path.join(effective_home, ".cargo")
        env["RUSTUP_HOME"] = os.path.join(effective_home, ".rustup")
        env["PATH"] = f"{cargo_bin_path}{os.pathsep}{env.get('PATH', '')}"

        result = run_command(
            ["rustup", "--version"],
            check=False,
            capture_output=True,
            text=True,
            env=env,
            timeout=10,
        )
        if result.returncode == 0:
            # Handle case where stdout might be None
            stdout_text = result.stdout.strip() if result.stdout else ""
            return True, stdout_text
        return False, ""
    except Exception:
        return False, ""


def _cargo_output_indicates_missing_default_toolchain(output: str) -> bool:
    """Return True if cargo output indicates rustup has no default toolchain."""
    lowered = (output or "").lower()
    return (
        "rustup could not choose a version of cargo to run" in lowered
        and "no default is configured" in lowered
    )


def _ensure_rustup_default_toolchain(env: dict[str, str] | None = None) -> bool:
    """Ensure rustup has a default toolchain configured (stable).

    This fixes environments where `cargo` exists but fails with:
    "rustup could not choose a version of cargo to run... no default is configured."
    """
    try:
        effective_home = _get_effective_user_home()
        cargo_bin_path = os.path.join(effective_home, ".cargo", "bin")
        rustup_exe = shutil.which("rustup")
        if not rustup_exe:
            candidate = os.path.join(cargo_bin_path, "rustup")
            if os.path.exists(candidate) and os.access(candidate, os.X_OK):
                rustup_exe = candidate
        if not rustup_exe:
            return False

        if env is None:
            env = os.environ.copy()
        env = dict(env)
        _apply_effective_user_home_to_env(env)
        # Always force these to the effective user; inherited env vars can point to /root.
        env["CARGO_HOME"] = os.path.join(effective_home, ".cargo")
        env["RUSTUP_HOME"] = os.path.join(effective_home, ".rustup")
        env["PATH"] = f"{cargo_bin_path}{os.pathsep}{env.get('PATH', '')}"

        # Ensure stable is installed and set as default.
        run_command(
            [rustup_exe, "toolchain", "install", "stable"],
            check=False,
            capture_output=True,
            text=True,
            env=env,
            timeout=300,
        )
        run_command(
            [rustup_exe, "default", "stable"],
            check=False,
            capture_output=True,
            text=True,
            env=env,
            timeout=120,
        )
        return True
    except Exception as exc:  # pragma: no cover - environment dependent
        telemetry.capture_exception(exc)
        return False


def _is_cargo_available(env=None):
    """Check if cargo is available in the system.

    Args:
        env (dict, optional): Environment variables for subprocess

    Returns:
        tuple: (bool, str) - (is_available, version_output)
    """
    try:
        effective_home = _get_effective_user_home()
        cargo_bin_path = os.path.join(effective_home, ".cargo", "bin")
        cargo_exe = os.path.join(cargo_bin_path, "cargo")

        if env is None:
            env = os.environ.copy()
        env = dict(env)
        _apply_effective_user_home_to_env(env)
        # Always force these to the effective user; inherited env vars can point to /root.
        env["CARGO_HOME"] = os.path.join(effective_home, ".cargo")
        env["RUSTUP_HOME"] = os.path.join(effective_home, ".rustup")
        env["PATH"] = f"{cargo_bin_path}{os.pathsep}{env.get('PATH', '')}"

        cmd = (
            [cargo_exe, "--version"]
            if os.path.exists(cargo_exe)
            else ["cargo", "--version"]
        )
        result = run_command(
            cmd,
            check=False,
            capture_output=True,
            text=True,
            env=env,
            timeout=15,
        )
        if result.returncode == 0:
            # Handle case where stdout might be None
            stdout_text = result.stdout.strip() if result.stdout else ""
            return True, stdout_text
        # Handle case where stderr might be None
        combined = (
            f"{(result.stdout or '').strip()}\n{(result.stderr or '').strip()}".strip()
        )
        stderr_text = combined or "Command failed with no error output"
        # Auto-repair common rustup misconfiguration where no default toolchain is set.
        if _cargo_output_indicates_missing_default_toolchain(stderr_text):
            if _ensure_rustup_default_toolchain(env):
                retry = run_command(
                    cmd,
                    check=False,
                    capture_output=True,
                    text=True,
                    env=env,
                    timeout=15,
                )
                if retry.returncode == 0:
                    return True, (retry.stdout or "").strip()
                retry_err = (retry.stderr or "").strip()
                if retry_err:
                    return False, retry_err
        return False, stderr_text
    except Exception as e:
        return False, str(e)


