def _get_current_shell_source_message():
    """Get the appropriate source command for the current shell.

    Returns:
        str: Source command message for the current shell
    """
    current_shell = os.environ.get("SHELL", "/bin/bash")

    if "zsh" in current_shell:
        return "source ~/.zshrc"
    if "bash" in current_shell:
        return "source ~/.bashrc"
    if "fish" in current_shell:
        return "source ~/.config/fish/config.fish"
    return "source ~/.profile"


