def _configure_go_path():
    """Configure ~/go/bin in shell profiles and current session.

    Returns:
        bool: True if configuration was successful or already configured
    """
    try:
        print_info_verbose("_configure_go_path() called - starting PATH configuration")
        go_bin_path = _expand_effective_user_path("~/go/bin")
        current_path = os.environ.get("PATH", "")

        # Add to current session PATH
        if go_bin_path not in current_path:
            os.environ["PATH"] = f"{go_bin_path}:{current_path}"

        # Detect current shell and determine which config file to use
        current_shell = os.environ.get("SHELL", "/bin/bash")
        shell_config_file = None

        if "zsh" in current_shell:
            shell_config_file = _expand_effective_user_path("~/.zshrc")
        elif "bash" in current_shell:
            shell_config_file = _expand_effective_user_path("~/.bashrc")
        elif "fish" in current_shell:
            shell_config_file = _expand_effective_user_path(
                "~/.config/fish/config.fish"
            )
        else:
            shell_config_file = _expand_effective_user_path("~/.profile")

        path_config_line = 'export PATH="$HOME/go/bin:$PATH"'
        configured_current_shell = False

        # Configure current shell's config file
        if shell_config_file and os.path.exists(shell_config_file):
            try:
                with open(shell_config_file, "r", encoding="utf-8") as f:
                    content = f.read()

                if (
                    path_config_line not in content
                    and "~/go/bin" not in content
                    and "$HOME/go/bin" not in content
                ):
                    with open(shell_config_file, "a", encoding="utf-8") as f:
                        f.write(f"\n# Go binaries\n{path_config_line}\n")
                    print_success(f"Added Go PATH to {shell_config_file}")
                    configured_current_shell = True

                    try:
                        go_bin_path = _expand_effective_user_path("~/go/bin")
                        current_path = os.environ.get("PATH", "")
                        if go_bin_path not in current_path:
                            os.environ["PATH"] = f"{go_bin_path}:{current_path}"
                            print_success("PATH updated for current session")
                    except Exception as e:
                        print_info_verbose(
                            f"Could not update PATH for current session: {e}"
                        )
                else:
                    print_info_verbose(
                        f"Go PATH already configured in {shell_config_file}"
                    )

                    try:
                        go_bin_path = _expand_effective_user_path("~/go/bin")
                        current_path = os.environ.get("PATH", "")
                        if go_bin_path not in current_path:
                            os.environ["PATH"] = f"{go_bin_path}:{current_path}"
                            print_success("PATH updated for current session")
                    except Exception as e:
                        print_info_verbose(
                            f"Could not update PATH for current session: {e}"
                        )

            except Exception as e:
                print_warning(f"Could not configure PATH in {shell_config_file}: {e}")

        # Also configure universal profile as backup
        profile_file = _expand_effective_user_path("~/.profile")
        if profile_file != shell_config_file and os.path.exists(profile_file):
            try:
                with open(profile_file, "r", encoding="utf-8") as f:
                    content = f.read()

                if (
                    path_config_line not in content
                    and "~/go/bin" not in content
                    and "$HOME/go/bin" not in content
                ):
                    with open(profile_file, "a", encoding="utf-8") as f:
                        f.write(f"\n# Go binaries\n{path_config_line}\n")
                    print_info_verbose(f"Added Go PATH to {profile_file} (backup)")
            except Exception as e:
                print_info_verbose(f"Could not configure PATH in {profile_file}: {e}")

        return configured_current_shell or True

    except Exception as e:
        print_warning(f"Error configuring Go PATH: {e}")
        return False


def _install_htb_cli(env=None):
    """Install htb-cli using go install.

    Args:
        env (dict, optional): Environment variables for subprocess

    Returns:
        tuple: (bool, str) - (install_success, output_message)
    """
    try:
        # Ensure ~/go/bin is in PATH for go install
        effective_home = _get_effective_user_home()
        go_home = os.path.join(effective_home, "go")
        go_bin_path = os.path.join(go_home, "bin")
        current_path = os.environ.get("PATH", "")
        if go_bin_path not in current_path:
            os.environ["PATH"] = f"{go_bin_path}:{current_path}"

        # Use clean environment for Go compilation to avoid PyInstaller library conflicts
        # If env is provided, use it; otherwise use clean environment
        if env is None:
            env = _get_clean_env_for_compilation()
        else:
            # If env is provided, ensure it's clean for compilation
            env = _get_clean_env_for_compilation(env)

        _apply_effective_user_home_to_env(env)
        env.setdefault("GOPATH", go_home)

        # Ensure go bin is in PATH for compilation
        env_path = env.get("PATH", "")
        if go_bin_path not in env_path:
            env["PATH"] = f"{go_bin_path}:{env_path}"

        print_info("Installing htb-cli via go install...")
        result = run_command(
            ["go", "install", "github.com/GoToolSharing/htb-cli@latest"],
            check=False,
            env=env,
            timeout=300,
        )

        if result.returncode == 0:
            output = (
                result.stdout.strip()
                if result.stdout
                else "htb-cli installed successfully"
            )
            return True, output
        error = (
            result.stderr.strip()
            if result.stderr
            else result.stdout.strip() or "Installation failed"
        )
        return False, error
    except Exception as e:
        return False, str(e)


