def _configure_pyenv_path_in_session():
    """Configure pyenv PATH in the current session.

    This function adds pyenv bin and shims directories to the current session's PATH
    and sets pyenv_root environment variable. This makes pyenv available immediately
    without requiring a terminal restart.

    Returns:
        bool: True if PATH was updated, False otherwise
    """
    try:
        pyenv_root = _expand_effective_user_path("~/.pyenv")  # pylint: disable=invalid-name
        pyenv_shims_path = os.path.join(pyenv_root, "shims")
        pyenv_bin_path = os.path.join(pyenv_root, "bin")

        current_path = os.environ.get("PATH", "")
        paths_to_prepend = []
        existing_path_set = set(current_path.split(os.pathsep))

        if os.path.isdir(pyenv_bin_path) and pyenv_bin_path not in existing_path_set:
            paths_to_prepend.append(pyenv_bin_path)
        if (
            os.path.isdir(pyenv_shims_path)
            and pyenv_shims_path not in existing_path_set
        ):
            paths_to_prepend.append(pyenv_shims_path)

        if paths_to_prepend:
            os.environ["PATH"] = (
                os.pathsep.join(paths_to_prepend) + os.pathsep + current_path
            )
            print_info_verbose(
                f"PATH updated for pyenv in current session: {os.pathsep.join(paths_to_prepend)} prepended."
            )

        os.environ["pyenv_root"] = pyenv_root
        os.environ["PYENV_ROOT"] = pyenv_root
        print_info_verbose(f"pyenv_root set to: {pyenv_root}")

        return len(paths_to_prepend) > 0
    except Exception as e:
        telemetry.capture_exception(e)
        print_warning(f"Error configuring pyenv PATH in current session: {e}")
        return False


def _ensure_pyenv_in_path():
    """Ensure pyenv is configured in PATH both in shell config and current session.

    This function:
    1. Checks if pyenv is already in PATH
    2. If not, checks if it's configured in shell config file
    3. If not configured, configures it in shell config file
    4. Always adds pyenv to current session PATH (so it works immediately)

    Returns:
        tuple: (shell_configured: bool, session_configured: bool)
    """
    shell_configured = False
    session_configured = False

    try:
        # First, check if pyenv is already in PATH
        pyenv_available, _, _ = _is_pyenv_available(os.environ)
        if pyenv_available:
            # Already in PATH, just ensure session PATH is set (in case pyenv_root is missing)
            session_configured = _configure_pyenv_path_in_session()
            # Check if it's configured in shell config (by checking if pyenv_root is in shell config)
            current_shell = os.environ.get("SHELL", "/bin/bash")
            shell_config_file = None
            if "zsh" in current_shell:
                shell_config_file = _expand_effective_user_path("~/.zshrc")
            elif "bash" in current_shell:
                shell_config_file = _expand_effective_user_path("~/.bashrc")

            shell_already_configured = False
            if shell_config_file and os.path.exists(shell_config_file):
                try:
                    with open(shell_config_file, "r", encoding="utf-8") as f:
                        content = f.read()
                    shell_already_configured = "pyenv_root" in content and (
                        "pyenv init" in content or "pyenv init -" in content
                    )
                except Exception:
                    pass

            return shell_already_configured, session_configured

        # pyenv is not in PATH - check if it's configured in shell config
        pyenv_root = _expand_effective_user_path("~/.pyenv")  # pylint: disable=invalid-name
        pyenv_executable = os.path.join(pyenv_root, "bin", "pyenv")

        if not os.path.exists(pyenv_executable):
            # pyenv is not installed
            return False, False

        # pyenv is installed but not in PATH - configure it
        print_info("pyenv is installed but not in PATH. Configuring it now...")

        # Configure in shell config file
        shell_configured = _configure_pyenv_shell()

        # Always configure in current session (so it works immediately)
        session_configured = _configure_pyenv_path_in_session()

        if shell_configured:
            print_success("pyenv configured in shell config file")
        if session_configured:
            print_success("pyenv added to current session PATH")

        return shell_configured, session_configured

    except Exception as e:
        telemetry.capture_exception(e)
        print_warning(f"Error ensuring pyenv in PATH: {e}")
        return False, False


def _configure_pyenv_shell():
    """Configure pyenv in shell profiles according to pyenv documentation.

    Adds pyenv initialization commands to the appropriate shell config file
    based on the current shell (zsh, bash, fish, or fallback to .profile).

    Returns:
        bool: True if configuration was successful or already configured
    """
    try:
        print_info_verbose(
            "_configure_pyenv_shell() called - starting pyenv shell configuration"
        )

        # Detect current shell and determine which config file to use
        current_shell = os.environ.get("SHELL", "/bin/bash")
        shell_config_file = None
        shell_name = None

        if "zsh" in current_shell:
            shell_config_file = _expand_effective_user_path("~/.zshrc")
            shell_name = "zsh"
        elif "bash" in current_shell:
            shell_config_file = _expand_effective_user_path("~/.bashrc")
            shell_name = "bash"
        elif "fish" in current_shell:
            shell_config_file = _expand_effective_user_path(
                "~/.config/fish/config.fish"
            )
            shell_name = "fish"
        else:
            shell_config_file = _expand_effective_user_path("~/.profile")
            shell_name = "bash"  # Default to bash syntax for .profile

        configured_current_shell = False

        # Pyenv configuration lines according to official documentation
        pyenv_config_lines = []

        if shell_name == "fish":
            # Fish shell has different syntax
            pyenv_config_lines = [
                "set -Ux pyenv_root $HOME/.pyenv",
                "fish_add_path $pyenv_root/bin",
                "pyenv init - fish | source",
            ]
        else:
            # Bash/Zsh syntax (also works for .profile)
            pyenv_config_lines = [
                'export pyenv_root="$HOME/.pyenv"',
                '[[ -d $pyenv_root/bin ]] && export PATH="$pyenv_root/bin:$PATH"',
                f'eval "$(pyenv init - {shell_name})"',
            ]

        # Configure current shell's config file
        if shell_config_file:
            try:
                # Expand path to handle ~ correctly
                shell_config_file = _expand_effective_user_path(shell_config_file)

                # Create file if it doesn't exist
                if not os.path.exists(shell_config_file):
                    # Create parent directory if needed (for fish)
                    parent_dir = os.path.dirname(shell_config_file)
                    if parent_dir:
                        os.makedirs(parent_dir, exist_ok=True)
                    with open(shell_config_file, "w", encoding="utf-8") as f:
                        f.write("")  # Create empty file
                    print_info(f"Created shell config file: {shell_config_file}")

                with open(shell_config_file, "r", encoding="utf-8") as f:
                    content = f.read()

                # Check if pyenv is already configured
                pyenv_already_configured = "pyenv_root" in content and (
                    "pyenv init" in content or "pyenv init -" in content
                )

                if not pyenv_already_configured:
                    # Add pyenv configuration
                    with open(shell_config_file, "a", encoding="utf-8") as f:
                        f.write("\n# Pyenv configuration\n")
                        for line in pyenv_config_lines:
                            f.write(f"{line}\n")
                    print_success(f"Added pyenv configuration to {shell_config_file}")
                    configured_current_shell = True
                else:
                    print_info_verbose(
                        f"Pyenv already configured in {shell_config_file}"
                    )
                    configured_current_shell = True

            except Exception as e:
                telemetry.capture_exception(e)
                print_warning(f"Could not configure pyenv in {shell_config_file}: {e}")

        # Also configure universal profile as backup (for bash/zsh syntax)
        if shell_name in ["bash", "zsh"]:
            profile_file = _expand_effective_user_path("~/.profile")
            if profile_file != shell_config_file and os.path.exists(profile_file):
                try:
                    with open(profile_file, "r", encoding="utf-8") as f:
                        content = f.read()

                    pyenv_already_configured = "pyenv_root" in content and (
                        "pyenv init" in content or "pyenv init -" in content
                    )

                    if not pyenv_already_configured:
                        with open(profile_file, "a", encoding="utf-8") as f:
                            f.write("\n# Pyenv configuration\n")
                            for line in pyenv_config_lines:
                                f.write(f"{line}\n")
                        print_info_verbose(
                            f"Added pyenv configuration to {profile_file} (backup)"
                        )
                except Exception as e:
                    print_info_verbose(
                        f"Could not configure pyenv in {profile_file}: {e}"
                    )

        return configured_current_shell or True

    except Exception as e:
        telemetry.capture_exception(e)
        print_warning(f"Error configuring pyenv in shell: {e}")
        return False


def _is_pyenv_available(env=None):
    """Check if pyenv is available in the system (in PATH or default location).

    Args:
        env (dict, optional): Environment variables for subprocess

    Returns:
        tuple: (bool, str, list) - (is_available, version_output, pyenv_cmd_list)
              pyenv_cmd_list is either ["pyenv"] or [path_to_pyenv_executable]
    """
    # Try "pyenv" from PATH first
    try:
        result = run_command(
            ["pyenv", "--version"], check=False, capture_output=True, text=True, env=env
        )
        if result and result.returncode == 0:
            stdout_text = result.stdout.strip() if result.stdout else ""
            return True, stdout_text, ["pyenv"]
    except FileNotFoundError:
        # pyenv not in PATH, continue to check default location
        pass
    except Exception as e:
        # Other errors (e.g., permission issues) - log but continue to check default location
        print_info_verbose(f"Error checking pyenv in PATH: {e}")

    # If not in PATH, check default install location
    pyenv_root = _expand_effective_user_path("~/.pyenv")  # pylint: disable=invalid-name
    expected_pyenv_executable = os.path.join(pyenv_root, "bin", "pyenv")

    if os.path.exists(expected_pyenv_executable):
        try:
            # Check if executable has proper permissions
            if not os.access(expected_pyenv_executable, os.X_OK):
                # Try to fix permissions
                try:
                    os.chmod(expected_pyenv_executable, 0o755)
                except OSError:
                    pass  # If we can't fix permissions, try anyway

            result = run_command(
                [expected_pyenv_executable, "--version"],
                check=False,
                capture_output=True,
                text=True,
                env=env,
            )
            if result and result.returncode == 0:
                stdout_text = result.stdout.strip() if result.stdout else ""
                return True, stdout_text, [expected_pyenv_executable]
            # Executable exists but doesn't work - return more specific error
            error_msg = (
                result.stderr.strip()
                if result and result.stderr
                else f"pyenv found at {expected_pyenv_executable} but --version failed"
            )
            return False, error_msg, None
        except FileNotFoundError:
            # This shouldn't happen if os.path.exists() returned True, but handle it anyway
            return (
                False,
                f"pyenv executable not found at {expected_pyenv_executable}",
                None,
            )
        except Exception as e:
            return (
                False,
                f"Error executing pyenv at {expected_pyenv_executable}: {e}",
                None,
            )
    else:
        # pyenv directory might exist but executable is missing
        if os.path.exists(pyenv_root):
            return (
                False,
                f"pyenv directory exists at {pyenv_root} but executable not found at {expected_pyenv_executable}",
                None,
            )
        return False, "pyenv not found in PATH or default location", None


def _is_pyenv_accessible(env=None):
    """Check if pyenv is accessible and can execute commands.

    Args:
        env (dict, optional): Environment variables for subprocess

    Returns:
        tuple: (bool, str) - (is_accessible, output_or_error)
    """
    try:
        pyenv_available, _, pyenv_cmd_list = _is_pyenv_available(env)
        if not pyenv_available or not pyenv_cmd_list:
            return False, "pyenv is not available"

        # Try to run a simple pyenv command
        result = run_command(
            pyenv_cmd_list + ["version"],
            check=False,
            capture_output=True,
            text=True,
            env=env,
        )
        if result and result.returncode == 0:
            stdout_text = result.stdout.strip() if result.stdout else ""
            return True, stdout_text
        stderr_text = (
            result.stderr.strip()
            if result and result.stderr
            else "Command failed with no error output"
        )
        return False, stderr_text
    except Exception as e:
        return False, str(e)


def _is_python_version_installed_in_pyenv(python_version, env=None):
    """Check if a specific Python version is installed in pyenv.

    Args:
        python_version (str): Python version to check (e.g., "3.12.3")
        env (dict, optional): Environment variables for subprocess

    Returns:
        tuple: (bool, str) - (is_installed, versions_output_or_error)
    """
    try:
        pyenv_available, _, pyenv_cmd_list = _is_pyenv_available(env)
        if not pyenv_available or not pyenv_cmd_list:
            return False, "pyenv is not available"

        # Get list of installed versions
        result = run_command(
            pyenv_cmd_list + ["versions", "--bare"],
            check=False,
            capture_output=True,
            text=True,
            env=env,
        )
        if result and result.returncode == 0:
            versions_output = result.stdout.strip() if result.stdout else ""
            # Check if the requested version is in the list
            # pyenv versions --bare outputs one version per line
            installed_versions = [
                v.strip() for v in versions_output.split("\n") if v.strip()
            ]

            # Check exact match first
            if python_version in installed_versions:
                return True, versions_output

            # Check if any installed version matches major.minor (e.g., 3.12.x)
            expected_major_minor = ".".join(python_version.split(".")[:2])
            for installed_version in installed_versions:
                installed_major_minor = ".".join(installed_version.split(".")[:2])
                if installed_major_minor == expected_major_minor:
                    return (
                        True,
                        f"Found compatible version {installed_version} (requested {python_version})",
                    )

            return False, versions_output or "No versions installed"
        stderr_text = (
            result.stderr.strip()
            if result.stderr
            else "Command failed with no error output"
        )
        return False, stderr_text
    except Exception as e:
        return False, str(e)


def _check_and_ensure_pyenv_status(python_version="3.12.3", auto_configure=True):
    """Check pyenv status and ensure it's properly configured.

    This is a comprehensive helper that checks all aspects of pyenv:
    - Installation status (directory and executable existence)
    - PATH availability (in current session)
    - Accessibility (can execute commands)
    - Python version installation
    - PATH configuration (in shell config)

    If auto_configure is True, automatically configures pyenv in PATH when needed.

    Args:
        python_version (str): Python version to check (default: "3.12.3")
        auto_configure (bool): If True, automatically configure pyenv in PATH when needed

    Returns:
        dict: Status dictionary with keys:
            - installed: bool - pyenv directory exists
            - executable_exists: bool - pyenv executable exists
            - available: bool - pyenv is available in PATH
            - accessible: bool - pyenv can execute commands
            - python_installed: bool - requested Python version is installed
            - path_configured: bool - pyenv is configured in shell config
            - session_path_configured: bool - pyenv is in current session PATH
            - pyenv_version: str - pyenv version string (if available)
            - pyenv_cmd_list: list - command list to use pyenv (if available)
            - python_versions_output: str - output from pyenv versions (if available)
            - path_info: dict - detailed PATH configuration info
            - shell_configured: bool - whether shell config was configured in this call
            - session_configured: bool - whether session PATH was configured in this call
            - shims_need_rehash: bool - whether pyenv shims need to be regenerated
    """
    check_env = os.environ.copy()
    _apply_effective_user_home_to_env(check_env)
    pyenv_root = _expand_effective_user_path("~/.pyenv")  # pylint: disable=invalid-name
    check_env["pyenv_root"] = pyenv_root
    check_env["PYENV_ROOT"] = pyenv_root
    pyenv_shims_path = os.path.join(pyenv_root, "shims")
    pyenv_bin_path = os.path.join(pyenv_root, "bin")
    current_path_parts = (
        check_env.get("PATH", "").split(os.pathsep) if check_env.get("PATH") else []
    )
    if pyenv_bin_path not in current_path_parts:
        current_path_parts.insert(0, pyenv_bin_path)
    if pyenv_shims_path not in current_path_parts:
        current_path_parts.insert(0, pyenv_shims_path)
    check_env["PATH"] = os.pathsep.join([p for p in current_path_parts if p])
    try:
        marked_home = mark_sensitive(check_env.get("HOME", ""), "path")
        marked_pyenv_root = mark_sensitive(pyenv_root, "path")
        print_info_debug(
            f"[pyenv] check env: HOME={marked_home} PYENV_ROOT={marked_pyenv_root} "
            f"bin_in_path={pyenv_bin_path in check_env.get('PATH', '')} "
            f"shims_in_path={pyenv_shims_path in check_env.get('PATH', '')}"
        )
        pyenv_root_probe = run_command(
            [os.path.join(pyenv_root, "bin", "pyenv"), "root"],
            check=False,
            capture_output=True,
            text=True,
            env=check_env,
        )
        if pyenv_root_probe and pyenv_root_probe.stdout:
            marked_probe = mark_sensitive(pyenv_root_probe.stdout.strip(), "path")
            print_info_debug(f"[pyenv] pyenv root probe: {marked_probe}")
    except Exception as exc:
        telemetry.capture_exception(exc)
    status = {
        "installed": False,
        "executable_exists": False,
        "available": False,
        "accessible": False,
        "python_installed": False,
        "path_configured": False,
        "session_path_configured": False,
        "pyenv_version": "",
        "pyenv_cmd_list": None,
        "python_versions_output": "",
        "path_info": {},
        "shell_configured": False,
        "session_configured": False,
    }

    # Check installation status
    status["installed"] = os.path.exists(pyenv_root)
    pyenv_executable = os.path.join(pyenv_root, "bin", "pyenv")
    status["executable_exists"] = os.path.exists(pyenv_executable)

    # Check availability in PATH
    pyenv_available, pyenv_version, pyenv_cmd_list = _is_pyenv_available(check_env)
    status["available"] = pyenv_available
    status["pyenv_version"] = pyenv_version if pyenv_version else ""
    status["pyenv_cmd_list"] = pyenv_cmd_list

    # If not available but executable exists, try to configure
    if not pyenv_available and status["executable_exists"] and auto_configure:
        shell_configured, session_configured = _ensure_pyenv_in_path()
        status["shell_configured"] = shell_configured
        status["session_configured"] = session_configured
        # Re-check availability after configuration
        # Rebuild env after potentially writing shell config / updating PATH.
        check_env = os.environ.copy()
        _apply_effective_user_home_to_env(check_env)
        check_env["pyenv_root"] = pyenv_root
        check_env["PYENV_ROOT"] = pyenv_root
        current_path_parts = (
            check_env.get("PATH", "").split(os.pathsep) if check_env.get("PATH") else []
        )
        if pyenv_bin_path not in current_path_parts:
            current_path_parts.insert(0, pyenv_bin_path)
        if pyenv_shims_path not in current_path_parts:
            current_path_parts.insert(0, pyenv_shims_path)
        check_env["PATH"] = os.pathsep.join([p for p in current_path_parts if p])
        pyenv_available, pyenv_version, pyenv_cmd_list = _is_pyenv_available(check_env)
        status["available"] = pyenv_available
        status["pyenv_version"] = pyenv_version if pyenv_version else ""
        status["pyenv_cmd_list"] = pyenv_cmd_list

    # Check accessibility (only if available)
    if status["available"]:
        pyenv_accessible, _ = _is_pyenv_accessible(check_env)
        status["accessible"] = pyenv_accessible

    # Check Python version installation
    if status["available"]:
        python_installed, python_versions_output = (
            _is_python_version_installed_in_pyenv(python_version, check_env)
        )
        status["python_installed"] = python_installed
        status["python_versions_output"] = python_versions_output
    elif status["executable_exists"]:
        # pyenv is installed but not in PATH - try with full path
        check_env = os.environ.copy()
        _apply_effective_user_home_to_env(check_env)
        check_env["pyenv_root"] = pyenv_root
        check_env["PYENV_ROOT"] = pyenv_root
        pyenv_bin_path = os.path.join(pyenv_root, "bin")
        pyenv_shims_path = os.path.join(pyenv_root, "shims")
        current_path_parts = (
            check_env.get("PATH", "").split(os.pathsep) if check_env.get("PATH") else []
        )
        if pyenv_bin_path not in current_path_parts:
            current_path_parts.insert(0, pyenv_bin_path)
        if pyenv_shims_path not in current_path_parts:
            current_path_parts.insert(0, pyenv_shims_path)
        check_env["PATH"] = os.pathsep.join([p for p in current_path_parts if p])
        python_installed, python_versions_output = (
            _is_python_version_installed_in_pyenv(python_version, check_env)
        )
        status["python_installed"] = python_installed
        status["python_versions_output"] = python_versions_output

    # Check PATH configuration
    path_configured, path_info = _is_pyenv_path_configured()
    status["path_configured"] = path_configured
    status["path_info"] = path_info

    # Check if pyenv is in current session PATH
    current_path = check_env.get("PATH", "")
    status["session_path_configured"] = pyenv_shims_path in current_path.split(
        os.pathsep
    ) or pyenv_bin_path in current_path.split(os.pathsep)

    # Check if shims need to be regenerated (shims directory exists but is empty or missing shims)
    # This can happen if Python was installed but shims weren't regenerated
    shims_need_rehash = False
    if status["executable_exists"] and status["python_installed"]:
        if os.path.isdir(pyenv_shims_path):
            # Check if shims directory has any shim files (at least python and pip should exist)
            try:
                shim_files = os.listdir(pyenv_shims_path)
                # Filter out non-shim files (like .gitkeep if it exists)
                shim_files = [f for f in shim_files if not f.startswith(".")]
                # If shims directory exists but has no shim files, they need to be regenerated
                if len(shim_files) == 0:
                    shims_need_rehash = True
            except OSError:
                # Can't read directory, assume it's fine
                pass
        elif status["python_installed"]:
            # Python is installed but shims directory doesn't exist - needs rehash
            shims_need_rehash = True

    status["shims_need_rehash"] = shims_need_rehash

    return status


def _regenerate_pyenv_shims(pyenv_cmd_list=None):
    """Regenerate pyenv shims by running 'pyenv rehash'.

    This is needed when Python versions are installed but shims haven't been created yet.

    Args:
        pyenv_cmd_list (list, optional): Command list to use pyenv. If None, will try to detect.

    Returns:
        bool: True if rehash was successful, False otherwise
    """
    try:
        if pyenv_cmd_list is None:
            pyenv_available, _, pyenv_cmd_list = _is_pyenv_available(os.environ)
            if not pyenv_available or not pyenv_cmd_list:
                print_warning("Cannot regenerate pyenv shims: pyenv not available")
                return False

        print_info("Regenerating pyenv shims...")
        clean_env = _get_clean_env_for_compilation()
        pyenv_root = _expand_effective_user_path("~/.pyenv")  # pylint: disable=invalid-name
        _apply_effective_user_home_to_env(clean_env)
        clean_env["pyenv_root"] = pyenv_root
        clean_env["PYENV_ROOT"] = pyenv_root

        # Ensure pyenv bin is in PATH for rehash command
        pyenv_bin_path = os.path.join(pyenv_root, "bin")
        clean_env_path = clean_env.get("PATH", "")
        if pyenv_bin_path not in clean_env_path:
            clean_env["PATH"] = f"{pyenv_bin_path}:{clean_env_path}"

        run_command(pyenv_cmd_list + ["rehash"], check=True, env=clean_env)
        print_success("pyenv shims regenerated successfully")
        return True
    except Exception as e:
        telemetry.capture_exception(e)
        print_warning(f"Failed to regenerate pyenv shims: {e}")
        return False


def _fix_pyenv_shims_permissions(pyenv_root: str, *, require_sudo: bool) -> bool:
    """Fix common pyenv permission issues where shims are owned by root.

    Args:
        pyenv_root: Path to the pyenv root (e.g., ~/.pyenv for the effective user)
        require_sudo: If True, attempt privileged ownership repair (sudo/chown) when needed.

    Returns:
        True if permissions look corrected enough for rehash to work, else False.
    """
    try:
        pyenv_shims_path = os.path.join(pyenv_root, "shims")
        os.makedirs(pyenv_shims_path, exist_ok=True)

        # If already writable, nothing to do.
        if os.access(pyenv_shims_path, os.W_OK):
            return True

        # If current user owns the dir, chmod is enough.
        try:
            st = os.stat(pyenv_shims_path)
            if st.st_uid == os.getuid():
                run_command(
                    ["chmod", "-R", "u+rwX", pyenv_shims_path],
                    check=False,
                    capture_output=True,
                    timeout=30,
                )
                return bool(os.access(pyenv_shims_path, os.W_OK))
        except Exception:
            pass

        if not require_sudo:
            return False

        if not _sudo_validate():
            return False

        import pwd

        target_user = os.environ.get("SUDO_USER") or pwd.getpwuid(os.getuid()).pw_name
        # Assume the common "user:user" ownership pattern.
        run_command(
            ["sudo", "-n", "chown", "-R", f"{target_user}:{target_user}", pyenv_root],
            check=False,
            capture_output=True,
            timeout=60,
        )
        run_command(
            ["sudo", "-n", "chmod", "-R", "u+rwX", pyenv_root],
            check=False,
            capture_output=True,
            timeout=60,
        )

        return bool(os.access(pyenv_shims_path, os.W_OK))
    except Exception as exc:  # pragma: no cover - environment dependent
        telemetry.capture_exception(exc)
        return False


def _is_pyenv_path_configured():
    """Check if pyenv shims and bin directories are in PATH.

    Returns:
        tuple: (bool, dict) - (is_configured, path_info)
              path_info contains: shims_in_path, bin_in_path, shims_path, bin_path
    """
    try:
        pyenv_root = _expand_effective_user_path("~/.pyenv")  # pylint: disable=invalid-name
        pyenv_shims_path = os.path.join(pyenv_root, "shims")
        pyenv_bin_path = os.path.join(pyenv_root, "bin")

        current_path = os.environ.get("PATH", "")
        path_parts = current_path.split(os.pathsep)

        shims_in_path = pyenv_shims_path in path_parts
        bin_in_path = pyenv_bin_path in path_parts

        path_info = {
            "shims_in_path": shims_in_path,
            "bin_in_path": bin_in_path,
            "shims_path": pyenv_shims_path,
            "bin_path": pyenv_bin_path,
            "shims_exists": os.path.isdir(pyenv_shims_path),
            "bin_exists": os.path.isdir(pyenv_bin_path),
            "shims_writable": os.access(pyenv_shims_path, os.W_OK)
            if os.path.isdir(pyenv_shims_path)
            else None,
            "bin_writable": os.access(pyenv_bin_path, os.W_OK)
            if os.path.isdir(pyenv_bin_path)
            else None,
        }

        # Consider configured if both shims and bin are in PATH, or if they don't exist yet
        is_configured = (shims_in_path and bin_in_path) or (
            not path_info["shims_exists"] and not path_info["bin_exists"]
        )

        return is_configured, path_info
    except Exception as e:
        return False, {"error": str(e)}


def _install_pyenv_python_and_venv(python_version="3.12.3", venv_path=None):
    """Install and configure pyenv, Python version, and create virtual environment.

    This function handles the complete pyenv/Python/venv setup:
    1. Detects or installs pyenv
    2. Configures PATH for pyenv in current session
    3. Installs Python version using pyenv (if not already installed)
    4. Creates virtual environment with fallback logic for pip installation

    Note: This function assumes Python build dependencies are already installed.
    Install them before calling this function.

    Args:
        python_version (str): Python version to install (e.g., "3.12.3")
        venv_path (str, optional): Path to virtual environment. Defaults to ADSCAN_BASE_DIR/venv

    Returns:
        tuple: (success: bool, pyenv_cmd_list: list or None, python_executable_path: str or None)
    """
    if venv_path is None:
        venv_path = os.path.join(ADSCAN_BASE_DIR, "venv")

    pyenv_root = _expand_effective_user_path("~/.pyenv")  # pylint: disable=invalid-name
    expected_pyenv_executable = os.path.join(pyenv_root, "bin", "pyenv")
    pyenv_cmd_list = None
    pyenv_detected = False
    pyenv_target_user = os.environ.get("SUDO_USER") or os.environ.get("USER")

    # Step 1: Detect or install pyenv
    print_info("Checking for pyenv...")
    try:
        # Use the same helper function as handle_check for consistency
        pyenv_available, pyenv_version, pyenv_cmd_list = _is_pyenv_available(os.environ)

        if pyenv_available and pyenv_cmd_list:
            pyenv_detected = True
            if pyenv_cmd_list[0] == "pyenv":
                print_success(f"pyenv found in PATH: {pyenv_version}")
            else:
                print_success(f"pyenv found at {pyenv_cmd_list[0]}: {pyenv_version}")
        elif os.path.exists(expected_pyenv_executable) and not os.access(
            expected_pyenv_executable, os.X_OK
        ):
            # Handle case where executable exists but lacks execute permissions
            print_warning(
                f"pyenv executable found at {expected_pyenv_executable} but is not executable. Fixing permissions..."
            )
            try:
                os.chmod(expected_pyenv_executable, 0o755)
                # Retry after fixing permissions
                pyenv_available, pyenv_version, pyenv_cmd_list = _is_pyenv_available(
                    os.environ
                )
                if pyenv_available and pyenv_cmd_list:
                    pyenv_detected = True
                    print_success(
                        f"pyenv found at {pyenv_cmd_list[0]}: {pyenv_version}"
                    )
            except Exception as perm_e:
                telemetry.capture_exception(perm_e)
                print_warning(f"Failed to fix pyenv permissions: {perm_e}")
    except Exception as check_e:
        telemetry.capture_exception(check_e)
        print_warning(f"Error checking pyenv: {check_e}")

    # Install pyenv if not detected
    if not pyenv_detected:
        print_warning("pyenv not detected. Attempting to install pyenv...")
        should_remove_existing = False
        if os.path.exists(pyenv_root):
            if os.path.exists(expected_pyenv_executable):
                if not os.access(expected_pyenv_executable, os.X_OK):
                    should_remove_existing = True
                else:
                    should_remove_existing = True
            else:
                should_remove_existing = True

        if should_remove_existing:
            try:
                shutil.rmtree(pyenv_root)
                print_info(f"Removed existing pyenv directory at {pyenv_root}")
            except Exception as rm_e:
                telemetry.capture_exception(rm_e)
                print_warning(
                    f"Failed to remove existing pyenv directory {pyenv_root}: {rm_e}"
                )

        try:
            clean_env = _get_clean_env_for_compilation()
            _apply_effective_user_home_to_env(clean_env)
            clean_env["PYENV_ROOT"] = pyenv_root
            clean_env["pyenv_root"] = pyenv_root
            run_command(
                ["sh", "-c", "curl -fsSL https://pyenv.run | bash"],
                check=True,
                env=clean_env,
            )
            print_success("pyenv installation script executed.")

            if os.path.exists(expected_pyenv_executable):
                try:
                    os.chmod(expected_pyenv_executable, 0o755)
                except OSError:
                    pass

                # Use the same helper function as handle_check for consistency
                pyenv_available, pyenv_version, pyenv_cmd_list = _is_pyenv_available(
                    os.environ
                )
                if pyenv_available and pyenv_cmd_list:
                    print_success(
                        f"pyenv installed and found at {pyenv_cmd_list[0]}: {pyenv_version}"
                    )

                    print_info("Configuring pyenv in shell profiles...")
                    if _configure_pyenv_shell():
                        print_success("Pyenv shell configuration completed")
                        print_info(
                            "   Restart your terminal or run: source ~/.bashrc (or ~/.zshrc) to activate pyenv"
                        )
                    else:
                        print_warning(
                            "Pyenv shell configuration had issues, but pyenv is installed"
                        )
                else:
                    print_error(
                        f"pyenv installation script ran, but pyenv is not accessible: {pyenv_version}"
                    )
                    return False, None, None
            else:
                # Defensive: if installer wrote to a different HOME, surface a more helpful message.
                root_pyenv = os.path.join("/root", ".pyenv", "bin", "pyenv")
                if os.path.exists(root_pyenv):
                    print_warning(
                        f"pyenv was installed under /root but expected under {pyenv_root}."
                    )
                    print_instruction(
                        "Run `adscan install` without a forced root HOME, or remove /root/.pyenv and retry."
                    )
                print_error(
                    f"pyenv installation script ran, but executable not found at {expected_pyenv_executable}."
                )
                return False, None, None
        except Exception as install_e:
            telemetry.capture_installation_failed(install_e)
            print_error_context(
                "Failed to install pyenv",
                context={
                    "expected_path": expected_pyenv_executable,
                    "home": _get_effective_user_home(),
                },
                suggestions=[
                    "Check internet connection for curl download",
                    "Verify ~/.bashrc or ~/.zshrc exists and is writable",
                    "Try manual install: curl https://pyenv.run | bash",
                    "Check installation guide: https://github.com/pyenv/pyenv#installation",
                ],
                show_exception=True,
                exception=install_e,
            )
            return False, None, None
    else:
        print_success(
            "[bold]pyenv[/bold] is already installed and available",
            panel=True,
        )

    # Ensure permissions are correct (legacy installs could leave root-owned shims).
    try:
        if pyenv_target_user:
            if os.geteuid() == 0:
                run_command(
                    [
                        "chown",
                        "-R",
                        f"{pyenv_target_user}:{pyenv_target_user}",
                        pyenv_root,
                    ],
                    check=False,
                    capture_output=True,
                    timeout=60,
                )
                run_command(
                    ["chmod", "-R", "u+rwX", pyenv_root],
                    check=False,
                    capture_output=True,
                    timeout=60,
                )
            else:
                # Best effort: ensure at least shims is writable for current user.
                _fix_pyenv_shims_permissions(pyenv_root, require_sudo=False)
    except Exception as exc:  # pragma: no cover - best effort
        telemetry.capture_exception(exc)

    if not pyenv_cmd_list:
        print_error("Could not determine pyenv command after installation attempts.")
        return False, None, None

    # Step 2: Configure PATH for pyenv in current session and shell config
    print_info("Configuring PATH for pyenv...")
    shell_configured, session_configured = _ensure_pyenv_in_path()

    if not shell_configured:
        # If shell config wasn't configured, try to configure it now
        if _configure_pyenv_shell():
            print_success("pyenv configured in shell config file")

    if session_configured:
        print_success("pyenv added to current session PATH")

    # Ensure pyenv_root is set (in case _configure_pyenv_path_in_session didn't run)
    os.environ["pyenv_root"] = pyenv_root
    os.environ["PYENV_ROOT"] = pyenv_root
    print_info_verbose(f"pyenv_root set to: {pyenv_root}")

    # Update pyenv_cmd_list if it's now available in PATH
    pyenv_available, _, updated_pyenv_cmd_list = _is_pyenv_available(os.environ)
    if pyenv_available and updated_pyenv_cmd_list:
        pyenv_cmd_list = updated_pyenv_cmd_list

    # Step 3: Install Python version
    try:
        # Define pyenv paths for use in subprocess environments
        pyenv_shims_path = os.path.join(pyenv_root, "shims")
        pyenv_bin_path = os.path.join(pyenv_root, "bin")

        versions_result = run_command(
            pyenv_cmd_list + ["versions"], capture_output=True
        )
        versions_output = (
            versions_result.stdout if versions_result and versions_result.stdout else ""
        )
        if python_version not in versions_output:
            print_info(
                f"Python {python_version} not found in pyenv. Installing it now (this may take a while)..."
            )
            try:
                clean_env = _get_clean_env_for_compilation()
                _apply_effective_user_home_to_env(clean_env)
                clean_env["pyenv_root"] = pyenv_root
                clean_env["PYENV_ROOT"] = pyenv_root
                clean_env_path = clean_env.get("PATH", "")
                if pyenv_bin_path not in clean_env_path:
                    clean_env["PATH"] = f"{pyenv_bin_path}:{clean_env_path}"
                if (
                    pyenv_shims_path
                    and os.path.isdir(pyenv_shims_path)
                    and pyenv_shims_path not in clean_env_path
                ):
                    clean_env["PATH"] = f"{pyenv_shims_path}:{clean_env['PATH']}"
                run_command(
                    pyenv_cmd_list + ["install", python_version],
                    check=True,
                    env=clean_env,
                )
                print_success(
                    f"Python {python_version} installed successfully using pyenv!"
                )

                # Verify installation
                constructed_python_path = os.path.join(
                    pyenv_root, "versions", python_version, "bin", "python"
                )
                if os.path.exists(constructed_python_path):
                    try:
                        installed_versions_result = run_command(
                            pyenv_cmd_list + ["versions", "--bare"], capture_output=True
                        )
                        installed_versions_output = (
                            installed_versions_result.stdout
                            if installed_versions_result
                            and installed_versions_result.stdout
                            else ""
                        )
                        if python_version not in installed_versions_output:
                            print_error(
                                f"Python {python_version} installation completed but pyenv doesn't recognize it as installed."
                            )
                            return False, pyenv_cmd_list, None

                        test_result = run_command(
                            [constructed_python_path, "--version"],
                            check=True,
                            capture_output=True,
                            text=True,
                            timeout=10,
                        )
                        version_output = test_result.stdout.strip()
                        version_match = re.search(r"(\d+\.\d+\.\d+)", version_output)
                        if version_match:
                            actual_version = version_match.group(1)
                            expected_major_minor = ".".join(
                                python_version.split(".")[:2]
                            )
                            actual_major_minor = ".".join(actual_version.split(".")[:2])
                            if expected_major_minor != actual_major_minor:
                                print_error(
                                    f"Python {python_version} was installed but version mismatch detected. Expected {expected_major_minor}.x, got {actual_version}"
                                )
                                return False, pyenv_cmd_list, None
                            if actual_version != python_version:
                                print_warning(
                                    f"Python version mismatch: pyenv installed {python_version} but executable reports {actual_version}"
                                )
                                print_warning(
                                    "This may indicate pyenv installed a different patch version than requested."
                                )

                                # Test basic imports and critical extensions
                                try:
                                    subprocess.run(
                                        [
                                            constructed_python_path,
                                            "-c",
                                            "import sys, os, subprocess; print('Python basic modules OK')",
                                        ],
                                        capture_output=True,
                                        text=True,
                                        timeout=10,
                                        check=True,
                                    )

                                    missing_extensions = []
                                    for ext in ["ssl", "bz2", "readline"]:
                                        try:
                                            subprocess.run(
                                                [
                                                    constructed_python_path,
                                                    "-c",
                                                    f"import {ext}",
                                                ],
                                                capture_output=True,
                                                text=True,
                                                timeout=5,
                                                check=True,
                                            )
                                        except subprocess.CalledProcessError:
                                            missing_extensions.append(ext)

                                    if missing_extensions:
                                        print_warning(
                                            f"Python installation is missing critical extensions: {', '.join(missing_extensions)}"
                                        )
                                        print_warning(
                                            "This may cause issues with package installation and SSL connections."
                                        )
                                        print_info(
                                            "   This usually means build dependencies were missing during compilation."
                                        )
                                        print_info(
                                            "   Install dependencies and reinstall Python:"
                                        )
                                        print_info(
                                            "     sudo apt-get install -y build-essential libssl-dev zlib1g-dev libbz2-dev libreadline-dev"
                                        )
                                        print_info(
                                            f"     pyenv uninstall {python_version} && pyenv install {python_version}"
                                        )
                                    else:
                                        print_info_verbose(
                                            "Python basic functionality verified (imports and critical extensions work)"
                                        )

                                except (
                                    subprocess.CalledProcessError,
                                    subprocess.TimeoutExpired,
                                ) as import_test_e:
                                    telemetry.capture_exception(import_test_e)
                                    print_error(
                                        f"Python installation appears corrupted - basic imports failed: {import_test_e}"
                                    )
                                    print_info(
                                        f"   Try reinstalling Python: pyenv uninstall {python_version} && pyenv install {python_version}"
                                    )
                    except (
                        subprocess.CalledProcessError,
                        subprocess.TimeoutExpired,
                        FileNotFoundError,
                    ) as verify_e:
                        telemetry.capture_exception(verify_e)
                        print_error(
                            f"Python {python_version} was installed but cannot be executed: {verify_e}"
                        )
                        return False, pyenv_cmd_list, None
                else:
                    print_error(
                        f"Python {python_version} installation completed but executable not found"
                    )
                    return False, pyenv_cmd_list, None
            except subprocess.CalledProcessError as e:
                telemetry.capture_exception(e)
                print_error(
                    f"Failed to install Python {python_version} using pyenv: {e}"
                )

                error_output = e.stderr if hasattr(e, "stderr") and e.stderr else ""
                error_output += e.stdout if hasattr(e, "stdout") and e.stdout else ""

                missing_deps = []
                if "bz2" in error_output.lower() or "bzip2" in error_output.lower():
                    missing_deps.append("libbz2-dev / bzip2-devel")
                if "readline" in error_output.lower():
                    missing_deps.append("libreadline-dev / readline-devel")
                if "ssl" in error_output.lower() or "openssl" in error_output.lower():
                    missing_deps.append("libssl-dev / openssl-devel")
                if "zlib" in error_output.lower():
                    missing_deps.append("zlib1g-dev / zlib-devel")

                if missing_deps:
                    print_error(
                        "Python installation failed due to missing build dependencies."
                    )
                    print_error("Missing dependencies detected:")
                    for dep in missing_deps:
                        print_error(f"  - {dep}")
                    print_info("")
                    print_info("To fix this, install the required build dependencies:")
                    print_info("")
                    print_info("  For Debian/Ubuntu/Kali:")
                    print_info("    sudo apt-get update")
                    print_info(
                        "    sudo apt-get install -y build-essential libssl-dev zlib1g-dev \\"
                    )
                    print_info(
                        "        libbz2-dev libreadline-dev libsqlite3-dev curl \\"
                    )
                    print_info(
                        "        libncursesw5-dev xz-utils tk-dev libffi-dev liblzma-dev"
                    )
                    print_info("")
                    print_info("  For RHEL/CentOS/Fedora:")
                    print_info("    sudo yum groupinstall -y 'Development Tools'")
                    print_info(
                        "    sudo yum install -y openssl-devel zlib-devel bzip2-devel \\"
                    )
                    print_info(
                        "        readline-devel sqlite-devel curl ncurses-devel \\"
                    )
                    print_info("        xz-devel tk-devel libffi-devel")
                else:
                    print_info(
                        "Make sure you have the necessary build dependencies for Python."
                    )
                    print_info(
                        "E.g., on Debian/Ubuntu/Kali: sudo apt-get install -y build-essential libssl-dev zlib1g-dev libbz2-dev libreadline-dev libsqlite3-dev curl libncursesw5-dev xz-utils tk-dev libffi-dev liblzma-dev"
                    )

                return False, pyenv_cmd_list, None
            except Exception as e:
                telemetry.capture_exception(e)
                print_error(
                    f"Unexpected error installing Python {python_version} using pyenv: {e}"
                )
                return False, pyenv_cmd_list, None
        else:
            print_info(f"Python {python_version} is already installed in pyenv.")
    except Exception as e:
        telemetry.capture_installation_failed(e)
        print_error("Error checking pyenv versions.")
        print_exception(show_locals=False, exception=e)
        return False, pyenv_cmd_list, None

    # Step 4: Determine Python executable path
    constructed_python_path = os.path.join(
        pyenv_root, "versions", python_version, "bin", "python"
    )
    python_executable_path = None
    if os.path.exists(constructed_python_path):
        python_executable_path = constructed_python_path
        print_info(f"Python executable for venv found at: {python_executable_path}")
    else:
        print_warning(
            f"Constructed Python executable not found at {constructed_python_path}. Attempting 'pyenv which python'..."
        )
        try:
            run_command(pyenv_cmd_list + ["global", python_version], check=True)
            print_info(
                f"Set pyenv global version to {python_version} for this session."
            )
            which_python_result = run_command(
                pyenv_cmd_list + ["which", "python"], capture_output=True
            )
            which_python_output = (
                which_python_result.stdout.strip()
                if which_python_result and which_python_result.stdout
                else ""
            )
            if (
                which_python_output
                and os.path.isabs(which_python_output)
                and os.path.exists(which_python_output)
                and python_version in which_python_output
            ):
                python_executable_path = which_python_output
                print_info(
                    f"Python executable for venv found via 'pyenv which python': {python_executable_path}"
                )
            else:
                if os.path.exists(constructed_python_path):
                    python_executable_path = constructed_python_path
                    print_info(
                        f"Reverting to constructed Python executable: {python_executable_path}"
                    )
        except Exception as e_which:
            telemetry.capture_exception(e_which)
            print_warning(
                f"Failed to determine Python executable using 'pyenv global' or 'pyenv which python': {e_which}"
            )
            if os.path.exists(constructed_python_path):
                python_executable_path = constructed_python_path
                print_info(
                    f"Using initially constructed Python executable: {python_executable_path}"
                )

    if not python_executable_path or not os.path.exists(python_executable_path):
        print_error(
            f"CRITICAL: Could not determine a valid path to Python {python_version} executable using pyenv."
        )
        return False, pyenv_cmd_list, None

    # Step 5: Create virtual environment
    if not os.path.exists(os.path.join(venv_path, "bin", "activate")):
        print_info(f"Creating virtual environment with {python_executable_path}...")

        # Verify ensurepip
        print_info_verbose("Verifying Python installation has ensurepip...")
        try:
            ensurepip_check = subprocess.run(
                [python_executable_path, "-m", "ensurepip", "--version"],
                capture_output=True,
                text=True,
                timeout=10,
                check=False,
            )
            if ensurepip_check.returncode != 0:
                print_warning(
                    "Python's ensurepip module may not be available. This might cause venv creation issues."
                )
                print_info(
                    "   Attempting to create venv anyway - will handle errors if they occur."
                )
        except Exception as ensurepip_check_e:
            print_info_verbose(f"Could not verify ensurepip: {ensurepip_check_e}")

        venv_created = False
        try:
            result = run_command(
                [python_executable_path, "-m", "venv", venv_path], check=False
            )
            if result.returncode == 0:
                print_success(
                    "[bold]Virtual environment[/bold] created successfully",
                    panel=True,
                )
                venv_created = True
            else:
                # Check if venv was partially created
                error_msg = (
                    result.stderr
                    if result.stderr
                    else result.stdout
                    if result.stdout
                    else "Unknown error"
                )
                print_warning(f"Venv creation returned non-zero exit code: {error_msg}")

                if os.path.exists(venv_path):
                    venv_python = os.path.join(venv_path, "bin", "python")
                    venv_pip = os.path.join(venv_path, "bin", "pip3")
                    if os.path.exists(venv_python):
                        python_test = subprocess.run(
                            [venv_python, "--version"],
                            capture_output=True,
                            text=True,
                            timeout=5,
                            check=False,
                        )
                        pip_exists = os.path.exists(venv_pip) or os.path.exists(
                            os.path.join(venv_path, "bin", "pip")
                        )
                        pip_test = None
                        if pip_exists:
                            pip_executable = (
                                venv_pip
                                if os.path.exists(venv_pip)
                                else os.path.join(venv_path, "bin", "pip")
                            )
                            pip_test = subprocess.run(
                                [pip_executable, "--version"],
                                capture_output=True,
                                text=True,
                                timeout=5,
                                check=False,
                            )

                        if (
                            python_test.returncode == 0
                            and pip_exists
                            and pip_test
                            and pip_test.returncode == 0
                        ):
                            print_info(
                                "Virtual environment appears to be functional despite error message."
                            )
                            venv_created = True
                        else:
                            print_warning(
                                "Virtual environment appears to be broken. Will remove and retry."
                            )
                            try:
                                shutil.rmtree(venv_path)
                            except Exception as rm_e:
                                telemetry.capture_exception(rm_e)
                                print_error(f"Could not remove broken venv: {rm_e}")
                                return False, pyenv_cmd_list, python_executable_path
                    else:
                        print_warning(
                            "Virtual environment directory exists but is incomplete. Removing..."
                        )
                        try:
                            shutil.rmtree(venv_path)
                        except Exception as rm_e:
                            telemetry.capture_exception(rm_e)
                            print_error(f"Could not remove incomplete venv: {rm_e}")
                            return False, pyenv_cmd_list, python_executable_path

                if not venv_created:
                    # Try fallback with --without-pip
                    print_info(
                        "Attempting to create venv without pip, then installing pip manually..."
                    )
                    try:
                        result = run_command(
                            [
                                python_executable_path,
                                "-m",
                                "venv",
                                "--without-pip",
                                venv_path,
                            ],
                            check=True,
                        )
                        print_success("Virtual environment created without pip.")

                        # Install pip manually using get-pip.py
                        venv_python = os.path.join(venv_path, "bin", "python")
                        print_info("Installing pip in virtual environment...")
                        get_pip_url = "https://bootstrap.pypa.io/get-pip.py"
                        get_pip_path = os.path.join(ADSCAN_BASE_DIR, "get-pip.py")
                        download_success = False

                        # Try multiple download methods using helper function
                        try:
                            _download_file_with_fallbacks(
                                get_pip_url, get_pip_path, timeout=30
                            )
                            download_success = True
                        except Exception as download_e:
                            telemetry.capture_exception(download_e)
                            print_error(f"Failed to download get-pip.py: {download_e}")

                        if download_success:
                            # Verify downloaded file
                            try:
                                if not os.path.exists(get_pip_path):
                                    print_error("Downloaded get-pip.py file not found.")
                                    return False, pyenv_cmd_list, python_executable_path

                                file_size = os.path.getsize(get_pip_path)
                                if file_size < 1000:
                                    print_error(
                                        f"Downloaded get-pip.py is too small ({file_size} bytes), likely corrupted."
                                    )
                                    try:
                                        os.remove(get_pip_path)
                                    except Exception:
                                        pass
                                    return False, pyenv_cmd_list, python_executable_path

                                # Verify it's a valid Python script
                                try:
                                    with open(get_pip_path, "rb") as f:
                                        first_bytes = f.read(100)
                                        if not (
                                            first_bytes.startswith(
                                                b"#!/usr/bin/env python"
                                            )
                                            or first_bytes.startswith(b"#!")
                                            or b"import" in first_bytes[:500]
                                            or b"#!/usr/bin/python" in first_bytes
                                        ):
                                            print_warning(
                                                "Downloaded file doesn't look like a valid Python script. Verifying..."
                                            )
                                            f.seek(0)
                                            content_start = f.read(500).decode(
                                                "utf-8", errors="ignore"
                                            )
                                            if (
                                                "pip" not in content_start.lower()
                                                and "bootstrap"
                                                not in content_start.lower()
                                            ):
                                                print_error(
                                                    "Downloaded file doesn't appear to be get-pip.py"
                                                )
                                                try:
                                                    os.remove(get_pip_path)
                                                except Exception:
                                                    pass
                                                return (
                                                    False,
                                                    pyenv_cmd_list,
                                                    python_executable_path,
                                                )
                                except Exception as verify_e:
                                    print_warning(
                                        f"Could not verify get-pip.py file: {verify_e}"
                                    )

                                print_info_verbose(
                                    f"Downloaded get-pip.py verified ({file_size} bytes)"
                                )

                                # Verify Python works
                                print_info_verbose(
                                    "Verifying Python executable before installing pip..."
                                )
                                python_test = subprocess.run(
                                    [
                                        venv_python,
                                        "-c",
                                        "import sys; print(sys.version)",
                                    ],
                                    capture_output=True,
                                    text=True,
                                    timeout=10,
                                    check=False,
                                )
                                if python_test.returncode != 0:
                                    print_error(
                                        f"Python executable is not working: {python_test.stderr}"
                                    )
                                    return False, pyenv_cmd_list, python_executable_path

                                # Install pip
                                print_info("Installing pip using get-pip.py...")
                                clean_env = _get_clean_env_for_compilation()
                                venv_bin = os.path.dirname(venv_python)
                                venv_dir = os.path.dirname(venv_bin)
                                clean_env["VIRTUAL_ENV"] = venv_dir
                                clean_env["PATH"] = (
                                    f"{venv_bin}:{clean_env.get('PATH', '')}"
                                )
                                clean_env.pop("PYTHONHOME", None)
                                clean_env.pop("PYTHONPATH", None)

                                try:
                                    run_command(
                                        [venv_python, get_pip_path],
                                        check=True,
                                        env=clean_env,
                                    )
                                    print_success(
                                        "pip installed successfully in virtual environment."
                                    )

                                    # Verify pip installation
                                    venv_bin_dir = os.path.dirname(venv_python)
                                    pip_executable = os.path.join(venv_bin_dir, "pip")
                                    pip3_executable = os.path.join(venv_bin_dir, "pip3")

                                    pip_verified = False
                                    pip_version_output = None

                                    if os.path.exists(pip_executable) or os.path.exists(
                                        pip3_executable
                                    ):
                                        print_info_verbose(
                                            "pip executable found in venv bin directory"
                                        )

                                    # Method 2: Try python -m pip
                                    try:
                                        pip_check = subprocess.run(
                                            [venv_python, "-m", "pip", "--version"],
                                            capture_output=True,
                                            text=True,
                                            timeout=10,
                                            check=True,
                                            env=None,
                                        )
                                        pip_verified = True
                                        pip_version_output = pip_check.stdout.strip()
                                        print_success(
                                            f"pip verified via 'python -m pip': {pip_version_output}"
                                        )
                                    except subprocess.CalledProcessError as pip_check_e:
                                        print_warning(
                                            f"pip check via 'python -m pip' failed: {pip_check_e}"
                                        )

                                    # Method 3: Try direct pip executable
                                    if not pip_verified:
                                        pip_to_try = (
                                            pip_executable
                                            if os.path.exists(pip_executable)
                                            else pip3_executable
                                        )
                                        if os.path.exists(pip_to_try):
                                            try:
                                                pip_check = subprocess.run(
                                                    [pip_to_try, "--version"],
                                                    capture_output=True,
                                                    text=True,
                                                    timeout=10,
                                                    check=True,
                                                    env=None,
                                                )
                                                pip_verified = True
                                                pip_version_output = (
                                                    pip_check.stdout.strip()
                                                )
                                                print_success(
                                                    f"pip verified via executable: {pip_version_output}"
                                                )
                                            except Exception as pip_exe_e:
                                                print_warning(
                                                    f"pip check via executable failed: {pip_exe_e}"
                                                )

                                    # Method 4: Check if pip module is importable
                                    if not pip_verified:
                                        try:
                                            pip_import_check = subprocess.run(
                                                [
                                                    venv_python,
                                                    "-c",
                                                    "import pip; print(pip.__version__)",
                                                ],
                                                capture_output=True,
                                                text=True,
                                                timeout=10,
                                                check=True,
                                                env=None,
                                            )
                                            pip_verified = True
                                            pip_version_output = (
                                                f"pip {pip_import_check.stdout.strip()}"
                                            )
                                            print_success(
                                                f"pip verified via import: {pip_version_output}"
                                            )
                                        except Exception as pip_import_e:
                                            print_warning(
                                                f"pip check via import failed: {pip_import_e}"
                                            )

                                    if pip_verified:
                                        venv_created = True
                                        print_info_verbose(
                                            "Virtual environment is fully functional with pip"
                                        )
                                    else:
                                        print_error(
                                            "pip installation appeared to succeed but pip is not accessible"
                                        )
                                        print_error(
                                            "This may indicate a problem with the virtual environment or Python installation."
                                        )
                                        return (
                                            False,
                                            pyenv_cmd_list,
                                            python_executable_path,
                                        )

                                except subprocess.CalledProcessError as pip_install_e:
                                    telemetry.capture_exception(pip_install_e)
                                    if (
                                        hasattr(pip_install_e, "returncode")
                                        and pip_install_e.returncode < 0
                                    ):
                                        print_error(
                                            f"pip installation failed with signal error (SIGBUS or similar): {pip_install_e}"
                                        )
                                        print_error("This may indicate:")
                                        print_error(
                                            "  - Corrupted Python installation in pyenv"
                                        )
                                        print_error(
                                            "  - Insufficient memory or disk space"
                                        )
                                        print_error("  - Corrupted get-pip.py file")
                                        print_info(
                                            f"   Try: pyenv uninstall {python_version} && pyenv install {python_version}"
                                        )
                                    else:
                                        print_error(
                                            f"Failed to install pip using get-pip.py: {pip_install_e}"
                                        )
                                    return False, pyenv_cmd_list, python_executable_path
                                except Exception as pip_install_e:
                                    telemetry.capture_exception(pip_install_e)
                                    print_error(
                                        f"Failed to install pip using get-pip.py: {pip_install_e}"
                                    )
                                    return False, pyenv_cmd_list, python_executable_path
                                finally:
                                    try:
                                        os.remove(get_pip_path)
                                    except Exception:
                                        pass
                            except Exception as verify_file_e:
                                telemetry.capture_exception(verify_file_e)
                                print_error(
                                    f"Error verifying downloaded get-pip.py: {verify_file_e}"
                                )
                                return False, pyenv_cmd_list, python_executable_path
                        else:
                            print_error(
                                "Failed to download get-pip.py using all available methods."
                            )
                            return False, pyenv_cmd_list, python_executable_path
                    except Exception as venv_retry_e:
                        telemetry.capture_exception(venv_retry_e)
                        print_error(
                            f"Failed to create venv even without pip: {venv_retry_e}"
                        )
                        return False, pyenv_cmd_list, python_executable_path
        except Exception as e:
            telemetry.capture_installation_failed(e)
            print_error(
                f"Failed to create virtual environment using {python_executable_path}: {e}"
            )
            if os.path.exists(venv_path) and not venv_created:
                try:
                    shutil.rmtree(venv_path)
                    print_info("Cleaned up partial virtual environment.")
                except Exception:
                    pass
            return False, pyenv_cmd_list, python_executable_path

        if not venv_created:
            print_error("Could not create virtual environment after all attempts.")
            return False, pyenv_cmd_list, python_executable_path
    else:
        print_info("Virtual environment already exists.")

    return True, pyenv_cmd_list, python_executable_path


def _remove_apt_rust_if_installed():
    """Remove Rust/cargo installed via apt package manager to avoid conflicts with rustup.

    This function checks if cargo or rustc are installed via apt (system package manager) and
    removes them to prevent conflicts when installing the official Rust toolchain via rustup.

    Returns:
        bool: True if apt Rust was found and removed, False otherwise
    """
    try:
        # Check if cargo binary exists
        cargo_path_check = subprocess.run(
            ["which", "cargo"], capture_output=True, text=True, check=False
        )

        cargo_from_apt = False
        if cargo_path_check.returncode == 0:
            cargo_binary_path = cargo_path_check.stdout.strip()
            print_info_verbose(f"Found existing cargo binary at: {cargo_binary_path}")

            # If cargo is from rustup installation, don't remove it
            if "/.cargo/bin/cargo" not in cargo_binary_path:
                cargo_from_apt = True

        # Check if rustc binary exists
        rustc_path_check = subprocess.run(
            ["which", "rustc"], capture_output=True, text=True, check=False
        )

        rustc_from_apt = False
        if rustc_path_check.returncode == 0:
            rustc_binary_path = rustc_path_check.stdout.strip()
            print_info_verbose(f"Found existing rustc binary at: {rustc_binary_path}")

            # If rustc is from rustup installation, don't remove it
            if "/.cargo/bin/rustc" not in rustc_binary_path:
                rustc_from_apt = True

        # If neither cargo nor rustc are from apt, nothing to remove
        if not cargo_from_apt and not rustc_from_apt:
            print_info_verbose("Rust toolchain is from rustup, no need to remove")
            return False

        # Rust is likely from apt (typically in /usr/bin/cargo or /usr/bin/rustc)
        if cargo_from_apt or rustc_from_apt:
            print_warning(
                "Rust toolchain appears to be installed via system package manager (apt)"
            )
            print_info(
                "Removing apt-installed Rust to avoid conflicts with rustup installation..."
            )

            try:
                clean_env = _get_clean_env_for_compilation()
                # Try to remove rustc and cargo packages
                packages_to_remove = []
                if cargo_from_apt:
                    packages_to_remove.append("cargo")
                if rustc_from_apt:
                    packages_to_remove.append("rustc")

                if packages_to_remove:
                    remove_result = subprocess.run(
                        ["apt", "remove", "--purge", "-y"] + packages_to_remove,
                        capture_output=True,
                        text=True,
                        timeout=60,
                        env=clean_env,
                        check=False,
                    )

                    if remove_result.returncode == 0:
                        print_success(
                            f"Removed apt-installed Rust packages: {', '.join(packages_to_remove)}"
                        )
                        return True
                    print_info_verbose(
                        f"Could not remove apt Rust packages (may not be installed via apt): {remove_result.stderr}"
                    )
                    return False
            except Exception as e:
                print_warning(f"Could not remove apt Rust packages: {e}")
                print_info("Continuing with rustup installation anyway...")
                return False

        return False

    except Exception as e:
        print_info_verbose(f"Error checking for apt Rust installation: {e}")
        return False


def _install_rustup():
    """Install Rust toolchain using rustup (official Rust installer).

    This installs the latest stable Rust toolchain, which includes:
    - rustc (Rust compiler)
    - cargo (Rust package manager)
    - rustup (Rust toolchain installer and updater)

    Returns:
        bool: True if installation successful, False otherwise
    """
    try:
        # Check if cargo is already available
        cargo_available, cargo_version = _is_cargo_available()
        if cargo_available:
            print_info(f"Cargo already available: {cargo_version}")

            # Check if it's from rustup installation (in ~/.cargo/bin)
            cargo_path_check = subprocess.run(
                ["which", "cargo"], capture_output=True, text=True, check=False
            )
            if cargo_path_check.returncode == 0:
                cargo_binary_path = cargo_path_check.stdout.strip()
                if "/.cargo/bin/cargo" in cargo_binary_path:
                    # Cargo is from rustup, check if rustup is also available
                    try:
                        rust_env = os.environ.copy()
                        _apply_effective_user_home_to_env(rust_env)
                        effective_home = _get_effective_user_home()
                        rust_env["CARGO_HOME"] = os.path.join(effective_home, ".cargo")
                        rust_env["RUSTUP_HOME"] = os.path.join(
                            effective_home, ".rustup"
                        )
                        cargo_bin = os.path.join(rust_env["CARGO_HOME"], "bin")
                        rust_env["PATH"] = (
                            f"{cargo_bin}{os.pathsep}{rust_env.get('PATH', '')}"
                        )

                        rustup_check = subprocess.run(
                            ["rustup", "--version"],
                            capture_output=True,
                            text=True,
                            check=False,
                            env=rust_env,
                        )

                        if rustup_check.returncode == 0:
                            print_info(
                                f"rustup already installed: {rustup_check.stdout.strip()}"
                            )

                            # Update to latest stable
                            print_info("Updating Rust toolchain to latest stable...")
                            update_result = run_command(
                                ["rustup", "update", "stable"],
                                check=False,
                                capture_output=True,
                                text=True,
                                env=rust_env,
                                timeout=300,
                            )

                            if update_result.returncode == 0:
                                print_success("Rust toolchain updated successfully")
                            else:
                                print_warning(
                                    "Failed to update Rust toolchain, but continuing..."
                                )

                            return True
                    except FileNotFoundError:
                        # rustup not found but cargo is from ~/.cargo/bin, continue with installation
                        pass
                else:
                    # Cargo is available but NOT from rustup (likely from apt)
                    print_warning(
                        f"Cargo is installed but not from rustup: {cargo_binary_path}"
                    )
                    print_info(
                        "Removing apt-installed Rust and installing via rustup..."
                    )
                    # Remove apt-installed Rust
                    _remove_apt_rust_if_installed()
                    # Continue with rustup installation below

        # rustup not installed or cargo not from rustup, install it
        print_info("Installing Rust toolchain via rustup (official installer)...")
        print_info("This will install the latest stable Rust (rustc + cargo + rustup)")

        # Remove apt-installed Rust if present to avoid conflicts (in case it wasn't removed above)
        _remove_apt_rust_if_installed()

        # Download and run rustup installer
        # Using -y flag for non-interactive installation
        # Use clean environment to avoid PyInstaller library conflicts with system tools
        clean_env = _get_clean_env_for_compilation()
        _apply_effective_user_home_to_env(clean_env)
        effective_home = _get_effective_user_home()
        clean_env["CARGO_HOME"] = os.path.join(effective_home, ".cargo")
        clean_env["RUSTUP_HOME"] = os.path.join(effective_home, ".rustup")
        curl_cmd = "curl --proto '=https' --tlsv1.2 -sSf https://sh.rustup.rs | sh -s -- -y --default-toolchain stable"

        result = subprocess.run(
            ["sh", "-c", curl_cmd],
            capture_output=True,
            check=False,
            text=True,
            timeout=300,  # 5 minutes timeout
            env=clean_env,
        )

        if result.returncode == 0:
            print_success(
                "[bold]rustup[/bold] installed successfully",
                panel=True,
            )

            # Source cargo env to update current shell's PATH
            cargo_env_path = _expand_effective_user_path("~/.cargo/env")
            if os.path.exists(cargo_env_path):
                print_info("Configuring environment for cargo...")
                # Update current process environment (prioritize ~/.cargo/bin)
                cargo_bin_path = _expand_effective_user_path("~/.cargo/bin")
                current_path = os.environ.get("PATH", "")
                # Remove any existing cargo paths to avoid conflicts
                path_parts = current_path.split(":")
                filtered_path = [
                    p
                    for p in path_parts
                    if "/.cargo/bin" not in p and "/usr/bin/cargo" not in p
                ]
                # Add rustup cargo path at the beginning
                os.environ["PATH"] = f"{cargo_bin_path}:{':'.join(filtered_path)}"

            # Verify installation (prefer the cargo from rustup path explicitly)
            effective_home = _get_effective_user_home()
            cargo_bin_path = os.path.join(effective_home, ".cargo", "bin")
            cargo_exe = os.path.join(cargo_bin_path, "cargo")
            verify_env = os.environ.copy()
            verify_env["PATH"] = (
                f"{cargo_bin_path}{os.pathsep}{verify_env.get('PATH', '')}"
            )
            _apply_effective_user_home_to_env(verify_env)
            verify_env["CARGO_HOME"] = os.path.join(effective_home, ".cargo")
            verify_env["RUSTUP_HOME"] = os.path.join(effective_home, ".rustup")

            cargo_cmd = (
                [cargo_exe, "--version"]
                if os.path.exists(cargo_exe)
                else ["cargo", "--version"]
            )
            cargo_check = run_command(
                cargo_cmd,
                check=False,
                capture_output=True,
                text=True,
                env=verify_env,
                timeout=15,
            )

            if cargo_check.returncode == 0:
                # Double-check that we're using the rustup installation
                verify_path_check = run_command(
                    ["which", "cargo"],
                    check=False,
                    capture_output=True,
                    text=True,
                    env=verify_env,
                    timeout=5,
                )
                if verify_path_check.returncode == 0:
                    actual_cargo_path = verify_path_check.stdout.strip()
                    print_info_verbose(f"Cargo binary location: {actual_cargo_path}")
                    if "/.cargo/bin/cargo" in actual_cargo_path:
                        print_success(
                            f"Cargo installed from rustup: {cargo_check.stdout.strip()}"
                        )
                    else:
                        print_warning(
                            f"Cargo installed but PATH may be pointing to different installation: {actual_cargo_path}"
                        )
                        print_info("This may require a terminal restart to take effect")

                return True
            # Fix common case where rustup exists but no default toolchain is configured.
            combined = f"{cargo_check.stdout or ''}\n{cargo_check.stderr or ''}".strip()
            if _cargo_output_indicates_missing_default_toolchain(combined):
                if _ensure_rustup_default_toolchain(verify_env):
                    cargo_recheck = run_command(
                        cargo_cmd,
                        check=False,
                        capture_output=True,
                        text=True,
                        env=verify_env,
                        timeout=15,
                    )
                    if cargo_recheck.returncode == 0:
                        print_success(
                            f"Cargo installed from rustup: {cargo_recheck.stdout.strip()}"
                        )
                        return True
            # More actionable diagnostics for debugging CI/desktop environments.
            print_warning("rustup installed but cargo verification failed")
            print_info_debug(f"[rustup] cargo verify cmd: {cargo_cmd}")
            print_info_debug(f"[rustup] cargo verify rc: {cargo_check.returncode}")
            print_info_debug(
                f"[rustup] cargo verify stdout: {(cargo_check.stdout or '').strip()[:500]}"
            )
            print_info_debug(
                f"[rustup] cargo verify stderr: {(cargo_check.stderr or '').strip()[:500]}"
            )
            which_check = run_command(
                ["which", "cargo"],
                check=False,
                capture_output=True,
                text=True,
                env=verify_env,
                timeout=5,
            )
            print_info_debug(
                f"[rustup] which cargo: {(which_check.stdout or '').strip()}"
            )
            return False
        if result.returncode != 0:
            print_error(f"rustup installation failed: {result.stderr}")
            return False

    except subprocess.TimeoutExpired:
        print_error("rustup installation timed out (>5 minutes)")
        return False
    except Exception as e:
        telemetry.capture_exception(e)
        print_error("Error installing rustup.")
        print_exception(show_locals=False, exception=e)
        return False


def _remove_apt_go_if_installed():
    """Remove Go installed via apt package manager to avoid conflicts with official installation.

    This function checks if Go is installed via apt (system package manager) and removes it
    to prevent conflicts when installing the official Go version from golang.org.

    Returns:
        bool: True if apt Go was found and removed, False otherwise
    """
    try:
        # Check if Go binary exists
        go_path_check = subprocess.run(
            ["which", "go"], capture_output=True, text=True, check=False
        )
        if go_path_check.returncode != 0:
            # Go not found, nothing to remove
            return False

        go_binary_path = go_path_check.stdout.strip()
        print_info_verbose(f"Found existing Go binary at: {go_binary_path}")

        # If Go is from official installation, don't remove it
        if "/usr/local/go/bin/go" in go_binary_path:
            print_info_verbose("Go is from official installation, no need to remove")
            return False

        # Go is likely from apt (typically in /usr/bin/go or /usr/local/bin/go)
        print_warning("Go appears to be installed via system package manager (apt)")
        print_info(
            "Removing apt-installed Go to avoid conflicts with official installation..."
        )

        try:
            clean_env = _get_clean_env_for_compilation()
            # Try to remove golang-go package
            remove_result = subprocess.run(
                ["apt", "remove", "--purge", "-y", "golang-go"],
                capture_output=True,
                text=True,
                timeout=60,
                env=clean_env,
                check=False,
            )

            if remove_result.returncode == 0:
                print_success("Removed apt-installed Go package")
                return True
            print_info_verbose(
                f"Could not remove apt Go package (may not be installed via apt): {remove_result.stderr}"
            )
            return False
        except Exception as e:
            print_warning(f"Could not remove apt Go package: {e}")
            print_info("Continuing with official installation anyway...")
            return False

    except Exception as e:
        print_info_verbose(f"Error checking for apt Go installation: {e}")
        return False


def _install_go_official():
    """Install Go toolchain from official golang.org source (latest version).

    This installs the latest stable Go toolchain directly from golang.org,
    similar to how rustup installs Rust. This ensures we get the latest
    version instead of relying on outdated apt packages.

    Returns:
        bool: True if installation successful, False otherwise
    """
    try:
        # Check if Go is already installed
        go_available, go_version = _is_go_available()
        if go_available:
            print_info(f"Go already installed: {go_version}")

            # Check if it's from official installation (in /usr/local/go)
            go_path_check = subprocess.run(
                ["which", "go"], capture_output=True, text=True, check=False
            )
            if go_path_check.returncode == 0:
                go_binary_path = go_path_check.stdout.strip()
                if "/usr/local/go/bin/go" in go_binary_path:
                    print_info(
                        "Go is installed from official source, checking for updates..."
                    )
                    # We could check for updates here, but for now just return True
                    return True
                # Go is available but NOT from official source (likely from apt)
                print_warning(
                    f"Go is installed but not from official source: {go_binary_path}"
                )
                print_info(
                    "Removing apt-installed Go and installing official version..."
                )
                # Remove apt-installed Go
                _remove_apt_go_if_installed()
                # Continue with official installation below

        # Go not installed or not from official source, install it
        print_info("Installing Go toolchain from official golang.org source...")
        print_info("This will install the latest stable Go version")

        # Remove apt-installed Go if present to avoid conflicts (in case it wasn't removed above)
        _remove_apt_go_if_installed()

        # Detect system architecture
        machine = platform.machine().lower()
        system = platform.system().lower()

        # Map architecture to Go's naming convention
        arch_map = {
            "x86_64": "amd64",
            "amd64": "amd64",
            "aarch64": "arm64",
            "arm64": "arm64",
            "armv7l": "armv6l",  # Go uses armv6l for ARMv7
            "i386": "386",
            "i686": "386",
        }

        go_arch = arch_map.get(machine, machine)
        go_os = system

        # Validate OS (Go supports linux, darwin, windows, freebsd, etc.)
        if go_os not in ["linux", "darwin", "freebsd", "openbsd", "netbsd"]:
            print_error(f"Unsupported OS for official Go installation: {go_os}")
            print_info("Falling back to apt installation...")
            return False

        # Get latest Go version from golang.org
        # We'll use a fixed latest version URL pattern, or fetch it dynamically
        # For simplicity, we'll use the latest stable version URL pattern
        # Go releases follow pattern: go1.XX.X
        print_info("Fetching latest Go version...")

        # Use clean environment to avoid PyInstaller library conflicts
        clean_env = _get_clean_env_for_compilation()

        # Try to get latest version from golang.org/VERSION endpoint
        try:
            version_response = requests.get("https://go.dev/VERSION?m=text", timeout=10)
            if version_response.status_code == 200:
                # The response may contain multiple lines (version + timestamp)
                # Extract only the first line and clean it
                version_text = version_response.text.strip()
                # Split by newlines and take the first line
                version_lines = version_text.split("\n")
                latest_version = version_lines[0].strip()

                # Validate version format (should be like "go1.23.4" or "go1.24")
                if not re.match(r"^go\d+\.\d+(\.\d+)?$", latest_version):
                    print_warning(
                        f"Invalid version format from API: {latest_version}, using fallback"
                    )
                    latest_version = "go1.23.4"
                else:
                    print_info(f"Latest Go version: {latest_version}")
            else:
                # Fallback to a recent stable version
                latest_version = "go1.23.4"
                print_warning(
                    f"Could not fetch latest version (HTTP {version_response.status_code}), using {latest_version}"
                )
        except Exception as e:
            print_warning(f"Could not fetch latest version: {e}")
            # Fallback to a recent stable version
            latest_version = "go1.23.4"
            print_info(f"Using fallback version: {latest_version}")

        # Construct download URL
        go_tarball = f"{latest_version}.{go_os}-{go_arch}.tar.gz"
        download_url = f"https://go.dev/dl/{go_tarball}"

        print_info(f"Downloading Go from: {download_url}")
        print_info_verbose(f"Tarball filename: {go_tarball}")

        # Create temporary directory for download
        temp_dir = tempfile.mkdtemp()
        tarball_path = os.path.join(temp_dir, go_tarball)

        try:
            # Download Go tarball
            print_info("Downloading Go tarball (this may take a few minutes)...")
            download_response = requests.get(download_url, timeout=300, stream=True)

            if download_response.status_code != 200:
                print_error(
                    f"Failed to download Go: HTTP {download_response.status_code}"
                )
                return False

            # Save tarball
            with open(tarball_path, "wb") as f:
                for chunk in download_response.iter_content(chunk_size=8192):
                    f.write(chunk)

            print_success("Go tarball downloaded successfully")

            # Remove existing Go installation if it exists
            go_install_path = "/usr/local/go"
            if os.path.exists(go_install_path):
                print_info("Removing existing Go installation...")
                shutil.rmtree(go_install_path)

            # Extract tarball to /usr/local
            print_info("Extracting Go tarball...")
            extract_result = subprocess.run(
                ["tar", "-C", "/usr/local", "-xzf", tarball_path],
                capture_output=True,
                text=True,
                check=False,
                timeout=300,
                env=clean_env,
            )

            if extract_result.returncode != 0:
                print_error(f"Failed to extract Go tarball: {extract_result.stderr}")
                return False

            print_success("Go extracted successfully")

            # Configure PATH for current session (prioritize /usr/local/go/bin)
            go_bin_path = "/usr/local/go/bin"
            current_path = os.environ.get("PATH", "")
            # Remove any existing Go paths to avoid conflicts
            path_parts = current_path.split(":")
            filtered_path = [
                p
                for p in path_parts
                if "/usr/local/go/bin" not in p and "/usr/bin/go" not in p
            ]
            # Add official Go path at the beginning
            os.environ["PATH"] = f"{go_bin_path}:{':'.join(filtered_path)}"

            # Verify installation
            go_available, go_version = _is_go_available()
            if go_available:
                # Double-check that we're using the official installation
                verify_path_check = subprocess.run(
                    ["which", "go"], capture_output=True, text=True, check=False
                )
                if verify_path_check.returncode == 0:
                    actual_go_path = verify_path_check.stdout.strip()
                    print_info_verbose(f"Go binary location: {actual_go_path}")
                    if "/usr/local/go/bin/go" in actual_go_path:
                        print_success(
                            f"Go installed successfully from official source: {go_version}"
                        )
                    else:
                        print_warning(
                            f"Go installed but PATH may be pointing to different installation: {actual_go_path}"
                        )
                        print_info("This may require a terminal restart to take effect")

                # Configure PATH in shell config files
                _configure_go_official_path()

                return True
            print_warning("Go installed but verification failed")
            print_info_verbose(
                "This may be due to PATH configuration - try restarting your terminal"
            )
            return False

        finally:
            # Clean up temporary files
            try:
                if os.path.exists(tarball_path):
                    os.remove(tarball_path)
                if os.path.exists(temp_dir):
                    os.rmdir(temp_dir)
            except Exception as e:
                print_info_verbose(f"Could not clean up temp files: {e}")

    except subprocess.TimeoutExpired:
        print_error("Go installation timed out (>5 minutes)")
        return False
    except Exception as e:
        telemetry.capture_exception(e)
        print_error("Error installing Go.")
        print_exception(show_locals=False, exception=e)
        return False


def _configure_go_official_path():
    """Configure /usr/local/go/bin in shell profiles and current session.

    This is separate from _configure_go_path() which configures ~/go/bin
    for Go modules. This configures the official Go installation path.

    Returns:
        bool: True if configuration was successful or already configured
    """
    try:
        go_bin_path = "/usr/local/go/bin"
        current_path = os.environ.get("PATH", "")

        # Add to current session PATH
        if go_bin_path not in current_path:
            os.environ["PATH"] = f"{go_bin_path}:{current_path}"

        # Detect current shell and determine which config file to use
        current_shell = os.environ.get("SHELL", "/bin/bash")
        shell_config_file = None

        if "zsh" in current_shell:
            shell_config_file = _expand_effective_user_path("~/.zshrc")
        elif "bash" in current_shell:
            shell_config_file = _expand_effective_user_path("~/.bashrc")
        elif "fish" in current_shell:
            shell_config_file = _expand_effective_user_path(
                "~/.config/fish/config.fish"
            )
        else:
            shell_config_file = _expand_effective_user_path("~/.profile")

        path_config_line = 'export PATH="/usr/local/go/bin:$PATH"'
        configured_current_shell = False

        # Configure current shell's config file
        if shell_config_file and os.path.exists(shell_config_file):
            try:
                with open(shell_config_file, "r", encoding="utf-8") as f:
                    content = f.read()

                if (
                    path_config_line not in content
                    and "/usr/local/go/bin" not in content
                ):
                    with open(shell_config_file, "a", encoding="utf-8") as f:
                        f.write(f"\n# Go official installation\n{path_config_line}\n")
                    print_success(f"Added Go PATH to {shell_config_file}")
                    configured_current_shell = True
                else:
                    print_info_verbose(
                        f"Go PATH already configured in {shell_config_file}"
                    )

            except Exception as e:
                print_warning(f"Could not configure PATH in {shell_config_file}: {e}")

        # Also configure universal profile as backup
        profile_file = _expand_effective_user_path("~/.profile")
        if profile_file != shell_config_file and os.path.exists(profile_file):
            try:
                with open(profile_file, "r", encoding="utf-8") as f:
                    content = f.read()

                if (
                    path_config_line not in content
                    and "/usr/local/go/bin" not in content
                ):
                    with open(profile_file, "a", encoding="utf-8") as f:
                        f.write(f"\n# Go official installation\n{path_config_line}\n")
                    print_info_verbose(f"Added Go PATH to {profile_file} (backup)")
            except Exception as e:
                print_info_verbose(f"Could not configure PATH in {profile_file}: {e}")

        return configured_current_shell or True

    except Exception as e:
        print_warning(f"Error configuring Go PATH: {e}")
        return False


def _install_rusthound_ce(env=None):
    """Install RustHound-CE using cargo.

    Args:
        env (dict, optional): Environment variables for subprocess

    Returns:
        tuple: (bool, str) - (success, output)
    """
    try:
        # Ensure ~/.cargo/bin is in PATH for the cargo install command
        effective_home = _get_effective_user_home()
        cargo_home = os.path.join(effective_home, ".cargo")
        rustup_home = os.path.join(effective_home, ".rustup")
        cargo_bin_path = os.path.join(cargo_home, "bin")
        current_path = os.environ.get("PATH", "")
        if cargo_bin_path not in current_path:
            os.environ["PATH"] = f"{cargo_bin_path}:{current_path}"

        # Use clean environment for Rust compilation to avoid PyInstaller library conflicts
        # If env is provided, use it; otherwise use clean environment
        if env is None:
            env = _get_clean_env_for_compilation()
        else:
            # If env is provided, ensure it's clean for compilation
            env = _get_clean_env_for_compilation(env)

        _apply_effective_user_home_to_env(env)
        # Force rustup/cargo home to the effective user to avoid picking up
        # root-owned installations or a mismatched toolchain state.
        env["CARGO_HOME"] = cargo_home
        env["RUSTUP_HOME"] = rustup_home

        # Ensure cargo bin is in PATH for compilation
        env_path = env.get("PATH", "")
        if cargo_bin_path not in env_path:
            env["PATH"] = f"{cargo_bin_path}:{env_path}"

        print_info("Installing RustHound-CE...")
        # Ensure rustup has a usable default toolchain in this execution env.
        _ensure_rustup_default_toolchain(env)

        cargo_exe = os.path.join(cargo_bin_path, "cargo")
        cargo_cmd = (
            [cargo_exe, "install", "rusthound-ce@2.4.7"]
            if os.path.exists(cargo_exe)
            else ["cargo", "install", "rusthound-ce@2.4.7"]
        )
        result = run_command(
            cargo_cmd, check=False, capture_output=True, text=True, env=env, timeout=900
        )
        combined = (
            f"{(result.stdout or '').strip()}\n{(result.stderr or '').strip()}".strip()
        )
        if result.returncode != 0 and _cargo_output_indicates_missing_default_toolchain(
            combined
        ):
            print_warning(
                "Rust toolchain looks misconfigured (no default toolchain). Repairing and retrying..."
            )
            _ensure_rustup_default_toolchain(env)
            result = run_command(
                cargo_cmd,
                check=False,
                capture_output=True,
                text=True,
                env=env,
                timeout=900,
            )

        if result.returncode == 0:
            # Handle case where stdout might be None
            stdout_text = (
                result.stdout.strip()
                if result.stdout
                else "Installation completed successfully"
            )
            return True, stdout_text
        # Handle case where stderr might be None
        stderr_text = (
            result.stderr.strip()
            if result.stderr
            else "Installation failed with no error output"
        )
        return False, stderr_text

    except Exception as e:
        return False, str(e)


def _verify_rusthound_installation(env=None):
    """Verify complete RustHound-CE installation and accessibility.

    This is the central function for all RustHound-CE verification logic.
    Used consistently by both handle_install and handle_check.

    Args:
        env (dict, optional): Environment variables for subprocess calls

    Returns:
        dict: Verification results with detailed status
    """
    verification_results = {
        "cargo_available": False,
        "cargo_version": "",
        "rusthound_installed": False,
        "rusthound_path": "",
        "cargo_bin_in_path": False,
        "rusthound_accessible": False,
        "rusthound_help": "",
        "overall_status": False,
    }

    try:
        # Check cargo availability (with optional env parameter)
        cargo_available, cargo_output = _is_cargo_available(env)
        verification_results["cargo_available"] = cargo_available
        verification_results["cargo_version"] = cargo_output

        if not cargo_available:
            verification_results["overall_status"] = False
            return verification_results

        # Check rusthound-ce installation
        rusthound_installed, rusthound_path = _is_rusthound_installed()
        verification_results["rusthound_installed"] = rusthound_installed
        verification_results["rusthound_path"] = rusthound_path

        if not rusthound_installed:
            verification_results["overall_status"] = False
            return verification_results

        # Check cargo bin in PATH
        cargo_bin_in_path, _ = _is_cargo_bin_in_path()
        verification_results["cargo_bin_in_path"] = cargo_bin_in_path

        # Check rusthound-ce accessibility
        rusthound_accessible, help_output = _is_rusthound_accessible(env=env)
        verification_results["rusthound_accessible"] = rusthound_accessible
        verification_results["rusthound_help"] = help_output

        # Overall status: all checks must pass
        verification_results["overall_status"] = (
            cargo_available and rusthound_installed and rusthound_accessible
        )

        return verification_results

    except Exception as e:
        verification_results["error"] = str(e)
        return verification_results


def _get_rusthound_verification_status(env=None):
    """Get comprehensive RustHound-CE verification status with actionable messages.

    This function provides consistent verification logic and messaging
    for both installation and check operations.

    Args:
        env (dict, optional): Environment variables for subprocess calls

    Returns:
        dict: Status with verification results and actionable messages
    """
    verification_results = _verify_rusthound_installation(env)

    status = {
        "verification_results": verification_results,
        "messages": {
            "cargo": "",
            "rusthound_installed": "",
            "cargo_bin_path": "",
            "rusthound_accessible": "",
            "overall": "",
            "recommendations": [],
        },
        "all_ok": False,
    }

    # Cargo availability messages
    if verification_results["cargo_available"]:
        status["messages"]["cargo"] = (
            f"Cargo found: {verification_results['cargo_version']}"
        )
    else:
        status["messages"]["cargo"] = (
            "Cargo not found. Rust toolchain is required for rusthound-ce."
        )
        status["messages"]["recommendations"].append(
            "Install it with: curl --proto '=https' --tlsv1.2 -sSf https://sh.rustup.rs | sh -s -- -y"
        )
        status["messages"]["recommendations"].append(
            "Or run: adscan install --only rusthound (will install rustup automatically)"
        )

    # RustHound-CE installation messages
    if verification_results["rusthound_installed"]:
        status["messages"]["rusthound_installed"] = (
            f"RustHound-CE binary found: {verification_results['rusthound_path']}"
        )
    else:
        status["messages"]["rusthound_installed"] = (
            f"RustHound-CE not found at: {verification_results['rusthound_path']}"
        )
        if verification_results["cargo_available"]:
            status["messages"]["recommendations"].append(
                "Install it with: cargo install rusthound-ce@2.4.7 --force"
            )
        else:
            status["messages"]["recommendations"].append(
                "First install cargo with: apt install cargo"
            )
            status["messages"]["recommendations"].append(
                "Then install RustHound-CE with: cargo install rusthound-ce@2.4.7 --force"
            )

    # Cargo bin in PATH messages
    if verification_results["cargo_bin_in_path"]:
        status["messages"]["cargo_bin_path"] = "~/.cargo/bin is in PATH"
    else:
        status["messages"]["cargo_bin_path"] = "~/.cargo/bin is not in PATH"
        status["messages"]["recommendations"].append(
            'Add it with: export PATH="$HOME/.cargo/bin:$PATH"'
        )
        status["messages"]["recommendations"].append(
            "Or run: adscan install --only rusthound (will configure PATH automatically)"
        )

    # RustHound-CE accessibility messages
    if verification_results["rusthound_accessible"]:
        status["messages"]["rusthound_accessible"] = (
            "RustHound-CE is accessible from PATH"
        )
    else:
        status["messages"]["rusthound_accessible"] = (
            "RustHound-CE is not accessible from PATH"
        )
        status["messages"]["recommendations"].append(
            f"PATH should be configured automatically - if issues persist, try: {_get_current_shell_source_message()}"
        )
        status["messages"]["recommendations"].append(
            "Or run: adscan install --only rusthound (will configure PATH automatically)"
        )

    # Overall status
    if verification_results["overall_status"]:
        status["messages"]["overall"] = "RustHound-CE installation is fully functional"
        status["all_ok"] = True
    else:
        status["messages"]["overall"] = "RustHound-CE installation has issues"
        status["messages"]["recommendations"].append(
            "Run: adscan install --only rusthound (will fix most issues automatically)"
        )
        status["all_ok"] = False

    return status


def _ensure_rust_toolchain_installed(env=None):
    """Ensure Rust toolchain is installed and available.

    This function checks if Rust is already installed, and if not, installs it.
    It can be used by both normal installation and --only rusthound modes.

    Args:
        env (dict, optional): Environment variables for subprocess

    Returns:
        tuple: (bool, str) - (success, message)
    """
    try:
        # First, check if Rust is already installed
        cargo_available, cargo_version = _is_cargo_available(env)
        if cargo_available:
            print_success(f"Rust toolchain already installed: {cargo_version}")
            return True, f"Rust already available: {cargo_version}"

        print_info("Rust toolchain not found, installing...")

        # Install Rust using rustup
        print_info("Installing Rust toolchain via rustup...")
        try:
            # Download and run rustup installer
            # Use clean environment to avoid PyInstaller library conflicts with system tools
            # Use shell=True to handle the pipe properly
            if env is None:
                clean_env = _get_clean_env_for_compilation()
            else:
                clean_env = _get_clean_env_for_compilation(env)
            result = subprocess.run(
                "curl --proto '=https' --tlsv1.2 -sSf https://sh.rustup.rs | sh -s -- -y --default-toolchain stable",
                shell=True,
                check=False,
                capture_output=True,
                text=True,
                env=clean_env,
            )

            if result.returncode == 0:
                print_success("Rust toolchain installed successfully")

                # Update PATH for current session
                cargo_bin_path = _expand_effective_user_path("~/.cargo/bin")
                if cargo_bin_path not in os.environ.get("PATH", ""):
                    os.environ["PATH"] = (
                        f"{cargo_bin_path}:{os.environ.get('PATH', '')}"
                    )

                # Verify installation
                cargo_available, cargo_version = _is_cargo_available(env)
                if cargo_available:
                    print_success(f"Rust toolchain verified: {cargo_version}")
                    return True, f"Rust installed successfully: {cargo_version}"
                return (
                    False,
                    "Rust installation completed but cargo is not accessible",
                )
            if result.returncode != 0:
                error_msg = f"Rust installation failed: {result.stderr}"
                print_error(error_msg)
                return False, error_msg

        except Exception as e:
            error_msg = f"Error during Rust installation: {e}"
            print_error(error_msg)
            return False, error_msg

    except Exception as e:
        error_msg = f"Error checking/installing Rust toolchain: {e}"
        print_error(error_msg)
        return False, error_msg


def _verify_system_packages(packages_config, mode="check"):
    """Verify system packages installation status using dpkg -l for robust verification.

    This function uses dpkg -l as the primary method to check package installation status,
    which is more reliable than checking individual commands in PATH.

    Args:
        packages_config (dict): Package configuration dictionary
        mode (str): "check" for simple verification, "install" for detailed pre-install check

    Returns:
        dict: Results with installed/missing packages and detailed status
    """
    # Define package fallbacks (primary -> fallback)
    # Some distributions use different package names for equivalent packages
    PACKAGE_FALLBACKS = {  # pylint: disable=invalid-name
        "freerdp3-x11": "freerdp2-x11",
        "ntpsec-ntpdate": "ntpdate",
        "libncursesw5-dev": "libncurses-dev",  # Kali and some Debian variants use libncurses-dev
        "libmagic1": "libmagic1t64",
    }

    results = {"installed": [], "missing": [], "to_install": [], "details": {}}

    def _is_package_installed_via_dpkg(package_name):
        """Check if a package is installed using dpkg -l.

        Args:
            package_name (str): Name of the package to check

        Returns:
            tuple: (is_installed, version_info)
        """
        try:
            result = run_command(
                ["dpkg", "-l", package_name],
                check=False,
                capture_output=True,
                text=True,
            )
            if result and result.returncode == 0 and result.stdout:
                # Parse dpkg output to check if package is actually installed
                # dpkg -l returns lines like: "ii  package-name version description"
                lines = result.stdout.strip().split("\n")
                for line in lines:
                    if line.startswith("ii") and package_name in line:
                        # Extract version info
                        parts = line.split()
                        if len(parts) >= 3:
                            version_info = parts[2]
                            return True, version_info
                        return True, "installed"
                return False, "not_found"
            return False, "not_found"
        except Exception as e:
            return False, f"error: {e}"

    try:
        for package_name in packages_config:
            # Use dpkg -l for all packages (some may not be installed via apt in certain distros).
            is_installed, version_info = _is_package_installed_via_dpkg(package_name)

            # Handle fallback packages
            if not is_installed and package_name in PACKAGE_FALLBACKS:
                fallback_package = PACKAGE_FALLBACKS[package_name]
                # Check if fallback package is installed
                fallback_installed, fallback_version = _is_package_installed_via_dpkg(
                    fallback_package
                )
                if fallback_installed:
                    results["installed"].append(package_name)
                    if mode == "install":
                        results["details"][package_name] = (
                            f"fallback_installed ({fallback_package} {fallback_version})"
                        )
                        print_success(
                            f"Package '{package_name}' fallback is installed ({fallback_package} {fallback_version})"
                        )
                    continue

            if is_installed:
                results["installed"].append(package_name)
                if mode == "install":
                    results["details"][package_name] = (
                        f"already_installed ({version_info})"
                    )
                    print_success(
                        f"Package '{package_name}' is already installed ({version_info})"
                    )
            else:
                results["missing"].append(package_name)
                results["to_install"].append(package_name)
                if mode == "install":
                    results["details"][package_name] = "needs_installation"
                    print_info(f"Package '{package_name}' needs to be installed")

        return results

    except Exception as e:
        print_error("Error verifying system packages.")
        print_exception(show_locals=False, exception=e)
        return results


def _print_install_summary():
    """Render a professional installation summary panel at the end of installation."""
    from rich.console import Group
    from rich.text import Text
    from rich.table import Table
    from rich.panel import Panel
    from rich.box import ROUNDED
    from adscan_internal.rich_output import (
        _get_console,
        _get_telemetry_console,
        BRAND_COLORS,
    )

    console = _get_console()
    telemetry_console = _get_telemetry_console()
    renderables = []

    # ── htb-cli section ──
    htb_cli_info = INSTALL_SUMMARY.get("htb_cli")
    if htb_cli_info:
        renderables.append(Text(""))
        htb_header = Text("htb-cli", style=f"bold {BRAND_COLORS['info']}")
        renderables.append(htb_header)

        if htb_cli_info.get("installed"):
            if htb_cli_info.get("accessible"):
                renderables.append(
                    Text("  Installed and accessible in PATH", style="green")
                )
            else:
                renderables.append(
                    Text(
                        "  Installed (may require terminal restart)",
                        style="yellow",
                    )
                )
        else:
            renderables.append(Text("  Installation failed", style="red"))

    # ── Telemetry section ──
    renderables.append(Text(""))
    tele_header = Text("Telemetry", style=f"bold {BRAND_COLORS['info']}")
    renderables.append(tele_header)

    telemetry_enabled = telemetry._is_telemetry_enabled()
    if telemetry_enabled:
        tele_status = Text("  ON", style="bold green")
        tele_status.append(" — anonymous, sanitized usage analytics", style="dim")
        renderables.append(tele_status)
        renderables.append(Text(""))

        tele_detail = Table.grid(padding=(0, 1))
        tele_detail.add_column(justify="right", style="dim", no_wrap=True, min_width=12)
        tele_detail.add_column(justify="left", style="dim")
        tele_detail.add_row("What", "Commands run, feature usage, errors")
        tele_detail.add_row("Not sent", "IPs, domains, credentials, paths")
        tele_detail.add_row("Session off", "export ADSCAN_TELEMETRY=0")
        tele_detail.add_row("Permanent", "telemetry off  (inside ADscan)")
        tele_detail.add_row("Details", "adscanpro.com/docs/telemetry")
        renderables.append(tele_detail)
    else:
        tele_status = Text("  OFF", style="bold yellow")
        tele_status.append(" — no data is collected", style="dim")
        renderables.append(tele_status)

    # ── Post-install check ──
    check_info = INSTALL_SUMMARY.get("post_install_check")
    if check_info:
        renderables.append(Text(""))
        check_header = Text("Health Check", style=f"bold {BRAND_COLORS['info']}")
        renderables.append(check_header)
        if check_info.get("success"):
            renderables.append(Text("  All checks passed", style="green"))
        else:
            renderables.append(
                Text("  Some checks failed — run: adscan check", style="yellow")
            )

    # ── Render panel ──
    panel = Panel(
        Group(*renderables),
        title="[bold]Installation Summary[/bold]",
        border_style="green",
        box=ROUNDED,
        padding=(1, 2),
        expand=True,
    )

    console.print()
    console.print(panel)
    console.print()
    if telemetry_console is not None:
        telemetry_console.print()
        telemetry_console.print(panel)
        telemetry_console.print()


