    @property
    def host_intel_cache(self):
        """Workspace-scoped HostIntelligenceCache, lazily created."""
        from adscan_internal.services.host_intelligence import HostIntelligenceCache
        ws = getattr(self, 'current_workspace_dir', None)
        if not ws:
            return None
        if self._host_intel_cache is None or getattr(self._host_intel_cache, '_ws_root', None) != ws:
            cache = HostIntelligenceCache(ws)
            cache._ws_root = ws  # type: ignore[attr-defined]
            self._host_intel_cache = cache
        # Bind the active domain so the cache emits the per-domain
        # Defensive Posture inventory file alongside ``host_intel.json``.
        try:
            self._host_intel_cache.bind_domain(getattr(self, 'current_domain', None))
        except Exception:
            pass
        return self._host_intel_cache

    @property
    def edr_intel(self):
        """Workspace-scoped EdrIntelligence, lazily created."""
        from adscan_internal.workspaces.edr_intelligence import EdrIntelligence
        ws = getattr(self, 'current_workspace_dir', None)
        if not ws:
            return None
        existing = getattr(self, '_edr_intel_obj', None)
        if existing is None or getattr(existing, '_ws_root', None) != ws:
            obj = EdrIntelligence(ws)
            obj._ws_root = ws  # type: ignore[attr-defined]
            self._edr_intel_obj = obj
        return self._edr_intel_obj

    def _generate_user_permutations_interactive(self, domain):
        """Interactively build a username wordlist based on provided names."""
        from adscan_internal.rich_output import mark_sensitive
        from adscan_core.username_patterns import (
            generate_username_candidates_for_name_pairs,
        )

        # Choose input method for custom wordlist via interactive menu
        options = [
            "Use file with 'Firstname Lastname' entries",
            "Enter names interactively",
        ]
        choice = self._questionary_select(
            f"Select input for wordlist in domain {domain}", options
        )
        if choice is None:
            print_error("Selection cancelled.")
            return None
        names = []
        if choice == 0:
            marked_domain = mark_sensitive(domain, "domain")
            path = Prompt.ask(
                f"Path to file with names for domain {marked_domain}:", default=""
            )
            if not path:
                print_error("No file path provided.")
                return None
            if not os.path.exists(path):
                marked_path = mark_sensitive(path, "path")
                print_error(f"File {marked_path} does not exist.")
                return None
            with open(path, encoding="utf-8") as f:
                for line in f:
                    parts = line.strip().split()
                    if len(parts) >= 2:
                        names.append((parts[0], parts[1]))
        else:
            # Interactive entry via full-screen editor
            initial = "# Enter each 'Firstname Lastname' on a new line\n"
            text = self._open_fullscreen_editor(
                f"Kerberos user entries for {domain}", initial
            )
            if text is None:
                print_error("User entry cancelled.")
                return None
            names = []
            for line in text.splitlines():
                line = line.strip()
                if not line or line.startswith("#"):
                    continue
                parts = line.split()
                if len(parts) >= 2:
                    names.append((parts[0], parts[1]))

        if not names:
            print_error("No names provided to build wordlist.")
            return None
        perms = generate_username_candidates_for_name_pairs(names)
        # Write to file
        km_dir = os.path.join(
            self.current_workspace_dir, self.domains_dir, domain, "kerberos"
        )
        os.makedirs(km_dir, exist_ok=True)
        out_file = os.path.join(km_dir, "possible_users_permutation.txt")
        with open(out_file, "w", encoding="utf-8") as f:
            for u in sorted(perms):
                f.write(u + "\n")
        print_info_verbose(f"Custom user wordlist generated at {out_file}")
        return out_file

    def __init__(
        self,
        command_runner: Optional[CommandRunner] = None,
        console_instance: Optional[Console] = None,
        license_mode: str = "LITE",
    ):
        global ACTIVE_SHELL
        # super().__init__() # Removed as we no longer inherit from cmd.Cmd
        self.console: Console = (
            console_instance if console_instance is not None else get_console()
        )

        # Wrap console to ensure direct print calls are captured in telemetry.
        # This fixes the regression where PentestShell output (like help tables)
        # was not being recorded because it bypassed the logging system.
        telemetry_console = globals().get("TELEMETRY_CONSOLE")
        if telemetry_console:
            self.console = TelemetryAwareConsole(self.console, telemetry_console)
        normalized_license_mode = (license_mode or "LITE").strip().upper()
        self.license_mode = (
            normalized_license_mode
            if normalized_license_mode in {"LITE", "PRO"}
            else "LITE"
        )
        if not hasattr(self, "domains_data") or self.domains_data is None:
            self.domains_data = CaseInsensitiveDict()
        signal.signal(signal.SIGINT, self.signal_handler)  # Keep custom signal handling
        for optional_sig in ("SIGHUP", "SIGTERM"):
            if hasattr(signal, optional_sig):
                try:
                    signal.signal(getattr(signal, optional_sig), self.signal_handler)
                except OSError:
                    print_info_debug(
                        f"{optional_sig} handler not installed (not supported on this platform)"
                    )
        self.lab_provider: Optional[str] = None
        self.lab_name: Optional[str] = None
        self.lab_name_whitelisted: Optional[bool] = None
        self.lab_confirmation_state: Optional[str] = None
        # Preflight installation check status (set by `handle_start`).
        self.preflight_check_passed: bool | None = None
        self.preflight_check_fix_attempted: bool = False
        self.preflight_check_overridden: bool = False
        self.show_intro()
        # First-run discovery hint — non-blocking, idempotent. Renders
        # once when no workspaces exist and the first-scan flag is unset.
        try:
            from adscan_internal.cli.first_run_panel import (
                maybe_show_first_run_panel,
            )
            maybe_show_first_run_panel()
        except Exception:  # noqa: BLE001 — discovery hint must not break startup
            pass
        self.ensure_workspaces_dir()
        # self.workspace_select() # This might be called before shell.run() in handle_start
        self.background_tasks = []  # List to keep track of active threads
        # self._prompt_drawn_by_command = False # Removed cmd.Cmd specific flag

        # Remote session management (reverse shells, etc.)
        self.session_manager = SessionManager()
        self.current_session: Optional[RemoteSession] = None

        # Cache of CredentialContext per (auth_domain, username) so each step
        # in an exploit chain reuses the same instance (and its in-place
        # ccache_path / issued_at_epoch updates).  See
        # ``adscan_internal/cli/exploits.py:_build_executor_credential_context``.
        self._credential_contexts: dict[tuple[str, str], object] = {}

        self.command_runner = command_runner or default_runner
        self.commands = {}
        self._register_commands()

        # Initialize paths for external tools
        # These paths are resolved once when the shell starts.
        self.netexec_path = get_tool_executable_path("netexec")
        self.certipy_path = get_tool_executable_path("certipy")
        self.bloodyad_path = get_tool_executable_path(
            "bloodyad"
        )  # exe_name is 'bloodyAD'
        self.enum_trusts_path = get_tool_executable_path("enum-trusts")
        self.manspider_path = get_tool_executable_path("manspider")
        self.credsweeper_path = get_tool_executable_path("credsweeper")
        if not self.credsweeper_path:
            try:
                from adscan_internal.services.credsweeper_service import (
                    CredSweeperService,
                )

                if CredSweeperService.is_library_available():
                    self.credsweeper_path = "__credsweeper_library__"
            except Exception:  # noqa: BLE001
                self.credsweeper_path = None
        self.pypykatz_path = get_tool_executable_path("pypykatz")
        self.lsassy_path = get_tool_executable_path("lsassy")
        self.kerbrute_path = get_external_tool_executable("kerbrute")
        self.medusa_path = None  # replaced by aardwolf native RDP stack

        # For Impacket scripts, store the venv bin directory path
        impacket_venv_bin_dir = os.path.join(
            TOOL_VENVS_BASE_DIR, "impacket", "venv", "bin"
        )
        if os.path.isdir(impacket_venv_bin_dir):
            self.impacket_scripts_dir = impacket_venv_bin_dir
        else:
            self.impacket_scripts_dir = None
            # Optionally, print a warning if impacket is expected to be always available
            # print_warning("[PentestShell] Impacket scripts directory not found. Some Impacket-based commands may not work.")

        # For external tools with isolated venvs (firepwd, LSA-Reaper, PKINITtools, responder)
        self.firepwd_python = get_external_tool_python("firepwd")
        self.lsa_reaper_python = get_external_tool_python("LSA-Reaper")
        self.pkinittools_python = get_external_tool_python("PKINITtools")
        self.coercer_python = get_external_tool_python("coercer")

        # Add more tool paths here as needed, for example:
        # self.dploot_path = get_tool_executable_path("dploot")
        # self.smbmap_path = get_tool_executable_path("smbmap")
        # self.kerbrute_path = get_tool_executable_path("kerbrute")

        # Output queue and processor setup
        self.output_queue = queue.Queue()
        self.prompt_results = {}  # Stores results from queued prompts
        self.prompt_events = {}  # Stores threading.Event objects for prompt synchronization
        self._output_processor_thread = None
        self._stop_output_processor = (
            threading.Event()
        )  # Signals the output processor to stop

        # New initializations for handling nested prompts
        self.prompt_interaction_lock = threading.Lock()
        self.is_sub_prompt_active = False
        # Track whether the auto-save background thread has been started
        self._auto_save_thread_started = False
        # Track DCSync context to allow automatic privilege reapplication
        self._current_dcsync_context: Dict[str, Any] | None = None
        # Guard against duplicate workspace/HTML exports during shutdown
        self._shutdown_in_progress = False
        self.session_command_type: str | None = SESSION_COMMAND_TYPE or "start"

        # Tier 2 — live chunked streaming.
        # ``_telemetry_streamer`` is the SessionStreamer instance when
        # the runtime command (start / ci / tui) is in the eligible
        # set AND telemetry is enabled AND the direct sessions URL is
        # embedded. ``None`` otherwise — the legacy single-shot path
        # then ships the session at exit via ``capture_session_end``.
        # See ``adscan_core.telemetry.make_session_streamer`` for the
        # full eligibility check.
        self._telemetry_streamer: Any = None
        try:
            self._init_telemetry_streamer()
        except Exception as exc:  # noqa: BLE001
            # Best-effort: telemetry must never break shell startup.
            telemetry.capture_exception(exc)
            print_info_debug(
                f"(telemetry-streamer) init failed: {type(exc).__name__}: {exc}"
            )

        # CTF flow control: once a domain is compromised ("pwned"), we stop the remaining
        # pipeline and run only a small allowlist of post-compromise actions.
        # We also need an explicit context depth flag to defer post-compromise actions
        # until the surrounding step finishes (prevents confusing "Completed" ordering).
        self._enumeration_context_depth: int = 0
        self._ctf_post_compromise_actions: dict[str, set[str]] = {}
        self._ctf_post_compromise_context: dict[str, dict[str, str]] = {}
        self._ctf_compromise_panel_shown: set[str] = set()
        # Idempotency guard: domains whose CTF post-compromise actions have
        # already been dispatched (flags captured, dcsync done). Prevents
        # double-execution when _flush_ctf_post_compromise_queue is called
        # from multiple places (inline from attack step + post-Phase flow).
        self._ctf_post_compromise_dispatched: set[str] = set()

        # Session tracking for telemetry (Hormozi Give:Ask ratio monitoring)
        self._session_start_time = None  # Will be set when session_start is captured
        self._session_commands_count = 0
        self._session_victories = []  # List of victory types achieved during session
        self._session_frustrations = []  # List of frustrations hit during session

        # Case study metrics tracking (TTFAP, TTFH only - TTFC/TTC in their own events)
        # TTFC is in first_cred_found.duration_minutes
        # TTC is in domain_compromise.duration_minutes
        self._session_first_attack_path_time: Optional[float] = None  # TTFAP
        self._session_first_hash_time: Optional[float] = None  # TTFH
        self._session_attack_paths_count: int = 0  # Total attack paths found
        self._session_credentials_count: int = 0  # Total credentials obtained
        self._session_hashes_count: int = 0  # Total hashes extracted
        self._session_compromise_status: str = SESSION_COMPROMISE_STATUS_UNKNOWN
        self._session_compromised_users: set[str] = set()

        # Scan-level metrics for case studies (reset per scan, not per session)
        # Note: Attack path metrics are computed from attack_graph.json at scan completion
        # using _compute_attack_path_metrics() rather than tracked at runtime
        self._scan_first_credential_time: Optional[float] = None  # For scan-level TTFC
        self._scan_compromise_time: Optional[float] = None  # For scan-level TTC

        # Service layer instances (lazy-loaded)
        self._graph_service: Optional[Any] = None
        self._domain_service: Optional[Any] = None
        self._credential_service: Optional[Any] = None
        self._enumeration_service: Optional[Any] = None
        self._dns_resolver_service: Optional[Any] = None
        self._dns_discovery_service: Optional[Any] = None
        self._credsweeper_service: Optional[Any] = None
        self._spidering_service: Optional[Any] = None
        self._ai_service: Optional[Any] = None

        ACTIVE_SHELL = self

    def _get_license_mode_enum(self) -> "LicenseMode":
        """Return the current LicenseMode enum for this shell.

        This helper avoids importing the service layer at module import time and
        centralizes the mapping between the string license mode used by the CLI
        and the internal enum used by services.

        Returns:
            LicenseMode: Current license mode.
        """
        from adscan_internal.core import LicenseMode

        license_mode = str(getattr(self, "license_mode", "PRO") or "PRO").upper()
        if license_mode == "LITE":
            return LicenseMode.LITE
        return LicenseMode.PRO

    def _get_graph_service(self) -> object:
        """Get or create the local attack-graph query service.

        Returns:
            object: Initialized LocalGraphService instance.
        """
        from adscan_internal.services import LocalGraphService

        existing = self._graph_service
        if existing is not None and getattr(existing, "edition", "") == "native":
            return existing
        service = LocalGraphService(self)
        self._graph_service = service
        return service

    def _get_dns_resolver_service(self) -> "DNSResolverService":
        """Get or create a cached DNSResolverService instance.

        This service centralizes Unbound management and resolver persistence logic.
        It is a transitional extraction from the `adscan.py` monolith.

        Returns:
            DNSResolverService: Initialized service instance.
        """
        existing = self._dns_resolver_service
        if existing is not None:
            return existing

        from adscan_internal.services import DNSResolverRuntime, DNSResolverService

        runtime = DNSResolverRuntime(
            is_full_container_runtime=_is_full_adscan_container_runtime,
            get_local_resolver_ip=_get_adscan_local_resolver_ip,
            is_unbound_listening_local=_is_unbound_listening_local,
            start_unbound_without_systemd=_start_unbound_without_systemd,
            start_unbound_without_systemd_via_sudo=_start_unbound_without_systemd_via_sudo,
            is_loopback_ip=_is_loopback_ip,
            is_systemd_available=_is_systemd_available,
        )
        service = DNSResolverService(host=self, runtime=runtime)
        self._dns_resolver_service = service
        return service

    def get_local_resolver_ip(self) -> str:
        """Get the local resolver IP address.

        Returns:
            IP address of the local DNS resolver (typically 127.0.0.1).
        """
        return _get_adscan_local_resolver_ip()

    # Ruff can incorrectly flag forward-referenced string annotations as undefined
    # in this file's current lint configuration; keep the runtime behaviour unchanged.
    def _get_dns_discovery_service(self) -> "DNSDiscoveryService":  # noqa: F821
        """Get or create a cached DNSDiscoveryService instance.

        This service encapsulates DNS discovery primitives used by multiple flows,
        such as SRV resolution and hostname A-record resolution.
        """
        existing = self._dns_discovery_service
        if existing is not None:
            return existing

        from adscan_internal.services import DNSDiscoveryRuntime, DNSDiscoveryService

        runtime = DNSDiscoveryRuntime(dig_compat_flags=_DIG_COMPAT_FLAGS)
        service = DNSDiscoveryService(host=self, runtime=runtime)
        self._dns_discovery_service = service
        return service

    def _get_credsweeper_service(self):
        """Get or create a cached CredSweeperService instance.

        This service encapsulates CredSweeper CLI integration so that multiple
        workflows (manspider share spidering, PowerShell history, transcripts,
        etc.) can reuse a single, testable implementation.
        """
        existing = self._credsweeper_service
        if existing is not None:
            return existing

        from adscan_internal.services import CredSweeperService

        service = CredSweeperService(command_executor=self.run_command)
        self._credsweeper_service = service
        return service

    def _get_spidering_service(self) -> "SpideringService":
        """Get or create a cached SpideringService instance."""
        existing = getattr(self, "_spidering_service", None)
        if existing is not None:
            return existing

        from adscan_internal.services import SpideringService

        spider_service = SpideringService(
            command_executor=self.run_command,
            credsweeper_service=self._get_credsweeper_service(),
            file2john_callback=self.file2john,
            certipy_callback=self.ptc_certipy,
            list_zip_callback=self.list_zip,
            extract_zip_callback=self.extract_zip,
            add_credential_callback=self.add_credential,
            cpassword_callback=self._process_cpassword_text,
            keepass_artifact_callback=self._process_keepass_artifact,
            office_artifact_callback=self._process_office_artifact,
            handle_found_credentials_callback=self.handle_found_credentials,
            credsweeper_path=getattr(self, "credsweeper_path", None),
            pypykatz_path=self.pypykatz_path,
        )
        self._spidering_service = spider_service
        return spider_service

    def _get_john_artifact_cracking_service(self):
        """Get or create a cached John artifact cracking service."""
