    def do_creds(self, args):
        """
        Manages the credentials for the current workspace.

        This thin wrapper delegates to :mod:`adscan_internal.cli.creds` so that
        the core logic can be reused by other UX layers.

        Subcommands:

            show: Displays the current workspace credentials.

            show_users: Alias of `show`.

            clear <domain>: Clears all credentials for the specified domain in the current workspace.

            delete <domain>: Deletes one selected credential for the specified domain in the current workspace.

            select <domain>: Run the enumeration of the user of the selected credential.

            save <domain> <username> <credential> [host] [service]: Saves a credential for the specified domain in the current workspace.

            add <domain> <username> <credential> [host] [service]: Alias of `save`.
        """
        from adscan_internal.cli.creds import (
            add_credential,
            clear_creds,
            delete_cred,
            ensure_domain_ready_for_manual_credential_save,
            normalize_creds_subcommand,
            select_cred,
            show_creds,
        )
        from adscan_internal.cli.attack_path_execution import (
            clear_writelogonscript_manual_validation,
            match_writelogonscript_manual_validation,
            _attempt_writelogonscript_cleanup_if_ready,
        )
        from adscan_internal.rich_output import print_error, print_instruction

        command_parts = args.split()
        if not command_parts:
            print_instruction(
                "Please provide a subcommand for 'creds'. Usage: creds <show|show_users|clear|delete|select|save> [options]"
            )
            self.do_help("creds")
            return

        command, alias_used = normalize_creds_subcommand(command_parts[0])
        if alias_used:
            print_info_debug(
                f"[cli] creds alias detected: {command_parts[0].lower()} -> {command}"
            )

        if command == "show":
            show_creds(self)
        elif command == "clear":
            if len(command_parts) == 2:
                clear_creds(self, command_parts[1])
            else:
                print_instruction("Usage: creds clear <domain_name>")
        elif command == "delete":
            if len(command_parts) == 2:
                delete_cred(self, command_parts[1])
            else:
                print_instruction("Usage: creds delete <domain_name>")
        elif command == "select":
            if len(command_parts) == 2:
                select_cred(self, command_parts[1])
            else:
                print_instruction("Usage: creds select <domain_name>")
        elif command == "save":
            if len(command_parts) < 4:
                print_instruction(
                    "Usage: creds save <domain_name> <username> <credential> [host] [service]"
                )
                return
            domain = command_parts[1]
            user = command_parts[2]
            cred = command_parts[3]
            host = command_parts[4] if len(command_parts) > 4 else None
            service = command_parts[5] if len(command_parts) > 5 else None
            is_local_target = bool(host and service)
            if not ensure_domain_ready_for_manual_credential_save(
                self,
                domain=domain,
                username=user,
                is_local_target=is_local_target,
            ):
                if not _should_disable_interactive_prompts(self):
                    from adscan_internal.cli.start import run_start_auth

                    if Confirm.ask(
                        "Do you want to start authenticated initialization now?",
                        default=True,
                    ):
                        run_start_auth(self, None)
                return
            pending_manual_validation = None
            trusted_manual_validation = False
            if not is_local_target:
                pending_manual_validation = match_writelogonscript_manual_validation(
                    self,
                    domain=domain,
                    username=user,
                    credential=cred,
                )
                trusted_manual_validation = pending_manual_validation is not None
            add_credential(
                self,
                domain,
                user,
                cred,
                host,
                service,
                trusted_manual_validation=trusted_manual_validation,
                mark_user_compromised=False,
            )
            if trusted_manual_validation and isinstance(
                pending_manual_validation, dict
            ):
                _attempt_writelogonscript_cleanup_if_ready(
                    self,
                    domain=domain,
                    summary=pending_manual_validation.get("summary")
                    if isinstance(pending_manual_validation.get("summary"), dict)
                    else {"steps": []},
                )
                clear_writelogonscript_manual_validation(
                    self,
                    domain=domain,
                    username=user,
                    credential=cred,
                )
        else:
            print_error(
                f"Unknown 'creds' subcommand: '{command}'. Use 'help creds' for available subcommands."
            )

