    def verify_domain_credentials(
        self,
        domain_name,
        user,
        cred_value,
        *,
        ui_silent: bool = False,
        password_change_attempted: bool = False,
        recovery_attempted: bool = False,
        source_steps: list[object] | None = None,
    ):
        """Verifies domain credentials against the domain's PDC using NetExec.

        Args:
            recovery_attempted: When True, the USER_NOT_FOUND branch will NOT
                re-enter the centralized credential-recovery service. Candidate
                verification calls and the winner re-persist set this to break
                the recursion (mirrors ``password_change_attempted``).
        """
        from rich.panel import Panel

        from adscan_internal.rich_output import mark_sensitive
        from adscan_internal.services.credential_service import CredentialStatus

        self._last_domain_credential_verification_result = None
        self._last_verified_domain_name = None
        self._last_verified_domain_username = None
        self._last_verified_domain_credential = None

        # Safely get PDC information, handling case when it doesn't exist
        domain_data = self.domains_data.get(domain_name, {})
        pdc_host = domain_data.get("pdc")
        pdc_hostname = domain_data.get("pdc_hostname")

        if not pdc_host or not pdc_hostname:
            marked_domain_name = mark_sensitive(domain_name, "domain")
            if not ui_silent:
                print_error(
                    f"PDC information not found in workspace variables for domain "
                    f"'[bold]{marked_domain_name}[/bold]'. Cannot verify credentials."
                )
                print_info(
                    "Hint: Set the PDC hostname using: [cyan]set pdc_hostname <PDC_HOSTNAME>[/cyan] "
                    "and the PDC IP with: [cyan]set pdc <PDC_IP>[/cyan]"
                )
            else:
                print_info_verbose(
                    "[ui_silent] Missing PDC information; cannot verify credentials."
                )
            return False

        pdc_fqdn = f"{pdc_hostname}.{domain_name}"

        if not pdc_hostname:
            marked_domain_name = mark_sensitive(domain_name, "domain")
            if not ui_silent:
                print_error(
                    f"PDC hostname not found in workspace variables for domain "
                    f"'[bold]{marked_domain_name}[/bold]'. Cannot verify credentials."
                )
                print_info(
                    "Hint: Set the PDC hostname using: [cyan]set pdc_hostname <PDC_HOSTNAME>[/cyan] "
                    "and the PDC IP with: [cyan]set pdc <PDC_IP>[/cyan]"
                )
            else:
                print_info_verbose(
                    "[ui_silent] Missing PDC hostname; cannot verify credentials."
                )
            return False

        cred_type = "Hash" if self.is_hash(cred_value) else "Password"
        if not ui_silent:
            print_operation_header(
                "Domain Credential Verification",
                details={
                    "Domain": domain_name,
                    "PDC": pdc_host,
                    "PDC FQDN": pdc_fqdn,
                    "Username": user,
                    cred_type: cred_value,
                    "Protocol": "LDAP",
                },
                icon="✓",
            )

        # Sync clock with PDC before requesting a TGT. Kerberos rejects
        # tickets when client and KDC drift more than 5 minutes
        # (KRB_AP_ERR_SKEW); this preserves the existing behaviour without
        # using the result for an auth-string branch (the NetExec LDAP
        # fallback that consumed it was deleted).
        self.do_sync_clock_with_pdc(domain_name)

        print_info_verbose("Executing credential verification")

        service = self._get_credential_service()

        try:
            # Native Kerberos path — single source of truth. Requesting a
            # TGT IS the verification: success means valid creds and yields
            # a usable ticket as a side-effect. The historic NetExec LDAP
            # fallback was deleted because it silently disagreed with
            # Kerberos's verdict; when port 88 is unreachable the result
            # message now embeds a TCP-probed diagnosis (filtered/closed/
            # reachable-but-failing) instead of switching protocols.
            result = service._verify_via_kerberos_sync(
                domain=domain_name,
                kdc_ip=pdc_host,
                username=user,
                credential=cred_value,
                credential_type="hash" if self.is_hash(cred_value) else "password",
            )

            if result.status == CredentialStatus.VALID and isinstance(
                result.raw_output, bytes
            ):
                # Persist the TGT we got as a side-effect of verification.
                try:
                    from adscan_internal.services.kerberos_ticket_service import (
                        KerberosTicketService,
                        _write_ccache_bytes,
                    )

                    if self.current_workspace_dir:
                        ccache_dir = KerberosTicketService._build_ccache_dir(
                            self.current_workspace_dir, domain_name
                        )
                        ccache_path = ccache_dir / f"{user}.ccache"
                        _write_ccache_bytes(result.raw_output, ccache_path)
                        print_info_verbose(
                            f"[verify] Kerberos TGT persisted for {user}@{domain_name}"
                        )
                    result.raw_output = None
                except Exception as exc_tgt:  # noqa: BLE001
                    telemetry.capture_exception(exc_tgt)

        except Exception as e:
            telemetry.capture_exception(e)
            if not ui_silent:
                print_error(
                    f"An unexpected error occurred during credential verification: {e}"
                )
            if not ui_silent:
                print_exception(show_locals=False, exception=e)
            else:
                print_info_verbose(
                    f"[ui_silent] Unexpected error during credential verification: {e}"
                )
            return False

        self._last_domain_credential_verification_result = result
        status = result.status
        marked_user = mark_sensitive(user, "user")
        marked_domain_name = mark_sensitive(domain_name, "domain")

        def _maybe_retry_pwdlastset_year_variant() -> bool:
            """Offer one same-user retry when pwdLastSet suggests a newer year."""
            if password_change_attempted or ui_silent or self.is_hash(cred_value):
                return False

            from adscan_internal.services.password_year_variant_service import (
                resolve_password_year_variant_suggestion,
            )

            suggestion = resolve_password_year_variant_suggestion(
                self,
                domain=domain_name,
                username=user,
                password=cred_value,
            )
            if suggestion is None:
                return False

            marked_original_password = mark_sensitive(cred_value, "password")
            marked_suggested_password = mark_sensitive(
                suggestion.suggested_password, "password"
            )
            print_info(
                "The password contains year "
                f"{suggestion.original_year}, but BloodHound reports that "
                f"'[bold]{marked_user}[/bold]' last changed their password in "
                f"{suggestion.pwdlastset_year}."
            )
            retry_variant = Confirm.ask(
                "Try the likely year-rolled variant "
                f"{marked_suggested_password} for this same user?",
                default=True,
            )
            if not retry_variant:
                print_info_verbose(
                    "Password year-rollover same-user retry declined by operator."
                )
                return False

            print_info_verbose(
                "Retrying credential verification with pwdLastSet year-rollover "
                f"variant for {marked_user}: {marked_original_password} -> "
                f"{marked_suggested_password}"
            )
            return bool(
                self.verify_domain_credentials(
                    domain_name,
                    user,
                    suggestion.suggested_password,
                    ui_silent=ui_silent,
                    password_change_attempted=True,
                    recovery_attempted=recovery_attempted,
                    source_steps=source_steps,
                )
            )

        if status == CredentialStatus.VALID:
            self._last_verified_domain_name = domain_name
            self._last_verified_domain_username = user
            self._last_verified_domain_credential = cred_value
            print_info_verbose(
                f"Successfully verified credentials for user '[bold]{marked_user}[/bold]' "
                f"on domain '[bold]{marked_domain_name}[/bold]' against PDC [bold]{pdc_host}[/bold]."
            )
            return True

        if status == CredentialStatus.INVALID:
            should_offer_spraying = False
            spraying_failure_detail = "incorrect credentials"

            # Distinguish generic invalid creds from pre-auth failure to keep the
            # user-facing explanation precise while still exposing the same
            # spraying shortcut for password-based secrets.
            if result.error_message == "Pre-authentication failed":
                should_offer_spraying = True
                spraying_failure_detail = "pre-authentication failed"
                marked_cred_value = mark_sensitive(cred_value, "password")
                if not ui_silent:
                    print_error(
                        "Credential verification failed for user "
                        f"'[bold]{marked_user}[/bold]' on domain '[bold]{marked_domain_name}[/bold]'. "
                        f"The user '[bold]{marked_user}[/bold]' might have changed the "
                        f"{marked_cred_value} password."
                    )
                else:
                    print_info_verbose(
                        f"[ui_silent] Credential verification failed for user {marked_user} on domain {marked_domain_name} (pre-authentication failed)."
                    )
                from adscan_internal.services.credential_store_service import (
                    CredentialStoreService,
                )

                if not CredentialStoreService._looks_like_ntlm_hash(cred_value):
                    if _maybe_retry_pwdlastset_year_variant():
                        return True
                    if not ui_silent and not password_change_attempted:
                        respuesta = Confirm.ask(
                            "Would you like to perform a password spraying with this password?",
                            default=True,
                        )
                        if respuesta:
                            self.spraying_with_password(
                                domain_name,
                                cred_value,
                                source_context={
                                    "auth_username": user,
                                    "origin": "credential_validation",
                                },
                                source_steps=source_steps,
                            )
                    elif ui_silent:
                        print_info_verbose(
                            "[ui_silent] Password spraying prompt suppressed."
                        )
                    else:
                        print_info_verbose(
                            "Password spraying prompt skipped for failed year-rollover retry."
                        )
                return False

            if not ui_silent:
                print_error(
                    f"Logon failure for user '[bold]{marked_user}[/bold]' on domain "
                    f"'[bold]{marked_domain_name}[/bold]' against PDC [bold]{pdc_host}[/bold]. "
                    "Incorrect credentials."
                )
            else:
                print_info_verbose(
                    f"[ui_silent] Logon failure for user {marked_user} on domain {marked_domain_name}."
                )

            should_offer_spraying = True
            from adscan_internal.services.credential_store_service import (
                CredentialStoreService,
            )

            if (
                should_offer_spraying
                and not CredentialStoreService._looks_like_ntlm_hash(cred_value)
            ):
                if _maybe_retry_pwdlastset_year_variant():
                    return True
                if not ui_silent and not password_change_attempted:
                    respuesta = Confirm.ask(
                        "Would you like to perform a password spraying with this password?",
                        default=True,
                    )
                    if respuesta:
                        self.spraying_with_password(
                            domain_name,
                            cred_value,
                            source_context={
                                "auth_username": user,
                                "origin": "credential_validation",
                                "verification_failure": spraying_failure_detail,
                            },
                            source_steps=source_steps,
                        )
                elif ui_silent:
                    print_info_verbose(
                        "[ui_silent] Password spraying prompt suppressed."
                    )
                else:
                    print_info_verbose(
                        "Password spraying prompt skipped for failed year-rollover retry."
                    )
            return False

        if status == CredentialStatus.ACCOUNT_LOCKED:
            if not ui_silent:
                print_error(
                    f"Account locked out for user '[bold]{marked_user}[/bold]' on domain "
                    f"'[bold]{marked_domain_name}[/bold]'."
                )
            else:
                print_info_verbose(
                    f"[ui_silent] Account locked for user {marked_user} on domain {marked_domain_name}."
                )
            return False

        if status == CredentialStatus.ACCOUNT_DISABLED:
            if not ui_silent:
                print_error(
                    f"Account disabled for user '[bold]{marked_user}[/bold]' on domain "
                    f"'[bold]{marked_domain_name}[/bold]'."
                )
            else:
                print_info_verbose(
                    f"[ui_silent] Account disabled for user {marked_user} on domain {marked_domain_name}."
                )
            return False

        if status == CredentialStatus.PASSWORD_EXPIRED:
            if not ui_silent:
                print_warning(
                    f"Password expired for user '[bold]{marked_user}[/bold]' on domain "
                    f"'[bold]{marked_domain_name}[/bold]'. Verification failed as password "
                    "needs change."
                )
            else:
                print_info_verbose(
                    f"[ui_silent] Password expired for user {marked_user} on domain {marked_domain_name}."
                )
            return False

        if status == CredentialStatus.PASSWORD_MUST_CHANGE:
            if not ui_silent:
                print_warning(
                    f"Password must be changed for user '[bold]{marked_user}[/bold]' "
                    f"on domain '[bold]{marked_domain_name}[/bold]' before logon can continue."
                )
            else:
                print_info_verbose(
                    f"[ui_silent] Password must change for user {marked_user} on domain "
                    f"{marked_domain_name}."
                )

            if password_change_attempted:
                return False

            new_password = self._maybe_change_password_after_must_change(
                domain_name=domain_name,
                user=user,
                current_password=cred_value,
                pdc_host=pdc_host,
                pdc_fqdn=pdc_fqdn,
                ui_silent=ui_silent,
            )
            if not new_password:
                return False

            return bool(
                self.verify_domain_credentials(
                    domain_name,
                    user,
                    new_password,
                    ui_silent=ui_silent,
                    password_change_attempted=True,
                    recovery_attempted=recovery_attempted,
                )
            )

        if status == CredentialStatus.USER_NOT_FOUND:
            print_error(
                f"User '[bold]{marked_user}[/bold]' not found on domain "
                f"'[bold]{marked_domain_name}[/bold]'."
            ) if not ui_silent else print_info_verbose(
                f"[ui_silent] User not found on domain {marked_domain_name}."
            )

            # ui_silent / recovery_attempted callers are themselves part of a
            # recovery (candidate verification or the winner re-persist), or
            # are background batch checks; never re-enter recovery from them.
            # This is the infinite-loop guard (mirrors password_change_attempted).
            if ui_silent or recovery_attempted:
                return False

            from adscan_core.rich_output import confirm_ask, prompt_ask
            from adscan_internal.services.credential_recovery_service import (
                recover_user_not_found,
            )

            def _verify_candidate(candidate_user: str) -> bool:
                """One auth attempt: the recovered secret is the oracle."""
                return bool(
                    self.verify_domain_credentials(
                        domain_name,
                        candidate_user,
                        cred_value,
                        ui_silent=True,
                        recovery_attempted=True,
                        source_steps=source_steps,
                    )
                )

            def _persist(resolved_user: str) -> None:
                self.add_credential(
                    domain_name,
                    resolved_user,
                    cred_value,
                    source_steps=source_steps,
                )

            def _spray() -> None:
                self.spraying_with_password(
                    domain_name,
                    cred_value,
                    source_context={
                        "auth_username": user,
                        "origin": "credential_recovery_user_not_found",
                    },
                    source_steps=source_steps,
                )

            def _confirm_spray() -> bool:
                return bool(
                    confirm_ask(
                        "Spray the recovered password across the known accounts "
                        "to find its owner?",
                        default=True,
                    )
                )

            def _prompt_manual_username() -> str | None:
                answer = prompt_ask(
                    "Enter the correct username, or 'n' to skip",
                    default="n",
                )
                answer = (answer or "").strip()
                return None if not answer or answer.lower() == "n" else answer

            try:
                recover_user_not_found(
                    self,
                    domain=domain_name,
                    failed_user=user,
                    cred_value=cred_value,
                    verify_candidate=_verify_candidate,
                    add_credential=_persist,
                    spray=_spray,
                    confirm_spray=_confirm_spray,
                    prompt_manual_username=_prompt_manual_username,
                    source_steps=source_steps,
                )
            except Exception as exc_recovery:  # noqa: BLE001
                telemetry.capture_exception(exc_recovery)
                print_error(
                    "Credential recovery failed; the credential was not adopted."
                )
            # The original (stored) username is still not found; recovery
            # persists any resolved/manual credential itself via add_credential,
            # so the verdict for THIS call stays False.
            return False

        if status == CredentialStatus.TIMEOUT:
            if not ui_silent:
                print_error(
                    "Credential verification command timed out for user "
                    f"'[bold]{marked_user}[/bold]' on domain '[bold]{marked_domain_name}[/bold]'."
                )
                print_instruction(
                    "Verify VPN/network connectivity to the target and retry."
                )
            else:
                print_info_verbose(
                    f"[ui_silent] Credential verification timed out for user {marked_user} on domain {marked_domain_name}."
                )
            return False

        # Default / ERROR / ACCOUNT_RESTRICTION and other unexpected states.
        error_detail = (result.error_message or "").strip()
        error_suffix = f" ({error_detail})" if error_detail else " with unknown error."
        if not ui_silent:
            print_error(
                f"Credential verification failed for user '[bold]{marked_user}[/bold]' "
                f"on domain '[bold]{marked_domain_name}[/bold]'{error_suffix}"
            )
        else:
            print_info_verbose(
                f"[ui_silent] Credential verification failed for user {marked_user} on domain {marked_domain_name}{error_suffix}"
            )

        if result.raw_output and SECRET_MODE:
            self.console.print(
                Panel(
                    result.raw_output.strip(),
                    title=f"NXC Output for {user}@{domain_name}",
                    border_style="dim red",
                    expand=False,
                )
            )
        elif not result.raw_output:
            print_info_verbose("NetExec produced no output.")

        return False

