    def run_enumeration(
        self,
        domain,
        *,
        stop_after_phase: int | None = None,
        start_from_phase: int | None = None,
    ):
        def _is_audit_map_only() -> bool:
            """Return True when audit mode is post-compromise and should avoid active exploitation."""
            try:
                return (
                    self.type == "audit"
                    and self.domains_data.get(domain, {}).get("auth") == "pwned"
                )
            except Exception:
                return False

        # If already compromised in CTF, execute queued post-compromise actions (once)
        # and skip the rest of the enumeration pipeline.
        if self._is_ctf_domain_pwned(domain):
            self._ctf_execute_post_compromise_actions(domain)
            return

        # Run workspace migrations before Phase 1 starts (idempotent).
        try:
            from adscan_internal.services.workspace_migrations import (
                run_workspace_migrations,
            )

            run_workspace_migrations(
                workspace_cwd=self.current_workspace_dir or os.getcwd(),
                domain=domain,
                domains_dir=self.domains_dir,
            )
        except Exception as _migration_exc:  # noqa: BLE001
            telemetry.capture_exception(_migration_exc)

        # Professional post-collection enumeration with phased workflow.
        from adscan_internal.rich_output import print_step_status

        # Determine total phases based on scan type.
        #
        # Phase design goals:
        # - Quick wins first (graph-derived steps + low-noise credential discovery)
        # - After any new credential, we can immediately search for paths from owned users
        # - Avoid repeating slow enumeration already covered by the local graph collection
        #
        # Base phases:
        #  1) Domain Intelligence
        #  2) Attack Paths Discovery (steps + offer execution from owned)
        #  3) Quick Credential Wins (Timeroast, ADCS detect, LDAP descriptions, GPP)
        #  4) Password Spraying
        #  5) Audit-only Unauthenticated Attack Surface
        #  6) Audit-only Extras (CVE scan + configs)
        #
        # Roasting and User Privilege Assessment are no longer dedicated phases:
        # kerberoast/asreproast attack steps and privilege analysis of the bound
        # user are materialized in Attack Paths Discovery via the collector
        # pipeline, and the operator executes them through the attack-paths
        # offer flow. Avoiding the redundant re-run keeps the workflow narrative
        # tight and prevents duplicate enumeration.

        # Inner-scan chapter list lives in adscan_internal.services.scan_phases
        # (single source of truth shared with _run_enum_domain_auth and the
        # trust-enumeration entry point). The local helper still exists so
        # the rest of this method keeps the same call signature, but it
        # delegates to the registry — adding a phase only means editing
        # ``scan_phases.SCAN_PHASES`` once.
        from adscan_internal.services.scan_phases import (
            emit_chapter as _emit_chapter_global,
            phases_for_scan_type as _phases_for_scan_type,
        )

        _scan_type = self.type or "default"
        _scan_phase_titles: list[str] = [
            phase.title for phase in _phases_for_scan_type(_scan_type)
        ]

        def _emit_scan_chapter(title: str) -> None:
            """Emit an inner-scan chapter divider for ``title``.

            Resolves ``title`` to a phase id by looking up the registry, then
            delegates to the shared :func:`emit_chapter` helper so trust,
            collection, and analysis phases all render with consistent
            numbering and the same phase strip.
            """
            from adscan_internal.services.scan_phases import SCAN_PHASES

            phase = next((p for p in SCAN_PHASES if p.title == title), None)
            if phase is None:
                return
            _emit_chapter_global(phase.phase_id, scan_type=_scan_type)

        # Single-slot tracker for the currently open timeline phase span.
        # ``_enter_phase`` automatically closes the prior span before opening
        # the next, so phase transitions stay symmetrical even when the
        # caller forgets to close explicitly. ``_close_active_phase`` runs
        # in the function-level finally to flush the last phase on exit.
        from adscan_internal.services.scan_phases import (
            SCAN_PHASES as _SCAN_PHASES_REG,
        )
        from adscan_internal.services.scan_timeline import (
            phase_span as _phase_span,
        )

        _active_phase_cm: list[Any] = [None]

        def _close_active_phase() -> None:
            cm = _active_phase_cm[0]
            if cm is None:
                return
            _active_phase_cm[0] = None
            try:
                cm.__exit__(None, None, None)
            except Exception:  # noqa: BLE001 — telemetry must never block
                pass

        def _enter_phase(title: str) -> None:
            """Render the chapter for ``title`` and open a fresh timeline span."""
            _close_active_phase()
            _emit_scan_chapter(title)
            phase = next(
                (p for p in _SCAN_PHASES_REG if p.title == title), None
            )
            if phase is None:
                return
            try:
                cm = _phase_span(
                    self,
                    domain,
                    phase_id=phase.phase_id,
                    phase_title=phase.title,
                )
                cm.__enter__()
                _active_phase_cm[0] = cm
            except Exception:  # noqa: BLE001
                _active_phase_cm[0] = None

        def _run_step(
            step_name: str,
            step_fn,
            *,
            step_number: int | None = None,
            total_steps: int | None = None,
            details: str | None = None,
        ) -> bool:
            """Run a step with consistent UX and allow early stop on CTF compromise.

            Returns:
                True if the enumeration pipeline should stop early (CTF + pwned).
            """
            # If we were compromised asynchronously (e.g. by another pipeline), stop
            # without printing additional "Running/Completed" noise in CTF mode.
            if self._is_ctf_domain_pwned(domain):
                self._ctf_execute_post_compromise_actions(domain)
                return True

            print_step_status(
                step_name,
                status="running",
                step_number=step_number,
                total_steps=total_steps,
                details=details,
            )
            try:
                self._enter_enumeration_context()
                step_fn()
                print_step_status(
                    step_name,
                    status="completed",
                    step_number=step_number,
                    total_steps=total_steps,
                )
            except Exception as e:
                telemetry.capture_exception(e)

                print_step_status(
                    step_name,
                    status="failed",
                    step_number=step_number,
                    total_steps=total_steps,
                )
                from adscan_internal.rich_output import print_exception

                # User-visible error is sanitized unless SECRET_MODE=True.
                print_exception(exception=e, show_locals=False)
            finally:
                self._exit_enumeration_context()

            # If the domain was compromised during this step, execute the minimal
            # post-compromise actions and stop the remaining pipeline.
            if self._is_ctf_domain_pwned(domain):
                self._ctf_execute_post_compromise_actions(domain)
                return True
            return False

        def _phase1_outputs_ready() -> bool:
            from adscan_internal.workspaces import domain_subpath

            workspace_cwd = self.current_workspace_dir or os.getcwd()
            computers_file = domain_subpath(
                workspace_cwd, self.domains_dir, domain, "enabled_computers.txt"
            )
            users_file = domain_subpath(
                workspace_cwd, self.domains_dir, domain, "enabled_users.txt"
            )
            return os.path.exists(computers_file) and os.path.exists(users_file)

        _skip_phase1 = bool(start_from_phase and start_from_phase > 1)

        phase1_marked_complete = bool(
            self.domains_data.get(domain, {}).get("phase1_complete")
        )
        phase1_outputs_exist = _phase1_outputs_ready()
        phase1_already_done = phase1_marked_complete or phase1_outputs_exist
        rerun_phase1 = False

        # The workspace-resume panel in `_run_enum_domain_auth` is the single
        # source of truth for the operator's intent (Resume/Refresh/Replay/
        # Inspect). REPLAY and REFRESH both want the analysis pipeline to re-
        # run, so we honour them even when the cached output files still exist
        # on disk. RESUME keeps the legacy behaviour (skip when artefacts are
        # there). When the panel was not shown (no prior results, CI mode with
        # no override), workspace_action is None and this collapses to the
        # original first-run flow.
        workspace_action = self.domains_data.get(domain, {}).get("_workspace_action")
        if workspace_action in {"refresh", "replay"}:
            rerun_phase1 = True
        if phase1_already_done and not _skip_phase1 and workspace_action == "resume":
            print_info(
                f"Reusing cached Phase 1 results for {mark_sensitive(domain, 'domain')}."
            )

        # ========== PHASE 1: Domain Intelligence ==========
        _enter_phase("Domain Intelligence")
        emit_phase("domain_analysis")
        if phase1_already_done and not rerun_phase1:
            print_step_status(
                "Host Inventory",
                status="skipped",
                step_number=1,
                total_steps=3,
                details="Using existing Phase 1 results",
            )
            print_step_status(
                "Identity Inventory",
                status="skipped",
                step_number=2,
                total_steps=3,
                details="Using existing Phase 1 results",
            )
            print_step_status(
                "ADCS Discovery",
                status="skipped",
                step_number=3,
                total_steps=3,
                details="Using existing Phase 1 results",
            )
        else:
            if _run_step(
                "Host Inventory",
                lambda: self.do_host_inventory(domain),
                step_number=1,
                total_steps=4,
            ):
                return

            time.sleep(2)

            if _run_step(
                "Identity Inventory",
                lambda: self.do_identity_inventory(domain),
                step_number=2,
                total_steps=4,
            ):
                return

            if _run_step(
                "ADCS Discovery",
                lambda: self._detect_adcs_metadata(
                    domain,
                    force=True,
                    source_context="authenticated_enum_phase1",
                ),
                step_number=3,
                total_steps=4,
            ):
                return

            # Per-host NTLMv1 sweep (sub-project #2). Runs HERE -- after the
            # reachable host set is known (Host Inventory) and BEFORE Attack
            # Paths Discovery -- so the per-host NTLMv1/v2 verdicts are persisted
            # when attack paths compute (see the per-host NTLMv1 detection
            # design spec, section 5.2). The sweep is fully self-gating: type
            # scope (ctf=all reachable / audit=DCs only with operator opt-in),
            # the >=2-reachable relay gate, the OPSEC confirm prompt
            # (auto-resolved in non-interactive runs), serial execution, and
            # per-host persistence all live inside the entry point. It emits its
            # own user-facing output; the returned summary dict is logged at
            # debug only.
            def _run_ntlm_auth_type_sweep_step() -> None:
                summary = self.ask_for_ntlm_auth_type_sweep(domain)
                print_info_debug(
                    f"[ntlm-capture][sweep] phase summary: {summary}"
                )

            if _run_step(
                "NTLM Auth-Type Sweep",
                _run_ntlm_auth_type_sweep_step,
                step_number=4,
                total_steps=4,
            ):
                return

            self.domains_data.setdefault(domain, {})["phase1_complete"] = (
                _phase1_outputs_ready()
            )

            # Capture environment metrics for case studies after Phase 1 completes
            try:
                from adscan_internal.workspaces import domain_subpath

                workspace_cwd = self.current_workspace_dir or os.getcwd()
                users_file = domain_subpath(
                    workspace_cwd, self.domains_dir, domain, "enabled_users.txt"
                )
                computers_file = domain_subpath(
                    workspace_cwd, self.domains_dir, domain, "enabled_computers.txt"
                )

                user_count = 0
                computer_count = 0

                if os.path.exists(users_file):
                    with open(users_file, "r", encoding="utf-8", errors="ignore") as f:
                        user_count = sum(1 for line in f if line.strip())

                if os.path.exists(computers_file):
                    with open(
                        computers_file, "r", encoding="utf-8", errors="ignore"
                    ) as f:
                        computer_count = sum(1 for line in f if line.strip())

                # Check if ADCS is present
                adcs_present = bool(self.domains_data.get(domain, {}).get("adcs"))

                # Get DC count from domain data
                dc_count = 1  # At minimum, we have the PDC

                properties = {
                    "user_count": user_count,
                    "computer_count": computer_count,
                    "dc_count": dc_count,
                    "adcs_present": adcs_present,
                    "scan_mode": getattr(self, "scan_mode", None),
                    "workspace_type": getattr(self, "type", None),
                }
                properties.update(build_lab_event_fields(shell=self, include_slug=True))
                telemetry.capture("environment_enumerated", properties)
            except Exception as exc:  # pragma: no cover - best effort
                telemetry.capture_exception(exc)

        if stop_after_phase == 1:
            return

        # ========== PHASE 2: Attack Paths Discovery ==========
        # In CTF workspaces the objective is foothold → DA → flags.  Once the
        # domain transitions to "pwned" there is nothing left to calculate —
        # re-running attack paths would just produce a redundant "Owned →
        # Domain" graph that the operator has already exploited.  In audit
        # workspaces this phase still runs post-compromise because the client
        # deliverable needs the full attack-path view including post-ex paths.
        _domain_already_pwned = (
            self.type == "ctf"
            and str(
                getattr(self, "domains_data", {}).get(domain, {}).get("auth") or ""
            ).strip().lower() == "pwned"
        )
        _skip_phase2 = bool(start_from_phase and start_from_phase > 2) or _domain_already_pwned
        if not _skip_phase2:
            _enter_phase("Attack Paths Discovery")
            emit_phase("attack_paths_discovery")
            if _run_step(
                "Attack Paths Discovery",
                lambda: self.do_attack_path_discovery(domain),
                step_number=1,
                total_steps=1,
            ):
                return

        if stop_after_phase == 2:
            return

        # NOTE: `ask_for_enum_cve_takeover` is intentionally not part of the
        # default pipeline for now. We keep it available as an on-demand UX in
        # case we want to re-introduce an early takeover-CVE scan later.

        # ========== PHASE 3: Quick Credential Wins ==========
        _enter_phase("Quick Credential Wins")
        step_num = 1
        total_quickwin_steps = 2 + (2 if self.type == "audit" else 0)

        if _run_step(
            "Timeroast Candidate Check",
            lambda: self.ask_for_timeroast(domain),
            step_number=step_num,
            total_steps=total_quickwin_steps,
        ):
            return
        step_num += 1

        if _run_step(
            "LDAP Description Parsing",
            lambda: self.ask_for_ldap_descriptions(domain),
            step_number=step_num,
            total_steps=total_quickwin_steps,
        ):
            return
        step_num += 1

        # GPP enumeration (audit mode only)
        if self.type == "audit":
            if _run_step(
                "GPP Autologin Search",
                lambda: self.ask_for_smb_gpp_autologin(domain),
                step_number=step_num,
                total_steps=total_quickwin_steps,
            ):
                return
            step_num += 1

            if _run_step(
                "GPP Password Search",
                lambda: self.ask_for_smb_gpp_passwords(domain),
                step_number=step_num,
                total_steps=total_quickwin_steps,
            ):
                return
            step_num += 1

        # NTLM auth-type detection (per-host sweep + DC-only classification) is
        # fully consolidated into Phase 3 (Domain Intelligence): every sweep path
        # either persists the DC's verdict (full per-host sweep), or runs the
        # DC-only quick-win directly (operator-skip and <2-reachable fallbacks,
        # for all engagement types incl. ctf which self-gates). There is no
        # remaining Quick-Credential-Wins NTLM step.

        if stop_after_phase == 3:
            return

        # ========== PHASE 4: Password Spraying ==========
        # Roasting & Cracking and User Privilege Assessment used to live here
        # as dedicated phases. They were removed because the underlying work is
        # now produced upstream: kerberoast/asreproast attack steps and the
        # bound-user privilege analysis are materialized inside Attack Paths
        # Discovery via the collector pipeline, and the operator executes them
        # through the attack-paths offer flow. The dedicated phases re-ran the
        # same work as visual ceremony, so they have been dropped to keep the
        # workflow narrative tight. The ask_for_kerberoast / ask_for_asreproast
        # / ask_for_user_privs methods themselves still exist and remain
        # available for manual invocation and attack-path execution.
        _enter_phase("Password Spraying")
        if _run_step(
            "Password Spraying",
            lambda: self.ask_for_spraying(domain),
            step_number=1,
            total_steps=1,
        ):
            return
        try:
            from adscan_internal.cli.spraying import (
                maybe_offer_ctf_pre2k_followup,
            )

            maybe_offer_ctf_pre2k_followup(
                self,
                domain,
                reason="phase_4_completed",
            )
        except Exception as exc:  # pragma: no cover - best-effort UX hint
            telemetry.capture_exception(exc)

        if stop_after_phase == 4:
            return

        # ========== PHASE 5: Share Credential Hunt ==========
        # Runs for both CTF and audit. Reads share exposure data already built
        # during Phase 1 collection (attack graph edges), displays the SMB
        # resources panel, and offers a credential scan on writable shares.
        # In non-interactive / CI mode it auto-selects all writable shares.
        _enter_phase("Share Credential Hunt")
        emit_phase("share_credential_hunt")
        if _run_step(
            "Share Credential Hunt",
            lambda: self.ask_for_share_credential_hunt(domain),
            step_number=1,
            total_steps=1,
        ):
            return

        if stop_after_phase == 5:
            return

        # ========== PHASE 6: Audit-only Unauthenticated Attack Surface ==========
        if self.type == "audit":
            _enter_phase("Unauthenticated Attack Surface")
            if _run_step(
                "Unauthenticated Scan",
                lambda: self.ask_for_unauth_scan(domain),
                step_number=1,
                total_steps=1,
            ):
                return

            if stop_after_phase == 6:
                return

        # ========== PHASE 7: CVE Verification ==========
        # In audit mode, the passive hygiene findings (SMBv1, password policy,
        # SMB signing, MAQ risk, stale users, etc.) were already surfaced after
        # the native collector in Phase 2 — see `_print_collector_enrichment_panel`
        # under intelligence.py. The legacy `Configuration Enumeration` sub-step
        # that re-derived the same findings via `nxc` was retired here: it lived
        # at `ask_for_enum_configs` (enum.py:99) and stays callable manually if
        # an operator wants to invoke it from the shell, but no longer auto-fires
        # in the scan flow because it duplicated the collector output.
        #
        # What remains in Phase 7 is the only thing the collector cannot do
        # passively: read-only CVE verification against DCs (Zerologon, NoPac)
        # — detection only, no exploitation — followed by a consolidated audit
        # summary that rehydrates hygiene findings + CVE results from disk into
        # a single closing panel for the auditor.
        if self.type == "audit":
            _enter_phase("CVE Verification")
            if _run_step(
                "CVE Vulnerability Check",
                lambda: self.ask_for_enum_cve(domain),
                step_number=1,
                total_steps=1,
            ):
                return
            try:
                self._render_audit_summary_panel(domain)
            except Exception as exc:  # noqa: BLE001
                telemetry.capture_exception(exc)
                print_warning_debug(
                    f"[audit_summary] render failed: {type(exc).__name__}: {exc}"
                )

        # In audit post-compromise we want to map as much as possible, then let the
        # operator decide which remaining paths to validate/exploit.
        if _is_audit_map_only():
            try:
                from adscan_internal.cli.attack_path_execution import (
                    offer_attack_paths_for_execution_summaries,
                )
                from adscan_internal.rich_output import print_panel
                from adscan_internal.services.attack_graph_service import (
                    get_attack_path_summaries,
                    ATTACK_PATHS_MAX_DEPTH_DOMAIN,
                )

                print_panel(
                    content=(
                        "The domain is already compromised. ADscan will now offer the remaining "
                        "unvalidated attack paths so you can choose what to attempt next."
                    ),
                    title="🧭 Audit Post-Compromise: Remaining Attack Paths",
                )

                def _compute_summaries() -> list[dict[str, Any]]:
                    return get_attack_path_summaries(
                        self,
                        domain,
                        scope="domain",
                        max_depth=ATTACK_PATHS_MAX_DEPTH_DOMAIN,
                        max_paths=None,
                        target="highvalue",
                    )

                summaries = _compute_summaries()
                offer_attack_paths_for_execution_summaries(
                    self,
                    domain,
                    summaries=summaries,
                    max_display=20,
                    execute_only_statuses={"theoretical"},
                    retry_attempted=False,
                    recompute_summaries=_compute_summaries,
                    auto_continue_theoretical_in_non_interactive=True,
                )
            except Exception as exc:  # noqa: BLE001
                telemetry.capture_exception(exc)

        # Capture scan_complete event with case study metrics
        self._capture_scan_complete(domain)

        # Report CTA and zero-findings diagnostic after scan
        # Hormozi: CTA with "what + why now" at victory (show the stack);
        # Perceived Likelihood when 0 findings (transparency builds credibility)
        _scan_attack_paths = getattr(self, "_session_attack_paths_count", 0)
        _scan_mode = getattr(self, "scan_mode", None)
        if _scan_attack_paths > 0 and should_show_victory_hint(
            "scan_complete_report", "subtle"
        ):
            _pro_url = mark_passthrough("https://adscanpro.com/pro")
            self.console.print()
            print_info(
                f"💡 Found [bold]{_scan_attack_paths} attack path(s)[/bold] — PRO turns them into a "
                f"client-ready PDF (exec summary, attack chains, compliance mapping) "
                f"in 90 seconds → {_pro_url}"
            )
            mark_victory_hint_shown("scan_complete_report")
        elif _scan_attack_paths == 0 and _scan_mode == "unauth":
            self.console.print()
            print_info(
                "[dim]No attack paths found in unauthenticated mode — expected without credentials.\n"
                "→ Scan the authenticated attack surface: "
                "[cyan]creds save <domain> <user> <pass>[/cyan][/dim]"
            )
        elif _scan_attack_paths == 0 and _scan_mode == "auth":
            self.console.print()
            print_info(
                "[dim]No exploitable attack paths detected. "
                "Checked 32+ attack vectors (kerberoasting, delegation, ADCS, DCSync, and more). "
                "Domain appears hardened against the scanned vectors.[/dim]"
            )

        # Post-scan lab confirmation: ask once only when lab context is still
        # unknown or inferred with weak confidence. Strong signals stay frictionless.
        try:
            from adscan_internal.cli.start import maybe_offer_post_scan_lab_confirmation

            maybe_offer_post_scan_lab_confirmation(self)
        except Exception as exc:  # noqa: BLE001
            telemetry.capture_exception(exc)

        # Flush the final phase span so its timeline row + delta footer are
        # emitted. Earlier phases are closed automatically by ``_enter_phase``
        # transitions; only the last phase needs an explicit close.
        _close_active_phase()

    # ------------------------------------------------------------------
    # Audit Summary — consolidated closing panel for audit mode
    # ------------------------------------------------------------------
    #
    # Single-source-of-truth rule: this panel re-renders findings that
    # already live on disk; it never recomputes them. Hygiene findings
    # come from ``<workspace>/technical_report.json`` (written by the
    # collector + `_persist_collector_findings`); active CVE results
    # come from ``<workspace>/cves/<scan_id>/report.json`` (written by
    # `persist_report` in cve_scanner.ux.report). If either file is
    # missing or empty the section degrades to a neutral "no data
    # recorded" line — never an alarming red error.
    #
    # The schema mapping below is the contract with `_persist_collector_findings`
    # (intelligence.py:375 _CAT_KEY). When you add a new audit category
    # there, add its display row here too.

    _AUDIT_HYGIENE_ROWS: tuple[tuple[str, str, str, str], ...] = (
        # (technical_report.json key, display label, singular unit, plural unit)
        # Singular vs plural is selected by count so "1 computer" reads
        # naturally instead of "1 computers". Domain-wide findings use the
        # same singular/plural string when grammatical number does not apply.
        ("smb_v1_enabled", "SMBv1 enabled", "computer", "computers"),
        ("smb_signing_disabled", "SMB signing not required", "computer", "computers"),
        ("password_not_required", "Password not required", "account", "accounts"),
        ("password_never_expires", "Password never expires", "account", "accounts"),
        ("stale_passwords", "Passwords older than current policy", "account", "accounts"),
        ("stale_enabled_users", "Stale enabled users", "account", "accounts"),
        ("krbtgt_password_age", "krbtgt password age", "rotation overdue", "rotations overdue"),
        ("rc4_only_accounts", "RC4-only accounts", "account", "accounts"),
        ("obsolete_computers", "Obsolete operating systems", "computer", "computers"),
        ("machine_account_quota_risk", "Machine Account Quota risk", "domain-wide", "domain-wide"),
        ("weak_password_policy", "Weak password policy", "domain-wide", "domain-wide"),
    )

    _AUDIT_SEVERITY_STYLE: dict[str, tuple[str, str]] = {
        # severity → (badge text, Rich style)
        "critical": ("CRITICAL", "bold red"),
        "high": ("HIGH    ", "red"),
        "medium": ("MEDIUM  ", "yellow"),
        "low": ("LOW     ", "cyan"),
        "info": ("INFO    ", "dim"),
    }

    _AUDIT_SEVERITY_ORDER: dict[str, int] = {
        "critical": 0,
        "high": 1,
        "medium": 2,
        "low": 3,
        "info": 4,
    }

    def _render_audit_summary_panel(self, domain: str) -> None:
        """Render the closing audit summary for ``domain``.

        Re-renders the data already written to disk by Phase 2 (collector
        hygiene findings) and Phase 7 (CVE probe results) into a single
        consolidated panel — no recomputation. Safe to call multiple
        times; degrades gracefully when either data source is missing.

        Only runs in audit mode; the caller is responsible for the
        ``self.type == "audit"`` guard.
        """
        from pathlib import Path
        from json import JSONDecodeError, load as _json_load
        from rich.console import Group
        from rich.text import Text
        from adscan_internal.services.cve_scanner.ux.report import (
            latest_scan_dir,
            load_report_summary,
        )

        workspace_dir_raw = getattr(self, "current_workspace_dir", None)
        if not workspace_dir_raw:
            print_info_debug(
                "[audit_summary] no workspace_dir on shell — skipping panel"
            )
            return
        workspace_dir = Path(workspace_dir_raw)

        # ── Hygiene findings ────────────────────────────────────────────
        hygiene_rows: list[tuple[str, str, str, int]] = []
        # rows: (severity_badge, label, value_text, severity_order)
        report_path = workspace_dir / "technical_report.json"
        if report_path.is_file():
            try:
                with report_path.open("r", encoding="utf-8") as fh:
                    report = _json_load(fh)
            except (OSError, JSONDecodeError) as exc:
                telemetry.capture_exception(exc)
                report = None
            if isinstance(report, dict):
                findings_root = (
                    report.get("findings")
                    if isinstance(report.get("findings"), dict)
                    else report
                )
                for key, label, unit_singular, unit_plural in self._AUDIT_HYGIENE_ROWS:
                    entry = findings_root.get(key) if isinstance(findings_root, dict) else None
                    if not isinstance(entry, dict):
                        continue
                    details = entry.get("details") if isinstance(entry.get("details"), dict) else entry
                    count = details.get("count") if isinstance(details, dict) else None
                    if not isinstance(count, int) or count <= 0:
                        continue
                    severity_raw = ""
                    if isinstance(details, dict):
                        severity_raw = str(details.get("severity_summary") or "").lower().strip()
                    badge, style = self._AUDIT_SEVERITY_STYLE.get(
                        severity_raw, self._AUDIT_SEVERITY_STYLE["info"]
                    )
                    order = self._AUDIT_SEVERITY_ORDER.get(severity_raw, 99)
                    if unit_singular == unit_plural:
                        # Policy-level finding (MAQ, etc.) — the count is
                        # always 1 by construction and reads as noise.
                        # Show just the descriptive scope.
                        value_text = unit_singular
                    else:
                        units = unit_singular if count == 1 else unit_plural
                        value_text = f"{count} {units}"
                    hygiene_rows.append(
                        (f"[{style}]{badge}[/{style}]", label, value_text, order)
                    )
        hygiene_rows.sort(key=lambda r: (r[3], r[1]))

        # ── CVE probe results ───────────────────────────────────────────
        cve_rows: list[tuple[str, str, str]] = []
        # rows: (status_glyph_styled, cve_label, host_or_result)
        scan_dir = latest_scan_dir(workspace_dir)
        cve_report = load_report_summary(scan_dir) if scan_dir else None
        if isinstance(cve_report, dict):
            results = cve_report.get("results") if isinstance(cve_report.get("results"), list) else []
            # Group by (cve_id, aka, status) so a CVE probed on multiple
            # hosts collapses into one row with the host list.
            by_cve: dict[tuple[str, str, str], list[str]] = {}
            for entry in results:
                if not isinstance(entry, dict):
                    continue
                cve_id = str(entry.get("cve_id") or "").strip()
                if not cve_id:
                    continue
                aka = str(entry.get("aka") or "").strip()
                status = str(entry.get("status") or "").strip().lower()
                host = str(entry.get("host") or "").strip()
                by_cve.setdefault((cve_id, aka, status), []).append(host)
            # Stable display order: vulnerable first, then errors, then
            # not_vulnerable, then anything else. Within a bucket, alpha.
            status_order = {
                "vulnerable": 0,
                "error": 1,
                "not_vulnerable": 2,
                "not_applicable": 3,
                "skipped": 4,
            }
            grouped = sorted(
                by_cve.items(),
                key=lambda kv: (status_order.get(kv[0][2], 99), kv[0][0]),
            )
            for (cve_id, aka, status), hosts in grouped:
                label = f"{aka} ({cve_id})" if aka else cve_id
                hosts_clean = sorted({h for h in hosts if h})
                # All four icons are detection states, not action verbs.
                # "Vulnerable" means "the read-only check determined the host
                # appears vulnerable" — no exploitation occurred. Glyph chosen
                # accordingly: ⚠ (attention) rather than ✗ (which implies failure
                # or attack execution).
                if status == "vulnerable":
                    glyph = "[bold red]⚠ Vulnerable[/bold red]"
                    detail = (
                        f"detected on {', '.join(hosts_clean)}"
                        if hosts_clean
                        else "(no host detail)"
                    )
                elif status == "not_vulnerable":
                    glyph = "[green]✓ Not vulnerable[/green]"
                    detail = (
                        f"{len(hosts_clean)} host(s) checked"
                        if hosts_clean
                        else "—"
                    )
                elif status == "error":
                    glyph = "[yellow]· Check error[/yellow]"
                    detail = ", ".join(hosts_clean) if hosts_clean else "(no host detail)"
                elif status == "not_applicable":
                    glyph = "[dim]— Not applicable[/dim]"
                    detail = ", ".join(hosts_clean) if hosts_clean else "—"
                else:
                    glyph = f"[dim]{status or 'unknown'}[/dim]"
                    detail = ", ".join(hosts_clean) if hosts_clean else "—"
                cve_rows.append((glyph, label, detail))

        # ── Build the renderable ────────────────────────────────────────
        body_parts: list[Any] = []

        def _section_heading(text: str) -> Text:
            head = Text()
            head.append(text, style="bold")
            return head

        # Passive findings section
        body_parts.append(_section_heading("Passive findings — from collector"))
        if hygiene_rows:
            hyg_table = Table.grid(padding=(0, 2))
            hyg_table.add_column(justify="left", no_wrap=True)  # severity badge
            hyg_table.add_column(justify="left", overflow="fold")  # label
            hyg_table.add_column(justify="right", no_wrap=True)  # value
            for badge, label, value, _ in hygiene_rows:
                hyg_table.add_row(badge, label, value)
            body_parts.append(hyg_table)
        else:
            body_parts.append(
                Text(
                    "  No passive findings recorded — clean posture or "
                    "collector did not run in this scan.",
                    style="dim",
                )
            )

        body_parts.append(Text(""))  # blank line separator

        # CVE verification section — read-only detection, no exploitation.
        body_parts.append(_section_heading("CVE verification — read-only checks"))
        if cve_rows:
            cve_table = Table.grid(padding=(0, 2))
            cve_table.add_column(justify="left", no_wrap=True)  # status glyph
            cve_table.add_column(justify="left", overflow="fold")  # cve label
            cve_table.add_column(justify="left", overflow="fold")  # host/detail
            for glyph, label, detail in cve_rows:
                cve_table.add_row(glyph, label, detail)
            body_parts.append(cve_table)
        else:
            body_parts.append(
                Text(
                    "  No CVE checks recorded — skipped or no scan results "
                    "on disk yet.",
                    style="dim",
                )
            )

        body_parts.append(Text(""))

        # Footer — pointers, not noise.
        footer = Text()
        footer.append("Workspace: ", style="dim")
        footer.append(str(workspace_dir), style="dim italic")
        body_parts.append(footer)

        print_panel(
            Group(*body_parts),
            title=f"🛡  Audit Summary — {domain}",
            title_align="left",
            border_style="cyan",
        )

    def _capture_scan_complete(self, domain: str) -> None:
        """Capture scan_complete telemetry event with case study metrics."""
        try:
            scan_start = getattr(self, "scan_start_time", None)
            if scan_start is None:
                return

            scan_duration_seconds = max(0.0, time.monotonic() - scan_start)
            scan_duration_minutes = round(scan_duration_seconds / 60.0, 2)

            # Calculate TTFAP and TTFH from scan_start_time
            ttfap_minutes = None
            ttfh_minutes = None
            if (
                hasattr(self, "_session_first_attack_path_time")
                and self._session_first_attack_path_time
            ):
                ttfap_minutes = round(
                    max(0.0, self._session_first_attack_path_time - scan_start) / 60.0,
                    2,
                )
            if (
                hasattr(self, "_session_first_hash_time")
                and self._session_first_hash_time
            ):
                ttfh_minutes = round(
                    max(0.0, self._session_first_hash_time - scan_start) / 60.0, 2
                )

            # Get TTFC from first_cred_found if available (scan-level)
            ttfc_minutes = None
            if (
                hasattr(self, "_scan_first_credential_time")
                and self._scan_first_credential_time
            ):
                ttfc_minutes = round(
                    max(0.0, self._scan_first_credential_time - scan_start) / 60.0, 2
                )

            # Get TTC from domain_compromise if available (scan-level)
            ttc_minutes = None
            if hasattr(self, "_scan_compromise_time") and self._scan_compromise_time:
                ttc_minutes = round(
                    max(0.0, self._scan_compromise_time - scan_start) / 60.0, 2
                )

            # Check if domain was compromised
            domain_compromised = (
                self.domains_data.get(domain, {}).get("auth") == "pwned"
            )

            # Compute attack path metrics from the attack graph
            from adscan_internal.services.attack_graph_service import (
                compute_attack_path_metrics,
            )

            path_metrics = compute_attack_path_metrics(self, domain, max_depth=10)

            lab_slug = self._get_lab_slug()
            properties = {
                # Timing metrics
                "scan_duration_minutes": scan_duration_minutes,
                "ttfap_minutes": ttfap_minutes,
                "ttfh_minutes": ttfh_minutes,
                "ttfc_minutes": ttfc_minutes,
                "ttc_minutes": ttc_minutes,
                # Attack path metrics (complete paths to Tier 0)
                "paths_to_tier0": path_metrics.get("paths_to_tier0", 0),
                "paths_exploited": path_metrics.get("paths_exploited", 0),
                "paths_partial": path_metrics.get("paths_partial", 0),
                "paths_not_attempted": path_metrics.get("paths_not_attempted", 0),
                "paths_by_type": path_metrics.get("paths_by_type", {}),
                # Finding metrics
                "credentials_obtained": getattr(self, "_session_credentials_count", 0),
                "hashes_extracted": getattr(self, "_session_hashes_count", 0),
                "domain_compromised": domain_compromised,
                # Context
                "scan_mode": getattr(self, "scan_mode", None),
                "workspace_type": getattr(self, "type", None),
                "auto_mode": getattr(self, "auto", False),
                "lab_slug": lab_slug,
            }
            properties.update(
                build_lab_telemetry_fields(
                    lab_provider=self.lab_provider,
                    lab_name=self.lab_name,
                    lab_name_whitelisted=self.lab_name_whitelisted,
                    include_slug=True,
                    lab_slug=lab_slug,
                )
            )

            telemetry.capture("scan_complete", properties)
        except Exception as exc:
            telemetry.capture_exception(exc)

