    def do_enum_cve_dcs(self, target_domain: str) -> None:
        """Enumerate CVEs on domain controllers using the native async scanner.

        Args:
            target_domain: The domain whose domain controllers to scan.
        """
        import os
        from adscan_internal.cli.cves_native import dispatch as _dispatch_cves
        from adscan_internal.workspaces.computers import domain_subpath

        workspace_dir = getattr(self, "current_workspace_dir", None) or os.getcwd()
        domains_dir = getattr(self, "domains_dir", "domains")
        dcs_file = domain_subpath(workspace_dir, domains_dir, target_domain, "dcs.txt")
        if not os.path.isfile(dcs_file):
            pdc_ip = (self.domains_data.get(target_domain) or {}).get("pdc")
            if pdc_ip:
                os.makedirs(os.path.dirname(dcs_file), exist_ok=True)
                with open(dcs_file, "w", encoding="utf-8") as _f:
                    _f.write(f"{pdc_ip}\n")
            else:
                from adscan_core.rich_output import print_error
                print_error(
                    f"No DC targets file found for {target_domain} and no PDC IP configured."
                )
                return
        _dispatch_cves(self, f"scan --dc-scope --targets {dcs_file}")

    def do_enum_cve_all(self, target_domain: str) -> None:
        """Enumerate CVEs on all domain hosts using the native async scanner.

        Args:
            target_domain: The domain whose enabled computers to scan.
        """
        import os
        from adscan_core.rich_output import print_error
        from adscan_internal.cli.cves_native import dispatch as _dispatch_cves
        from adscan_internal.workspaces.computers import (
            resolve_domain_service_target_file,
        )

        workspace_dir = getattr(self, "current_workspace_dir", None) or os.getcwd()
        domains_dir = getattr(self, "domains_dir", "domains")
        domain_data = self.domains_data.get(target_domain) or {}
        targets_file, _source = resolve_domain_service_target_file(
            workspace_dir,
            domains_dir,
            target_domain,
            service="smb",
            domain_data=domain_data,
        )
        if not targets_file:
            print_error(
                f"No host targets available for domain {target_domain}. Run host discovery first."
            )
            return
        _dispatch_cves(self, f"scan --targets {targets_file}")

    def drop_the_mic(self, target_domain):
        """
        Performs a scan for vulnerabilities associated with Drop-The-Mic on all hosts in a domain.

        Executes the drop_the_mic_scan.py script with the options -vuln all and -target-file with the IP file
        of the specified domain. Authentication is done using the current domain credentials.

        Args:
            target_domain (str): The name of the domain to enumerate.
        """
        from adscan_internal.workspaces.computers import ensure_enabled_computer_ip_file

        auth = self.build_auth_impacket(
            self.domains_data[self.domain]["username"],
            self.domains_data[self.domain]["password"],
            self.domain,
        )
        target_file_path, source = ensure_enabled_computer_ip_file(
            getattr(self, "current_workspace_dir", None) or os.getcwd(),
            getattr(self, "domains_dir", "domains"),
            target_domain,
            self.domains_data.get(target_domain, {}),
        )
        if not target_file_path:
            marked_target_domain = mark_sensitive(target_domain, "domain")
            print_error(
                f"No host targets are available for domain {marked_target_domain}."
            )
            return
        target_file = shlex.quote(target_file_path)
        command = (
            f"drop_the_mic_scan.py -vuln all -target {auth} -target-file {target_file}"
        )
        marked_target_domain = mark_sensitive(target_domain, "domain")
        print_info(
            f"Performing scan for vulnerabilities associated with Drop-The-Mic for domain {marked_target_domain}"
        )
        print_info_debug(
            "[drop_the_mic] using domain target file "
            f"source={source} for {marked_target_domain}: "
            f"{mark_sensitive(target_file_path, 'path')}"
        )
        completed_process = self.run_command(command, timeout=300)

        vulnerable_found = (
            False  # Flag to indicate if any line containing "accepted" was found
        )
        output_lines = completed_process.stdout.splitlines()

        for line in output_lines:
            if "accepted" in line.lower():
                self.console.print(
                    line
                )  # Using self.console.print and adding newline by default
                vulnerable_found = True

        if not vulnerable_found:
            marked_target_domain = mark_sensitive(target_domain, "domain")
            print_info(
                f"No hosts vulnerable to Drop-The-Mic related vulnerabilities were found in domain {marked_target_domain}"
            )

        if completed_process.returncode != 0:
            print_error(
                f"Error executing drop_the_mic_scan.py: {completed_process.stderr.strip() if completed_process.stderr else 'Details not available'}"
            )

