    def extract_firefox_passwords(self, domain, host, firefox_dir):
        """
        Extracts passwords from Firefox files using firepwd.py.

        Args:
            domain (str): User's domain
            host (str): Target host
            firefox_dir (str): Directory containing the Firefox files
        """
        try:
            from adscan_internal.rich_output import print_info

            # Use Python from isolated venv if available, fallback to system python
            firepwd_python = self.firepwd_python or "python"
            firepwd_path = os.path.join(TOOLS_INSTALL_DIR, "firepwd", "firepwd.py")
            command = (
                f"{shlex.quote(str(firepwd_python))} "
                f"{shlex.quote(firepwd_path)} "
                f"-d {shlex.quote(str(firefox_dir))}"
            )
            print_info("Extracting Firefox passwords")

            proc = self.run_command(command, timeout=300)

            if proc.returncode == 0:
                # Search for the passwords section
                if "decrypting login/password pairs" in proc.stdout:
                    passwords_section = proc.stdout.split(
                        "decrypting login/password pairs"
                    )[1].strip()

                    # Professional credentials display
                    from adscan_internal import (
                        create_credentials_table,
                        get_console,
                        print_results_summary,
                    )

                    # Process and collect credentials
                    found_credentials = {}
                    for line in passwords_section.splitlines():
                        if ":" in line:  # Only process lines with credentials
                            url, creds = line.split(":", 1)
                            url = url.strip()
                            # Extract user and password from the format b'user',b'pass'
                            creds_match = re.findall(r"b'([^']*)'", creds)
                            if len(creds_match) >= 2:
                                user, password = creds_match[0:2]
                                found_credentials[user] = password
                                # Store credentials
                                self.add_credential(
                                    domain, user, password, host=host, service="firefox"
                                )

                    # Display results with professional table
                    if found_credentials:
                        print_results_summary(
                            "Firefox Credentials Extracted",
                            {
                                "Host": host,
                                "Credentials Found": len(found_credentials),
                                "Status": "Success",
                            },
                        )

                        console = get_console()
                        table = create_credentials_table(
                            found_credentials,
                            title="Discovered Firefox Credentials",
                            show_preview=True,
                        )
                        console.print(table)
                else:
                    print_warning("No passwords found in the files")
            else:
                print_error(
                    f"Error executing firepwd.py: {proc.stderr.strip() if proc.stderr else 'Details not available'}"
                )

        except Exception as e:
            telemetry.capture_exception(e)
            print_error("Error extracting Firefox passwords.")
            print_exception(show_locals=False, exception=e)

