    def manspider_passwd_files(self, target_domain, username, password, shares, hosts):
        from adscan_internal.rich_output import mark_sensitive
        from adscan_internal.services.smb_exclusion_policy import (
            build_manspider_exclusion_args,
        )

        if self._should_skip_unauth_followups(target_domain, username):
            return

        if target_domain not in self.domains:
            marked_target_domain = mark_sensitive(target_domain, "domain")
            print_error(
                f"Domain '{marked_target_domain}' is not configured. Please add or select a valid domain."
            )
            return
        workspace_path = os.path.abspath(self.current_workspace_dir)
        spider_output_dir = os.path.join(workspace_path, "smb", "spidering")
        spider_output_arg = shlex.quote(spider_output_dir)
        manspider_bin = shlex.quote(str(self.manspider_path))
        hosts_str = " ".join(shlex.quote(str(host)) for host in hosts)
        exclusion_args = build_manspider_exclusion_args()
        if self.domains_data[target_domain]["auth"] == "auth":
            auth = self.build_auth_nxc(
                username, password, target_domain, kerberos=False
            )
            command = (
                f"{manspider_bin} --threads 256 {hosts_str} {auth} "
                f"-c '\\$ANSIBLE_VAULT' -l {spider_output_arg} "
                f"{exclusion_args}"
            )
        else:
            command = (
                f"{manspider_bin} --threads 256 {hosts_str} "
                f"-c '\\$ANSIBLE_VAULT' -l {spider_output_arg} "
                f"{exclusion_args}"
            )

        # Professional operation header

        print_operation_header(
            "Share Spidering (Password Files)",
            details={
                "Domain": target_domain,
                "Target Hosts": f"{len(hosts)} hosts",
                "Search Pattern": "ANSIBLE_VAULT",
                "Output": f"{workspace_path}/smb/spidering/",
            },
            icon="🔍",
        )

        print_info_debug(f"Command: {command}")
        self.execute_manspider(
            command,
            target_domain,
            "gpp",
            hosts=hosts,
            shares=shares,
            auth_username=username,
        )

    def manspider_extensions(
        self,
        target_domain,
        username,
        password,
        shares,
        hosts,
        *,
        extensions=None,
        phase=None,
    ):
        from adscan_internal.rich_output import mark_sensitive
        from adscan_internal.services.smb_sensitive_file_policy import (
            SMB_SENSITIVE_SCAN_PHASE_DIRECT_SECRET_ARTIFACTS,
            SMB_SENSITIVE_SCAN_PHASE_HEAVY_ARTIFACTS,
        )
        from adscan_internal.services.smb_exclusion_policy import (
            build_manspider_exclusion_args,
            GLOBAL_SMB_HEAVY_ARTIFACT_MAX_FILESIZE_MB,
        )

        if self._should_skip_unauth_followups(target_domain, username):
            return

        if target_domain not in self.domains:
            marked_target_domain = mark_sensitive(target_domain, "domain")
            print_error(
                f"Domain '{marked_target_domain}' is not configured. Please add or select a valid domain."
            )
            return
        workspace_path = os.path.abspath(self.current_workspace_dir)
        output_subdir = "artifacts"
        if phase == SMB_SENSITIVE_SCAN_PHASE_HEAVY_ARTIFACTS:
            output_subdir = "heavy_artifacts"
        elif phase == SMB_SENSITIVE_SCAN_PHASE_DIRECT_SECRET_ARTIFACTS:
            output_subdir = "direct_secret_artifacts"
        spider_output_dir = os.path.join(
            workspace_path, "smb", "spidering", output_subdir
        )
        os.makedirs(spider_output_dir, exist_ok=True)
        spider_output_arg = shlex.quote(spider_output_dir)
        manspider_bin = shlex.quote(str(self.manspider_path))
        hosts_str = " ".join(shlex.quote(str(host)) for host in hosts)
        exclusion_args = build_manspider_exclusion_args()
        selected_extensions = list(
            extensions
            or [
                "pfx",
                "vdi",
                "kdbx",
                "kdb",
                "conf",
                "rsa",
                "key",
                "pem",
                "psd1",
                "psm1",
                "pub",
                "config",
                "xlsm",
                "zip",
                "pcap",
                "DMP",
                "xlsx",
            ]
        )
        extensions_arg = " ".join(shlex.quote(str(ext)) for ext in selected_extensions)
        if self.domains_data[target_domain]["auth"] == "auth":
            auth = self.build_auth_nxc(
                username, password, target_domain, kerberos=False
            )
            command = (
                f"{manspider_bin} --threads 256 {hosts_str} {auth} "
                f"-e {extensions_arg} -l {spider_output_arg} "
                f"--max-filesize {GLOBAL_SMB_HEAVY_ARTIFACT_MAX_FILESIZE_MB}M {exclusion_args}"
            )
        else:
            command = (
                f"{manspider_bin} --threads 256 {hosts_str} "
                f"-e {extensions_arg} -l {spider_output_arg} "
                f"--max-filesize {GLOBAL_SMB_HEAVY_ARTIFACT_MAX_FILESIZE_MB}M {exclusion_args}"
            )

        # Professional operation header

        print_operation_header(
            "Share Spidering (File Extensions)",
            details={
                "Domain": target_domain,
                "Target Hosts": f"{len(hosts)} hosts",
                "Extensions": "pfx, kdbx, conf, key, pem, xlsx, zip...",
                "Max File Size": "50 MB",
                "Output": f"{workspace_path}/smb/spidering/",
            },
            icon="🕷️",
        )

        print_info_debug(f"Command: {command}")
        return self.execute_manspider(
            command,
            target_domain,
            "ext",
            hosts=hosts,
            shares=shares,
            auth_username=username,
            loot_dir=spider_output_dir,
        )

    def manspider_passw(
        self,
        target_domain,
        username,
        password,
        shares,
        hosts,
        *,
        profile=None,
        phase=None,
        analysis_context=None,
    ):
        from adscan_internal.rich_output import mark_sensitive
        from adscan_internal.services.credsweeper_service import (
            get_default_credsweeper_jobs,
        )
        from adscan_internal.services.smb_exclusion_policy import (
            build_manspider_exclusion_args,
        )
        from adscan_internal.services.smb_sensitive_file_policy import (
            DEFAULT_SMB_SENSITIVE_FILE_PROFILE,
            SMB_SENSITIVE_SCAN_PHASE_DOCUMENT_CREDENTIALS,
            get_manspider_sensitive_extensions,
            get_sensitive_phase_max_file_size_bytes,
        )

        if self._should_skip_unauth_followups(target_domain, username):
            return

        if target_domain not in self.domains:
            marked_target_domain = mark_sensitive(target_domain, "domain")
            print_error(
                f"Domain '{marked_target_domain}' is not configured. Please add or select a valid domain."
            )
            return
        workspace_path = os.path.abspath(self.current_workspace_dir)
        output_subdir = "passw"
        if phase == SMB_SENSITIVE_SCAN_PHASE_DOCUMENT_CREDENTIALS:
            output_subdir = "document_credentials"
        spider_output_dir = os.path.join(
            workspace_path, "smb", "spidering", output_subdir
        )
        os.makedirs(spider_output_dir, exist_ok=True)
        spider_output_arg = shlex.quote(spider_output_dir)
        manspider_bin = shlex.quote(str(self.manspider_path))
        hosts_str = " ".join(shlex.quote(str(host)) for host in hosts)
        exclusion_args = build_manspider_exclusion_args()
        extensions_arg = " ".join(
            shlex.quote(extension)
            for extension in get_manspider_sensitive_extensions(
                str(profile or DEFAULT_SMB_SENSITIVE_FILE_PROFILE)
            )
        )
        max_filesize_arg = ""
        if phase == SMB_SENSITIVE_SCAN_PHASE_DOCUMENT_CREDENTIALS:
            max_file_size_bytes = get_sensitive_phase_max_file_size_bytes(
                SMB_SENSITIVE_SCAN_PHASE_DOCUMENT_CREDENTIALS
            )
            if isinstance(max_file_size_bytes, int) and max_file_size_bytes > 0:
                max_file_size_mb = max(1, int(max_file_size_bytes // (1024 * 1024)))
                max_filesize_arg = f"--max-filesize {max_file_size_mb}M "
        if self.domains_data[target_domain]["auth"] == "auth":
            auth = self.build_auth_nxc(
                username, password, target_domain, kerberos=False
            )
            command = (
                f"{manspider_bin} --threads 256 {hosts_str} {auth} "
                f"-e {extensions_arg} -l {spider_output_arg} "
                f"{max_filesize_arg}{exclusion_args}"
            )
        else:
            command = (
                f"{manspider_bin} --threads 256 {hosts_str} "
                f"-e {extensions_arg} -l {spider_output_arg} "
                f"{max_filesize_arg}{exclusion_args}"
            )
        marked_target_domain = mark_sensitive(target_domain, "domain")
        print_info(
            f"Searching for possible passwords in the shares of domain {marked_target_domain}."
        )
        print_info_debug(f"Command: {command}")

        from adscan_core.interaction import is_non_interactive
        from adscan_core.tui.patience_notice import (
            PatienceNoticeConfig,
            maybe_show_patience_notice,
        )
        from adscan_core.tui.progress_dashboard import (
            ProgressDashboard,
            ProgressDashboardConfig,
        )

        # Upfront patience notice -- threshold-gated on the host count queued for
        # the share credential hunt. Silent below the threshold; a single line
        # under non-interactive runs. Centralizes the old ad-hoc "be patient"
        # print. count=0 keeps it silent when the host set is unavailable.
        host_count = len(hosts) if hosts else 0
        try:
            maybe_show_patience_notice(
                PatienceNoticeConfig(
                    operation="Share credential hunt",
                    unit="hosts",
                    threshold=10,
                    env_var="ADSCAN_PATIENCE_THRESHOLD_SHARE_CRED_HUNT",
                ),
                count=host_count,
                non_interactive=is_non_interactive(self),
            )
        except Exception:  # noqa: BLE001 -- notice must never abort the hunt
            pass

        # Indeterminate live dashboard. manspider is a blocking subprocess with
        # no parseable live-progress stream, so a determinate X/N bar would
        # require a guessed ETA -- spinner + elapsed shows the hunt is alive so
        # the operator avoids Ctrl+C-ing a working long scan. The blocking call
        # runs in a single worker thread so the spinner ticks while it blocks;
        # LiveSession falls back to inline logging on non-TTY/CI itself.
        # FAIL-SAFE: a dashboard/LiveSession setup failure falls back to a plain
        # blocking call so the hunt always runs and parsing is never skipped;
        # an exception raised by the hunt itself propagates unchanged.
        def _run_manspider() -> any:
            return self.execute_manspider(
                command,
                target_domain,
                "passw",
                hosts=hosts,
                shares=shares,
                auth_username=username,
                loot_dir=spider_output_dir,
                credsweeper_jobs=get_default_credsweeper_jobs(),
                phase=phase,
                analysis_context=analysis_context,
            )

        try:
            dashboard = ProgressDashboard(
                ProgressDashboardConfig(
                    title="Share Credential Hunt",
                    total=None,  # indeterminate -- spinner + elapsed (opaque subprocess)
                    unit="hosts",
                )
            )
        except Exception:  # noqa: BLE001 -- dashboard build must never block the hunt
            return _run_manspider()

        def _safe_update(dash: "ProgressDashboard") -> None:
            try:
                dash.update()
            except Exception:  # noqa: BLE001 -- a render error must not abort the hunt
                pass

        import concurrent.futures
        import time as _time

        call_started = False
        try:
            with dashboard.live_session():
                with concurrent.futures.ThreadPoolExecutor(max_workers=1) as pool:
                    fut = pool.submit(_run_manspider)
                    call_started = True
                    while not fut.done():
                        _safe_update(dashboard)
                        _time.sleep(0.25)
                    result = fut.result()  # re-raises worker exceptions here
                    _safe_update(dashboard)
                    return result
        except Exception:  # noqa: BLE001
            if call_started:
                # The hunt (or its worker plumbing) raised -- propagate to the
                # caller's existing handling. Do NOT re-run the hunt.
                raise
            # Dashboard / LiveSession failed before the call started -- fall back
            # to a plain blocking call so the hunt still completes.
            return _run_manspider()

