    def _process_computers_list(
        self, domain: str, comp_file: str, computers: list[str]
    ) -> None:
        """Process and persist a BloodHound computers list without using bloodhound-cli."""
        from adscan_internal.rich_output import mark_sensitive
        from adscan_internal.workspaces import DEFAULT_DOMAIN_LAYOUT, domain_subpath

        workspace_cwd = self.current_workspace_dir or os.getcwd()
        computers_file = domain_subpath(
            workspace_cwd, self.domains_dir, domain, comp_file
        )
        nmap_dir = domain_subpath(
            workspace_cwd,
            self.domains_dir,
            domain,
            DEFAULT_DOMAIN_LAYOUT.nmap,
        )

        os.makedirs(os.path.dirname(computers_file), exist_ok=True)
        os.makedirs(nmap_dir, exist_ok=True)

        cleaned: list[str] = []
        seen: set[str] = set()
        for comp in computers:
            value = str(comp or "").strip()
            if not value:
                continue
            key = value.lower()
            if key in seen:
                continue
            seen.add(key)
            cleaned.append(value)

        with open(computers_file, "w", encoding="utf-8") as file:
            if cleaned:
                file.write("\n".join(cleaned) + "\n")
            else:
                file.truncate(0)

        marked_path = mark_sensitive(computers_file, "path")
        print_info_debug(f"[bloodhound] Wrote computers list to {marked_path}")

        try:
            comp_type = comp_file.replace(".txt", "")
            properties = {
                "computer_type": comp_type,
                "count": len(cleaned),
                "scan_mode": getattr(self, "scan_mode", None),
                "auth_type": self.domains_data[domain].get("auth", "unknown"),
            }
            properties.update(build_lab_event_fields(shell=self, include_slug=True))
            telemetry.capture("computers_enumerated", properties)
        except Exception as e:
            telemetry.capture_exception(e)

        if comp_file == "enabled_computers_with_laps.txt":
            self._display_items(cleaned, "Computers with LAPS")
        elif comp_file == "enabled_computers_without_laps.txt":
            self._display_items(cleaned, "Computers without LAPS")
        else:
            self._display_items(cleaned, "Enabled Computers")

        if comp_file == "enabled_computers.txt":
            pdc_ip = None
            try:
                pdc_ip = self.domains_data.get(domain, {}).get("pdc")
            except Exception:
                pdc_ip = None
            if not self.do_check_dns(domain, pdc_ip):
                if pdc_ip:
                    self.do_update_resolv_conf(f"{domain} {pdc_ip}")
            self.convert_hostnames_to_ips_and_scan(domain, computers_file, nmap_dir)

