    def process_dmp_file(self, dmp_file, domain):
        """Processes a .DMP file using pypykatz to extract MSV credentials."""
        from adscan_internal.rich_output import mark_sensitive

        try:
            marked_dmp_file = mark_sensitive(dmp_file, "path")
            pypykatz_cmd = self.pypykatz_path or "pypykatz"
            command = f'"{pypykatz_cmd}" lsa minidump "{marked_dmp_file}" -p msv'
            print_info("Analyzing memory dump file")
            proc = self.run_command(command, timeout=300)

            if proc.returncode == 0:
                # Process pypykatz output
                output = proc.stdout

                # New simplified regular expression that directly searches for the Username and NT pattern
                cred_pattern = r"Username: ([^\n]+).*?NT: ([a-fA-F0-9]{32})"
                matches = re.finditer(cred_pattern, output, re.DOTALL)

                found_creds = set()  # Set to avoid duplicates
                for match in matches:
                    username = match.group(1).strip()
                    nt_hash = match.group(2).strip()

                    # Only filter out Windows service accounts
                    if not username.startswith(("UMFD-", "DWM-")):
                        cred_tuple = (username, nt_hash)
                        found_creds.add(cred_tuple)

                # Process the found credentials
                if found_creds:
                    marked_dmp_file = mark_sensitive(dmp_file, "path")
                    print_warning(f"Credentials found in {marked_dmp_file}:")
                    for username, nt_hash in found_creds:
                        marked_username = mark_sensitive(username, "user")
                        marked_nt_hash = mark_sensitive(nt_hash, "password")
                        print_warning(f"User: {marked_username}")
                        print_warning(f"NT Hash: {marked_nt_hash}")
                        self.add_credential(domain, username, nt_hash)
                else:
                    print_warning("No valid credentials found in the dump file")
            else:
                print_error(f"Error executing pypykatz: {proc.stderr.strip()}")

        except Exception as e:
            telemetry.capture_exception(e)
            print_error("Error processing DMP file.")
            print_exception(show_locals=False, exception=e)

