    def analyze_log_with_credsweeper(self, log_file: str) -> dict:
        """
        Analyze a log file with CredSweeper and return all credential-like findings.

        This is a thin wrapper around ``CredSweeperService.analyze_file`` so that
        existing flows in ``adscan.py`` can keep their current call sites while
        the heavy lifting is delegated to the service layer.
        """
        if not getattr(self, "credsweeper_path", None):
            print_info_verbose(
                "Credential extraction tool not available. Skipping analysis."
            )
            return {}

        if not os.path.exists(log_file):
            print_warning(f"Log file not found: {log_file}")
            return {}

        service = self._get_credsweeper_service()
        return service.analyze_file(log_file, credsweeper_path=self.credsweeper_path)

