    def save_credentials_to_files(self, credentials, base_dir="smb/spidering"):
        """
        Saves credentials to JSON files organized by category.
        Each credential type gets its own file.

        Args:
            credentials (dict): Dictionary of credentials organized by type.
            base_dir (str): Base directory to save credential files.

        Returns:
            dict: Dictionary mapping credential types to file paths where they were saved.
        """
        saved_files = {}

        if not credentials:
            return saved_files

        # Ensure directory exists
        os.makedirs(base_dir, exist_ok=True)

        for cred_type, creds_list in credentials.items():
            if not creds_list:
                continue

            # Sanitize credential type name for filename
            safe_type_name = cred_type.lower().replace(" ", "_").replace("/", "_")
            filename = f"{safe_type_name}.json"
            file_path = os.path.join(base_dir, filename)

            # Prepare data for JSON
            cred_data = []
            for value, ml_prob, context_line, line_num, file_path_orig in creds_list:
                cred_data.append(
                    {
                        "value": value,
                        "ml_confidence": ml_prob,
                        "context_line": context_line,
                        "line_number": line_num,
                        "source_file": file_path_orig,
                    }
                )

            # Sort by ML confidence (highest first)
            cred_data.sort(key=lambda x: x["ml_confidence"], reverse=True)

            # Save to JSON file
            try:
                with open(file_path, "w", encoding="utf-8") as f:
                    json.dump(
                        {
                            "credential_type": cred_type,
                            "count": len(cred_data),
                            "credentials": cred_data,
                        },
                        f,
                        indent=2,
                        ensure_ascii=False,
                    )

                saved_files[cred_type] = file_path
            except Exception as e:
                telemetry.capture_exception(e)
                print_warning(f"Error saving {cred_type} credentials to file: {e}")

        return saved_files

