    def do_is_computer_dc(self, args):
        """
        Interactive command that checks if a host is a Domain Controller.
        Usage: is_computer_dc <domain> <target_host>
        """
        from adscan_internal.cli.dns import is_computer_dc
        from adscan_internal.rich_output import mark_sensitive

        args = args.split()
        if len(args) != 2:
            print_instruction("Usage: is_computer_dc <domain> <target_host>")
            return

        domain, target_host = args
        if is_computer_dc(self, domain, target_host):
            marked_target_host = mark_sensitive(target_host, "hostname")
            marked_domain = mark_sensitive(domain, "domain")
            print_success(
                f"{marked_target_host} is a Domain Controller in domain {marked_domain}."
            )
        else:
            marked_target_host = mark_sensitive(target_host, "hostname")
            marked_domain = mark_sensitive(domain, "domain")
            print_warning(
                f"{marked_target_host} is not a Domain Controller in domain {marked_domain}."
            )

    def check_admin_count(self, domain, username, password=None, logging=True):
        from adscan_internal.rich_output import mark_sensitive
        from adscan_internal.principal_utils import is_machine_account

        try:
            marked_username = mark_sensitive(username, "user")
            marked_domain = mark_sensitive(domain, "domain")
            print_info_debug(
                f"[admin-count] start: user={marked_username} domain={marked_domain}"
            )
            # Check if it is a machine account
            if is_machine_account(username):
                print_info_debug(
                    f"[admin-count] Detected machine account: {marked_username}"
                )
                dc_role = self.get_user_dc_role(domain, username)
                if dc_role == "writable_dc":
                    print_warning(f"{marked_username} is a Domain Controller")
                    return self.dcsync(domain, username, password)
                if dc_role == "rodc":
                    print_warning(
                        f"{marked_username} is a Read-Only Domain Controller and "
                        "requires follow-up steps before domain compromise."
                    )
                    return False
            else:
                print_info_debug(
                    f"[admin-count] Not a machine account: {marked_username}"
                )
            admins_file = os.path.join(
                "domains", domain, "control_exposure_identities.txt"
            )
            if os.path.exists(admins_file):
                with open(admins_file, "r", encoding="utf-8") as f:
                    # Each line is read with whitespace and newlines stripped, ignoring empty lines.
                    admins = [line.strip().lower() for line in f if line.strip()]

                if username.lower() in admins:
                    if logging:
                        marked_username = mark_sensitive(username, "user")
                        marked_domain = mark_sensitive(domain, "domain")
                        print_warning(
                            f"The user {marked_username} appears in the control exposure inventory for domain {marked_domain}"
                        )
                    return True
                if logging:
                    marked_username = mark_sensitive(username, "user")
                    marked_domain = mark_sensitive(domain, "domain")
                    print_info(
                        f"The user {marked_username} is not present in the control exposure inventory for domain {marked_domain}"
                    )
                return False

            # Modern path when the exported file is absent: build the
            # identity-risk snapshot on demand from collected memberships /
            # attack-graph. This is robust to the attack-graph report step not
            # having run, uses real group-membership classification (Tier-0 /
            # control exposure) instead of a stale adminCount, and — crucially —
            # avoids a live LDAP adminCount probe that crashes ("Cannot run the
            # event loop while another loop is running") when invoked from inside
            # an async dump loop, which silently dropped DA detection + follow-ups.
            try:
                from adscan_internal.services.identity_risk_service import (
                    load_or_build_identity_risk_snapshot,
                )

                snapshot = load_or_build_identity_risk_snapshot(self, domain)
            except Exception as snap_exc:  # noqa: BLE001
                telemetry.capture_exception(snap_exc)
                snapshot = None
            if isinstance(snapshot, dict) and snapshot.get("users"):
                uname = username.split("@", 1)[0].strip().lower()
                control_exposed = {
                    str(u).split("@", 1)[0].strip().lower()
                    for u in snapshot.get("control_exposure_identities", [])
                }
                if uname in control_exposed:
                    if logging:
                        print_warning(
                            f"The user {mark_sensitive(username, 'user')} is a "
                            "control-exposed/Tier-0 principal in domain "
                            f"{mark_sensitive(domain, 'domain')} (identity-risk snapshot)"
                        )
                    return True
                return False

            # Last resort only when we have no collected identity data at all.
            return self.check_old_admin_count(domain, username, password, logging)

        except Exception as e:
            telemetry.capture_exception(e)
            if logging:
                print_error("Error checking the privileged file.")
                print_exception(show_locals=False, exception=e)
            return False

    def check_old_admin_count(self, domain, username, password=None, logging=True):
        from adscan_internal.rich_output import mark_sensitive
        from adscan_internal.principal_utils import is_machine_account

        try:
            # Check if it is a machine account
            if is_machine_account(username):
                dc_role = self.get_user_dc_role(domain, username)
                if dc_role == "writable_dc":
                    marked_username = mark_sensitive(username, "user")
                    print_warning(f"{marked_username} is a Domain Controller")
                    return self.dcsync(domain, username, password)
                if dc_role == "rodc":
                    marked_username = mark_sensitive(username, "user")
                    print_warning(
                        f"{marked_username} is a Read-Only Domain Controller and "
                        "requires follow-up steps before domain compromise."
                    )
                    return False

            # If not a machine account, continue with checking adminCount via CLI helper
            from adscan_internal.cli.ldap import run_ldap_admincount_and_signing

            result = run_ldap_admincount_and_signing(
                self,
                domain=domain,
                username=username,
                password=(
                    password
                    if password is not None
                    else self.domains_data[domain]["password"]
                ),
                logging=logging,
            )
            if result is None:
                marked_username = mark_sensitive(username, "user")
                marked_domain = mark_sensitive(domain, "domain")
                print_info_debug(
                    "[admin-count] LDAP adminCount check returned None for "
                    f"{marked_username}@{marked_domain}; keeping stored credential."
                )
                return None
            return bool(result)

        except Exception as e:
            telemetry.capture_exception(e)
            print_error("An error occurred while checking adminCount.")
            print_exception(show_locals=False, exception=e)
            return False

    def check_high_value(self, domain, username, password=None, logging=True):
        from adscan_internal.rich_output import mark_sensitive

        try:
            from adscan_internal.services.high_value import (
                is_user_tier0_or_high_value,
                normalize_samaccountname,
            )
            from adscan_internal.workspaces import domain_subpath

            sam = normalize_samaccountname(username)
            if not sam:
                return False

            # Keep the user-facing hint when the cached list isn't present,
            # but still allow best-effort fallbacks (attack_graph/BloodHound/snapshot).
            workspace_cwd = self.current_workspace_dir or os.getcwd()
            admins_file = domain_subpath(
                workspace_cwd,
                self.domains_dir,
                domain,
                "control_exposure_identities.txt",
            )
            if logging and not os.path.exists(admins_file):
                marked_domain = mark_sensitive(domain, "domain")
                print_warning(
                    f"No cached control exposure inventory found for {marked_domain} (control_exposure_identities.txt). "
                    "Using best-effort detection."
                )

            result = is_user_tier0_or_high_value(
                self, domain=domain, samaccountname=sam
            )

            if logging:
                marked_username = mark_sensitive(username, "user")
                marked_domain = mark_sensitive(domain, "domain")
                if result:
                    print_success(
                        f"The user {marked_username} is classified as control-exposed in domain {marked_domain}"
                    )
                else:
                    print_info(
                        f"The user {marked_username} is not classified as control-exposed in domain {marked_domain}"
                    )
            return bool(result)

        except Exception as e:
            telemetry.capture_exception(e)
            print_error("Error checking the administrators file.")
            print_exception(show_locals=False, exception=e)
            return False

    def build_auth_nxc(self, username, password, domain=None, kerberos=False):
        """
        Builds the authentication string for netexec commands.

        Args:
            username (str): The username
            password (str): The password, NT hash, or .ccache file path
            domain (str, optional): The domain if needed

        Returns:
            str: The authentication string formatted for netexec
        """
        if password.lower().endswith(".ccache"):
            auth = f"-u '{username}' --use-kcache"
            if domain:
                auth += f" -d {domain} -k"
            else:
                auth += " --local-auth"
            return auth

        # Check if it is an NT hash (32 hexadecimal characters)
        is_hash = len(password) == 32 and all(
            c in "0123456789abcdef" for c in password.lower()
        )

        # Build the authentication part
        auth = f"-u '{username}' "
        if is_hash:
            auth += f"-H {password}"
        else:
            from adscan_internal.integrations.netexec.helpers import (
                build_nxc_plaintext_password_arg,
            )

            auth += build_nxc_plaintext_password_arg(password)

        # Add the domain if provided
        if domain:
            auth += f" -d {domain}"

            if kerberos:
                auth += " -k"

        else:
            auth += " --local-auth"

        return auth

    def build_auth_bloody(self, username, password, domain=None, kerberos=False):
        """
        Builds the authentication string for bloodyAD commands.

        Args:
            username (str): The username
            password (str): The password or NT hash
            domain (str, optional): The domain if needed

        Returns:
            str: The authentication string formatted for bloodyAD
        """
        # Check if it is an NT hash (32 hexadecimal characters)
        is_hash = len(password) == 32 and all(
            c in "0123456789abcdef" for c in password.lower()
        )

        # Build the base string
        auth = ""

        # Add the domain if provided
        if domain:
            auth += f" -d {domain} "

        # Add username and password
        auth += f"-u '{username}' "

        # If it is a hash, add a colon before it
        if is_hash:
            if kerberos:
                auth += f"-p '{password}' -f rc4"
            else:
                auth += f"-p ':{password}'"
        else:
            auth += f"-p '{password}'"

        if kerberos:
            auth += " -k"

        return auth

    def build_auth_impacket(self, username, password, domain, kerberos=False):
        """
        Builds the authentication string for netexec commands.

        Args:
            username (str): The username
            password (str): The password, NT hash, or .ccache file
            domain (str, optional): The domain if needed

        Returns:
            str: The authentication string formatted for netexec
        """
        # Check if it is a .ccache file
        if password.lower().endswith(".ccache"):
            # Specific authentication for .ccache files with Kerberos
            auth = f"-k -no-pass {domain}/'{username}'@{self.domains_data[domain]['pdc_hostname']}"
        else:
            # Check if it is an NT hash (32 hexadecimal characters)
            is_hash = len(password) == 32 and all(
                c in "0123456789abcdef" for c in password.lower()
            )

            # Build the authentication part
            auth = f"{domain}/'{username}'"
            auth += (
                f"@{self.domains_data[domain]['pdc']} -hashes :{password}"
                if is_hash
                else f":'{password}'@{self.domains_data[domain]['pdc']}"
            )
        if kerberos:
            auth += " -k"
        return auth

    def build_auth_impacket_no_host(self, username, password, domain, kerberos=False):
        """
        Builds the authentication string for netexec commands.

        Args:
            username (str): The username
            password (str): The password or NT hash
            domain (str, optional): The domain if needed

        Returns:
            str: The authentication string formatted for netexec
        """
        # Check if it is an NT hash (32 hexadecimal characters)
        is_hash = len(password) == 32 and all(
            c in "0123456789abcdef" for c in password.lower()
        )

        # Build the authentication part
        auth = f"{domain}/'{username}'"
        auth += f" -hashes :{password}" if is_hash else f":'{password}'"

        if kerberos:
            auth += "-k"

        return auth

    def build_auth_certipy(self, domain, username, password):
        """
        Builds the authentication string for netexec commands.

        Args:
            username (str): The username
            password (str): The password or NT hash
            domain (str, optional): The domain if needed

        Returns:
            str: The authentication string formatted for netexec
        """
        # Check if it is an NT hash (32 hexadecimal characters)
        is_hash = len(password) == 32 and all(
            c in "0123456789abcdef" for c in password.lower()
        )

        # Build the authentication part
        auth = f"-u '{username}'@{domain}"
        auth += f" -hashes :{password}" if is_hash else f" -p '{password}'"

        return auth

