    def check_privileged_groups(
        self,
        domain,
        username,
        password,
        *,
        execute_actions: bool = True,
        prefer_live_ldap: bool = False,
    ):
        """
        Checks privileged group membership for a user.

        We prefer memberships.json for recursive group memberships when available.
        If the snapshot is missing or yields no groups, fall back to live LDAP
        queries, and then to BloodHound as a last resort.
        """
        from adscan_internal.rich_output import mark_sensitive
        from adscan_internal.cli.ldap import peek_exact_ldap_connection_timeout_state
        from adscan_internal.principal_utils import is_machine_account

        try:
            marked_username = mark_sensitive(username, "user")
            marked_domain = mark_sensitive(domain, "domain")
            if execute_actions:
                print_info_verbose(
                    f"Checking group membership for user {marked_username} in domain {marked_domain}."
                )
            else:
                print_info_debug(
                    f"[priv-groups] Checking group membership for user {marked_username} in domain {marked_domain}."
                )
            privileged_groups = None
            source = "unknown"
            skip_further_live_ldap = False

            if prefer_live_ldap:
                print_info_debug(
                    "[priv-groups] forcing live LDAP lookup for "
                    f"{marked_username}@{marked_domain} (bypassing cached memberships/BloodHound first-pass)."
                )
                privileged_groups = self._check_privileged_groups_with_ldap(
                    domain, username, password
                )
                source = "ldap-live"
                skip_further_live_ldap = peek_exact_ldap_connection_timeout_state(self)
                if skip_further_live_ldap:
                    print_info_debug(
                        "[priv-groups] live LDAP lookup hit the exact LDAP "
                        f"connection-timeout signature for {marked_username}@{marked_domain}; "
                        "skipping any further live LDAP fallbacks in this privilege check."
                    )

            if privileged_groups is None:
                from adscan_internal.services.attack_graph_service import (
                    resolve_principal_groups,
                )

                group_result = resolve_principal_groups(self, domain, username)
                group_sids = group_result.get("group_sids", [])
                group_names = group_result.get("groups", [])
                source = group_result.get("source", "unknown")

                if group_sids:
                    from adscan_internal.services.privileged_group_classifier import (
                        classify_privileged_membership,
                    )

                    privileged_groups = classify_privileged_membership(
                        group_sids=group_sids,
                        group_names=group_names,
                    ).as_dict()
                    privileged_groups["groups"] = []
                    print_info_debug(
                        "[priv-groups] group SID lookup resolved "
                        f"{len(group_sids)} SID(s) for {marked_username}@{marked_domain} "
                        f"(source={source})."
                    )
                    self._debug_log_privileged_membership_resolution(
                        domain=domain,
                        username=username,
                        source=source,
                        group_sids=group_sids,
                        privileged_groups=privileged_groups,
                    )
                elif group_names:
                    raw_text = "\n".join(f"{group}@{domain}" for group in group_names)
                    privileged_groups = self._parse_privileged_group_output(raw_text)
                    print_info_debug(
                        "[priv-groups] group name lookup resolved "
                        f"{len(group_names)} group(s) for {marked_username}@{marked_domain} "
                        f"(source={source})."
                    )
                    self._debug_log_privileged_membership_resolution(
                        domain=domain,
                        username=username,
                        source=source,
                        group_names=group_names,
                        privileged_groups=privileged_groups,
                    )
                else:
                    if skip_further_live_ldap:
                        print_info_debug(
                            "[priv-groups] group lookup returned no results for "
                            f"{marked_username}@{marked_domain} (source={source}); "
                            "skipping additional LDAP fallback because live LDAP already "
                            "hit the exact connection-timeout signature."
                        )
                    else:
                        print_info_debug(
                            "[priv-groups] group lookup returned no results for "
                            f"{marked_username}@{marked_domain} (source={source}); falling back to LDAP."
                        )
                        privileged_groups = self._check_privileged_groups_with_ldap(
                            domain, username, password
                        )
                        source = "LDAP"

            if privileged_groups is None:
                print_info_verbose(
                    "Membership snapshot/LDAP group lookup failed or is unavailable. Falling back to BloodHound."
                )
                privileged_groups = self._check_privileged_groups_with_graph(
                    domain, username
                )
                source = "bloodhound"

            if privileged_groups is None:
                marked_username = mark_sensitive(username, "user")
                marked_domain = mark_sensitive(domain, "domain")
                print_error(
                    f"Unable to determine privileged groups for user {marked_username} in domain {marked_domain}."
                )
                return {}

            if is_machine_account(username):
                dc_role = self.get_user_dc_role(domain, username)
                if dc_role == "rodc" and not bool(
                    privileged_groups.get("read_only_domain_controllers")
                ):
                    privileged_groups = dict(privileged_groups)
                    privileged_groups["read_only_domain_controllers"] = True
                    print_info_debug(
                        "[priv-groups] overlaying Read-Only Domain Controllers "
                        f"membership from machine-account DC role for {marked_username}@{marked_domain}."
                    )

            structured_groups = privileged_groups.get("groups")
            if isinstance(structured_groups, list):
                resolved_group_names = [
                    f"{group.get('group', '')}@{group.get('domain', '')}"
                    for group in structured_groups
                    if isinstance(group, dict)
                ]
            else:
                resolved_group_names = []
            self._debug_log_privileged_membership_resolution(
                domain=domain,
                username=username,
                source=source,
                group_names=resolved_group_names,
                privileged_groups=privileged_groups,
            )

            if not execute_actions:
                return privileged_groups

            return self._handle_privileged_group_membership(
                domain, username, password, privileged_groups, source
            )

        except Exception as e:
            telemetry.capture_exception(e)
            print_error("Error checking privileged groups.")
            print_exception(show_locals=False, exception=e)
            return {}

    def _handle_privileged_group_membership(
        self, domain, username, password, membership, source
    ):
        """Execute follow-up actions based on privileged group membership."""
        from adscan_internal.rich_output import mark_sensitive
        from adscan_internal.services.adcs_target_filter import (
            domain_has_adcs_for_attack_steps,
        )
        from adscan_internal.services.privileged_group_classifier import (
            PrivilegedFollowupOption,
            resolve_privileged_followup_decision,
            resolve_privileged_followup_options,
        )

        privileged_groups = {
            "domain_admin": bool(membership.get("domain_admin")),
            "backup_operators": bool(membership.get("backup_operators")),
            "read_only_domain_controllers": bool(
                membership.get("read_only_domain_controllers")
            ),
            "Administrators": bool(membership.get("Administrators")),
            "cert_publishers": bool(membership.get("cert_publishers")),
            "key_admins": bool(membership.get("key_admins")),
            "enterprise_key_admins": bool(membership.get("enterprise_key_admins")),
            "exchange_trusted_subsystem": bool(
                membership.get("exchange_trusted_subsystem")
            ),
            "exchange_windows_permissions": bool(
                membership.get("exchange_windows_permissions")
            ),
            "account_operators": bool(membership.get("account_operators")),
        }
        has_adcs = domain_has_adcs_for_attack_steps(self, domain)
        followup_decision = resolve_privileged_followup_decision(
            privileged_groups,
            adcs_available=has_adcs,
        )
        followup_options = resolve_privileged_followup_options(
            privileged_groups,
            adcs_available=has_adcs,
        )
        marked_username = mark_sensitive(username, "user")
        marked_domain = mark_sensitive(domain, "domain")
        print_info_debug(
            "[priv-groups] executing follow-up actions for "
            f"{marked_username}@{marked_domain}: source={source} flags={privileged_groups} "
            f"primary={followup_decision.primary_key} rank={followup_decision.highest_rank} "
            f"adcs_available={has_adcs}"
        )

        def _select_followup_option(
            options: tuple[PrivilegedFollowupOption, ...],
        ) -> PrivilegedFollowupOption | None:
            actionable = [option for option in options if option.actionable]
            if not actionable:
                return None
            domain_admin_option = next(
                (option for option in actionable if option.key == "domain_admin"),
                None,
            )
            if domain_admin_option is not None:
                return domain_admin_option
            administrators_option = next(
                (option for option in actionable if option.key == "Administrators"),
                None,
            )
            if administrators_option is not None:
                return administrators_option
            if len(actionable) == 1 or _should_disable_interactive_prompts(self):
                return actionable[0]

            selector = getattr(self, "_questionary_select", None)
            if not callable(selector):
                return actionable[0]

            labels = [
                (f"{option.label} (Recommended)" if index == 0 else option.label)
                for index, option in enumerate(actionable)
            ]
            choice_idx = selector(
                (
                    f"Multiple privileged follow-ups are available for "
                    f"{marked_username}@{marked_domain}. Which one do you want to run?"
                ),
                labels,
                default_idx=0,
            )
            if not isinstance(choice_idx, int) or not (
                0 <= choice_idx < len(actionable)
            ):
                return actionable[0]
            return actionable[choice_idx]

        selected_followup = _select_followup_option(followup_options)
        selected_key = selected_followup.key if selected_followup else None
        print_info_debug(
            "[priv-groups] follow-up selection: "
            f"matched={tuple(option.key for option in followup_options)} "
            f"selected={selected_key!r}"
        )

        if selected_followup is None:
            return privileged_groups

        if selected_key == "domain_admin":
            print_warning(
                f"The user {marked_username} is a member of the Domain Admins group"
            )
            try:
                from adscan_internal.services.membership_snapshot import (
                    add_runtime_user_group_membership,
                )

                add_runtime_user_group_membership(
                    self,
                    domain,
                    username=username,
                    group_name="Domain Admins",
                    source="priv_group_enumeration",
                    evidence={
                        "detected_at": datetime.now(timezone.utc).isoformat(),
                        "source": "privileged-group enumeration follow-up",
                    },
                    origin_kind="runtime_effective",
                    origin_relation="MemberOf",
                )
            except Exception as _exc:  # noqa: BLE001
                telemetry.capture_exception(_exc)

            from adscan_internal.services.domain_compromise_promotion import (
                CompromiseEvidence,
                promote_to_pwned,
            )

            promote_to_pwned(
                self,
                domain=domain,
                evidence=CompromiseEvidence.DOMAIN_ADMIN_MEMBERSHIP,
                username=username,
                credential=password,
                ctf_actions={"flags", "dcsync"},
            )
            try:
                from adscan_internal.cli.backup_operators_escalation import (
                    handle_backup_ops_sysvol_cleanup,
                )

                handle_backup_ops_sysvol_cleanup(
                    self,
                    domain=domain,
                    username=username,
                    password=password,
                )
            except Exception as exc:  # pragma: no cover - best effort
                telemetry.capture_exception(exc)
                print_info_debug(f"[backup-ops] cleanup helper failed: {exc}")

            if self.type == "ctf":
                return privileged_groups
            self.ask_for_dcsync(domain, username, password)
            if self.type == "audit":
                self._run_audit_post_da_graph_refresh(
                    domain,
                    username,
                    password,
                )
                self.ask_for_post_da_host_dumps(domain, username, password)
            self.ask_for_raise_child(domain, username, password)
            return privileged_groups

        if selected_key == "Administrators":
            print_warning(
                f"The user {marked_username} is a member of the Administrators group"
            )
            # In CTF mode: run DCSync first so we get the Domain Admin / Administrator
            # NT hash, then rely on the credential-add pipeline to trigger flag
            # collection with reliable credentials.  Asking for flags here fires
            # before DCSync and uses the current (possibly contaminated) Kerberos
            # session, causing ACCESS_DENIED on SMB C$ probes.
            self.ask_for_dcsync(domain, username, password)

        if selected_key == "backup_operators":
            print_warning(
                f"The user {marked_username} is a member of the Backup Operators group"
            )
            try:
                from adscan_internal.cli.backup_operators_escalation import (
                    record_backup_ops_discovered,
                    offer_backup_operators_escalation,
                )

                record_backup_ops_discovered(
                    self,
                    domain=domain,
                    username=username,
                )
                offer_backup_operators_escalation(
                    self,
                    domain=domain,
                    username=username,
                    password=password,
                )
            except Exception as exc:  # pragma: no cover - best effort
                telemetry.capture_exception(exc)
                print_info_debug(f"[backup-ops] escalation helper failed: {exc}")

        if selected_key == "read_only_domain_controllers":
            print_warning(
                f"The user {marked_username} is a member of the Read-Only Domain Controllers group"
            )
            try:
                from adscan_internal.cli.rodc_escalation import (
                    offer_rodc_escalation,
                )

                offer_rodc_escalation(
                    self,
                    domain=domain,
                    username=username,
                    password=password,
                )
            except Exception as exc:  # pragma: no cover - best effort
                telemetry.capture_exception(exc)
                print_info_debug(f"[rodc] escalation helper failed: {exc}")

        if selected_key == "account_operators":
            print_warning(
                f"The user {marked_username} is a member of the Account Operators group"
            )
            try:
                from adscan_internal.cli.account_operators_escalation import (
                    offer_account_operators_escalation,
                )

                offer_account_operators_escalation(
                    self,
                    domain=domain,
                    username=username,
                    password=password,
                )
            except Exception as exc:  # pragma: no cover - best effort
                telemetry.capture_exception(exc)
                print_info_debug(f"[acct-ops] escalation helper failed: {exc}")

        if selected_key == "exchange_windows_permissions":
            print_warning(
                f"The user {marked_username} is a member of the Exchange Windows Permissions group"
            )
            try:
                from adscan_internal.cli.account_operators_escalation import (
                    offer_exchange_windows_permissions_escalation,
                )

                offer_exchange_windows_permissions_escalation(
                    self,
                    domain=domain,
                    username=username,
                    password=password,
                )
            except Exception as exc:  # pragma: no cover - best effort
                telemetry.capture_exception(exc)
                print_info_debug(
                    f"[exchange-windows-permissions] escalation helper failed: {exc}"
                )

        if selected_key == "exchange_trusted_subsystem":
            print_warning(
                f"The user {marked_username} is a member of the Exchange Trusted Subsystem group"
            )
            try:
                from adscan_internal.cli.account_operators_escalation import (
                    offer_exchange_trusted_subsystem_escalation,
                )

                offer_exchange_trusted_subsystem_escalation(
                    self,
                    domain=domain,
                    username=username,
                    password=password,
                )
            except Exception as exc:  # pragma: no cover - best effort
                telemetry.capture_exception(exc)
                print_info_debug(
                    f"[exchange-trusted-subsystem] escalation helper failed: {exc}"
                )

        return privileged_groups

    def _check_privileged_groups_with_graph(self, domain, username):
        """Use BloodHoundService to resolve group membership. Returns dict or None on failure."""

        # In native mode the membership snapshot already covers group resolution.
        # If we reached this point both snapshot and LDAP lookups already failed,
        # so returning None degrades gracefully — the caller handles None.
        return None
        try:
            service = self._get_graph_service()
            groups = service.get_user_groups(
                domain=domain, username=username, recursive=True
            )
            # Prefer SID/RID based classification when possible (language-agnostic).
            from adscan_internal.services.privileged_group_classifier import (
                classify_privileged_membership,
            )

            group_sids: list[str] = []
            group_distinguished_names: list[str] = []
            resolver_fn = getattr(service, "get_group_node_by_samaccountname", None)
            if callable(resolver_fn):
                from typing import Callable, cast

                resolver = cast(Callable[[str, str], object], resolver_fn)
                for group in groups:
                    group_name = str(group or "").strip()
                    if not group_name:
                        continue
                    # BloodHound group membership strings are typically GROUP@DOMAIN.
                    if "@" in group_name:
                        group_name = group_name.split("@", 1)[0].strip()
                    node = resolver(domain, group_name)  # pylint: disable=not-callable
                    if isinstance(node, dict):
                        sid = (
                            node.get("objectid")
                            or node.get("objectId")
                            or (node.get("properties") or {}).get("objectid")
                            or (node.get("properties") or {}).get("objectId")
                        )
                        if isinstance(sid, str) and sid.strip():
                            group_sids.append(sid.strip())
                        distinguished_name = (
                            node.get("distinguishedname")
                            or node.get("distinguishedName")
                            or (node.get("properties") or {}).get("distinguishedname")
                            or (node.get("properties") or {}).get("distinguishedName")
                        )
                        if (
                            isinstance(distinguished_name, str)
                            and distinguished_name.strip()
                        ):
                            group_distinguished_names.append(distinguished_name.strip())
                        else:
                            group_distinguished_names.append("")

            if group_sids:
                membership = classify_privileged_membership(
                    group_sids=group_sids,
                    group_names=groups,
                    group_distinguished_names=group_distinguished_names,
                )
                result = membership.as_dict()
                result["groups"] = []
                return result

            # Fallback: reuse existing name-based parser for backward compatibility.
            raw_text = "\n".join(groups)
            return self._parse_privileged_group_output(raw_text)
        except Exception as exc:
            telemetry.capture_exception(exc)
            print_warning(
                f"BloodHound group lookup raised an exception: {exc}. Falling back."
            )
            return None

    def _check_privileged_groups_with_ldap(self, domain, username, password):
        """Resolve group membership using live LDAP queries (preferred)."""
        try:
            from adscan_internal.cli.ldap import (
                clear_exact_ldap_connection_timeout_state,
                consume_exact_ldap_connection_timeout_state,
                mark_exact_ldap_connection_timeout_state,
                get_recursive_user_groups_in_chain,
                get_recursive_principal_group_sids_in_chain,
                run_ldap_groupmembership_privileged,
            )
            from adscan_internal.services.privileged_group_classifier import (
                classify_privileged_membership,
            )

            clear_exact_ldap_connection_timeout_state(self)
            group_sids = get_recursive_principal_group_sids_in_chain(
                self,
                domain=domain,
                target_samaccountname=username,
                auth_username=username,
                auth_password=password,
            )
            if group_sids is not None:
                membership = classify_privileged_membership(
                    group_sids=group_sids,
                )
                result = membership.as_dict()
                # Keep the legacy shape for any downstream consumers.
                result["groups"] = []
                return result
            if consume_exact_ldap_connection_timeout_state(self):
                mark_exact_ldap_connection_timeout_state(self)
                marked_user = mark_sensitive(username, "user")
                marked_domain = mark_sensitive(domain, "domain")
                print_info_debug(
                    "[priv-groups] LDAP group SID lookup hit the exact LDAP "
                    f"connection-timeout signature for {marked_user}@{marked_domain}; "
                    "skipping further LDAP fallbacks."
                )
                return None
            try:
                marked_user = mark_sensitive(username, "user")
                marked_domain = mark_sensitive(domain, "domain")
                print_info_debug(
                    "[priv-groups] LDAP group SID lookup unavailable for "
                    f"{marked_user}@{marked_domain}; falling back to group name parsing."
                )
            except Exception:
                pass

            groups = get_recursive_user_groups_in_chain(
                self,
                domain=domain,
                target_username=username,
                auth_username=username,
                auth_password=password,
            )
            if groups is not None:
                raw_text = "\n".join(f"{group}@{domain}" for group in groups)
                return self._parse_privileged_group_output(raw_text)
            if consume_exact_ldap_connection_timeout_state(self):
                mark_exact_ldap_connection_timeout_state(self)
                marked_user = mark_sensitive(username, "user")
                marked_domain = mark_sensitive(domain, "domain")
                print_info_debug(
                    "[priv-groups] LDAP recursive group lookup hit the exact LDAP "
                    f"connection-timeout signature for {marked_user}@{marked_domain}; "
                    "skipping NetExec LDAP module fallback."
                )
                return None

            # Only emit a debug hint when we are falling back within LDAP.
            try:
                marked_user = mark_sensitive(username, "user")
                marked_domain = mark_sensitive(domain, "domain")
                print_info_debug(
                    "[priv-groups] LDAP recursive group lookup unavailable for "
                    f"{marked_user}@{marked_domain}; falling back to NetExec module output."
                )
            except Exception:
                pass

            # Fallback: legacy NetExec module output (non-recursive).
            result = run_ldap_groupmembership_privileged(
                self, domain=domain, username=username, password=password
            )
            if result is None and consume_exact_ldap_connection_timeout_state(self):
                marked_user = mark_sensitive(username, "user")
                marked_domain = mark_sensitive(domain, "domain")
                print_info_debug(
                    "[priv-groups] LDAP groupmembership module hit the exact LDAP "
                    f"connection-timeout signature for {marked_user}@{marked_domain}."
                )
            return result
        except Exception as exc:
            telemetry.capture_exception(exc)
            print_error("LDAP privileged group lookup failed.")
            print_exception(show_locals=False, exception=exc)
            return None

    def _format_privileged_debug_sample(
        self,
        values: list[str] | tuple[str, ...] | set[str],
        *,
        limit: int = 8,
    ) -> str:
        """Return a compact preview for privileged-membership debug logs."""
        normalized = [str(value).strip() for value in values if str(value).strip()]
        if not normalized:
            return "none"

        unique_sorted = sorted(dict.fromkeys(normalized))
        preview = unique_sorted[:limit]
        if len(unique_sorted) > limit:
            remaining = len(unique_sorted) - limit
            return f"{', '.join(preview)} ... (+{remaining} more)"
        return ", ".join(preview)

    def _debug_log_privileged_membership_resolution(
        self,
        *,
        domain: str,
        username: str,
        source: str,
        group_sids: list[str] | None = None,
        group_names: list[str] | None = None,
        privileged_groups: dict[str, object] | None = None,
    ) -> None:
        """Emit a structured debug line for privileged-group resolution."""
        from adscan_internal.rich_output import mark_sensitive

        marked_user = mark_sensitive(username, "user")
        marked_domain = mark_sensitive(domain, "domain")
        sid_preview = self._format_privileged_debug_sample(group_sids or [])
        name_preview = self._format_privileged_debug_sample(group_names or [])
        flags = {
            "domain_admin": bool((privileged_groups or {}).get("domain_admin")),
            "Administrators": bool((privileged_groups or {}).get("Administrators")),
            "backup_operators": bool((privileged_groups or {}).get("backup_operators")),
            "read_only_domain_controllers": bool(
                (privileged_groups or {}).get("read_only_domain_controllers")
            ),
            "exchange_trusted_subsystem": bool(
                (privileged_groups or {}).get("exchange_trusted_subsystem")
            ),
            "exchange_windows_permissions": bool(
                (privileged_groups or {}).get("exchange_windows_permissions")
            ),
            "account_operators": bool(
                (privileged_groups or {}).get("account_operators")
            ),
        }
        print_info_debug(
            "[priv-groups] resolved membership for "
            f"{marked_user}@{marked_domain}: source={source} "
            f"sids=[{sid_preview}] groups=[{name_preview}] flags={flags}"
        )

    def _parse_privileged_group_output(self, raw_text: str) -> Dict[str, Any]:
        """Parse CLI output and return dict of privileged group memberships.

        This function is used for both:
        - `bloodhound-cli group -u <user> -d <domain>` output, which is typically in
          the form `GROUP NAME@DOMAIN` (with possibly multiple spaces before the `@`).
        - NetExec LDAP `groupmembership` module output.

        It normalizes lines by:
        - Using `@` as the delimiter between group name and domain (ignoring spaces),
          which is more robust than splitting on whitespace because group names
          themselves may contain spaces.
        - Converting both group and domain to lowercase.

        The structured `(group, domain)` pairs are collected in the `groups` field
        of the returned dictionary for future consumers, while the existing
        boolean flags are preserved for backward compatibility.
        """
        text = raw_text or ""
        groups: List[Dict[str, str]] = []

        for line in text.splitlines():
            line = line.strip()
            if not line or "@" not in line:
                continue

            # Use '@' as the delimiter, allowing arbitrary spaces before it.
            left, right = line.rsplit("@", 1)
            group_name = left.rstrip().lower()
            group_domain = right.strip().lower()

            if group_name and group_domain:
                groups.append({"group": group_name, "domain": group_domain})

        lowered_text = text.lower()

        # Determine privileged memberships, preferring structured groups when present
        domain_admin = any(
            g["group"].startswith("domain admins") for g in groups
        ) or any(
            marker in lowered_text
            for marker in ("domain admins", "admins. del dominio")
        )

        administrators = any(
            g["group"].endswith("administrators") or g["group"] == "administrators"
            for g in groups
        ) or any(
            marker in lowered_text
            for marker in (" administrators", " administradores", "administrators")
        )

        backup_operators = any("backup operators" in g["group"] for g in groups) or any(
            marker in lowered_text
            for marker in ("backup operators", "operadores de copia")
        )
        read_only_domain_controllers = (
            any("read-only domain controllers" in g["group"] for g in groups)
            or "read-only domain controllers" in lowered_text
        )

        account_operators = (
            any("account operators" in g["group"] for g in groups)
            or "account operators" in lowered_text
        )
        exchange_windows_permissions = (
            any("exchange windows permissions" in g["group"] for g in groups)
            or "exchange windows permissions" in lowered_text
        )
        exchange_trusted_subsystem = (
            any("exchange trusted subsystem" in g["group"] for g in groups)
            or "exchange trusted subsystem" in lowered_text
        )

        return {
            "domain_admin": domain_admin,
            "Administrators": administrators,
            "backup_operators": backup_operators,
            "read_only_domain_controllers": read_only_domain_controllers,
            "exchange_trusted_subsystem": exchange_trusted_subsystem,
            "exchange_windows_permissions": exchange_windows_permissions,
            "account_operators": account_operators,
            "groups": groups,
        }

