    def ask_for_user_privs(self, domain, username, password, auto_mode=False):
        from adscan_internal.rich_output import (
            mark_sensitive,
        )
        from adscan_internal.cli.attack_path_execution import (
            offer_attack_paths_with_non_high_value_fallback,
        )
        from adscan_internal.services.adcs_target_filter import (
            domain_has_adcs_for_attack_steps,
        )
        from adscan_internal.services.attack_graph_service import (
            ATTACK_PATHS_MAX_DEPTH_USER,
        )
        from adscan_internal.services.privileged_group_classifier import (
            resolve_privileged_followup_decision,
        )

        if self.domains_data[domain]["auth"] == "pwned" and self.type == "ctf":
            return
        self.do_sync_clock_with_pdc(domain)

        def _offer_attack_paths() -> None:
            # Reuse the centralized UX: show paths, allow inspecting details, and
            # optionally execute one (step mapping is handled by the helper).
            offer_attack_paths_with_non_high_value_fallback(
                self,
                domain,
                start=username,
                max_depth=ATTACK_PATHS_MAX_DEPTH_USER,
                max_display=20,
                target="all",
                context_username=username,
                context_password=password,
            )

        if self.domains_data[domain]["pdc"] is not None:
            marked_username = mark_sensitive(username, "user")
            marked_domain = mark_sensitive(domain, "domain")
            print_info_debug(
                f"[user-privs] Checking admin privileges for {marked_username} "
                f"in {marked_domain}"
            )
            # Check if the user has adminCount=1 (elevated privileges)
            has_admin_privs = self.check_admin_count(domain, username, password)
            # If the credentials are invalid, exit the function
            if has_admin_privs is None:
                print_info_debug(
                    f"[user-privs] Privilege check returned None for {marked_username}"
                )
                return
            if has_admin_privs:
                # Check privileged groups and execute corresponding actions
                privileged_groups = self.check_privileged_groups(
                    domain, username, password
                )
                has_adcs = domain_has_adcs_for_attack_steps(self, domain)
                followup_decision = resolve_privileged_followup_decision(
                    privileged_groups,
                    adcs_available=has_adcs,
                )

                # If the user is already privileged, direct follow-up beats
                # showing noisy attack paths from that same user.
                if followup_decision.skip_attack_path_search:
                    if self.domains_data.get(domain, {}).get("auth") == "pwned":
                        print_info_verbose(
                            f"Skipping user privilege enumeration for {marked_username}: domain is already pwned."
                        )
                        return

                    print_info_verbose(
                        f"Skipping attack path search for {marked_username}: "
                        f"user is already privileged via {followup_decision.primary_key}."
                    )

                    if auto_mode:
                        marked_username = mark_sensitive(username, "user")
                        print_success(
                            f"Automatically enumerating post-auth service access for user {marked_username}"
                        )
                        self.netexec_user_postauth_access(domain, username, password)
                    else:
                        marked_username = mark_sensitive(username, "user")
                        if Confirm.ask(
                            f"Do you want to enumerate post-auth service access for user {marked_username}?",
                            default=True,
                        ):
                            self.netexec_user_postauth_access(
                                domain, username, password
                            )
                        else:
                            marked_username = mark_sensitive(username, "user")
                            print_info_verbose(
                                f"Post-auth service enumeration for user {marked_username} has been cancelled."
                            )
                else:
                    _offer_attack_paths()
            else:
                live_membership = self.check_privileged_groups(
                    domain,
                    username,
                    password,
                    execute_actions=False,
                    prefer_live_ldap=True,
                )
                has_adcs = domain_has_adcs_for_attack_steps(self, domain)
                live_followup_decision = resolve_privileged_followup_decision(
                    live_membership or {},
                    adcs_available=has_adcs,
                )
                if live_followup_decision.skip_attack_path_search:
                    print_info_debug(
                        "[user-privs] Live LDAP membership indicates privileged access "
                        f"for {marked_username}@{marked_domain} despite adminCount/cache check."
                    )
                    self._handle_privileged_group_membership(
                        domain,
                        username,
                        password,
                        live_membership,
                        "ldap-live-admincount-bypass",
                    )
                    return
                if live_followup_decision.should_run_enrichment_followup:
                    print_info_debug(
                        "[user-privs] Running non-blocking privileged enrichment "
                        f"for {marked_username}@{marked_domain}."
                    )
                    self._handle_privileged_group_membership(
                        domain,
                        username,
                        password,
                        live_membership,
                        "ldap-live-enrichment",
                    )

                # If the user does not have adminCount=1, ask if privilege enumeration should be executed
                _offer_attack_paths()
                if self.domains_data.get(domain, {}).get("auth") == "pwned":
                    print_info_verbose(
                        f"Skipping user privilege enumeration for {marked_username}: domain is already pwned."
                    )
                    return

                if auto_mode:
                    print_success(
                        f"Automatically enumerating post-auth service access for user {marked_username}"
                    )
                    self.netexec_user_postauth_access(domain, username, password)
                else:
                    marked_username = mark_sensitive(username, "user")
                    respuesta = Confirm.ask(
                        f"Do you want to enumerate post-auth service access for user {marked_username}?"
                    )
                    if respuesta:  # Prompt.ask for (y/n) returns boolean
                        self.netexec_user_postauth_access(domain, username, password)
                    else:
                        marked_username = mark_sensitive(username, "user")
                        print_info_verbose(
                            f"Post-auth service enumeration for user {marked_username} has been cancelled."
                        )

