    def _extract_acl_header(self, output):
        """Extracts the header section from the BloodHound ACL output."""
        if not output:
            return ""
        separator = "\n--------------------------------------------------------------------------------"
        if separator in output:
            return output.split(separator, 1)[0].strip()
        secondary_separator = "\n---"
        if secondary_separator in output:
            return output.split(secondary_separator, 1)[0].strip()
        return output.strip()

    def _format_acl_block(self, ace):
        """Formats a single ACE dictionary into a displayable string block."""
        lines = [
            "--------------------------------------------------------------------------------",
            f"Source: {ace.get('origen', 'Unknown')}",
            f"Source Type: {ace.get('tipoorigen', 'Unknown')}",
            f"Source Domain: {ace.get('dominio_origen', 'Unknown')}",
            f"Target: {ace.get('destino', 'Unknown')}",
            f"Target Type: {ace.get('tipodestino', 'Unknown')}",
            f"Target Domain: {ace.get('dominio_destino', 'Unknown')}",
            f"Relation: {ace.get('acl', 'Unknown')}",
        ]
        if "target_enabled" in ace:
            lines.append(f"Target Enabled: {ace['target_enabled']}")
        return "\n".join(lines)

    def _filter_aces_by_adcs_requirement(self, aces):
        """Filters ACEs requiring ADCS and returns tuples of (filtered, skipped)."""
        from adscan_internal.services.adcs_target_filter import (
            domain_has_adcs_for_attack_steps,
            target_requires_adcs,
        )

        filtered_aces = []
        skipped_aces = []
        for ace in aces:
            skip = False
            relation = ace.get("acl", "").lower()

            # Skip pure Enroll relations (ADCS enrollment rights), which are
            # handled separately by the dedicated ADCS enumeration logic.
            if relation == "enroll":
                try:
                    print_info_verbose(
                        "Skipping ACE with relation 'Enroll' (handled by ADCS enumeration)."
                    )
                except Exception:
                    pass
                skipped_aces.append(ace)
                continue

            target_type = ace.get("tipodestino", "").lower()
            target_name = str(ace.get("destino") or "").strip()
            target_domain = str(ace.get("dominio_destino") or "").strip()
            if target_type == "group" and target_requires_adcs(
                {
                    "name": (
                        f"{target_name}@{target_domain.upper()}"
                        if target_name and target_domain
                        else target_name
                    ),
                    "target_object_id": ace.get("target_object_id"),
                    "targetObjectId": ace.get("target_object_id"),
                },
                target_domain,
            ):
                has_adcs = domain_has_adcs_for_attack_steps(self, target_domain)
                if not has_adcs:
                    marked_target_domain = mark_sensitive(target_domain, "domain")
                    print_info_verbose(
                        f"Skipping ACE for {ace.get('destino')} in domain {marked_target_domain} because ADCS is not implemented."
                    )
                    skipped_aces.append(ace)
                    skip = True
            if skip:
                continue
            filtered_aces.append(ace)
        return filtered_aces, skipped_aces

