    def _infer_service_command_target_count(self, command: str) -> int:
        """Infer how many targets one NetExec service command will process."""

        try:
            argv = shlex.split(str(command or ""))
        except ValueError:
            return 1

        services = {
            "smb",
            "ldap",
            "mssql",
            "rdp",
            "winrm",
            "ssh",
            "vnc",
            "ftp",
            "http",
            "https",
        }
        service_index = next(
            (idx for idx, token in enumerate(argv) if token in services),
            None,
        )
        if service_index is None or service_index + 1 >= len(argv):
            return 1

        target_value = str(argv[service_index + 1]).strip()
        if not target_value:
            return 1
        target_path = Path(_expand_effective_user_path(target_value))
        if not target_path.is_file():
            return 1

        try:
            with target_path.open("r", encoding="utf-8", errors="replace") as handle:
                count = sum(1 for line in handle if line.strip())
        except OSError:
            return 1
        return max(count, 1)

    def _infer_service_command_targets(self, command: str) -> list[str]:
        """Infer concrete targets one NetExec service command will probe."""

        try:
            argv = shlex.split(str(command or ""))
        except ValueError:
            return []

        services = {
            "smb",
            "ldap",
            "mssql",
            "rdp",
            "winrm",
            "ssh",
            "vnc",
            "ftp",
            "http",
            "https",
        }
        service_index = next(
            (idx for idx, token in enumerate(argv) if token in services),
            None,
        )
        if service_index is None or service_index + 1 >= len(argv):
            return []

        target_value = str(argv[service_index + 1]).strip()
        if not target_value:
            return []
        target_path = Path(_expand_effective_user_path(target_value))
        if not target_path.is_file():
            return [target_value]

        try:
            with target_path.open("r", encoding="utf-8", errors="replace") as handle:
                return [line.strip() for line in handle if line.strip()]
        except OSError:
            return [target_value]

    def _ensure_service_command_netexec_timeout(
        self,
        *,
        command: str,
        service: str,
    ) -> str:
        """Raise internal NetExec per-target timeout for slower service protocols."""

        normalized_service = str(service or "").strip().lower()
        desired_timeout = get_recommended_internal_timeout(
            normalized_service,
            default=30,
        )
        if desired_timeout <= 30:
            return command

        timeout_pattern = re.compile(r"(?:(^|\s)--timeout\s+)(\d+)\b")
        match = timeout_pattern.search(command)
        if match:
            current_timeout = int(match.group(2))
            if current_timeout >= desired_timeout:
                return command
            updated = timeout_pattern.sub(
                lambda m: f"{m.group(1)}--timeout {desired_timeout}",
                command,
                count=1,
            )
            print_info_debug(
                "[service-access] Raised internal NetExec timeout for "
                f"service={normalized_service}: {current_timeout}s -> {desired_timeout}s"
            )
            return updated

        updated = f"{command} --timeout {desired_timeout}"
        print_info_debug(
            "[service-access] Added internal NetExec timeout for "
            f"service={normalized_service}: {desired_timeout}s"
        )
        return updated

    def run_service_command(
        self,
        command,
        domain,
        service,
        username,
        password,
        return_boolean=False,
        prompt=True,
        workflow_intent=None,
    ):
        from adscan_internal.rich_output import mark_sensitive

        max_retries = 3
        found_privileged_hosts = False
        command = self._ensure_service_command_netexec_timeout(
            command=command,
            service=service,
        )
        target_count = self._infer_service_command_target_count(command)
        target_entries = self._infer_service_command_targets(command)
        timeout_seconds: int | None = resolve_service_command_timeout_seconds(
            service=service, target_count=target_count, return_boolean=return_boolean
        )
        print_info_debug(
            "[service-access] timeout policy: "
            f"service={service} target_count={target_count} "
            f"global_timeout={timeout_seconds if timeout_seconds is not None else 'disabled'}"
        )

        # Modify the command for RDP outside of execute_command
        # if service == "rdp":
        #     marked_username = mark_sensitive(username, "user")
        #     marked_password = mark_sensitive(password, "password")
        #     marked_domain = mark_sensitive(domain, "domain")
        #     marked_domain = mark_sensitive(domain, "domain")
        #     marked_username = mark_sensitive(username, "user")
        #     command = f"{self.netexec_path} smb enabled_computers_ips.txt -u '{marked_username}' -p '{marked_password}' -d {marked_domain} -t 16 --timeout 15 --log domains/{marked_domain}/{service}/{marked_username}_privs.log -M rdplogin"

        def execute_command():
            from adscan_internal.rich_output import mark_sensitive

            try:
                completed_process = self.run_command(command, timeout=timeout_seconds)

                # Process finished within timeout or was terminated by the timeout mechanism of subprocess.run
                # Check return code. If the process was terminated by a signal, returncode will be -SIGNAL_NUMBER.
                if (
                    completed_process.returncode != 0
                    and completed_process.returncode != -signal.SIGTERM
                ):
                    # Special handling for netexec returning 1 but providing output for certain modules
                    if (
                        service in ["smb", "winrm", "ssh", "ftp", "ldap"]
                        and completed_process.returncode == 1
                        and completed_process.stdout
                    ):
                        marked_username = mark_sensitive(username, "user")
                        print_warning(
                            f"Command for {service} for user {marked_username} finished with return code 1 but produced output. This might be acceptable. Output: {completed_process.stdout[:200]}... Error: {completed_process.stderr}"
                        )
                    else:
                        # Raise CalledProcessError to be caught by the outer retry loop
                        raise subprocess.CalledProcessError(
                            completed_process.returncode,
                            command,
                            output=completed_process.stdout,
                            stderr=completed_process.stderr,
                        )
                return completed_process.stdout

            except subprocess.TimeoutExpired as e:
                telemetry.capture_exception(e)
                # Timeout occurred as per subprocess.run's own mechanism

                print_error(
                    f"Timeout reached for service {service} with command '{e.cmd}'. Captured stdout: '{e.stdout}'. Captured stderr: '{e.stderr}'."
                )
                # subprocess.run with preexec_fn=os.setsid and timeout should have killed the process group.
                # Re-raise for the outer loop to handle retries.
                raise
            # Other exceptions (like a manually raised CalledProcessError or unexpected errors)
            # will propagate to the outer try-except block in the retry loop.

        for attempt in range(max_retries):
            try:
                output = execute_command()
                if output:  # Only process if there is output
                    privileged_hosts = []
                    confirmed_findings: list[ServiceAccessFinding] = []

                    for line in output.splitlines():
                        mssql_authenticated = (
                            service == "mssql"
                            and "[+]" in line
                            and "\\" in line
                            and ":" in line
                            and "(name:" not in line
                        )
                        privileged_indicator = (
                            "RDP Access Granted" in line or "(Pwn3d!)" in line
                        )
                        if privileged_indicator or mssql_authenticated:
                            match_ip = re.search(r"(\d+\.\d+\.\d+\.\d+)", line)
                            match_hostname = re.search(
                                r"^\S+\s+\S+\s+\S+\s+(\S+)", line
                            )
                            if match_ip and match_hostname:
                                host = match_ip.group(0)
                                privileged_hosts.append(host)
                                confirmed_findings.append(
                                    ServiceAccessFinding(
                                        service=service,
                                        host=host,
                                        username=username,
                                        category="confirmed",
                                        reason=(
                                            "authenticated_access"
                                            if mssql_authenticated
                                            and not privileged_indicator
                                            else "confirmed"
                                        ),
                                        status=line.strip(),
                                        backend="netexec",
                                    )
                                )
                                found_privileged_hosts = True
                                if return_boolean:
                                    return True
                                marked_username = mark_sensitive(username, "user")

                                marked_host = mark_sensitive(host, "hostname")
                                print_warning(
                                    f"User {marked_username} has confirmed {service} access on host {marked_host}"
                                )
                                try:
                                    from adscan_internal.services.attack_graph_service import (
                                        upsert_netexec_privilege_edge,
                                    )

                                    if service == "mssql":
                                        relation = (
                                            "SQLAdmin"
                                            if "(Pwn3d!)" in line
                                            else "SQLAccess"
                                        )
                                    else:
                                        relation_map = {
                                            "smb": "AdminTo",
                                            "rdp": "CanRDP",
                                            "winrm": "CanPSRemote",
                                        }
                                        relation = relation_map.get(service)
                                    if relation:
                                        hostname_hint = (
                                            match_hostname.group(1)
                                            if match_hostname
                                            else None
                                        )
                                        upsert_netexec_privilege_edge(
                                            self,
                                            domain,
                                            username=username,
                                            relation=relation,
                                            target_ip=host,
                                            target_hostname=hostname_hint,
                                        )
                                except Exception as exc:  # noqa: BLE001
                                    telemetry.capture_exception(exc)

                    if confirmed_findings:
                        render_service_access_results(
                            service=service,
                            username=username,
                            findings=confirmed_findings,
                            total_targets=target_count,
                        )
                        try:
                            record_service_access_probe_batch(
                                workspace_dir=(
                                    self._get_workspace_cwd()
                                    if hasattr(self, "_get_workspace_cwd")
                                    else getattr(
                                        self, "current_workspace_dir", os.getcwd()
                                    )
                                ),
                                domains_dir=getattr(self, "domains_dir", "domains"),
                                domain=domain,
                                username=username,
                                service=service,
                                targets=target_entries,
                                confirmed_hosts=[
                                    finding.host for finding in confirmed_findings
                                ],
                                source="run_service_command",
                                backend="netexec",
                                pivot_capable=is_service_pivot_capable(service),
                            )
                        except Exception as exc:  # noqa: BLE001
                            telemetry.capture_exception(exc)
                            print_info_debug(
                                f"[service-access] failed to persist probe history: {exc}"
                            )
                        if prompt:
                            selected_followups, used_selector = (
                                select_confirmed_service_access_followup_targets(
                                    self,
                                    service=service,
                                    findings=confirmed_findings,
                                )
                            )
                            if used_selector:
                                func = getattr(self, f"ask_for_{service}_access")
                                if service == "smb":
                                    selected_hosts = [
                                        finding.host for finding in selected_followups
                                    ]
                                    marked_username = mark_sensitive(username, "user")
                                    marked_hosts = [
                                        mark_sensitive(host, "hostname")
                                        for host in selected_hosts
                                    ]
                                    print_info_debug(
                                        "[service-access] launching batch SMB follow-up: "
                                        f"service={service} user={marked_username} hosts={marked_hosts}"
                                    )
                                    func(
                                        domain,
                                        selected_hosts,
                                        username,
                                        password,
                                    )
                                else:
                                    for finding in selected_followups:
                                        marked_username = mark_sensitive(
                                            finding.username, "user"
                                        )
                                        marked_host = mark_sensitive(
                                            finding.host, "hostname"
                                        )
                                        print_info_debug(
                                            "[service-access] launching selected service follow-up: "
                                            f"service={service} user={marked_username} host={marked_host}"
                                        )
                                        func(
                                            domain,
                                            finding.host,
                                            finding.username,
                                            password,
                                            **(
                                                {"workflow_intent": workflow_intent}
                                                if service == "winrm"
                                                and workflow_intent
                                                else {}
                                            ),
                                        )
                            else:
                                func = getattr(self, f"ask_for_{service}_access")
                                for finding in confirmed_findings:
                                    marked_username = mark_sensitive(
                                        finding.username, "user"
                                    )
                                    marked_host = mark_sensitive(
                                        finding.host, "hostname"
                                    )
                                    print_info_debug(
                                        "[service-access] launching service follow-up prompt: "
                                        f"service={service} user={marked_username} host={marked_host}"
                                    )
                                    func(
                                        domain,
                                        finding.host,
                                        finding.username,
                                        password,
                                        **(
                                            {"workflow_intent": workflow_intent}
                                            if service == "winrm" and workflow_intent
                                            else {}
                                        ),
                                    )
                        else:
                            for finding in confirmed_findings:
                                marked_username = mark_sensitive(
                                    finding.username, "user"
                                )
                                marked_host = mark_sensitive(finding.host, "hostname")
                                print_info_debug(
                                    "[service-access] service follow-up prompt suppressed: "
                                    f"service={service} user={marked_username} host={marked_host}"
                                )

                    if not privileged_hosts:
                        render_no_confirmed_service_access(
                            service=service,
                            username=username,
                            total_targets=target_count,
                        )
                        try:
                            record_service_access_probe_batch(
                                workspace_dir=(
                                    self._get_workspace_cwd()
                                    if hasattr(self, "_get_workspace_cwd")
                                    else getattr(
                                        self, "current_workspace_dir", os.getcwd()
                                    )
                                ),
                                domains_dir=getattr(self, "domains_dir", "domains"),
                                domain=domain,
                                username=username,
                                service=service,
                                targets=target_entries,
                                confirmed_hosts=[],
                                source="run_service_command",
                                backend="netexec",
                                pivot_capable=is_service_pivot_capable(service),
                            )
                        except Exception as exc:  # noqa: BLE001
                            telemetry.capture_exception(exc)
                            print_info_debug(
                                f"[service-access] failed to persist probe history: {exc}"
                            )
                        if return_boolean:
                            return False
                    return found_privileged_hosts

            except subprocess.TimeoutExpired as e:
                telemetry.capture_exception(e)

                print_error(
                    f"Timeout during attempt {attempt + 1} of {max_retries} for service {service}"
                )
                if attempt < max_retries - 1:
                    print_info("Retrying in 5 seconds...")
                    time.sleep(5)
                else:
                    print_error(f"Attempts exhausted for service {service}")
                    if return_boolean:
                        return False
                    return found_privileged_hosts

            except subprocess.CalledProcessError as e:
                telemetry.capture_exception(e)
                if "[ADSCAN] NETEXEC_COMMAND_TIMEOUT" in str(e.stderr or ""):
                    marked_service = mark_sensitive(service, "text")
                    print_warning(
                        f"NetExec {marked_service} enumeration ended due to timeout recovery being declined or exhausted."
                    )
                    if return_boolean:
                        return False
                    return found_privileged_hosts
                print_error(f"Error executing {service} enumeration: {e.stderr}")
                return found_privileged_hosts

            except Exception as e:
                telemetry.capture_exception(e)

                print_error(f"Unexpected error during {service} enumeration.")
                print_exception(
                    show_locals=False,
                    exception=e,
                    context={
                        "service": mark_sensitive(service, "service"),
                        "domain": mark_sensitive(domain, "domain"),
                        "username": mark_sensitive(username, "user"),
                    },
                )
                return found_privileged_hosts

        return found_privileged_hosts

