    def do_paths_inspect(self, args):
        """Inspect one attack path and list its applicable post-exploitation techniques.

        Phase 5 surface for the post-exploitation catalog. Renders the path
        summary, the catalog techniques applicable to its foothold (ranked by
        likelihood-of-domain-compromise minus a detection penalty), and a
        per-technique plan with MITRE IDs. Execution from this menu is Phase 6.

        Usage:
            paths_inspect <domain> <index>          # 1-based index in the attack_paths table
            paths_inspect <index>                   # uses the active workspace domain

        Examples:
            paths_inspect north.sevenkingdoms.local 1
            paths_inspect 1
        """
        from adscan_internal.cli.attack_graph_reports import (
            _resolve_attack_paths_compute_cap,  # noqa: PLC0415
        )
        from adscan_internal.cli.post_ex_inspect import render_paths_inspect  # noqa: PLC0415
        from adscan_core import telemetry  # noqa: PLC0415
        from adscan_internal.services.attack_graph_service import (  # noqa: PLC0415
            ATTACK_PATHS_MAX_DEPTH_USER,
            get_attack_path_summaries,
        )

        parts = (args or "").split()
        if not parts:
            print_instruction("Usage: paths_inspect <domain> <index>  |  paths_inspect <index>")
            return

        domain: str
        index_str: str
        if len(parts) == 1:
            domain = self.domain or ""
            index_str = parts[0]
        else:
            domain = parts[0]
            index_str = parts[1]

        if not domain:
            print_instruction("Usage: paths_inspect <domain> <index>  (no active domain)")
            return

        try:
            index = int(index_str)
        except ValueError:
            print_instruction(f"Index must be an integer, got: {index_str!r}")
            return

        if domain not in self.domains:
            print_error(
                f"Domain '{mark_sensitive(domain, 'domain')}' is not configured."
            )
            return

        try:
            paths = get_attack_path_summaries(
                self,
                domain,
                scope="domain",
                max_depth=ATTACK_PATHS_MAX_DEPTH_USER,
                max_paths=_resolve_attack_paths_compute_cap(50),
                target="highvalue",
                target_mode="tier0",
                no_cache=False,
            )
        except Exception as exc:  # noqa: BLE001 — telemetry sink
            telemetry.capture_exception(exc)
            print_error(f"Failed to load attack paths: {exc}")
            return

        from pathlib import Path as _Path  # noqa: PLC0415
        ws_dir = getattr(self, 'current_workspace_dir', None)
        ws_path = _Path(ws_dir) if ws_dir else None
        render_paths_inspect(
            console=self.console,
            domain=domain,
            paths=list(paths or []),
            index=index,
            workspace_path=ws_path,
        )

    def do_paths_execute(self, args):
        """Execute one post-exploitation technique against an attack path.

        Sister command to ``paths_inspect``. ``paths_inspect`` is read-only;
        ``paths_execute`` is the explicit mutate. The orchestrator resolves
        the foothold credential from the workspace, runs the technique,
        inserts any derived edges into ``attack_graph.json``, persists the
        execution record on the per-domain sidecar, and prints a summary.

        Usage:
            paths_execute <domain> <path-index> <technique-index>
            paths_execute <path-index> <technique-index>     (uses active workspace domain)

        Example:
            paths_execute north.sevenkingdoms.local 1 2
        """
        import asyncio  # noqa: PLC0415
        from adscan_core import telemetry  # noqa: PLC0415
        from adscan_internal.cli.attack_graph_reports import (  # noqa: PLC0415
            _resolve_attack_paths_compute_cap,
        )
        from adscan_internal.cli.post_ex_execute import render_paths_execute  # noqa: PLC0415
        from adscan_internal.services.attack_graph_service import (  # noqa: PLC0415
            ATTACK_PATHS_MAX_DEPTH_USER,
            get_attack_path_summaries,
        )

        parts = (args or "").split()
        if len(parts) not in (2, 3):
            print_instruction(
                "Usage: paths_execute <domain> <path-index> <technique-index>"
            )
            return

        if len(parts) == 2:
            domain = self.domain or ""
            path_index_str, technique_index_str = parts
        else:
            domain, path_index_str, technique_index_str = parts

        if not domain:
            print_instruction(
                "Usage: paths_execute <domain> <path-index> <technique-index> "
                "(no active domain)"
            )
            return

        try:
            path_index = int(path_index_str)
            technique_index = int(technique_index_str)
        except ValueError:
            print_instruction(
                "path-index and technique-index must be integers"
            )
            return

        if domain not in self.domains:
            print_error(
                f"Domain '{mark_sensitive(domain, 'domain')}' is not configured."
            )
            return

        try:
            paths = get_attack_path_summaries(
                self,
                domain,
                scope="domain",
                max_depth=ATTACK_PATHS_MAX_DEPTH_USER,
                max_paths=_resolve_attack_paths_compute_cap(50),
                target="highvalue",
                target_mode="tier0",
                no_cache=False,
            )
        except Exception as exc:  # noqa: BLE001 — telemetry sink
            telemetry.capture_exception(exc)
            print_error(f"Failed to load attack paths: {exc}")
            return

        try:
            asyncio.run(
                render_paths_execute(
                    shell=self,
                    console=self.console,
                    domain=domain,
                    paths=list(paths or []),
                    path_index=path_index,
                    technique_index=technique_index,
                )
            )
        except Exception as exc:  # noqa: BLE001 — telemetry sink
            telemetry.capture_exception(exc)
            print_error(f"paths_execute failed: {exc}")

    def do_attack_path_discovery(self, args):
        """Build and display attack paths from the local attack graph."""
        from adscan_internal.cli.intelligence import run_attack_path_discovery

        parts = args.split()
        domain = parts[0] if parts else (self.domain or "")
        if not domain:
            print_instruction("Usage: attack_path_discovery <domain> [max_depth]")
            return

        # Depth budget counts only actionable edges. Structural relations
        # (MemberOf, Contains, GpLink, TrustedBy, HasSIDHistory) flow freely
        # — see ``_count_actionable_edges`` in attack_graph_core. So 6 here
        # means up to 6 attack actions. 4 was the historical default but it
        # truncated real GOAD-class kill chains (ASREPRoast → GenericAll →
        # GenericAll → GenericWrite → ReadLAPSPassword → DumpLSA needs 5-6
        # actions); 6 matches the engine's existing per-scope safety cap
        # (``_effective_max_depth``: user+all → 6) so it adds no risk of
        # path explosion beyond what the cap already permits.
        max_depth = 6
        if len(parts) >= 2:
            try:
                max_depth = int(parts[1])
            except ValueError:
                print_instruction("Usage: attack_path_discovery <domain> [max_depth]")
                return

        run_attack_path_discovery(self, domain, max_depth=max_depth)

    def do_attack_paths(self, args):
        """List attack paths computed from the domain attack graph.

        This command reads `domains/<domain>/attack_graph.json`, computes maximal
        paths, and displays a table of the shortest paths. By default, it only
        shows paths whose terminal node is a high-value target, based on
        BloodHound `highvalue` plus Tier-0 / privileged-group heuristics. Use
        `--tier0-only` to restrict results to Tier-0 targets only. Use `--all`
        to include every path regardless of the target. Use `--lowpriv` to show
        only paths to non-high-value targets (pivot opportunities, lateral movement).

        Usage:
            attack_paths <domain>   [--max N] [--depth N] [--path-steps N] [--all] [--lowpriv]

        Args:
            domain: Target domain (e.g. `north.sevenkingdoms.local`)
            user: Optional start node label to compute paths from (e.g. `jon.snow`).
                Pass multiple usernames to compute paths for all of them (principals scope).
                Special value `owned` computes paths for all domain users with
                stored domain credentials in `domains_data["credentials"]`.
            index: Optional path index to display details directly (1-based)

        Flags:
            --max N: Max number of paths shown in the summary (default: 20)
            --depth N: Max path length to compute (default: 10)
            --path-steps N: Max number of steps shown inline per path in the summary table (default: unlimited)
            --tier0-only: Restrict paths to Tier-0 targets only
            --all: Include paths whose target is not high value
            --lowpriv: Show only paths to non-high-value targets (pivot/lateral-movement opportunities)

        Examples:
            attack_paths north.sevenkingdoms.local
            attack_paths north.sevenkingdoms.local --tier0-only
            attack_paths north.sevenkingdoms.local --all
            attack_paths north.sevenkingdoms.local --lowpriv
            attack_paths north.sevenkingdoms.local --max 20 --depth 6
            attack_paths north.sevenkingdoms.local --path-steps 2
            attack_paths north.sevenkingdoms.local jon.snow
            attack_paths north.sevenkingdoms.local jon.snow 1
            attack_paths north.sevenkingdoms.local jon.snow arya.stark
            attack_paths north.sevenkingdoms.local owned
            attack_paths north.sevenkingdoms.local 2
        """
        from adscan_internal.cli.attack_graph_reports import run_show_attack_paths
        from adscan_internal.services.attack_graph_service import (
            ATTACK_PATHS_MAX_DEPTH_USER,
        )

        parts = args.split()
        domain = parts[0] if parts else (self.domain or "")
        if not domain:
            print_instruction(
                "Usage: attack_paths <domain> [user|owned|user1 user2 ...] [index] [--max N] [--depth N] "
                "[--path-steps N] [--tier0-only] [--all] [--lowpriv] [--no-cache]"
            )
            return

        index: int | None = None
        start_user: str | None = None
        max_display = 20
        max_depth = ATTACK_PATHS_MAX_DEPTH_USER
        max_path_steps: int | None = None
        include_all = False
        lowpriv = False
        target_mode = "object"
        no_cache = False

        # Parse flags first: --max N, --depth N (and remove them from positional parsing).
        positionals: list[str] = []
        i = 0
        while i < len(parts):
            token = parts[i]
            if token == "--all":
                include_all = True
                i += 1
                continue
            if token in {"--lowpriv", "--low-priv", "--non-highvalue"}:
                include_all = False
                lowpriv = True
                i += 1
                continue
            if token in {"--tier0-only", "--tierzero-only", "--tier0"}:
                target_mode = "tier0"
                i += 1
                continue
            if token in {"--impact", "--highvalue"}:
                # Backward-compatible alias for the current default.
                i += 1
                continue
            if token == "--max" and i + 1 < len(parts):
                try:
                    max_display = int(parts[i + 1])
                except ValueError:
                    pass
                i += 2
                continue
            if token.startswith("--max="):
                try:
                    max_display = int(token.split("=", 1)[1])
                except ValueError:
                    pass
                i += 1
                continue
            if token == "--depth" and i + 1 < len(parts):
                try:
                    max_depth = int(parts[i + 1])
                except ValueError:
                    pass
                i += 2
                continue
            if token.startswith("--depth="):
                try:
                    max_depth = int(token.split("=", 1)[1])
                except ValueError:
                    pass
                i += 1
                continue
            if token == "--path-steps" and i + 1 < len(parts):
                try:
                    max_path_steps = int(parts[i + 1])
                except ValueError:
                    max_path_steps = None
                i += 2
                continue
            if token.startswith("--path-steps="):
                try:
                    max_path_steps = int(token.split("=", 1)[1])
                except ValueError:
                    max_path_steps = None
                i += 1
                continue
            if token == "--no-cache":
                no_cache = True
                i += 1
                continue
            positionals.append(token)
            i += 1

        # Positional args after domain: [user|owned|user1 user2 ...] [index]
        # Rules:
        #   - Single non-digit, non-"owned" token  → user scope
        #   - Multiple non-digit tokens            → principals scope (multi-user)
        #   - "owned" token                        → owned scope
        #   - Trailing digit token                 → path index
        start_users: list[str] = []
        if len(positionals) >= 2:
            # Collect all non-digit positionals after domain as user tokens,
            # then look for an optional trailing numeric index.
            remaining = positionals[1:]
            if remaining and remaining[-1].isdigit():
                index = int(remaining[-1])
                remaining = remaining[:-1]
            for token in remaining:
                if token.isdigit():
                    # Unexpected second digit — treat as index (legacy compat)
                    index = int(token)
                else:
                    start_users.append(token)

        if len(start_users) == 1:
            start_user = start_users[0]
        elif len(start_users) > 1:
            start_user = None  # principals scope handled via start_users

        attack_target = "lowpriv" if lowpriv else "all" if include_all else "highvalue"
        run_show_attack_paths(
            self,
            domain,
            start_user=start_user,
            start_users=start_users if len(start_users) > 1 else None,
            index=index,
            max_display=max_display,
            max_depth=max_depth,
            max_path_steps=max_path_steps,
            target=attack_target,
            target_mode=target_mode,
            allow_execution=True,
            no_cache=no_cache,
        )

    def do_attack_steps(self, args):
        """List attack graph steps (edges) recorded for a domain.

        This command displays the raw edges stored in `domains/<domain>/attack_graph.json`
        (one row per step). It is a diagnostic/transparency view that helps you
        understand why specific attack paths exist.

        Usage:
            attack_steps <domain> [user] [--max N] [--relation REL]

        Args:
            domain: Target domain (e.g. `north.sevenkingdoms.local`)
            user: Optional source node label to filter by (e.g. `jon.snow`)

        Flags:
            --max N: Max number of rows shown in the table (default: 10)
            --relation REL: Filter by relation (e.g. AdminTo, GenericWrite). Supports
                comma-separated values.

        Examples:
            attack_steps north.sevenkingdoms.local
            attack_steps north.sevenkingdoms.local --max 50
            attack_steps north.sevenkingdoms.local jon.snow
            attack_steps north.sevenkingdoms.local --relation AdminTo
            attack_steps north.sevenkingdoms.local --relation LocalCredToDomainReuse
            attack_steps north.sevenkingdoms.local jon.snow --relation AllowedToDelegate
        """
        from adscan_internal.cli.attack_graph_reports import run_show_attack_steps

        parts = args.split()
        domain = parts[0] if parts else (self.domain or "")
        if not domain:
            print_instruction(
                "Usage: attack_steps <domain> [user] [--max N] [--relation REL]"
            )
            return

        start_user: str | None = None
        max_display = 10
        relation_filter: str | None = None

        positionals: list[str] = []
        i = 0
        while i < len(parts):
            token = parts[i]
            if token == "--max" and i + 1 < len(parts):
                try:
                    max_display = int(parts[i + 1])
                except ValueError:
                    pass
                i += 2
                continue
            if token.startswith("--max="):
                try:
                    max_display = int(token.split("=", 1)[1])
                except ValueError:
                    pass
                i += 1
                continue
            if token in {"--relation", "--rel"} and i + 1 < len(parts):
                relation_filter = parts[i + 1]
                i += 2
                continue
            if token.startswith("--relation=") or token.startswith("--rel="):
                relation_filter = token.split("=", 1)[1]
                i += 1
                continue
            positionals.append(token)
            i += 1

        # Positional args: domain [user]
        if len(positionals) >= 2:
            start_user = positionals[1]

        run_show_attack_steps(
            self,
            domain,
            start_user=start_user,
            max_display=max_display,
            relation_filter=relation_filter,
        )

