    def execute_kerberos_enum_users(self, command, domain, initial_count, users_file):
        """Legacy function for executing Kerberos enumeration.

        Note: This function appears to be legacy/unused. The modern approach uses
        run_kerberos_enum_users from adscan_internal.cli.ldap which delegates to
        EnumerationService.kerberos.enumerate_users_kerberos.

        If this function is still needed, it should be refactored to use the service layer.
        """
        from adscan_internal.rich_output import mark_sensitive

        try:
            if not self.do_sync_clock_with_pdc(domain, verbose=True):
                return

            completed_process = self.run_command(command, timeout=300)

            # Check if command execution failed
            if completed_process is None:
                marked_domain = mark_sensitive(domain, "domain")
                print_error(
                    f"Failed to execute Kerberos user enumeration command for domain {marked_domain}"
                )
                print_error(
                    "This might be due to missing dependencies, timeout, or permission issues"
                )
                return

            if completed_process.returncode == 0:
                # Count new users found
                if os.path.exists(users_file):
                    with open(users_file, "r", encoding="utf-8") as f:
                        final_count = sum(1 for line in f)
                    new_users = final_count - initial_count
                    # Display new Kerberos users or count
                    with open(users_file) as f:
                        all_users = [line.strip() for line in f if line.strip()]
                    new_list = all_users[initial_count:]
                    self._display_items(new_list, "Users")

                    if new_users > 0:
                        self.ask_for_kerberos_user_enum(domain, relaunch=True)
                        self.do_enum_with_users(domain)
                else:
                    print_error("Could not find the users file after enumeration")
            else:
                marked_domain = mark_sensitive(domain, "domain")
                print_error(
                    f"Error enumerating users for domain {marked_domain} via Kerberos"
                )
                if completed_process.stderr:
                    print_error(completed_process.stderr.strip())
        except Exception as e:
            telemetry.capture_exception(e)
            print_error("Error executing kerbrute.")
            print_exception(show_locals=False, exception=e)

