    def monitor_smb(self, proc, domain):
        while True:
            line = proc.stdout.readline().decode("utf-8")
            if not line:
                break
            elif "successfully" in line:
                # Define the directory and file where the hash will be saved
                output_directory = os.path.join(os.getcwd(), "cracking")
                output_file = os.path.join(output_directory, "hashes.NTLMv2")
                # Attempt to read the next line to extract the hash
                hash_line = proc.stdout.readline().decode("utf-8").strip()

                # Clean the hash by removing any markers like '[*]' or others
                if "[*]" in hash_line:
                    hash_ntlmv2 = hash_line.replace("[*]", "").strip()
                else:
                    hash_ntlmv2 = (
                        hash_line  # Leave it as is if it doesn't contain '[*]'
                    )

                # Display the extracted hash
                print_warning(f"NTLMv2 hash captured: {hash_ntlmv2}")
                # Save the hash to the file
                with open(output_file, "a", encoding="utf-8") as f:
                    f.write(
                        f"{hash_ntlmv2}\n"
                    )  # Write the hash to the file (append a new line)

                # Call the function to close the SMB process
                self.close_smb(proc)

                self.ask_for_cracking("NTLMv2", domain, hash_ntlmv2)
                break  # End the loop once the hash is found and processed
            else:
                # Uncomment the following line to see other output for debugging if needed
                # print(line.strip())
                continue

    def close_smb(self, proc):
        """Closes the SMB process and cleans up associated resources after a delay."""
        try:
            # Search and kill any remaining process on port 445
            pid_command = 'lsof -i:445 | awk "{print \\$2}" | grep -v PID'
            completed_pid_process = self.run_command(pid_command, timeout=300)
            pid = None
            if (
                completed_pid_process.returncode == 0
                and completed_pid_process.stdout.strip()
            ):
                # Get the first line of output, which should be the PID
                pid_lines = completed_pid_process.stdout.strip().splitlines()
                if pid_lines:
                    pid = pid_lines[0].strip()
            elif completed_pid_process.returncode != 0:
                print_error(
                    f"Error finding PID on port 445: {completed_pid_process.stderr.strip()}"
                )

            if pid:
                pid = pid.strip()  # Ensure no leading/trailing whitespace from readline
                print_info_verbose(f"The PID of the smbserver process is {pid}.")
                stop_command = f"kill {pid}"
                print_info_verbose("Closing the process completely")
                kill_process_result = self.run_command(stop_command, timeout=300)
                if kill_process_result.returncode != 0:
                    print_error(
                        f"Error killing process {pid}: {kill_process_result.stderr.strip()}"
                    )

        except Exception as e:
            telemetry.capture_exception(e)
            print_error("Error closing the SMB process.")
            print_exception(show_locals=False, exception=e)

