    def do_check_dns(self, domain, ip=None):
        """Check DNS resolution for a domain and optionally auto-configure if needed.

        This is a thin wrapper around :func:`check_dns` in
        ``adscan_internal.cli.dns``.
        """
        from adscan_internal.cli.dns import check_dns

        return check_dns(self, domain, ip)

    def dns_find_dcs(self, domain, pdc_ip=None):
        """Discover all domain controllers for a domain.

        This is a thin wrapper around DNSDiscoveryService.discover_domain_controllers.
        """
        from adscan_internal.rich_output import mark_sensitive, print_info_verbose
        from adscan_internal.workspaces import domain_subpath
        from adscan_internal.cli.dns import (
            is_domain_best_effort_mode,
            resolve_pdc_hostname_best_effort,
        )

        normalized_domain = (domain or "").strip().rstrip(".")
        if not normalized_domain:
            return

        marked_domain = mark_sensitive(normalized_domain, "domain")

        domains_data_pdc = None
        domain_info = {}
        try:
            if self.domains_data and domain in self.domains_data:
                domain_info = self.domains_data[domain]
                domains_data_pdc = domain_info.get("pdc")
        except Exception:
            domains_data_pdc = None
            domain_info = {}

        if is_domain_best_effort_mode(self, normalized_domain):
            fallback_pdc_ip = pdc_ip or domains_data_pdc or getattr(self, "pdc", None)
            if not fallback_pdc_ip:
                print_warning_debug(
                    f"[dns_find_dcs] Best-effort domain {marked_domain} has no PDC IP; aborting DC discovery"
                )
                return

            hostname_hint = domain_info.get("pdc_hostname")
            best_effort_hostname = resolve_pdc_hostname_best_effort(
                self,
                domain=normalized_domain,
                pdc_ip=fallback_pdc_ip,
                hostname_hint=hostname_hint,
            )
            self.dcs = [fallback_pdc_ip]
            self.pdc = fallback_pdc_ip
            self.pdc_hostname = best_effort_hostname

            if self.domains_data is None:
                self.domains_data = CaseInsensitiveDict()
            if domain not in self.domains_data:
                self.domains_data[domain] = {}
            self.domains_data[domain]["dcs"] = [fallback_pdc_ip]
            self.domains_data[domain]["pdc"] = fallback_pdc_ip
            if best_effort_hostname:
                self.domains_data[domain]["pdc_hostname"] = best_effort_hostname
                self.domains_data[domain]["dcs_hostnames"] = [
                    best_effort_hostname.lower()
                ]
            else:
                self.domains_data[domain]["dcs_hostnames"] = []

            workspace_cwd = self.current_workspace_dir or os.getcwd()
            domain_path = domain_subpath(workspace_cwd, self.domains_dir, domain)
            dcs_path = (
                domain_subpath(workspace_cwd, self.domains_dir, domain, "dcs.txt")
                if os.path.exists(domain_path)
                else "dcs.txt"
            )
            with open(dcs_path, "w", encoding="utf-8") as f:
                f.write(f"{fallback_pdc_ip}\n")

            marked_pdc = mark_sensitive(fallback_pdc_ip, "ip")
            marked_hostname = (
                mark_sensitive(best_effort_hostname, "hostname")
                if best_effort_hostname
                else None
            )
            print_info_verbose(
                f"Best-effort DC context for {marked_domain}: "
                f"{marked_pdc}"
                + (
                    f" with hostname {marked_hostname}"
                    if marked_hostname
                    else " (hostname unresolved)"
                )
            )
            try:
                self.add_to_hosts(domain)
            except Exception:
                pass

            try:
                from adscan_internal.cli.start import (  # noqa: PLC0415
                    _maybe_upgrade_inference_from_pdc,
                )

                _maybe_upgrade_inference_from_pdc(self, domain)
            except Exception:  # noqa: BLE001
                pass
            return

        # First check if DNS resolution is working
        if not self.do_check_dns(domain, pdc_ip):
            print_warning_debug(
                f"[dns_find_dcs] DNS check failed for domain {marked_domain}, aborting DC discovery"
            )
            return

        preferred_ips = [pdc_ip, domains_data_pdc, getattr(self, "pdc", None)]
        preferred_ips = [ip for ip in preferred_ips if ip]

        service = self._get_dns_discovery_service()
        dc_ips, dc_hostnames, dc_ip_to_hostname = service.discover_domain_controllers(
            domain=normalized_domain,
            pdc_ip=pdc_ip,
            preferred_ips=preferred_ips if preferred_ips else None,
        )

        self.dcs = dc_ips

        # Save the DC IPs in a file named dcs.txt
        workspace_cwd = self.current_workspace_dir or os.getcwd()
        domain_path = domain_subpath(workspace_cwd, self.domains_dir, domain)
        if os.path.exists(domain_path):
            dcs_path = domain_subpath(
                workspace_cwd, self.domains_dir, domain, "dcs.txt"
            )
            with open(dcs_path, "w", encoding="utf-8") as f:
                for dc_ip in self.dcs:
                    f.write(f"{dc_ip}\n")
            print_info_debug(f"[dns_find_dcs] Saved DC IPs to {dcs_path}")
        else:
            with open("dcs.txt", "w", encoding="utf-8") as f:
                for dc_ip in self.dcs:
                    f.write(f"{dc_ip}\n")
            print_info_debug(
                "[dns_find_dcs] Saved DC IPs to dcs.txt (domain path does not exist)"
            )

        # Update domains_data with the DC information
        if self.domains_data is None:
            self.domains_data = CaseInsensitiveDict()
        if domain not in self.domains_data:
            self.domains_data[domain] = {}
        self.domains_data[domain]["dcs"] = list(self.dcs)  # List of DC IPs
        self.domains_data[domain]["dcs_hostnames"] = list(
            {dc.split(".")[0].lower() for dc in dc_hostnames}
        )

        # Check if there is only one DC and also store it as the PDC
        if len(self.dcs) == 1:
            self.pdc = self.dcs[0]
            self.pdc_hostname = dc_ip_to_hostname.get(
                self.dcs[0], dc_hostnames[0]
            ).split(".")[0]
            marked_pdc_1 = mark_sensitive(self.pdc, "ip")
            marked_pdc_hostname_2 = mark_sensitive(self.pdc_hostname, "hostname")
            print_info_verbose(
                f"PDC for domain {marked_domain} found: {marked_pdc_1} with hostname: {marked_pdc_hostname_2}"
            )
            self.add_to_hosts(domain)
        elif len(self.dcs) == 0:
            print_warning_debug(
                f"[dns_find_dcs] No DCs found for domain {marked_domain} (dc_hostnames={dc_hostnames}, selected_ips={list(dc_ip_to_hostname.keys())})"
            )
            # If no DCs found but we have a pdc_ip, use it as fallback
            if pdc_ip:
                marked_pdc_ip_fallback = mark_sensitive(pdc_ip, "ip")
                print_info_debug(
                    f"[dns_find_dcs] No DCs found via SRV query, using provided PDC IP {marked_pdc_ip_fallback} as fallback"
                )
                self.dcs = [pdc_ip]
                self.pdc = pdc_ip
                # Update domains_data with the fallback DC
                if self.domains_data is None:
                    self.domains_data = CaseInsensitiveDict()
                if domain not in self.domains_data:
                    self.domains_data[domain] = {}
                self.domains_data[domain]["dcs"] = list(self.dcs)

                # Try to resolve hostname for the PDC IP
                try:
                    # Try reverse lookup
                    host_helper = getattr(self, "_host", None)
                    if host_helper is None or not hasattr(host_helper, "run_command"):
                        raise AttributeError("Host helper not available")
                    dns_service = self._get_dns_discovery_service()
                    hostname = dns_service.reverse_resolve_fqdn_robust(pdc_ip)
                    if hostname:
                        self.pdc_hostname = (
                            hostname.split(".")[0] if "." in hostname else hostname
                        )
                    else:
                        # If reverse lookup fails, try to use the domain to construct hostname
                        # This is a best-effort approach
                        self.pdc_hostname = None
                except Exception:
                    self.pdc_hostname = None
                marked_pdc = mark_sensitive(self.pdc, "ip")
                marked_pdc_hostname = (
                    mark_sensitive(self.pdc_hostname, "hostname")
                    if self.pdc_hostname
                    else None
                )
                if self.pdc_hostname:
                    print_info_verbose(
                        f"PDC for domain {marked_domain} set to: {marked_pdc} with hostname: {marked_pdc_hostname}"
                    )
                else:
                    print_info_verbose(
                        f"PDC for domain {marked_domain} set to: {marked_pdc} (hostname could not be resolved)"
                    )
                self.add_to_hosts(domain)
            else:
                print_info_verbose(f"DCs for domain {marked_domain} found: {self.dcs}")
        else:
            # If there is more than one DC, specifically search for the PDC
            print_info_verbose(f"DCs for domain {marked_domain} found: {self.dcs}")
            print_info_debug(
                f"[dns_find_dcs] Multiple DCs found ({len(self.dcs)}), searching for PDC specifically"
            )
            self.dns_find_pdc(domain)

        # Upgrade lab inference now that pdc_hostname is known.  The scan-start
        # call to _maybe_apply_domain_inference fired before DC discovery so
        # infer_from_pdc_hostname had no data to work with at that point.
        try:
            from adscan_internal.cli.start import (  # noqa: PLC0415
                _maybe_upgrade_inference_from_pdc,
            )

            _maybe_upgrade_inference_from_pdc(self, domain)
        except Exception:  # noqa: BLE001
            pass

    def update_domain_data(
        self,
        domain,
        pdc=None,
        pdc_hostname=None,
        username=None,
        password=None,
        hash_value=None,
        base_dn=None,
        domain_dir=None,
        host=None,
        netbios=None,
    ):
        # If the domain does not exist, initialize an empty dictionary
        domains_data_status = self.domains_data

        # Initialize domains_data if it's not configured
        if domains_data_status is None:
            self.domains_data = CaseInsensitiveDict()

        if domain not in self.domains_data:
            self.domains_data[domain] = {}

        # Ensure the 'auth' key exists, assigning "unauth" if not defined
        if "auth" not in self.domains_data[domain]:
            self.domains_data[domain]["auth"] = "unauth"

        # Only update attributes that are not None
        if pdc is not None:
            self.domains_data[domain]["pdc"] = pdc
        if pdc_hostname is not None:
            self.domains_data[domain]["pdc_hostname"] = pdc_hostname
        if username is not None:
            self.domains_data[domain]["username"] = username
        if password is not None:
            self.domains_data[domain]["password"] = password
        if hash_value is not None:
            self.domains_data[domain]["hash"] = hash_value
        if base_dn is not None:
            self.domains_data[domain]["base_dn"] = base_dn
        if domain_dir is not None:
            self.domains_data[domain]["dir"] = domain_dir
        if host is not None:
            self.domains_data[domain]["host"] = host
        if netbios is not None:
            self.domains_data[domain]["netbios"] = netbios

    def do_update_domain_data(self, args):
        """
        Updates the domain information in the domains list.

        Usage: update_domain_data <domain> <PDC> <PDC_hostname> <DCs> <DC_hostnames>

        Where:
            <domain> is the domain to be updated.
            <PDC> is the IP of the domain's PDC.
            <PDC_hostname> is the hostname of the domain's PDC.
            <DCs> is a string with the DCs' IPs separated by commas.
            <DC_hostnames> is a string with the DCs' hostnames separated by commas.

        If any parameter is not provided, the current value will be kept.
        """
        args = args.split()
        domain = args[0] if len(args) > 0 else None
        if not domain:
            print_error(
                "Domain is required. Usage: update_domain_data <domain> [PDC] [PDC_hostname] [DCs] [DC_hostnames]"
            )
            return

        pdc = args[1] if len(args) > 1 else None
        pdc_hostname = args[2] if len(args) > 2 else None
        # It is assumed that the fourth parameter is a string with the DCs separated by commas
        dcs = args[3] if len(args) > 3 else None
        # It is assumed that the fifth parameter is a string with the DC hostnames separated by commas
        dcs_hostnames = args[4] if len(args) > 4 else None

        try:
            from adscan_internal.services.report_service import update_domain_data

            update_domain_data(
                shell=self,
                domain=domain,
                pdc=pdc,
                pdc_hostname=pdc_hostname,
                dcs=dcs,
                dcs_hostnames=dcs_hostnames,
            )
            return
        except ImportError:
            # LITE fallback when report service is excluded.
            self.update_domain_data(
                domain=domain,
                pdc=pdc,
                pdc_hostname=pdc_hostname,
            )
            if dcs is not None:
                self.domains_data.setdefault(domain, {})["dcs"] = dcs
            if dcs_hostnames is not None:
                self.domains_data.setdefault(domain, {})["dcs_hostnames"] = (
                    dcs_hostnames
                )

    def _resolve_ipv4_addresses(
        self, fqdn: str, resolver: str | None = None, *, tcp: bool = False
    ) -> list[str]:
        return self._get_dns_discovery_service().resolve_ipv4_addresses(
            fqdn,
            resolver=resolver,
            tcp=tcp,
        )

    def dns_find_pdc(self, domain):
        """Discover PDC for a domain using DNSDiscoveryService."""
        from adscan_internal.rich_output import mark_sensitive, print_success
        from adscan_internal.cli.dns import (
            is_domain_best_effort_mode,
            resolve_pdc_hostname_best_effort,
        )

        marked_domain = mark_sensitive(domain, "domain")
        print_info_debug(
            f"[dns_find_pdc] Starting PDC discovery for domain: {marked_domain}"
        )

        # Get preferred IPs from domain data
        preferred_ips = [
            self.domains_data.get(domain, {}).get("pdc")
            if self.domains_data and domain in self.domains_data
            else None,
            getattr(self, "pdc", None),
        ]
        preferred_ips = [ip for ip in preferred_ips if ip]

        if is_domain_best_effort_mode(self, domain):
            fallback_ip = preferred_ips[0] if preferred_ips else None
            if not fallback_ip:
                print_warning_debug(
                    f"[dns_find_pdc] Best-effort domain {marked_domain} has no persisted PDC IP"
                )
                return
            hostname_hint = (
                self.domains_data.get(domain, {}).get("pdc_hostname")
                if self.domains_data and domain in self.domains_data
                else None
            )
            pdc_hostname = resolve_pdc_hostname_best_effort(
                self,
                domain=domain,
                pdc_ip=fallback_ip,
                hostname_hint=hostname_hint,
            )
            self.pdc = fallback_ip
            self.pdc_hostname = pdc_hostname
            if self.domains_data and domain in self.domains_data and pdc_hostname:
                self.domains_data[domain]["pdc_hostname"] = pdc_hostname
            marked_pdc = mark_sensitive(self.pdc, "ip")
            marked_pdc_hostname = (
                mark_sensitive(self.pdc_hostname, "hostname")
                if self.pdc_hostname
                else "[unknown]"
            )
            print_success(
                f"PDC found: {marked_pdc} with hostname: {marked_pdc_hostname}"
            )
            self.add_to_hosts(domain)
            return

        # Use DNSDiscoveryService to discover PDC
        service = self._get_dns_discovery_service()
        selected_ip, pdc_hostname = service.discover_pdc(
            domain=domain,
            preferred_ips=preferred_ips if preferred_ips else None,
        )

        if selected_ip and pdc_hostname:
            self.pdc = selected_ip
            self.pdc_hostname = pdc_hostname
            marked_pdc_1 = mark_sensitive(self.pdc, "ip")
            marked_pdc_hostname_2 = mark_sensitive(self.pdc_hostname, "hostname")
            print_success(
                f"PDC found: {marked_pdc_1} with hostname: {marked_pdc_hostname_2}"
            )
            print_info_debug(
                f"[dns_find_pdc] Final PDC result: pdc={marked_pdc_1}, pdc_hostname={marked_pdc_hostname_2}"
            )
            self.add_to_hosts(domain)
        else:
            # Fallback: if service didn't find PDC but we have existing data, use it
            if hasattr(self, "pdc") and self.pdc:
                marked_pdc_1 = mark_sensitive(self.pdc, "ip")
                marked_pdc_hostname_2 = mark_sensitive(
                    getattr(self, "pdc_hostname", "unknown"), "hostname"
                )
                print_success(
                    f"PDC found: {marked_pdc_1} with hostname: {marked_pdc_hostname_2}"
                )
                self.add_to_hosts(domain)
            else:
                print_warning_debug(
                    f"[dns_find_pdc] No PDC found for domain {marked_domain}"
                )

    def do_update_resolv_conf(self, args):
        """
        Updates the /etc/resolv.conf file with the domain information and the PDC IP.

        Usage: update_resolv_conf <domain> <pdc_ip>

        This is a thin wrapper around :func:`update_resolv_conf` in
        ``adscan_internal.cli.dns``.
        """
        from adscan_internal.cli.dns import update_resolv_conf

        return update_resolv_conf(self, args)

    def _run_privileged_command(
        self,
        command: str,
        *,
        timeout: int | None = None,
        check: bool = False,
        ignore_errors: bool = False,
        cwd: str | None = None,
    ) -> subprocess.CompletedProcess[str] | None:
        """Run a command requiring root privileges.

        If ADscan is running as root, runs the command directly. Otherwise, prefixes
        the command with ``sudo`` and disables output capture so the sudo password
        prompt is visible to the user.
        """
        if os.geteuid() == 0:
            return self.run_command(
                command,
                timeout=timeout,
                check=check,
                ignore_errors=ignore_errors,
                cwd=cwd,
            )

        # Container runtime: never allow sudo to prompt (it would block the CLI).
        # The image entrypoint is expected to configure passwordless sudo for the
        # limited set of commands ADscan uses.
        if _is_full_adscan_container_runtime():
            if not shutil.which("sudo"):
                return self.run_command(
                    command,
                    timeout=timeout,
                    check=check,
                    ignore_errors=ignore_errors,
                    cwd=cwd,
                )
            sudo_prefix = (
                f"sudo -n --preserve-env={','.join(_DEFAULT_SUDO_PRESERVE_ENV_KEYS)}"
            )
        else:
            sudo_prefix = (
                f"sudo --preserve-env={','.join(_DEFAULT_SUDO_PRESERVE_ENV_KEYS)}"
            )

        sudo_command = f"{sudo_prefix} {command}"
        cmd_env = _build_effective_user_env_for_command(sudo_command, shell=True)
        return self.run_command(
            sudo_command,
            timeout=timeout,
            check=check,
            ignore_errors=ignore_errors,
            cwd=cwd,
            capture_output=False,
            use_clean_env=False,
            env=cmd_env,
        )

    def _ensure_system_dir(self, path: str) -> bool:
        """Ensure a system directory exists, using sudo when necessary."""
        try:
            if _is_full_adscan_container_runtime():
                os.makedirs(path, exist_ok=True)
                return True
            if os.path.exists(path):
                return True
            if os.geteuid() == 0:
                os.makedirs(path, exist_ok=True)
                return True
            result = self._run_privileged_command(
                f"mkdir -p {shlex.quote(path)}",
                timeout=60,
                check=False,
                ignore_errors=True,
            )
            return bool(result and result.returncode == 0)
        except Exception as exc:
            telemetry.capture_exception(exc)
            return False

    def _write_system_file(self, path: str, content: str, *, mode: int = 0o644) -> bool:
        """Write a root-owned system file (e.g., under /etc) safely.

        When not running as root, writes to a temporary file and installs it via sudo
        so we don't rely on fragile shell redirection.
        """
        try:
            # Container runtime: the entrypoint may chown selected /etc paths (e.g. Unbound
            # drop-ins) to the host UID/GID so ADscan can write without sudo/systemd.
            if _is_full_adscan_container_runtime():
                parent = os.path.dirname(path)
                if parent:
                    os.makedirs(parent, exist_ok=True)
                try:
                    with open(path, "w", encoding="utf-8") as f:
                        f.write(content)
                    try:
                        os.chmod(path, mode)
                    except OSError:
                        pass
                    return True
                except PermissionError:
                    # Some system files (e.g. /etc/hosts) are intentionally root-owned in
                    # the container. Fall back to a non-interactive privileged write.
                    if not shutil.which("sudo"):
                        return False

                    # Docker mounts /etc/hosts inside the container; it is writable but
                    # cannot be atomically replaced (rename/unlink) which breaks `install`.
                    # The entrypoint should make it writable for the ADscan user, but keep
                    # a non-interactive best-effort fallback here.
                    if os.path.normpath(path) == "/etc/hosts":
                        result = self._run_privileged_command(
                            f"sh -lc {shlex.quote(f'cat > {path}')}",
                            timeout=30,
                            check=False,
                            ignore_errors=True,
                        )
                        # If sudo is not permitted for shell, this will fail; caller will
                        # surface a warning and continue without host overrides.
                        return bool(result and result.returncode == 0)

                    import tempfile

                    with tempfile.NamedTemporaryFile(
                        mode="w",
                        encoding="utf-8",
                        delete=False,
                        prefix="adscan-",
                        suffix=".tmp",
                    ) as tmp:
                        tmp.write(content)
                        tmp_path = tmp.name

                    mode_str = oct(mode)[2:]
                    result = self._run_privileged_command(
                        f"install -m {mode_str} {shlex.quote(tmp_path)} {shlex.quote(path)}",
                        timeout=30,
                        check=False,
                        ignore_errors=True,
                    )
                    try:
                        os.remove(tmp_path)
                    except OSError:
                        pass
                    return bool(result and result.returncode == 0)

            parent = os.path.dirname(path)
            if parent:
                if not self._ensure_system_dir(parent):
                    return False

            if os.geteuid() == 0:
                with open(path, "w", encoding="utf-8") as f:
                    f.write(content)
                os.chmod(path, mode)
                return True

            import tempfile

            with tempfile.NamedTemporaryFile(
                mode="w",
                encoding="utf-8",
                delete=False,
                prefix="adscan-",
                suffix=".tmp",
            ) as tmp:
                tmp.write(content)
                tmp_path = tmp.name

            mode_str = oct(mode)[2:]
            result = self._run_privileged_command(
                f"install -m {mode_str} {shlex.quote(tmp_path)} {shlex.quote(path)}",
                timeout=60,
                check=False,
                ignore_errors=True,
            )
            try:
                os.remove(tmp_path)
            except OSError:
                pass
            return bool(result and result.returncode == 0)
        except Exception as exc:
            telemetry.capture_exception(exc)
            return False

    def _remove_system_file(self, path: str) -> bool:
        """Remove a system file, using sudo when necessary (best-effort)."""
        try:
            if not os.path.exists(path):
                return True
            if os.geteuid() == 0:
                os.remove(path)
                return True
            result = self._run_privileged_command(
                f"rm -f {shlex.quote(path)}",
                timeout=30,
                check=False,
                ignore_errors=True,
            )
            return bool(result and result.returncode == 0)
        except Exception as exc:
            telemetry.capture_exception(exc)
            return False

    def _ensure_unbound_available(self) -> bool:
        """Ensure Unbound is installed and its config directory exists."""
        return self._get_dns_resolver_service().ensure_unbound_available()

    def _read_unbound_adscan_forward_zones(
        self,
    ) -> tuple[dict[str, list[str]], list[str]]:
        """Read ADscan Unbound forward zones from disk.

        Returns:
            tuple:
                - domain_forwarders: Mapping of domain -> list of forward-addr values.
                - root_forwarders: Forwarders for the "." zone.
        """
        return self._get_dns_resolver_service().read_forward_zones()

    def _write_unbound_adscan_config(
        self,
        *,
        domain_forwarders: dict[str, list[str]],
        root_forwarders: list[str],
    ) -> bool:
        """Write Unbound configuration for ADscan conditional forwarding.

        Args:
            domain_forwarders: Mapping of domain -> list of upstream DNS server IPs.
            root_forwarders: Upstream DNS servers used for all other lookups (zone ".").
        """
        return self._get_dns_resolver_service().write_unbound_config(
            domain_forwarders=domain_forwarders,
            root_forwarders=root_forwarders,
        )

    def _restart_unbound(self) -> bool:
        """Restart Unbound and return True on success."""
        return self._get_dns_resolver_service().restart_unbound()

    def _configure_system_dns_for_unbound(
        self, fallback_nameservers: list[str]
    ) -> bool:
        """Configure the system to use Unbound as the local DNS resolver.

        On systems running systemd-resolved, configure resolved to forward to
        127.0.0.1 (Unbound) without rewriting /etc/resolv.conf. Otherwise, write
        /etc/resolv.conf to point at 127.0.0.1 and keep fallbacks.
        """
        return self._get_dns_resolver_service().configure_system_dns_for_unbound(
            fallback_nameservers
        )

    def _get_existing_nameservers(self):
        """
        Gets existing nameservers from resolv.conf.
        """
        return self._get_dns_resolver_service().get_existing_nameservers()

    def _is_loopback_ip(self, value: str) -> bool:
        """Return True if *value* is a loopback IP address.

        Args:
            value: IP address string to check

        Returns:
            True if the IP is a loopback address, False otherwise
        """
        return _is_loopback_ip(value)

    def _log_dns_management_debug(self, context: str) -> None:
        """Log DNS management context to help diagnose resolv.conf persistence issues."""
        self._get_dns_resolver_service().log_dns_management_debug(context)

    def _ensure_dhcpcd_preserves_resolv_conf(self):
        """Ensure dhcpcd does not overwrite /etc/resolv.conf.

        This keeps the system resolver pointed at the local resolver (Unbound on 127.0.0.1)
        across DHCP renewals on distros that use dhcpcd.
        """
        return self._get_dns_resolver_service().ensure_dhcpcd_preserves_resolv_conf()

    def _restart_dhcpcd_service(self):
        """
        Attempts to restart dhcpcd so configuration changes take effect.
        """
        return self._get_dns_resolver_service().restart_dhcpcd_service()

    def _ensure_dhcpcd_enter_hook_enforces_resolv_conf(
        self, resolv_lines: list[str]
    ) -> bool:
        """Ensure dhcpcd enforces our desired resolv.conf on DHCP events.

        On some systems (notably Kali with Docker/bridges), dhcpcd runs multiple helper
        processes and may regenerate ``/etc/resolv.conf`` with incomplete content
        (sometimes only the header) despite our dhcpcd.conf settings.

        dhcpcd supports a global hook at ``/etc/dhcpcd.enter-hook`` that is executed
        on DHCP events. We use it to re-assert ``nameserver 127.0.0.1`` (Unbound)
        and known fallbacks whenever dhcpcd touches resolv.conf.

        Safety:
          - Only acts when ``/etc/resolv.conf`` is a regular file (not a symlink).
          - Managed via explicit start/end markers so we do not clobber other hooks.

        Args:
            resolv_lines: Lines to write into /etc/resolv.conf.

        Returns:
            True if the hook is present/updated successfully.
        """
        return self._get_dns_resolver_service().ensure_dhcpcd_enter_hook_enforces_resolv_conf(
            resolv_lines
        )

    def _clean_domain_entries(self, domain):
        """Remove ADscan resolver entries for a domain from Unbound and /etc/hosts."""
        return self._get_dns_resolver_service().clean_domain_entries(domain)

    def _verify_dns_resolution(self, domain: str) -> bool:
        """Verify local DNS resolution for an Active Directory domain.

        AD domains often do not have an apex A record (e.g. ``darkzero.htb``), so checking
        the domain apex A record can produce false negatives. Instead we validate that the local
        resolver can retrieve AD SRV records through our conditional forwarding setup.
        """
        from adscan_internal.rich_output import mark_sensitive

        try:
            domain = (domain or "").strip().rstrip(".")
            if not domain:
                print_warning("Cannot verify DNS: domain is empty.")
                return False

            marked_domain = mark_sensitive(domain, "domain")
            local_resolver_ip = _get_adscan_local_resolver_ip()
            marked_local_resolver_ip = mark_sensitive(local_resolver_ip, "ip")
            # Fast check: ensure something is listening on the local resolver IP so the DNS check doesn't hang.
            try:
                if not _is_unbound_listening_local(resolver_ip=local_resolver_ip):
                    print_warning(
                        "Local DNS resolver is not listening on "
                        f"{marked_local_resolver_ip}:53 for {marked_domain}."
                    )
                    print_info_verbose("Attempting to restart Unbound...")
                    self._restart_unbound()
            except Exception as exc:
                telemetry.capture_exception(exc)
                print_info_debug("[dns] Failed to probe local port 53 listeners.")

            dns_service = self._get_dns_discovery_service()
            is_valid, error_kind = dns_service.verify_dns_resolution(
                domain=domain,
                resolver_ip=local_resolver_ip,
            )
            if is_valid:
                print_success(
                    f"DNS resolution configured correctly for {marked_domain}"
                )
                return True

            if error_kind == "timeout":
                print_info_verbose(
                    "Check for a service listening on "
                    f"{marked_local_resolver_ip}:53 (dnsmasq/unbound conflict)."
                )
                return False

            # Attempt a one-time self-heal for common validating-resolver
            # failure modes (DNSSEC validation SERVFAIL) by rewriting/restarting Unbound.
            if error_kind == "servfail":
                print_warning(
                    f"DNS resolution for {marked_domain} is failing due to resolver validation (SERVFAIL). "
                    "Refreshing Unbound configuration..."
                )
                try:
                    domain_forwarders, root_forwarders = (
                        self._read_unbound_adscan_forward_zones()
                    )
                    normalized_domain = domain.lower().rstrip(".")
                    if not root_forwarders:
                        root_forwarders = [
                            ns
                            for ns in self._get_existing_nameservers()
                            if ns and not _is_loopback_ip(ns)
                        ]
                    if normalized_domain in domain_forwarders:
                        self._write_unbound_adscan_config(
                            domain_forwarders=domain_forwarders,
                            root_forwarders=root_forwarders,
                        )
                        self._restart_unbound()

                        retry_ok, _retry_error = dns_service.verify_dns_resolution(
                            domain=domain,
                            resolver_ip=local_resolver_ip,
                        )
                        if retry_ok:
                            print_success(
                                f"DNS resolution configured correctly for {marked_domain}"
                            )
                            return True
                except Exception as exc:
                    telemetry.capture_exception(exc)

            print_error(f"DNS resolution failed for {marked_domain}")
            return False
        except Exception as e:
            print_error("Error verifying DNS resolution.")
            print_exception(show_locals=False, exception=e)
            telemetry.capture_exception(e)
            return False

    def dns_find_pdc_resolv(self, domain, ip):
        """Resolve the PDC IP for a domain using a specific resolver.

        This uses direct DNS queries and supports a TCP fallback when UDP/53 is
        blocked.
        """
        from adscan_internal.rich_output import mark_sensitive

        normalized_domain = (domain or "").strip().rstrip(".")
        marked_domain = mark_sensitive(normalized_domain, "domain")
        marked_ip = mark_sensitive(ip, "ip")

        domain_pdc = (
            self.domains_data.get(domain, {}).get("pdc")
            if self.domains_data and domain in self.domains_data
            else None
        )
        preferred_ips = [ip, domain_pdc, getattr(self, "pdc", None)]
        service = self._get_dns_discovery_service()
        selected_ip, hostname = service.find_pdc_with_selection(
            domain=normalized_domain,
            resolver_ip=ip,
            preferred_ips=preferred_ips,
            reference_ip=ip,
        )
        if not selected_ip or not hostname:
            print_warning_debug(
                f"[dns_find_pdc_resolv] No PDC SRV answer for {marked_domain} via resolver {marked_ip}"
            )
            return None

        self.pdc_hostname = hostname
        self.pdc = selected_ip
        print_info_debug(
            f"[DNS] Selected PDC IP via resolver {marked_ip} for {marked_domain}: {selected_ip}"
        )
        return selected_ip

    def add_to_hosts(self, domain, dns_a_records=None):
        """Delegate /etc/hosts update to DNSResolverService.

        When ``dns_a_records`` is provided, the resolver service refuses to write
        a line whose IP is not one of the domain's own A-records (defense-in-depth
        against the cross-domain leak). Legacy callers pass nothing → unchanged.
        """
        try:
            service = self._get_dns_resolver_service()
            return service.add_hosts_entry(
                domain=domain,
                ip=getattr(self, "pdc", None),
                hostname=getattr(self, "pdc_hostname", None),
                dns_a_records=dns_a_records,
            )
        except Exception as exc:  # noqa: BLE001
            telemetry.capture_exception(exc)
            print_error("Failed to update /etc/hosts.")
            print_exception(show_locals=False, exception=exc)
            return False

    def do_open_smb(self, domain=None):
        """
        Opens a local SMB port in the current directory using smbserver.py.
        """
        if not self.myip:
            print_error("Please configure your interface with 'set iface <value>'.")
            return

        if not self.impacket_scripts_dir:
            print_error(
                "Impacket scripts directory not configured. Please ensure Impacket is installed via 'adscan install'."
            )
            return
        smb_path = os.path.join(self.impacket_scripts_dir, "smbserver.py")
        if not os.path.isfile(smb_path) or not os.access(smb_path, os.X_OK):
            print_error(
                f"smbserver.py not found or not executable in {self.impacket_scripts_dir}. Please check Impacket installation."
            )
            return

        smb_command = f'{shlex.quote(smb_path)} smbFolder "$(pwd)" -smb2support'
        try:
            proc = self.spawn_command(
                smb_command,
                shell=True,
            )
            self._smb_proc = proc  # Track SMB server for cleanup
            atexit.register(self.close_smb, proc)
            if proc is None:
                print_error("Failed to open local SMB port")
                return
            print_success("Local SMB port opened successfully")
        except Exception as e:
            telemetry.capture_exception(e)
            print_error("Failed to open local SMB port.")
            print_exception(show_locals=False, exception=e)
            return
        # threading.Thread(target=self.monitor_smb, args=(proc, domain)).start()

    def _prompt_type_if_missing(self):
        """Interactively prompt for pentest type if not configured."""
        if self.type:
            return True

        from adscan_internal import print_warning

        print_warning("⚠️  Pentest type not configured")

        type_options = [
            "🎯 CTF (Capture The Flag)",
            "🔒 Audit (Real Pentest)",
        ]

        selection_idx = self._questionary_select("Select pentest type:", type_options)

        if selection_idx is None:
            print_error("Pentest type is required to continue.")
            return False

        # Map selection to type value
        type_values = ["ctf", "audit"]
        self.type = type_values[selection_idx]
        print_success(f"✓ Pentest type configured: {self.type}")

        if self.type == "ctf":
            self.auto = True
            print_info("   Auto mode enabled automatically for CTF")

        return True

    def _prompt_interface_if_missing(self):
        """Interactively prompt for network interface if not configured."""
        if self.interface:
            return True

        from adscan_internal import print_warning

        print_warning("⚠️  Network interface not configured")

        # Get available network interfaces
        try:
            import netifaces

            interfaces = netifaces.interfaces()
            # Filter out loopback
            interfaces = [iface for iface in interfaces if iface != "lo"]

            if not interfaces:
                print_error("No network interfaces found.")
                return False

            # Format options with icons
            iface_options = [f"🌐 {iface}" for iface in interfaces]

            selection_idx = self._questionary_select(
                "Select network interface:", iface_options
            )

            if selection_idx is None:
                print_error("Network interface is required to continue.")
                return False

            selected_iface = interfaces[selection_idx]
            self.interface = selected_iface
            ip = self.set_interface_ip(selected_iface)

            if ip:
                print_success(
                    f"Interface configured: {self.interface} with IP: {self.myip}"
                )
            else:
                print_error(f"Could not get IP for interface {self.interface}")
                return False

            return True

        except ImportError:
            # Fallback to manual input if netifaces not available
            from rich.prompt import Prompt

            iface_input = Prompt.ask("Enter network interface (e.g., eth0, tun0)")

            if not iface_input:
                print_error("Network interface is required to continue.")
                return False

            self.interface = iface_input
            ip = self.set_interface_ip(iface_input)

            if ip:
                print_success(
                    f"Interface configured: {self.interface} with IP: {self.myip}"
                )
                return True
            else:
                print_error(f"Could not get IP for interface {self.interface}")
                return False

    def _prompt_auto_if_missing(self):
        """Interactively prompt for auto mode if not configured."""
        if self.auto is not None:
            return True

        from adscan_internal import print_warning

        print_warning("⚠️  Auto mode not configured")

        auto_options = [
            "🤖 Automatic (no prompts)",
            "👤 Semi-automatic (with prompts)",
        ]

        selection_idx = self._questionary_select("Select scan mode:", auto_options)

        if selection_idx is None:
            print_error("Auto mode is required to continue.")
            return False

        # 0 = Automatic (True), 1 = Semi-automatic (False)
        self.auto = selection_idx == 0
        mode_text = "Automatic" if self.auto else "Semi-automatic"
        print_success(f"✓ Auto mode configured: {mode_text}")

        return True

    def _prompt_hosts_if_missing(self):
        """Interactively prompt for target hosts if not configured."""
        if self.hosts:
            return True

        from adscan_internal import print_warning

        print_warning("⚠️  Target hosts not configured")

        from rich.prompt import Prompt

        hosts_input = Prompt.ask(
            "Enter target hosts (e.g., 192.168.1.0/24, 10.10.10.1-50)",
            default="192.168.1.0/24",
        )

        if not hosts_input:
            print_error("Target hosts are required to continue.")
            return False

        self.hosts = hosts_input
        print_success(f"✓ Hosts configured: {self.hosts}")

        return True

    def do_start_unauth(self, args):
        """Start an unauthenticated domain scan workflow.

        Usage:
            start_unauth [domain]

        Runs the unauthenticated discovery/orchestration path for the selected
        domain (or current domain when omitted).
        """
        from adscan_internal.cli.start import run_start_unauth

        scan_ctx = self._begin_scan_lifecycle(auth_mode="unauth", args=args)
        try:
            run_start_unauth(self, args)
        finally:
            self._end_scan_lifecycle(scan_ctx)

    def do_start_auth(self, args):
        """Start an authenticated domain scan workflow.

        Usage:
            start_auth [domain]

        Executes the authenticated scan orchestration for the selected domain
        (or current domain when omitted), using the currently configured
        credential/auth context.
        """
        from adscan_internal.cli.start import run_start_auth

        scan_ctx = self._begin_scan_lifecycle(auth_mode="auth", args=args)
        try:
            run_start_auth(self, args)
        finally:
            self._end_scan_lifecycle(scan_ctx)

    # ──────────────────────────────────────────────────────────────────
    # Scan lifecycle helpers — drive Tier 2 streaming markers.
    #
    # ``do_start_unauth`` and ``do_start_auth`` are the two commands
    # the operator runs from the interactive shell to fire a scan. We
    # wrap them with these helpers so the streamer (when active) emits
    # a ``scan_started`` lifecycle chunk on entry and a
    # ``scan_finished`` chunk on exit, regardless of how the scan
    # ended (success, exception, KeyboardInterrupt). The streamer
    # itself decides whether to ship the markers — if it's not running
    # (telemetry off, command_type not in scope, no direct URL) these
    # helpers are cheap no-ops.
    # ──────────────────────────────────────────────────────────────────

    def _begin_scan_lifecycle(self, *, auth_mode: str, args: Any) -> dict[str, Any]:
        streamer = getattr(self, "_telemetry_streamer", None)
        scan_started_at = time.monotonic()
        ctx: dict[str, Any] = {
            "auth_mode": auth_mode,
            "started_at": scan_started_at,
        }
        if streamer is None:
            return ctx
        try:
            domain = self._resolve_scan_domain_for_lifecycle(args)
        except Exception:  # noqa: BLE001
            domain = None
        ctx["domain"] = domain
        try:
            streamer.emit_lifecycle(
                "scan_started",
                {
                    "auth_mode": auth_mode,
                    "domain": domain,
                },
            )
        except Exception as exc:  # noqa: BLE001
            print_info_debug(
                f"(telemetry-streamer) scan_started emit failed: {type(exc).__name__}: {exc}"
            )
        return ctx

    def _end_scan_lifecycle(self, ctx: dict[str, Any]) -> None:
        streamer = getattr(self, "_telemetry_streamer", None)
        if streamer is None:
            return
        try:
            duration = max(0.0, time.monotonic() - float(ctx.get("started_at") or 0.0))
            findings = self._collect_scan_metadata_for_lifecycle()
            findings.update(
                {
                    "auth_mode": ctx.get("auth_mode"),
                    "domain": ctx.get("domain"),
                    "duration_seconds": round(duration, 2),
                }
            )
            streamer.emit_lifecycle("scan_finished", findings)
        except Exception as exc:  # noqa: BLE001
            print_info_debug(
                f"(telemetry-streamer) scan_finished emit failed: {type(exc).__name__}: {exc}"
            )

    def _resolve_scan_domain_for_lifecycle(self, args: Any) -> Optional[str]:
        """Best-effort: capture the domain the operator targeted.

        ``start_unauth`` / ``start_auth`` accept either a positional
        domain or fall back to the shell's current domain. We mirror
        that resolution shallowly here without firing any side effect.
        """
        argv = args.split() if isinstance(args, str) else (args or [])
        if argv:
            cand = str(argv[0]).strip()
            if cand:
                return cand
        return getattr(self, "current_domain", None) or None

    def _collect_scan_metadata_for_lifecycle(self) -> dict[str, Any]:
        """Snapshot scan outcome counters for the scan_finished marker.

        All fields are best-effort: a missing attribute or transient
        exception simply omits that key from the chunk metadata. The
        server displays whatever arrives.
        """
        metadata: dict[str, Any] = {}
        try:
            attack_summaries = getattr(self, "_attack_path_summaries", None)
            if isinstance(attack_summaries, list):
                metadata["attack_paths_count"] = len(attack_summaries)
        except Exception:  # noqa: BLE001
            pass
        try:
            if hasattr(self, "_session_compromise_status"):
                metadata["compromise_status"] = str(self._session_compromise_status)
        except Exception:  # noqa: BLE001
            pass
        try:
            if hasattr(self, "compromised_users"):
                metadata["compromised_users_count"] = len(self.compromised_users)
        except Exception:  # noqa: BLE001
            pass
        return metadata

    def _init_telemetry_streamer(self) -> None:
        """Spin up the Tier 2 streamer when the command is eligible.

        Called from ``__init__`` after the shell's command_type is set.
        The factory in ``adscan_core.telemetry`` returns ``None`` when
        any eligibility check fails (command not in scope, telemetry
        disabled, no direct ingest URL, missing token) — in which case
        we silently keep the Tier 1 single-shot path.

        Once started, the streamer immediately emits a
        ``session_started`` lifecycle chunk so the server can bootstrap
        the sessions row + live-view route before any scan fires.
        """
        from adscan_core import telemetry as _tel

        # Diagnostic breadcrumb so ``--debug`` always shows the streamer
        # init was reached (silent failure modes upstream were
        # historically the hardest to diagnose).
        print_info_debug(
            f"(telemetry-streamer) init: command_type="
            f"{self.session_command_type!r}"
        )

        # Normally the launcher seeds ADSCAN_SESSION_TRACE_ID before
        # docker run. When running adscan directly (``uv run adscan
        # start`` for dev/CI smoke tests) the launcher is bypassed —
        # seed a trace id ourselves so live streaming still works
        # end-to-end. ``capture_session_end`` reads from the same env
        # var, so a single seed covers both ingest paths.
        trace_id = os.getenv("ADSCAN_SESSION_TRACE_ID") or ""
        if not trace_id:
            import uuid as _uuid

            trace_id = _uuid.uuid4().hex
            os.environ["ADSCAN_SESSION_TRACE_ID"] = trace_id
            print_info_debug(
                f"(telemetry-streamer) seeded ADSCAN_SESSION_TRACE_ID: {trace_id!r}"
            )
        else:
            print_info_debug(
                f"(telemetry-streamer) using inherited "
                f"ADSCAN_SESSION_TRACE_ID: {trace_id!r}"
            )

        command_type = (self.session_command_type or "start").lower()
        # Privacy: we never pass ``current_workspace`` to the streamer
        # — only the derived ``workspace_id_hash`` does, and that's
        # snapshotted on every chunk via ``_version_payload`` below so
        # the dashboard picks up workspace changes the moment
        # ``workspace_select`` runs.
        #
        # Environment label resolved once at process start; we mirror
        # the value the legacy path computes in capture_session_end.
        environment = (
            os.getenv("ADSCAN_SESSION_ENV") or os.getenv("ADSCAN_ENV") or "prod"
        ).strip().lower() or "prod"

        started_at_dt = datetime.now(timezone.utc)
        session_started_monotonic = time.monotonic()
        self._streamer_session_started_at = started_at_dt
        self._streamer_session_started_monotonic = session_started_monotonic

        def _export_html() -> str:
            # ``clear=False`` is load-bearing: Rich's
            # ``Console.export_html()`` clears the internal record
            # buffer by default. Without this flag, each streamer tick
            # would receive ONLY the chars rendered since the previous
            # tick — and ``capture_session_end`` at session exit would
            # see an empty buffer because the streamer had already
            # drained everything. The diff math (``sanitized[sent_chars:]``)
            # also breaks because the cursor outruns the buffer the
            # first time it's reset, producing zero-byte chunks for the
            # rest of the session (we observed this in production —
            # ``raw_html_chars`` collapsing from 81K → 1.2K → 1.1K
            # between consecutive ticks).
            try:
                return TELEMETRY_CONSOLE.export_html(clear=False)
            except Exception:  # noqa: BLE001
                return ""

        def _version_payload() -> dict[str, Any]:
            # Version + lab/workspace block included on every chunk so
            # the server can bootstrap the sessions row from the first
            # chunk that arrives. We reuse the canonical helper that
            # ``capture_session_end`` already uses for the legacy
            # single-shot payload — same source of truth, same shape,
            # zero drift between the two ingest paths.
            try:
                from adscan_core.version_context import (
                    get_telemetry_version_fields as _ver,
                )

                fields = dict(_ver() or {})
            except Exception:  # noqa: BLE001
                fields = {}
            # Carry the workspace identity on every chunk in case it
            # changed mid-session (``workspace_select`` after the
            # streamer already started). The server takes whichever
            # value arrives on the latest chunk for the row update.
            #
            # Privacy: only the stable ``workspace_id_hash`` ever
            # leaves the host. The raw workspace name is
            # customer-sensitive (think "acme-corp-prod") and stays
            # local — single source of truth for that rule is
            # ``_build_session_metadata`` in telemetry.py.
            try:
                workspace_now = getattr(self, "current_workspace", None)
                if workspace_now:
                    from adscan_core.telemetry import (
                        compute_workspace_id_hash as _wsh,
                    )
                    ws_hash = _wsh(workspace_now)
                    if ws_hash:
                        fields["workspace_id_hash"] = ws_hash
            except Exception:  # noqa: BLE001
                pass
            return fields

        streamer = _tel.make_session_streamer(
            trace_id=trace_id,
            user_id_hash=str(_tel.TELEMETRY_ID),
            command_type=command_type,
            session_scope="runtime",
            environment=environment,
            started_at=started_at_dt,
            export_html_fn=_export_html,
            version_payload_fn=_version_payload,
        )
        if streamer is None:
            # ``make_session_streamer`` already emitted the specific
            # ``skipped: <reason>`` line. No extra log needed here.
            return
        self._telemetry_streamer = streamer

        # Fire ``session_started`` immediately so the server bootstraps
        # the sessions row + the operator can already open the live
        # page in the viewer. The chunk content at this point is the
        # short banner + welcome panel, exactly what the operator just
        # saw in the terminal.
        # Privacy: never put the raw workspace name in lifecycle
        # metadata. The streamer's ``version_payload_fn`` snapshot
        # already carries ``workspace_id_hash`` on every chunk.
        try:
            streamer.emit_lifecycle(
                "session_started",
                {
                    "command_type": command_type,
                    "environment": environment,
                },
            )
        except Exception as exc:  # noqa: BLE001
            print_info_debug(
                f"(telemetry-streamer) session_started emit failed: "
                f"{type(exc).__name__}: {exc}"
            )

    def _finalise_telemetry_streamer(self) -> None:
        """Close the streamer and ship the final chunk with ``is_final``.

        Called from ``capture_session_end`` BEFORE the legacy
        single-shot export runs — if the streamer was active for this
        session, the legacy export is then skipped (the server already
        has the full content via assembled chunks).
        """
        streamer = getattr(self, "_telemetry_streamer", None)
        if streamer is None:
            return
        try:
            streamer.finalise(
                finished_at=datetime.now(timezone.utc),
                compromise_status=getattr(self, "_session_compromise_status", None),
                compromised_users_count=(
                    len(self._session_compromised_users)
                    if hasattr(self, "_session_compromised_users")
                    else None
                ),
            )
        except Exception as exc:  # noqa: BLE001
            print_info_debug(
                f"(telemetry-streamer) finalise failed: {type(exc).__name__}: {exc}"
            )
        finally:
            self._telemetry_streamer = None

