    def do_system(self, arg):
        """Usage: system <command>
        Executes a system command.
        """
        if not arg:
            print_error("You must provide a command to execute.")
            return

        try:
            # In Docker runtime, some tools (notably hashcat/OpenCL) are more stable
            # when executed as root inside the container.
            arg = _maybe_wrap_hashcat_for_container(arg)

            # Use run_command to automatically handle clean_env and avoid PyInstaller conflicts
            completed_process = self.run_command(
                arg,
                shell=True,
                capture_output=True,
                text=True,
                timeout=300,
                check=False,
            )

            # This check is crucial for when the command times out, as run_command returns None.
            if completed_process is None:
                print_error("Failed to execute command")
                return

            if completed_process.returncode == 0:
                if completed_process.stdout:
                    self.console.print(completed_process.stdout)
                if completed_process.stderr:
                    print_warning(
                        f"Stderr (even on success): {completed_process.stderr}"
                    )
            else:
                print_error(
                    f"Command '{arg}' failed with return code {completed_process.returncode}"
                )
                if completed_process.stdout:
                    print_info(f"Stdout (on error): {completed_process.stdout}")
                if completed_process.stderr:
                    print_error(f"Error: {completed_process.stderr}")

        except Exception as e:
            telemetry.capture_exception(e)
            # This catches errors if, for instance, completed_process is None and we try to access its attributes.
            print_error("An unexpected error occurred in do_system.")
            print_exception(show_locals=False, exception=e)

    def do_cd(self, arg):
        """Change the current working directory.
        Usage: cd <directory_path>"""
        if not arg:
            # No argument, print current directory (like Bash)
            # Or, go to home directory: target_path = os.path.expanduser("~")
            try:
                current_dir = os.getcwd()
                self.console.print(f"[cyan]{current_dir}[/cyan]")
            except OSError as e:
                telemetry.capture_exception(e)
                print_error("Error getting current directory.")
                print_exception(show_locals=False, exception=e)
            return

        target_path = _expand_effective_user_path(arg)  # Handle ~ for home directory

        if not os.path.isdir(target_path):
            print_error(f"cd: No such file or directory: {target_path}")
            return

        try:
            os.chdir(target_path)
            # Optionally, update a variable like self.current_path if your prompt uses it
            # self.current_path = os.getcwd()
            # The prompt will reflect os.getcwd() if it's designed to do so dynamically
            # For example, if _get_rich_prompt_object uses os.getcwd()
            # print_info(f"Current directory changed to: {os.getcwd()}") # Optional feedback
        except OSError as e:
            telemetry.capture_exception(e)
            print_error("cd: Error changing directory to {target_path}.")
            print_exception(show_locals=False, exception=e)

