    def _format_size(self, size_bytes):
        """Converts a size in bytes to a human-readable string."""
        if (
            size_bytes == "N/A"
            or not isinstance(size_bytes, (int, float))
            or size_bytes < 0
        ):
            return "N/A"
        if size_bytes == 0:
            return "0 B"
        size_name = ("B", "KB", "MB", "GB", "TB", "PB", "EB", "ZB", "YB")
        i = int(math.floor(math.log(size_bytes, 1024)))
        p = math.pow(1024, i)
        s = round(size_bytes / p, 1)
        return f"{s} {size_name[i]}"

    def do_ls(self, arg):
        """Lists directory contents with Rich table. Usage: ls [path]"""
        raw_args = arg.split()
        path_arg = "."  # Default to current directory
        show_all = False
        human_readable = False
        processed_args = []  # Arguments that are not our flags

        # Simple flag parsing
        for item in raw_args:
            if item == "-a" or item == "--all":
                show_all = True
            elif item == "-h" or item == "--human-readable":
                human_readable = True
            elif item.startswith("-"):
                # Unrecognized option, fall back to system ls
                # self.console.print(f"[yellow]Rich 'ls' does not support option: {item}. Falling back to system 'ls'.[/yellow]")
                self.do_system(f"ls {arg}")
                return
            else:
                processed_args.append(item)

        if processed_args:  # If there are non-flag arguments, the first one is the path
            path_arg = processed_args[0]
        # If more than one non-flag argument, 'ls' usually errors or treats them differently.
        # For simplicity, this Rich version only handles one path argument.
        if len(processed_args) > 1:
            print_error(f"ls: too many arguments: {' '.join(processed_args)}")
            return

        try:
            target_path_abs = os.path.abspath(_expand_effective_user_path(path_arg))

            if not os.path.isdir(target_path_abs):
                print_error(
                    f"ls: cannot access '{path_arg}': No such file or directory"
                )
                return

            table = Table(
                title=f"Contents of [cyan]{target_path_abs}[/cyan]",
                show_header=True,
                header_style="bold magenta",
            )
            table.add_column("Name", style="dim", width=40, overflow="fold")
            table.add_column("Type", width=10)
            table.add_column("Size", justify="right", width=15)
            table.add_column("Last Modified", width=20)

            scandir_results = os.scandir(target_path_abs)

            if not show_all:
                # Filter out hidden files/directories (starting with '.') if -a is not specified
                entries_filtered = [
                    e for e in scandir_results if not e.name.startswith(".")
                ]
            else:
                entries_filtered = list(scandir_results)

            entries = sorted(entries_filtered, key=lambda e: e.name.lower())

            for entry in entries:
                name = entry.name
                try:
                    stat_info = entry.stat(
                        follow_symlinks=False
                    )  # Get stat of link itself, not target
                    size_bytes = stat_info.st_size
                    mod_time_dt = datetime.fromtimestamp(stat_info.st_mtime)
                    mod_time_str = mod_time_dt.strftime("%Y-%m-%d %H:%M:%S")
                except OSError as e:
                    telemetry.capture_exception(e)
                    # Could happen for broken symlinks, etc.
                    size_bytes = "N/A"
                    mod_time_str = "N/A"

                entry_type_str = "Unknown"
                name_style = "white"

                if entry.is_dir():
                    entry_type_str = "Dir"
                    name_style = "bold blue"
                    # For directories, size is often not what users expect from 'ls'.
                    # Could show item count or leave as is (often 4096 or similar for the dir entry itself).
                    # For simplicity, we show the stat size.
                elif entry.is_file():
                    entry_type_str = "File"
                    name_style = "green"
                elif entry.is_symlink():
                    entry_type_str = "Link"
                    name_style = "cyan"
                    try:
                        link_target = os.readlink(entry.path)
                        name += f"-> {link_target}"
                    except OSError as e:
                        telemetry.capture_exception(e)
                        name += " -> [broken link]"

                display_size = (
                    self._format_size(size_bytes) if human_readable else str(size_bytes)
                )

                table.add_row(
                    f"[{name_style}]{name}[/{name_style}]",
                    entry_type_str,
                    display_size,
                    mod_time_str,
                )

            self.console.print(table)

        except FileNotFoundError as e:
            telemetry.capture_exception(e)
            print_error(f"ls: cannot access '{path_arg}': No such file or directory")
        except PermissionError as e:
            telemetry.capture_exception(e)
            print_error(f"ls: cannot open directory '{path_arg}': Permission denied")
        except Exception as e:
            telemetry.capture_exception(e)
            print_error("An unexpected error occurred with ls.")
            print_exception(show_locals=False, exception=e)
            # For debugging, you might want to see the full traceback:

            print_exception(show_locals=True)

