    def _complete_file_paths(self, text):
        """Helper method for file path autocompletion.

        Args:
            text: The text to complete (partial file path)

        Returns:
            list: List of matching file paths
        """
        if not text:
            text = "."

        try:
            # Get the directory and pattern
            if os.path.isdir(text) or text == ".":
                directory = text if text != "." else "."
                pattern = ""
            else:
                directory = os.path.dirname(text) if os.path.dirname(text) else "."
                pattern = os.path.basename(text)

            if not os.path.exists(directory):
                return []

            matches = []
            for item in os.listdir(directory):
                item_path = os.path.join(directory, item) if directory != "." else item
                if pattern and not item.startswith(pattern):
                    continue
                matches.append(item_path)

            return sorted(matches)
        except Exception:
            return []

