    def do_cat(self, args):
        """Displays the content of a file using batcat.
        Usage: cat <file_path> -l <language>
        """
        from adscan_internal.rich_output import mark_sensitive

        try:
            parts = args.split()
            if not parts:
                print_error("Please specify a file.")
                return

            file_path = parts[0]
            language = parts[2] if len(parts) > 2 and parts[1] == "-l" else None

            if os.path.exists(file_path):
                # Choose available file viewer
                if shutil.which("batcat"):
                    viewer = "batcat"
                elif shutil.which("bat"):
                    viewer = "bat"
                else:
                    viewer = "cat"
                cmd = f"{viewer} {file_path}"
                if viewer in ("batcat", "bat") and language:
                    cmd += f" -l {language}"
                self.do_system(cmd)
            else:
                marked_file_path = mark_sensitive(file_path, "path")
                print_error(f"The file {marked_file_path} does not exist.")
        except Exception as e:
            telemetry.capture_exception(e)
            print_error("Error executing batcat.")
            print_exception(show_locals=False, exception=e)

    def complete_cat(self, text, line, begidx, endidx):
        """Autocomplete for the cat command using file paths."""
        return self._complete_file_paths(text)

    def do_clear_all(self, arg):
        """
        Clears the current workspace by deleting all files and folders,
        except for workspace metadata and logging directories.
        Resets the authentication values for each domain and clears the domains list.
        """
        protected_files = [
            "variables.json",
            "technical_report.json",
            ".adscan_history",
            "logs",
            "log",
        ]

        # Obtain a list of all files and folders in the current directory
        current_dir = os.getcwd()
        items = os.listdir(current_dir)

        # Filter the files and folders to delete
        items_to_delete = [item for item in items if item not in protected_files]

        # Delete files and folders
        for item in items_to_delete:
            item_path = os.path.join(current_dir, item)

            try:
                if os.path.isfile(item_path):
                    os.remove(item_path)  # Delete file
                elif os.path.isdir(item_path):
                    shutil.rmtree(item_path)  # Delete folder and its contents
            except Exception as e:
                telemetry.capture_exception(e)
                print_error("Error deleting {item}.")
                print_exception(show_locals=False, exception=e)

        # Reset the authentication values for each domain
        for domain in self.domains:
            if domain in self.domains_data:
                self.domains_data[domain]["auth"] = "unauth"
                self.clear_creds(domain)
            else:
                self.domains_data[domain] = {"auth": "unauth"}

        self.domain = None
        self.domains.clear()
        self.domains_data = {}
        print_success("Workspace cleared.")

    def do_clear_auths(self, arg):
        """
        Clears the authentications for all domains.

        Sets the 'auth' value of the domains to unauth.
        """
        for domain in self.domains:
            if domain in self.domains_data:
                self.domains_data[domain]["auth"] = "unauth"
            else:
                self.domains_data[domain] = {"auth": "unauth"}

        print_success("Auths cleared.")

    def do_add_auths(self, arg):
        """
        Sets the authentications for all domains as authenticated.

        Sets the 'auth' value of the domains to auth.
        """
        for domain in self.domains:
            if domain in self.domains_data:
                self.domains_data[domain]["auth"] = "auth"
            else:
                self.domains_data[domain] = {"auth": "unauth"}

        print_success("Auths changed to authenticated.")

    def do_clear_creds_and_auths(self, arg):
        """
        Clears the credentials and authentications for all domains.

        If an auth type is provided, sets that auth value for all domains.
        Otherwise, defaults to unauth unless the domain is marked as pwned,
        in which case the user is prompted to choose auth vs unauth.
        Finally, sets self.domain to None.
        """
        auth_value = (arg or "").strip().lower()
        if auth_value and auth_value not in {"auth", "unauth", "pwned"}:
            print_error("Invalid auth value. Use one of: auth, unauth, pwned.")
            return

        for domain in self.domains:
            domain_entry = self.domains_data.get(domain, {})
            current_auth = str(domain_entry.get("auth", "")).lower()

            if auth_value:
                new_auth = auth_value
            elif current_auth == "pwned":
                marked_domain = mark_sensitive(domain, "domain")
                selection_idx = self._questionary_select(
                    f"Domain {marked_domain} is marked as pwned. "
                    "Select the new auth state:",
                    ["auth", "unauth"],
                    default_idx=0,
                )
                new_auth = "auth" if selection_idx == 0 else "unauth"
            else:
                new_auth = "unauth"

            if domain in self.domains_data:
                self.domains_data[domain]["auth"] = new_auth
                self.clear_creds(domain)
            else:
                self.domains_data[domain] = {"auth": new_auth}

        self.domain = None
        print_success("Credentials and auths cleared.")

    def do_exit(self, exit=True):
        """Exits the shell."""
        global _SESSION_CAPTURE_FINALIZED
        exit_requested = exit if isinstance(exit, bool) else True
        if getattr(self, "_shutdown_in_progress", False):
            print_warning("Shutdown already in progress. Please wait...")
            return exit_requested
        self._shutdown_in_progress = True
        # ACL/attribute-level environment change cleanup
        try:
            from adscan_internal.services.acl_change_cleanup_service import (
                execute_acl_cleanup,
            )

            execute_acl_cleanup(self)
        except Exception as exc:  # pragma: no cover - best-effort shutdown
            telemetry.capture_exception(exc)
            print_info_debug(f"[acl-cleanup] shutdown cleanup failed: {exc}")
        try:
            from adscan_internal.services.ligolo_artifact_cleanup_service import (
                cleanup_workspace_ligolo_artifacts,
            )

            cleanup_workspace_ligolo_artifacts(self, reason="adscan_exit")
        except Exception as exc:  # pragma: no cover - best-effort shutdown
            telemetry.capture_exception(exc)
            print_info_debug(f"[ligolo-cleanup] shutdown cleanup failed: {exc}")
        # Durable operator_confirmed changes (machine accounts, RBCD grants,
        # KeyCredentialLink) are NOT auto-reverted. Prompt the operator whether
        # to revert them now (non-interactive policy: CI reverts all, otherwise
        # keep). The auto_revert class is handled by the owning services above.
        try:
            from adscan_internal.cli.relay_rbcd import (
                run_operator_confirmed_exit_cleanup,
            )

            run_operator_confirmed_exit_cleanup(self)
        except Exception as exc:  # pragma: no cover - best-effort shutdown
            telemetry.capture_exception(exc)
            print_info_debug(f"[ledger] operator-confirmed exit cleanup failed: {exc}")
        # Render environment change cleanup summary and finalise ledger
        try:
            if getattr(self, "environment_change_ledger", None) is not None:
                from adscan_internal.services.cleanup_ux import (
                    render_cleanup_exit_panel,
                )

                render_cleanup_exit_panel(self.environment_change_ledger)
                self.environment_change_ledger.finalize()
        except Exception as exc:
            telemetry.capture_exception(exc)
            print_info_debug(f"[ledger] exit panel failed: {exc}")
        # Use telemetry console for session recording export. This console
        # records a superset of what the user sees in the terminal and is
        # only used for sanitized session uploads.
        self.workspace_save()
        # Attach environment change ledger data for Appendix F
        try:
            if getattr(self, "environment_change_ledger", None) is not None:
                import json as _json
                import os as _os

                _ledger_path = _os.path.join(
                    self.current_workspace_dir or "", "technical_report.json"
                )
                if _os.path.isfile(_ledger_path):
                    with open(_ledger_path, "r", encoding="utf-8") as _f:
                        _report = _json.load(_f)
                    _report["environment_changes"] = {
                        "summary": self.environment_change_ledger.get_summary(),
                        "changes": self.environment_change_ledger.get_changes(),
                    }
                    with open(_ledger_path, "w", encoding="utf-8") as _f:
                        _json.dump(_report, _f, indent=2)
        except Exception as exc:
            telemetry.capture_exception(exc)
            print_info_debug(f"[ledger] failed to attach to technical_report: {exc}")
        print_info("Workspace saved.")
        # Context-aware exit: attribution (once-ever) → summary → CTAs
        _maybe_ask_attribution(self)
        _show_exit_summary(self)
        _maybe_show_report_cta(self)
        # Build metadata from workspace context
        command_type = _resolve_command_type(shell=self)
        if _is_session_capture_allowed(command_type):
            metadata = _build_command_metadata(shell=self)
            # Tier 2: when the streamer is active, it has been shipping
            # chunks throughout the session. We finalise it here — that
            # blocks until the final ``is_final=true`` chunk is sent and
            # then resets ``self._telemetry_streamer = None``. The legacy
            # single-shot export still runs for the path it covers
            # (commands not in the stream-eligible set), because
            # ``capture_session_end`` is the canonical single sink and
            # the rest of the pipeline (PostHog event, exit summary,
            # case-study metrics) depends on it. The duplicate upload of
            # the same Rich recording is harmless: the server's chunk
            # endpoint stitches via ``trace_id`` so the row already
            # exists; the legacy POST with the same ``user_id_hash``
            # creates a SECOND row only when the trace ids differ, which
            # they don't in a streaming session. (If we ever observe
            # duplicates in production we add an explicit skip-when-
            # streamed flag here — for now keep both pipelines coherent.)
            try:
                self._finalise_telemetry_streamer()
            except Exception as exc:  # noqa: BLE001
                telemetry.capture_exception(exc)
                print_info_debug(
                    f"(telemetry-streamer) finalise hook in do_exit failed: "
                    f"{type(exc).__name__}: {exc}"
                )
            telemetry.capture_session_end(console=TELEMETRY_CONSOLE, metadata=metadata)

        # Capture session summary event (Hormozi: Monitor Give:Ask ratio)
        if (
            hasattr(self, "_session_start_time")
            and self._session_start_time is not None
        ):
            duration_minutes = max(
                0.0, (time.monotonic() - self._session_start_time) / 60.0
            )

            # Calculate case study metrics (TTFAP, TTFH only)
            # TTFC and TTC are already captured in first_cred_found and domain_compromise events
            # Use scan_start_time for accurate timing (when the actual scan started)
            ttfap_minutes = None
            ttfh_minutes = None

            scan_start = getattr(self, "scan_start_time", None)
            if scan_start is not None:
                if (
                    hasattr(self, "_session_first_attack_path_time")
                    and self._session_first_attack_path_time is not None
                ):
                    ttfap_minutes = round(
                        max(0.0, self._session_first_attack_path_time - scan_start)
                        / 60.0,
                        2,
                    )

                if (
                    hasattr(self, "_session_first_hash_time")
                    and self._session_first_hash_time is not None
                ):
                    ttfh_minutes = round(
                        max(0.0, self._session_first_hash_time - scan_start) / 60.0, 2
                    )

            session_summary = {
                "duration_minutes": round(duration_minutes, 2),
                "commands_executed": getattr(self, "_session_commands_count", 0),
                "victories_achieved": getattr(self, "_session_victories", []),
                "frustrations_hit": getattr(self, "_session_frustrations", []),
                "workspace_type": getattr(self, "type", None),
                # Case study metrics (TTFAP, TTFH only - TTFC/TTC in their own events)
                "ttfap_minutes": ttfap_minutes,
                "ttfh_minutes": ttfh_minutes,
                "attack_paths_count": resolve_session_attack_paths_for_summary(
                    self,
                    fallback_count=getattr(self, "_session_attack_paths_count", 0),
                ),
                "credentials_count": getattr(self, "_session_credentials_count", 0),
                "workspace_credentials_count": count_workspace_credentials(self),
                "hashes_count": getattr(self, "_session_hashes_count", 0),
            }
            session_summary.update(build_session_compromise_metadata(self))
            telemetry.capture("session_end", session_summary)

        _SESSION_CAPTURE_FINALIZED = True
        self._restore_ntp_service()
        if exit_requested:
            print_info("Exiting...")
            return True
        return False

    def do_export(self, args):
        """Export session findings to TXT/JSON.

        Usage:
            export              Export to JSON (default)
            export txt          Export to human-readable TXT
            export json         Export to JSON
            export --output F   Export to specific file
        """
        from adscan_internal.cli.export import handle_export

        handle_export(self, args)

