# --- Helper function to get tool executable paths ---
def get_tool_executable_path(tool_key):
    """Gets the full path to an executable for a tool defined in PipToolsConfig."""
    if tool_key not in PipToolsConfig:
        print_error(f"Tool key '{tool_key}' not found in PipToolsConfig.")
        return None

    config = PipToolsConfig[tool_key]
    exe_name = config.get("exe_name")

    if not exe_name:
        # This tool might be a library or its executable isn't defined for direct calling this way.
        # print_warning(f"No executable name defined for tool '{tool_key}' in PipToolsConfig.")
        return None  # Or raise an error, depending on desired strictness

    return os.path.join(TOOL_VENVS_BASE_DIR, tool_key, "venv", "bin", exe_name)


def get_external_tool_python(tool_name):
    """Gets the Python executable path for an external tool with isolated venv.

    External tools with requirements.txt (firepwd, LSA-Reaper, PKINITtools)
    are installed in isolated venvs at TOOL_VENVS_BASE_DIR/tool_name/venv/

    Args:
        tool_name (str): Name of the external tool (must match key in EXTERNAL_TOOLS_CONFIG)

    Returns:
        str: Path to Python executable in the tool's isolated venv, or None if not found
    """
    if tool_name not in EXTERNAL_TOOLS_CONFIG:
        return None

    tool_specific_venv_path = os.path.join(TOOL_VENVS_BASE_DIR, tool_name, "venv")
    tool_specific_python = os.path.join(tool_specific_venv_path, "bin", "python")

    if os.path.exists(tool_specific_python):
        return tool_specific_python
    else:
        return None


def get_external_tool_executable(tool_name: str) -> str | None:
    """Return the path to an external tool's executable if defined in config."""
    config = EXTERNAL_TOOLS_CONFIG.get(tool_name)
    if not config:
        return None

    executable_name = config.get("name") or config.get("script_name")
    if not executable_name:
        return None

    executable_path = os.path.join(TOOLS_INSTALL_DIR, tool_name, executable_name)
    if os.path.exists(executable_path):
        return executable_path

    return None


