# --- Check Logic ---
def _print_check_summary(all_ok: bool):
    """Print a professional consolidated summary table of installation status.

    Args:
        all_ok: Overall status of all checks
    """
    from rich.panel import Panel
    from rich.text import Text

    from adscan_internal import create_status_table, reset_spacing
    from adscan_internal.cli.check import get_check_failure_recovery_guidance
    from adscan_internal.theme import ADSCAN_PRIMARY

    full_container_runtime = _is_full_adscan_container_runtime()

    # Build status items for create_status_table
    status_items = []

    # Core Components
    if full_container_runtime:
        status_items.append(
            {
                "name": "Python Virtual Env",
                "status": "success",
                "details": "Not required (ADscan Docker runtime)",
            }
        )
    else:
        venv_python = os.path.join(VENV_PATH, "bin", "python")
        if os.path.exists(venv_python):
            try:
                python_version = subprocess.run(
                    [
                        venv_python,
                        "-c",
                        "import sys; print(f'{sys.version_info.major}.{sys.version_info.minor}.{sys.version_info.micro}')",
                    ],
                    capture_output=True,
                    text=True,
                    check=True,
                    timeout=5,
                ).stdout.strip()
                status_items.append(
                    {
                        "name": "Python Virtual Env",
                        "status": "success",
                        "details": f"Python {python_version} at {VENV_PATH}",
                    }
                )
            except Exception:
                status_items.append(
                    {
                        "name": "Python Virtual Env",
                        "status": "pending",
                        "details": f"Found but version check failed at {VENV_PATH}",
                    }
                )
        else:
            status_items.append(
                {
                    "name": "Python Virtual Env",
                    "status": "failed",
                }
            )

    # System Python
    system_python = shutil.which("python3") or sys.executable
    if system_python:
        status_items.append(
            {
                "name": "System Python",
                "status": "success",
                "details": f"Available at {system_python}",
            }
        )
    else:
        status_items.append(
            {
                "name": "System Python",
                "status": "failed",
                "details": "Not found",
            }
        )

    # Overall Installation Status
    status_items.append(
        {
            "name": "Overall Installation",
            "status": "success" if all_ok else "failed",
            "details": "All components verified"
            if all_ok
            else "Some components missing (see details above)",
        }
    )

    # Create table using the correct signature
    table = create_status_table(
        items=status_items,
        title="Installation Status Summary",
        show_icons=True,
    )

    # Overall status panel
    if all_ok:
        status_text = Text("✓ All checks passed", style="bold green")
        status_message = "ADscan is ready to use. Run 'adscan start' to begin."
    else:
        status_text = Text("⚠ Some checks failed", style="bold yellow")
        status_message = get_check_failure_recovery_guidance(
            full_container_runtime=full_container_runtime
        ).status_message

    status_panel = Panel(
        Text.assemble(
            status_text,
            "\n\n",
            (status_message, "dim"),
        ),
        border_style=ADSCAN_PRIMARY if all_ok else "yellow",
        padding=(1, 2),
    )

    # Print everything
    reset_spacing()
    print_info("")  # Spacing
    console.print(table)
    print_info("")  # Spacing
    console.print(status_panel)


